# ============================================================================
# Script Type Detection Utility
# ============================================================================

def detect_script_type(code: str) -> tuple:
    """Detect if code is a shell command or a script.
    
    Args:
        code: The code/command to analyze
        
    Returns:
        Tuple of (script_type, is_action_command) where:
        - script_type: 'shell' or 'python'
        - is_action_command: True if it's a shell command to execute, False if it's a script
        
    Examples:
        >>> detect_script_type('python3 /app/script.py --arg value')
        ('shell', True)  # Shell command
        >>> detect_script_type('import sys\\nprint("hello")')
        ('python', False)  # Python script
    """
    if not code or not code.strip():
        return ('python', False)
    
    code_lines = code.strip().split('\n')
    first_line = code_lines[0].strip()
    
    # Check for shell command patterns (commands starting with interpreter or shell utilities)
    # These indicate the code is a shell command to execute, not a script file
    shell_command_patterns = (
        first_line.startswith('python ') or
        first_line.startswith('python3 ') or
        first_line.startswith('bash ') or
        first_line.startswith('sh ') or
        first_line.startswith('node ') or
        first_line.startswith('java ') or
        first_line.startswith('Rscript ') or
        first_line.startswith('julia ') or
        first_line.startswith('./') or
        first_line.startswith('bash -c') or
        first_line.startswith('sh -c') or
        first_line.startswith('mpirun ') or
        first_line.startswith('source ') or
        first_line.startswith('module ') or
        first_line.startswith('export ')
    )

    if shell_command_patterns:
        return ('shell', True)

    # Check for single-line CLI commands: word followed by quoted string or flags
    # This catches patterns like: fisher "some text" or mycommand --flag
    # IMPORTANT: Must NOT match strings that start with flags (--name, -f) as those are
    # incomplete commands (likely missing the interpreter prefix like python3)
    cli_command_patterns = (
        # command "args" or command 'args' - but NOT if it looks like a flag (starts with -)
        (len(code_lines) == 1 and re.match(r'^[a-zA-Z][\w-]*\s+["\']', first_line) and not first_line.startswith('-')) or
        # command -flag or command --flag - command must not itself be a flag
        (len(code_lines) == 1 and re.match(r'^[a-zA-Z][\w-]*\s+-', first_line) and not first_line.startswith('-')) or
        # Shell operators in single line (pipes, redirects, etc.) - but not if starts with flag
        (len(code_lines) == 1 and ('|' in first_line or '>>' in first_line) and not first_line.startswith('-'))
    )

    if cli_command_patterns:
        return ('shell', True)
    
    # Check for shell script patterns (shebang, shell operators)
    shell_script_patterns = (
        first_line.startswith('#!') or
        '&&' in first_line or
        '||' in first_line or
        'mpi/openmpi' in code  # Common MPI module pattern
    )
    
    if shell_script_patterns:
        return ('shell', False)
    
    # Check for Python script patterns
    # It's a Python script if it starts with typical Python constructs
    python_script_patterns = (
        first_line.startswith('#') or  # Comment
        first_line.startswith('import ') or
        first_line.startswith('from ') or
        first_line.startswith('def ') or
        first_line.startswith('class ') or
        (len(code_lines) > 3 and any(line.startswith('    ') or line.startswith('\t') for line in code_lines[1:]))
    )
    
    if python_script_patterns:
        return ('python', False)
    
    # Default: treat as shell command (single-line commands are typically shell)
    if len(code_lines) == 1:
        return ('shell', True)
    
    # Multi-line without clear indicators: assume Python script
    return ('python', False)

