def _extract_discovery_operation_id(discovery_data):
    """Try several common fields/locations for the discovery operation id returned by the workspace.
    Works with responses containing 'id', 'operationId', 'name', or nested structures.
    """
    if not discovery_data:
        return None

    # If it's already a string
    if isinstance(discovery_data, str):
        return discovery_data

    # Common top-level keys
    for k in ('id', 'operationId', 'operation_id', 'name'):
        v = discovery_data.get(k) if isinstance(discovery_data, dict) else None
        if v and isinstance(v, str) and v.strip():
            return v.strip()

    # Some responses may nest operation info under 'operation' or 'job'
    for container_key in ('operation', 'job', 'result'):
        nested = discovery_data.get(container_key) if isinstance(discovery_data, dict) else None
        if isinstance(nested, dict):
            for k in ('id', 'operationId', 'name'):
                v = nested.get(k)
                if v and isinstance(v, str) and v.strip():
                    return v.strip()


def resolve_tool_name_for_agent(agent_name, server_traces):
    """Resolve the Discovery published tool name and command template from the
    agent's tool-definition YAML. This function treats the tool-definition
    top-level 'name' as the single source of truth and will raise ValueError
    with a helpful message if it is missing or invalid.

    Returns: (tool_name:str, command_template:str, tool_def_yaml:dict)
    """
    if 'agent_manager' not in globals() or agent_manager is None:
        trace_msg = f"❌ Agent catalog (agent_manager) is not available on the server"
        server_traces.append(trace_msg)
        print(trace_msg)
        raise RuntimeError('Agent catalog not available')

    if not agent_name or agent_name not in getattr(agent_manager, 'agents', {}):
        trace_msg = f"❌ Agent '{agent_name}' not found in agents-catalog"
        server_traces.append(trace_msg)
        print(trace_msg)
        raise ValueError(f"Agent '{agent_name}' not found in catalog")

    # Load richer agent info (this will attempt to load YAML config if present)
    try:
        info = agent_manager._load_agent_info(agent_name)
    except Exception:
        info = None

    tool_def_yaml = None
    # Always load the tool-definition YAML file from the catalog entry.
    entry = agent_manager.agents.get(agent_name)
    # Prefer explicit 'tools_definition' field if present on the catalog entry, else fall back to 'agent_config'
    cfg_path = getattr(entry, 'tools_definition', None) or getattr(entry, 'agent_config', None)
    if cfg_path:
        abs_path = cfg_path
        if not os.path.isabs(cfg_path):
            abs_path = os.path.abspath(os.path.join(os.path.dirname(__file__), cfg_path))
        if os.path.exists(abs_path):
            try:
                import yaml as _yaml
                with open(abs_path, 'r', encoding='utf-8') as f:
                    tool_def_yaml = _yaml.safe_load(f)
                try:
                    # Add debug traces about the file we loaded and its structure
                    server_traces.append(f"DEBUG: Loaded tool-definition from path: {abs_path}")
                    if isinstance(tool_def_yaml, dict):
                        # show up to first 50 top-level keys to avoid huge output
                        server_traces.append(f"DEBUG: loaded YAML top-level keys: {list(tool_def_yaml.keys())[:50]}")
                        # helpful common fields check
                        for common_field in ('name', 'agent', 'infra', 'code_environments', 'command'):
                            if common_field in tool_def_yaml:
                                server_traces.append(f"DEBUG: YAML contains top-level field: {common_field}")
                except Exception:
                    pass
            except Exception as e:
                trace_msg = f"⚠️ Failed to load tool-definition yaml at {abs_path}: {e}"
                server_traces.append(trace_msg)
                print(trace_msg)
        else:
            server_traces.append(f"DEBUG: tool-definition path does not exist: {abs_path}")
    else:
        server_traces.append(f"DEBUG: catalog entry has no 'tools_definition' or 'agent_config' path for agent '{agent_name}'")

    if not tool_def_yaml or not isinstance(tool_def_yaml, dict):
        trace_msg = f"❌ Agent '{agent_name}' catalog entry is missing a valid YAML tool definition"
        server_traces.append(trace_msg)
        print(trace_msg)
        # Add more context when available
        try:
            entry = agent_manager.agents.get(agent_name)
            cfg_path = getattr(entry, 'agent_config', None)
            server_traces.append(f"DEBUG: catalog workflow agent_config path: {cfg_path}")
        except Exception:
            pass
        raise ValueError(f"Agent '{agent_name}' missing tool definition in catalog")

    # REQUIREMENT: Tool 'name' must be present in the tool-definition YAML top-level
    # Primary: top-level 'name'
    top_name = tool_def_yaml.get('name') if isinstance(tool_def_yaml, dict) else None

    # Enforce strict requirement: top-level 'name' must be present and non-empty.
    if not top_name or not isinstance(top_name, str) or not top_name.strip():
        trace_msg = (
            "❌ Tool definition missing required top-level 'name' field. "
            "Discovery tool name must be provided as the top-level 'name' in the tool-definition YAML."
        )
        try:
            keys = list(tool_def_yaml.keys()) if isinstance(tool_def_yaml, dict) else []
            server_traces.append(f"DEBUG: tool-definition top-level keys present: {keys[:50]}")
        except Exception:
            pass
        try:
            if 'abs_path' in locals():
                server_traces.append(f"DEBUG: attempted YAML path: {abs_path}")
        except Exception:
            pass
        server_traces.append(trace_msg)
        print(trace_msg)
        raise ValueError("Tool definition missing top-level 'name' field. Cannot determine Discovery tool id.")
    tool_name = top_name.strip()
    
    # Detect tool type: action-based vs code-environment
    # Action-based tools have 'actions' array with commands already defined in the container
    # Code-environment tools use 'code_environments' or 'command' for script execution
    is_action_based = False
    command_template = "python \"/{{scriptName}}\""
    
    try:
        # Check for action-based tools
        actions = tool_def_yaml.get('actions', [])
        if actions and isinstance(actions, list) and len(actions) > 0:
            is_action_based = True
            # For action-based tools, the command should NOT include {{scriptName}}
            # The command is defined in the action and invokes scripts already in the container
            # We'll use a placeholder that indicates no script upload is needed
            command_template = None
            server_traces.append(f"🎬 Detected action-based tool with {len(actions)} actions")
        else:
            # Code-environment tools - check for command template
            code_environments = tool_def_yaml.get('code_environments', [])
            if code_environments and len(code_environments) > 0:
                command_template = code_environments[0].get('command', command_template)
            else:
                # Fallback: check for top-level command
                command_template = tool_def_yaml.get('command', command_template)
    except Exception as e:
        server_traces.append(f"⚠️ Error detecting tool type: {e}")

    trace_msg = f"📝 Resolved tool name: {tool_name}; type: {'action-based' if is_action_based else 'code-environment'}; command template: {command_template}"
    server_traces.append(trace_msg)
    print(trace_msg)

    return tool_name, command_template, tool_def_yaml

    # Search recursively for any string that looks like a hex-like id (best-effort)
    def _search(obj):
        if isinstance(obj, str):
            if len(obj) >= 8:
                return obj
            return None
        if isinstance(obj, dict):
            for val in obj.values():
                r = _search(val)
                if r:
                    return r
        if isinstance(obj, list):
            for item in obj:
                r = _search(item)
                if r:
                    return r
        return None

    return _search(discovery_data)

