def get_normalized_container_name(agent_name):
    """Get consistent container name format matching client-side expectations"""
    # Match the JavaScript format: {agent-name}-container (normalize spaces and underscores to hyphens)
    return f"{agent_name.lower().replace(' ', '-').replace('_', '-')}-container"


def validate_container_mounts(container, agent_name: str) -> tuple[bool, str]:
    """Check if container's bind mounts match expected session directories.

    Args:
        container: Docker container object
        agent_name: Name of the agent to check session directories for

    Returns:
        Tuple of (is_valid, message) where is_valid is True if mounts match,
        False if container needs recreation. Message contains details.
    """
    try:
        expected_dirs = ensure_shared_directories(agent_name=agent_name)

        # Get actual mounts from container config
        container_info = docker_client.api.inspect_container(container.id)
        actual_binds = container_info.get('HostConfig', {}).get('Binds', [])

        # Parse actual binds into a dict: {container_path: host_path}
        # Format is "host_path:container_path:mode" but Windows paths have drive letters (C:\...)
        actual_mounts = {}
        for bind in actual_binds:
            # Handle Windows paths with drive letters (e.g., "C:\path:/container:rw")
            # Find the container path by looking for the first '/' after a ':'
            colon_indices = [i for i, c in enumerate(bind) if c == ':']
            if len(colon_indices) >= 2:
                # On Windows, first colon is drive letter, second starts container path
                # On Linux, first colon starts container path
                for idx in colon_indices:
                    if idx + 1 < len(bind) and bind[idx + 1] == '/':
                        host_path = bind[:idx]
                        rest = bind[idx + 1:]
                        # rest is "/container:mode" or "/container"
                        container_path = rest.split(':')[0]
                        actual_mounts[container_path] = host_path
                        break

        # Check each expected mount
        mount_mappings = [
            ('/input', expected_dirs['input']),
            ('/output', expected_dirs['output']),
            ('/workdir', expected_dirs['workdir']),
        ]

        for container_path, expected_host_path in mount_mappings:
            actual_host_path = actual_mounts.get(container_path)
            if actual_host_path is None:
                msg = f"Mount validation: missing mount for {container_path}"
                print(f"⚠️ {msg}")
                return False, msg
            # Normalize paths for comparison (handle Windows path variations)
            norm_actual = os.path.normpath(actual_host_path).lower()
            norm_expected = os.path.normpath(expected_host_path).lower()
            if norm_actual != norm_expected:
                msg = f"Mount validation: {container_path} mismatch - expected {expected_host_path}, got {actual_host_path}"
                print(f"⚠️ Mount validation: {container_path} mismatch")
                print(f"   Expected: {expected_host_path}")
                print(f"   Actual:   {actual_host_path}")
                return False, msg

        print(f"✅ Mount validation: all mounts match expected session directories")
        return True, "All mounts valid"
    except Exception as e:
        msg = f"Mount validation error: {e}"
        print(f"⚠️ {msg}")
        # On error, assume mounts are invalid to be safe
        return False, msg


def acquire_management_token_fallback() -> Optional[str]:
    """Strict token acquisition: only use DefaultAzureCredential.

    Per policy, do not attempt environment-based client credential flows or az CLI fallbacks.
    Return the access token string on success or None on failure.
    """
    if not AZURE_IDENTITY_AVAILABLE:
        print('❌ azure-identity not available; no fallback allowed')
        return None

    local_traces = []
    tok = _get_token_default_credential("https://management.azure.com/.default", local_traces, purpose='management-fallback')
    if tok:
        print("✅ Obtained management token via DefaultAzureCredential")
        return tok
    else:
        # Provide a concise hint for interactive auth when helpful
        hint = 'Configure a managed identity or set AZURE_TENANT_ID, AZURE_CLIENT_ID, AZURE_CLIENT_SECRET environment variables.'
        # Try to surface the short failure reason if available
        short = local_traces[-1] if local_traces else 'DefaultAzureCredential failed'
        print(f"❌ DefaultAzureCredential failed to acquire management token: {short}; {hint}")
        return None


def _get_token_default_credential(scope: str, server_traces: list, purpose: str = '') -> Optional[str]:
    # Delegate to centralized helper to keep consistent quiet behavior
    try:
        from azure_auth_helpers import get_token_default_credential
        return get_token_default_credential(scope, server_traces, purpose=purpose)
    except Exception:
        server_traces.append('❌ azure_auth_helpers unavailable; cannot obtain token')
        return None


def _safe_decode_jwt(token: str) -> dict:
    """Decode JWT without verification to expose common claims for debugging."""
    try:
        parts = token.split('.')
        if len(parts) < 2:
            return {}
        import base64
        # JWT payload is the second part
        payload_b64 = parts[1]
        # pad base64
        padding = '=' * (-len(payload_b64) % 4)
        payload_b64 += padding
        payload_bytes = base64.urlsafe_b64decode(payload_b64)
        payload_str = payload_bytes.decode('utf-8')
        return json.loads(payload_str)
    except Exception as e:
        print(f"⚠️ Failed to decode JWT for debugging: {e}")
        return {}


