# Short-term cache for discovery agent listings to avoid repeated expensive calls
# Keyed by (subscription_id, resource_group). TTL is small (seconds) to keep data fresh.
DISCOVERY_AGENTS_CACHE = {}
DISCOVERY_AGENTS_CACHE_LOCK = threading.Lock()
DISCOVERY_AGENTS_CACHE_TTL_SECONDS = int(os.environ.get('AW_DISCOVERY_CACHE_TTL', '30'))  # Increased to match AzureDiscoveryClient TTL

def cached_list_discovery_agents(subscription_id: str, resource_group: str, azure_client=None, tenant_id: str = None) -> dict:
    """Return the result of azure_client.list_discovery_agents but cache it for a few seconds.

    The cache key is (subscription_id, resource_group, tenant_id). The cached value is returned when
    within TTL to avoid repeated network calls during per-agent validation.
    
    Args:
        subscription_id: Azure subscription ID
        resource_group: Azure resource group name
        azure_client: Optional Azure client. If None, uses the global shared client.
        tenant_id: Optional Azure tenant ID for multi-tenant support.
    """
    key = f"{subscription_id}||{resource_group}||{tenant_id or ''}"
    now = time.time()
    # Fast path: check cache under lock
    try:
        with DISCOVERY_AGENTS_CACHE_LOCK:
            entry = DISCOVERY_AGENTS_CACHE.get(key)
            if entry and (now - entry.get('ts', 0)) < DISCOVERY_AGENTS_CACHE_TTL_SECONDS:
                print(f"Using cached discovery agent list for {subscription_id}/{resource_group} (tenant: {tenant_id})")
                return entry.get('result')
    except Exception:
        # If cache lock fails for any reason, fall back to direct call
        pass

    # Get Azure client (use provided one or shared global instance)
    if azure_client is None:
        azure_client = get_azure_discovery_client()
        if azure_client is None:
            return {'exists': False, 'error': 'Azure Discovery Client not available'}

    # Cache miss or expired: call the client
    try:
        result = azure_client.list_discovery_agents(subscription_id, resource_group, "*", tenant_id=tenant_id)
    except Exception as e:
        # Don't cache failures; just return the exception-like structure
        print(f"Error listing discovery agents: {e}")
        return {'exists': False, 'error': str(e)}

    # Store in cache
    try:
        with DISCOVERY_AGENTS_CACHE_LOCK:
            DISCOVERY_AGENTS_CACHE[key] = {'ts': now, 'result': result}
    except Exception:
        pass

    return result

# Global Azure Discovery Client for reuse across requests
_global_azure_client = None
_global_azure_client_lock = threading.Lock()

def get_azure_discovery_client():
    """Get a shared Azure Discovery Client instance to reduce initialization overhead."""
    global _global_azure_client
    
    if _global_azure_client is None:
        with _global_azure_client_lock:
            # Double-check pattern
            if _global_azure_client is None:
                try:
                    from discovery_publisher import AzureDiscoveryClient
                    _global_azure_client = AzureDiscoveryClient()
                except ImportError:
                    pass
    
    return _global_azure_client

# Global Universe cache for trajectory file reuse across requests
# Key: (trajectory_path, topology_path, traj_mtime, topo_mtime)
# Value: MDAnalysis Universe object
_universe_cache = {}
_universe_cache_lock = threading.Lock()
_universe_cache_max_size = 5  # Keep max 5 universes in memory

def get_cached_universe(trajectory_path, topology_path=None):
    """Get cached Universe or create new one. Returns (universe, was_cached)."""
    import os
    
    # Build cache key with file paths and modification times
    traj_mtime = os.path.getmtime(trajectory_path)
    topo_mtime = os.path.getmtime(topology_path) if topology_path else 0
    cache_key = (trajectory_path, topology_path or '', traj_mtime, topo_mtime)
    
    with _universe_cache_lock:
        # Check cache
        if cache_key in _universe_cache:
            return _universe_cache[cache_key], True
        
        # Load new Universe
        import MDAnalysis as mda
        if topology_path:
            universe = mda.Universe(topology_path, trajectory_path)
        else:
            universe = mda.Universe(trajectory_path)
        
        # Store in cache (LRU eviction if full)
        if len(_universe_cache) >= _universe_cache_max_size:
            # Remove oldest entry
            oldest_key = next(iter(_universe_cache))
            del _universe_cache[oldest_key]
        
        _universe_cache[cache_key] = universe
        return universe, False

