class CatalogFileHandler(FileSystemEventHandler):
    """Handles file system events for the agents catalog file and discovery config."""
    
    def __init__(self, catalog_reload_callback, config_reload_callback, debounce_seconds=1.0):
        super().__init__()
        self.catalog_reload_callback = catalog_reload_callback
        self.config_reload_callback = config_reload_callback
        self.debounce_seconds = debounce_seconds
        self.last_modified = {}
        self.timers = {}
        
    def on_modified(self, event):
        if event.is_directory:
            return
            
        current_time = time.time()
        
        # Check which file was modified and call appropriate callback
        if event.src_path.endswith('agents-catalog.yaml') or event.src_path.endswith('agents-catalog.yaml'):
            self._handle_file_change(event.src_path, current_time, self.catalog_reload_callback, 'catalog')
        elif event.src_path.endswith('discovery_config.json'):
            self._handle_file_change(event.src_path, current_time, self.config_reload_callback, 'config')
            
    def _handle_file_change(self, file_path, current_time, callback, file_type):
        """Handle file change with debouncing."""
        # Debounce: only process if enough time has passed since last modification
        if file_path in self.last_modified:
            if current_time - self.last_modified[file_path] < self.debounce_seconds:
                return
                
        self.last_modified[file_path] = current_time
        
        # Cancel previous timer if it exists
        if file_path in self.timers:
            self.timers[file_path].cancel()
            
        # Set up a new timer to reload after debounce period
        self.timers[file_path] = threading.Timer(
            self.debounce_seconds, 
            self._delayed_reload, 
            [file_path, callback, file_type]
        )
        self.timers[file_path].start()
            
    def _delayed_reload(self, file_path, callback, file_type):
        """Delayed reload function called after debounce period."""
        try:
            print(f"🔄 External change detected in {os.path.basename(file_path)}, reloading {file_type}...")
            callback()
            print(f"✅ {file_type.capitalize()} reloaded successfully")
        except Exception as e:
            print(f"❌ Error reloading {file_type}: {e}")
        finally:
            # Clean up timer
            if file_path in self.timers:
                del self.timers[file_path]

# Global file monitoring variables
file_observer = None
catalog_file_handler = None

def setup_file_monitoring():
    """Set up file monitoring for the agents catalog and discovery config."""
    global file_observer, catalog_file_handler, agent_manager
    
    if not WATCHDOG_AVAILABLE:
        print("⚠️ File monitoring not available (watchdog not installed)")
        return
        
    if not agent_manager:
        print("⚠️ Agent manager not initialized, skipping file monitoring setup")
        return
        
    try:
        # Get the catalog directory path
        catalog_path = os.path.dirname(agent_manager.catalog_path)
        
        # Create file handler with both reload callbacks
        def reload_catalog():
            """Reload the agent catalog from disk."""
            try:
                agent_manager.reload_catalog()
            except Exception as e:
                print(f"Error reloading agent catalog: {e}")
                
        def reload_config():
            """Reload the discovery configuration."""
            reload_discovery_config()
                
        catalog_file_handler = CatalogFileHandler(reload_catalog, reload_config)
        
        # Set up file observer
        file_observer = Observer()
        file_observer.schedule(catalog_file_handler, catalog_path, recursive=False)
        file_observer.start()

        print(f"📁 File monitoring started for: {catalog_path}")
        print("🔍 Monitoring: agents-catalog.yaml, discovery_config.json")

    except Exception as e:
        print(f"❌ Failed to setup file monitoring: {e}")

def cleanup_file_monitoring():
    """Clean up file monitoring resources."""
    global file_observer, catalog_file_handler
    
    if file_observer:
        try:
            file_observer.stop()
            file_observer.join(timeout=1.0)
            print("🛑 File monitoring stopped")
        except Exception as e:
            print(f"Warning: Error stopping file observer: {e}")
        finally:
            file_observer = None
            
    if catalog_file_handler and hasattr(catalog_file_handler, 'timers'):
        try:
            # Cancel all pending timers
            for timer in catalog_file_handler.timers.values():
                timer.cancel()
            catalog_file_handler.timers.clear()
        except Exception:
            pass
        finally:
            catalog_file_handler = None

def reload_discovery_config():
    """Reload discovery configuration and global variables."""
    global config_manager, endpoint, deployment, subscription_key, api_url

    try:
        print("🔄 Reloading discovery configuration...")

        # Reinitialize config manager if available
        if DISCOVERY_AVAILABLE:
            # Create a new instance but also update the global one used by LLMClient
            config_manager = DiscoveryConfigManager()
            from discovery_config_manager import set_global_config_manager
            set_global_config_manager(config_manager)
            print("[Config Reload] Updated global config manager for LLMClient")
            try:
                azure_openai_cfg = config_manager.get_azure_openai_config()
                if not (azure_openai_cfg and azure_openai_cfg.get('endpoint_url') and azure_openai_cfg.get('deployment_name') and (azure_openai_cfg.get('api_key') or azure_openai_cfg.get('auth_type') == 'azure_ad')):
                    print('⚠️ Discovery config missing Azure OpenAI settings')
                    endpoint = None
                    deployment = None
                    subscription_key = None
                    api_version = azure_openai_cfg.get('api_version', '2024-02-15-preview') if azure_openai_cfg else '2024-02-15-preview'
                else:
                    endpoint = azure_openai_cfg.get('endpoint_url')
                    deployment = azure_openai_cfg.get('deployment_name')
                    subscription_key = azure_openai_cfg.get('api_key')
                    api_version = azure_openai_cfg.get('api_version', '2024-02-15-preview')
            except Exception as cfg_err:
                print(f"⚠️ Error reading Azure OpenAI config from discovery: {cfg_err}")
                endpoint = None
                deployment = None
                subscription_key = None
                api_version = '2024-02-15-preview'
            
            # Rebuild the API URL with the updated configuration
            if endpoint and deployment:
                api_url = f"{endpoint}/openai/deployments/{deployment}/chat/completions?api-version={api_version}"
            else:
                api_url = None
            
            # Load conversation configuration from config file and apply to ConversationManager
            conversation_config = config_manager.get_conversation_config()
            try:
                # Reinitialize conversation manager with the new settings
                initialize_conversation_manager()
            except Exception as e:
                print(f"⚠️ Warning: Failed to initialize ConversationManager after config reload: {e}")

            # Print concise status using values returned by config manager
            try:
                max_tokens = conversation_config.get('max_tokens')
                target_tokens = conversation_config.get('target_tokens')
                strategy_name = conversation_config.get('strategy')
            except Exception:
                max_tokens = target_tokens = strategy_name = None

            print(f"✅ Discovery config reloaded - Endpoint: {endpoint is not None}, Deployment: {deployment is not None}, API Key: {subscription_key is not None}")
            print(f"✅ Conversation settings - Max: {max_tokens}, Target: {target_tokens}, Strategy: {strategy_name}")

    except Exception as e:
        print(f"❌ Error reloading discovery config: {e}")

def load_initial_config():
    """Load initial configuration at startup."""
    global config_manager, endpoint, deployment, subscription_key, api_url
    
    try:
        if DISCOVERY_AVAILABLE and config_manager:
            # Load Azure OpenAI configuration
            azure_openai_config = config_manager.get_azure_openai_config()
            endpoint = azure_openai_config.get('endpoint_url')
            deployment = azure_openai_config.get('deployment_name')
            subscription_key = azure_openai_config.get('api_key')
            api_version = azure_openai_config.get('api_version', '2024-02-15-preview')
            
            # Rebuild the API URL now that we have the correct endpoint and deployment
            if endpoint and deployment:
                api_url = f"{endpoint}/openai/deployments/{deployment}/chat/completions?api-version={api_version}"
            else:
                api_url = None
            
            # Load conversation configuration and initialize manager (must succeed)
            conversation_config = config_manager.get_conversation_config()
            print(f"✅ Configuration loaded - Azure OpenAI: {'✓' if endpoint and deployment and subscription_key else '✗'}")
            print(f"✅ Conversation: {conversation_config}")

            # Initialize conversation manager with loaded config (will raise if config missing)
            initialize_conversation_manager()
        else:
            print("⚠️ Discovery not available - using default configuration")
            # Discovery not available: fail fast since conversation settings must come from config
            raise RuntimeError("Discovery configuration unavailable; conversation settings must be provided in discovery_config.json")
            
    except Exception as e:
        print(f"❌ Error loading initial config: {e}")
        # Initialize conversation manager with defaults even if config loading fails
        initialize_conversation_manager()

def initialize_conversation_manager():
    """Initialize the conversation manager with current configuration."""
    global conversation_manager, session_manager
    print("🔄 Initializing conversation manager...")

    # Require DiscoveryConfigManager to be present. Conversation parameters must come from discovery_config.json
    if not DISCOVERY_AVAILABLE or not config_manager:
        raise RuntimeError("DiscoveryConfigManager not available; cannot initialize ConversationManager")

    conv_cfg = config_manager.get_conversation_config()

    # Required fields: max_tokens, target_tokens, strategy
    missing = [k for k in ('max_tokens', 'target_tokens', 'strategy') if conv_cfg.get(k) is None]
    if missing:
        raise RuntimeError(f"Conversation configuration missing required keys: {missing}")

    max_tokens = conv_cfg.get('max_tokens')
    target_tokens = conv_cfg.get('target_tokens')
    strategy_name = conv_cfg.get('strategy')

    # Use deployment name directly for model name
    model_name = deployment or "gpt-4"

    if strategy_name == "sliding_window":
        strategy = ContextStrategy.SLIDING_WINDOW
    elif strategy_name == "summarization":
        strategy = ContextStrategy.SUMMARIZATION
    else:
        strategy = ContextStrategy.HYBRID

    conversation_manager = ConversationManager(
        max_tokens=max_tokens,
        target_tokens=target_tokens,
        strategy=strategy,
        model_name=model_name
    )

    # Optional fields: max_output_tokens, temperature
    if conv_cfg.get('max_output_tokens') is not None and hasattr(conversation_manager, 'max_output_tokens'):
        conversation_manager.max_output_tokens = conv_cfg.get('max_output_tokens')
    if conv_cfg.get('temperature') is not None and hasattr(conversation_manager, 'temperature'):
        conversation_manager.temperature = conv_cfg.get('temperature')

    print(f"✅ Conversation manager initialized (Strategy: {strategy.value}, Model: {model_name})")

    # Initialize session manager for multi-session support
    base_dir = os.path.dirname(os.path.abspath(__file__))
    session_manager = init_session_manager(base_dir)
    print(f"✅ Session manager initialized (Current session: {session_manager.current_session_id})")

