def rewrite_yaml_agent_names(file_path: str, old_name: str, new_name: str):
    """
    Reusable function to update agent names and references in YAML files.
    Used by both cloning and renaming operations.
    
    Args:
        file_path: Path to the YAML file to update
        old_name: Original agent name to replace
        new_name: New agent name to use
    """
    import re
    try:
        print(f"🔄 Rewriting YAML: {file_path}")
        
        # Read the original file content as text
        with open(file_path, 'r', encoding='utf-8') as yf:
            content = yf.read()
        
        changes_made = False
        
        # Pattern 1: agent.name field (with various spacing/indentation)
        # Matches: "  name: old_name" or "    name: old_name" etc.
        agent_name_pattern = rf'^(\s*name:\s*){re.escape(old_name)}(\s*)$'
        if re.search(agent_name_pattern, content, re.MULTILINE):
            content = re.sub(agent_name_pattern, rf'\g<1>{new_name}\g<2>', content, flags=re.MULTILINE)
            print(f"  → Updated agent name: {old_name} -> {new_name}")
            changes_made = True
        
        # Pattern 2: workflow top-level name field
        # Matches workflow files with top-level "name: old_name"
        workflow_name_pattern = rf'^(name:\s*){re.escape(old_name)}(\s*)$'
        if re.search(workflow_name_pattern, content, re.MULTILINE):
            content = re.sub(workflow_name_pattern, rf'\g<1>{new_name}\g<2>', content, flags=re.MULTILINE)
            print(f"  → Updated workflow name: {old_name} -> {new_name}")
            changes_made = True
        
        # Pattern 3: Agent references in workflow (e.g., "agent: hlgap-pln")
        # Matches component agent references that follow the naming pattern
        component_pattern = rf'(agent:\s*){re.escape(old_name.lower())}-([a-zA-Z0-9_-]+)(\s*)$'
        if re.search(component_pattern, content, re.MULTILINE):
            content = re.sub(component_pattern, rf'\g<1>{new_name.lower()}-\g<2>\g<3>', content, flags=re.MULTILINE)
            print(f"  → Updated component agent references: {old_name.lower()}-* -> {new_name.lower()}-*")
            changes_made = True
        
        # Pattern 4: Direct agent name references that follow the pattern
        # Matches standalone references like "hlgap-pln" in various contexts
        standalone_component_pattern = rf'\b{re.escape(old_name.lower())}-([a-zA-Z0-9_-]+)\b'
        if re.search(standalone_component_pattern, content):
            content = re.sub(standalone_component_pattern, rf'{new_name.lower()}-\g<1>', content)
            print(f"  → Updated standalone component references: {old_name.lower()}-* -> {new_name.lower()}-*")
            changes_made = True
        
        # Pattern 5: Agent name in instruction text (e.g., "You are hlgap-pln")
        # Update references in instruction text
        instruction_agent_pattern = rf'(You are (?:the )?){re.escape(old_name.lower())}-([a-zA-Z0-9_-]+)(\b)'
        if re.search(instruction_agent_pattern, content, re.IGNORECASE):
            content = re.sub(instruction_agent_pattern, rf'\g<1>{new_name.lower()}-\g<2>\g<3>', content, flags=re.IGNORECASE)
            print(f"  → Updated instruction agent references: You are {old_name.lower()}-* -> You are {new_name.lower()}-*")
            changes_made = True
        
        # Pattern 6: Any other occurrences of the source name that might need updating
        # Be more selective to avoid false positives in descriptions/instructions
        # Only replace if it's clearly a name reference (e.g., "You are old_name:")
        instruction_name_pattern = rf'(You are\s+){re.escape(old_name)}(\s*:)'
        if re.search(instruction_name_pattern, content, re.IGNORECASE):
            content = re.sub(instruction_name_pattern, rf'\g<1>{new_name}\g<2>', content, flags=re.IGNORECASE)
            print(f"  → Updated instruction reference: {old_name} -> {new_name}")
            changes_made = True
        
        # Write back the modified content if changes were made
        if changes_made:
            with open(file_path, 'w', encoding='utf-8') as yf:
                yf.write(content)
            print(f"  → YAML updated with preserved formatting")
        else:
            print(f"  → No changes needed in {file_path}")
            
    except Exception as yerr:
        print(f"⚠️ YAML name rewrite skipped for {file_path}: {yerr}")

def is_configuration_complete():
    """Check if all required configuration is complete."""
    if not DISCOVERY_AVAILABLE or not config_manager:
        return False
    
    try:
        return config_manager.is_config_complete()
    except Exception as e:
        print(f"❌ Error checking configuration completeness: {e}")
        return False

@app.route('/api/config-status', methods=['GET'])
def get_config_status():
    """Check if configuration is complete and return status."""
    try:
        is_complete = is_configuration_complete()
        
        # Get current configuration status
        status = {
            'is_complete': is_complete,
            'requires_setup': not is_complete,
            'missing_sections': []
        }
        
        if DISCOVERY_AVAILABLE and config_manager:
            # Check individual sections
            azure_openai = config_manager.get_azure_openai_config()
            azure = config_manager.get_azure_config()
            
            # Check Azure OpenAI configuration based on auth type
            auth_type = azure_openai.get('auth_type', 'api_key').lower()
            azure_openai_valid = False
            
            if azure_openai.get('endpoint_url') and azure_openai.get('deployment_name'):
                if auth_type == 'azure_ad':
                    # For Azure AD auth, we just need the azure_ad section configured
                    azure_ad_config = azure_openai.get('azure_ad', {})
                    if azure_ad_config.get('tenant_id'):
                        azure_openai_valid = True
                else:
                    # For API key auth, we need the api_key
                    if azure_openai.get('api_key'):
                        azure_openai_valid = True
            
            if not azure_openai_valid:
                status['missing_sections'].append('azure_openai')
            
            if not azure.get('subscription_id') or not azure.get('resource_group') or not azure.get('location'):
                status['missing_sections'].append('azure')
        
        return jsonify({
            'success': True,
            'status': status
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/system/capabilities', methods=['GET'])
def get_system_capabilities():
    """Return system capabilities for UI to adjust available features.

    This endpoint exposes the availability of optional features like:
    - Docker (local builds)
    - Azure CLI (cloud builds)
    - ACR configuration

    The UI uses this to enable/disable features appropriately.

    Query parameters:
    - refresh: If 'true', re-check Azure CLI status instead of using cached values
    """
    global AZ_CLI_AVAILABLE, AZ_CLI_AUTHENTICATED, AZ_CLI_SUBSCRIPTION_NAME

    try:
        # Check if we should refresh Azure CLI status
        refresh = request.args.get('refresh', 'false').lower() == 'true'

        # Get current Azure CLI status (re-check if refresh requested)
        az_cli_installed = AZ_CLI_AVAILABLE
        az_cli_authenticated = AZ_CLI_AUTHENTICATED
        az_cli_subscription = AZ_CLI_SUBSCRIPTION_NAME

        if refresh:
            print("[Cloud Build] Refreshing Azure CLI status...")
            # Re-check Azure CLI availability
            az_cli_installed = shutil.which("az") is not None
            print(f"[Cloud Build] az CLI in PATH: {az_cli_installed}")

            if az_cli_installed:
                # Re-check authentication status
                try:
                    # On Windows, we need shell=True for proper command execution
                    is_windows = sys.platform == 'win32'
                    cmd = "az account show --output json" if is_windows else ["az", "account", "show", "--output", "json"]
                    result = subprocess.run(
                        cmd,
                        capture_output=True, text=True, timeout=15,
                        shell=is_windows
                    )
                    print(f"[Cloud Build] az account show returncode: {result.returncode}")
                    if result.stderr:
                        print(f"[Cloud Build] az account show stderr: {result.stderr[:500]}")
                    if result.returncode == 0:
                        az_cli_authenticated = True
                        try:
                            account = json.loads(result.stdout)
                            az_cli_subscription = account.get('name', 'Unknown')
                            print(f"[Cloud Build] Authenticated! Subscription: {az_cli_subscription}")
                        except json.JSONDecodeError as je:
                            print(f"[Cloud Build] JSON decode error: {je}")
                            az_cli_subscription = 'Unknown'
                        # Update global cache
                        AZ_CLI_AVAILABLE = True
                        AZ_CLI_AUTHENTICATED = True
                        AZ_CLI_SUBSCRIPTION_NAME = az_cli_subscription
                    else:
                        print(f"[Cloud Build] az account show failed: {result.stderr[:200] if result.stderr else 'no stderr'}")
                        az_cli_authenticated = False
                        az_cli_subscription = None
                        AZ_CLI_AUTHENTICATED = False
                        AZ_CLI_SUBSCRIPTION_NAME = None
                except subprocess.TimeoutExpired:
                    print("[Cloud Build] az account show timed out")
                except Exception as e:
                    print(f"[Cloud Build] Exception: {type(e).__name__}: {e}")
            else:
                az_cli_authenticated = False
                az_cli_subscription = None

        # Get Azure config for ACR settings
        azure_config = {}
        if DISCOVERY_AVAILABLE and config_manager:
            azure_config = config_manager.get_azure_config() or {}

        acr_name = azure_config.get('acr_name', '')

        # Determine cloud build availability and reason if unavailable
        cloud_build_available = az_cli_installed and az_cli_authenticated and bool(acr_name)
        unavailable_reason = None

        if not az_cli_installed:
            if sys.platform == 'win32':
                unavailable_reason = "Azure CLI not installed. Run: winget install Microsoft.AzureCLI"
            elif sys.platform == 'darwin':
                unavailable_reason = "Azure CLI not installed. Run: brew install azure-cli"
            else:
                unavailable_reason = "Azure CLI not installed. See: https://aka.ms/InstallAzureCLIDeb"
        elif not az_cli_authenticated:
            unavailable_reason = "Azure CLI not authenticated. Run: az login"
        elif not acr_name:
            unavailable_reason = "ACR not configured. Set ACR name in Settings > Azure"

        # Check Docker daemon status
        docker_daemon_running = False
        if docker_client:
            try:
                docker_client.ping()
                docker_daemon_running = True
            except Exception:
                pass

        # Get Azure OpenAI config for tenant info
        azure_openai_config = {}
        if DISCOVERY_AVAILABLE and config_manager:
            azure_openai_config = config_manager.get_azure_openai_config() or {}

        # Extract tenant_id from azure_ad config if available
        azure_ad_config = azure_openai_config.get('azure_ad', {})
        tenant_id = azure_ad_config.get('tenant_id', '')

        return jsonify({
            'docker': {
                'available': docker_client is not None,
                'daemon_running': docker_daemon_running
            },
            'azure_cli': {
                'installed': az_cli_installed,
                'authenticated': az_cli_authenticated,
                'subscription_name': az_cli_subscription,
                'help_url': 'https://docs.microsoft.com/cli/azure/install-azure-cli'
            },
            'azure_config': {
                'tenant_id': tenant_id,
                'subscription_id': azure_config.get('subscription_id', ''),
                'subscription_name': azure_config.get('subscription_name', '')
            },
            'acr': {
                'configured': bool(acr_name),
                'name': acr_name
            },
            'cloud_build': {
                'available': cloud_build_available,
                'unavailable_reason': unavailable_reason
            }
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


