# Load Mermaid system prompt template at startup
MERMAID_SYSTEM_PROMPT = None
MERMAID_PROMPT_PATH = None
# Exact init fence to ensure portability if the model omits it
MERMAID_INIT_FENCE = (
    "%%{init: {\"securityLevel\":\"strict\",\"theme\":\"neutral\",\"themeVariables\":{\"primaryColor\":\"#0F6CBD\",\"lineColor\":\"#6B7280\",\"actorBkg\":\"#F7F7F8\",\"actorBorder\":\"#B3B3B3\",\"noteBkgColor\":\"#FFF7E6\",\"noteTextColor\":\"#374151\",\"fontSize\":\"12px\",\"textColor\":\"#1F2937\"}}}%%"
)
try:
    prompts_dir = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'prompts')
    # Use PromptLoader utility for consistency
    loader = get_prompt_loader()
    # Ensure loader is pointed to our prompts dir
    loader.prompts_dir = prompts_dir
    MERMAID_PROMPT_PATH = os.path.join(prompts_dir, 'mermaid_system.txt')
    MERMAID_SYSTEM_PROMPT = loader.load_prompt('mermaid_system.txt')
except Exception as e:
    MERMAID_SYSTEM_PROMPT = None
    print(f"⚠️ Mermaid prompt: file template unavailable ({e}); will use inline fallback.")


@app.route('/api/generate-diagram', methods=['POST'])
def generate_mermaid_diagram():
    """Generate a Mermaid diagram from workflow YAML using an LLM.

    Request JSON supports either:
      - { "yaml": "...", "workflowName": "...", "previousError": "..." }  -> server composes the strict prompt and auto-saves diagram
      - { "prompt": "..." } -> server sends prompt as-is (no auto-save)

    The optional previousError field contains validation/render error from a prior attempt,
    which is injected into the prompt to help the LLM avoid repeating the same mistake.

    Returns JSON: { success: bool, diagram?: str, error?: str, savedTo?: str }
    """
    try:
        data = request.get_json(silent=True) or {}
        yaml_text = data.get('yaml') or data.get('YAML')
        workflow_name = data.get('workflowName')
        previous_error = data.get('previousError')  # Error feedback from prior failed attempt
        prompt = data.get('prompt')

        # Compose the exact prompt by injecting YAML into the latest on-disk template
        if not prompt and yaml_text:
            escaped_yaml = str(yaml_text).replace("'", "''")
            # Always read the latest prompt from disk to reflect any edits
            try:
                prompts_dir = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'prompts')
                prompt_path = MERMAID_PROMPT_PATH or os.path.join(prompts_dir, 'mermaid_system.txt')
                if prompt_path and os.path.exists(prompt_path):
                    with open(prompt_path, 'r', encoding='utf-8') as f:
                        latest_template = f.read()
                    prompt = latest_template.replace('{yaml}', escaped_yaml)
                else:
                    raise FileNotFoundError('mermaid_system.txt not found')
            except Exception as e:
                # Fallback inline template if file missing or read fails
                prompt = (
                    "Generate a Mermaid sequence diagram from the provided workflow YAML. Return ONLY Mermaid text.\n\n"
                    "Requirements: sequenceDiagram; autonumber; participants (User + one per agent, use aliases when needed); alt/else per routing events; colored rect blocks; balanced activate/deactivate; strict lines only (no prose).\n\n"
                    "YAML:\n"
                    f"'{escaped_yaml}'\n"
                )
                print(f"📝 Mermaid prompt: using inline fallback template; reason={e}; yaml_len={len(yaml_text)}")

            # Inject previous error feedback into the prompt if this is a retry
            if previous_error:
                error_feedback = (
                    f"\n\nIMPORTANT - PREVIOUS ATTEMPT FAILED:\n"
                    f"Your previous Mermaid output caused the following validation/render error:\n"
                    f"Error: {previous_error}\n\n"
                    f"Please fix this specific issue in your new output. Common fixes:\n"
                    f"- Ensure all 'activate X' have matching 'deactivate X' within the same block\n"
                    f"- Do not deactivate a participant that is not currently active\n"
                    f"- Ensure 'end' keywords are on their own line, not concatenated with other text\n"
                    f"- Verify all participant aliases are declared before use\n"
                    f"- Check that all blocks (rect, alt, loop, etc.) are properly closed\n"
                )
                prompt += error_feedback
                print(f"📝 Mermaid prompt: injected error feedback for retry; error={previous_error[:100]}...")

        if not prompt:
            return jsonify({
                'success': False,
                'error': 'Missing input. Provide either "yaml" or a pre-built "prompt".'
            }), 400

        # Determine API version from discovery config (fall back to sensible default)
        try:
            cfg_api_version = None
            if config_manager:
                _ao = config_manager.get_azure_openai_config()
                cfg_api_version = (_ao.get('api_version') if isinstance(_ao, dict) else None)
        except Exception:
            cfg_api_version = None

        api_version = cfg_api_version or '2024-12-01-preview'

        # Build Azure OpenAI Chat Completions URL
        url = f"{endpoint.rstrip('/')}/openai/deployments/{deployment}/chat/completions?api-version={api_version}"
        print(f"[Mermaid] 📍 Using api_version: {api_version} (from config_manager: {cfg_api_version})")
        print(f"[Mermaid] Using endpoint: {endpoint[:50] if endpoint else 'NOT SET'}...")

        payload = {
            'messages': [
                {
                    'role': 'system',
                    'content': 'You generate Mermaid diagrams and must return ONLY the final Mermaid text.'
                },
                { 'role': 'user', 'content': prompt }
            ],
            'temperature': 0,
            'top_p': 0,
            'max_tokens': 2000
        }

        # Build auth headers: prefer subscription_key (api-key) but support Azure AD bearer token
        headers = { 'Content-Type': 'application/json' }
        if subscription_key:
            headers['api-key'] = subscription_key
        else:
            # Try to acquire an Azure AD token for Cognitive Services/OpenAI scope
            token = None
            try:
                if AZURE_IDENTITY_AVAILABLE:
                    _local_traces = []
                    token = _get_token_default_credential('https://cognitiveservices.azure.com/.default', _local_traces, purpose='cogservices')
                    # helper returns the token string or None
                    # token variable will be the raw token string on success
                else:
                    # REST client_credentials fallback (if env vars set)
                    tenant = os.environ.get('AZURE_TENANT_ID')
                    client_id = os.environ.get('AZURE_CLIENT_ID')
                    client_secret = os.environ.get('AZURE_CLIENT_SECRET')
                    if tenant and client_id and client_secret:
                        token_url = f"https://login.microsoftonline.com/{tenant}/oauth2/v2.0/token"
                        payload_tok = {
                            'client_id': client_id,
                            'client_secret': client_secret,
                            'grant_type': 'client_credentials',
                            'scope': 'https://cognitiveservices.azure.com/.default'
                        }
                        tr = requests.post(token_url, data=payload_tok, timeout=15)
                        tr.raise_for_status()
                        token = tr.json().get('access_token')
            except Exception as _e:
                print(f"⚠️ Failed to acquire Azure AD token for OpenAI: {_e}")

            if not token:
                return jsonify({
                    'success': False,
                    'error': 'LLM auth unavailable. Provide api_key or configure Azure AD credentials.'
                }), 500

            headers['Authorization'] = f"Bearer {token}"

        resp = requests.post(url, headers=headers, data=json.dumps(payload), timeout=60)
        if resp.status_code != 200:
            return jsonify({
                'success': False,
                'error': f"LLM request failed: {resp.status_code} {resp.text[:500]}"
            }), 502

        data = resp.json()
        diagram = None
        try:
            if isinstance(data, dict) and data.get('choices'):
                diagram = (data['choices'][0].get('message', {}) or {}).get('content', '')
        except Exception:
            diagram = None

        if not diagram:
            # Fallback extraction if provider returns different shape
            diagram = (data.get('diagram') or data.get('text') or '').strip() if isinstance(data, dict) else ''

        if not diagram:
            return jsonify({ 'success': False, 'error': 'No content returned by LLM.' }), 502

        # Strip code fences if the model still returned them
        content = diagram.strip()
        if content.startswith('```') and content.endswith('```'):
            # Remove the first line (``` or ```mermaid) and trailing ```
            first_nl = content.find('\n')
            last_fence = content.rfind('```')
            if first_nl != -1 and last_fence != -1 and last_fence > first_nl:
                content = content[first_nl+1:last_fence].strip()

        # Normalize line endings and sanitize a common concat bug ("Endend")
        content = content.replace('\r\n', '\n').replace('\r', '\n')

        # Ensure the init fence is present as the very first line for portability
        head = content.lstrip()  # ignore leading whitespace
        if not head.startswith('%%{init:'):
            content = f"{MERMAID_INIT_FENCE}\n" + content

        # Fix a frequent LLM concatenation issue where a message label "End" and a control 'end'
        # end up as "Endend" on the same line (e.g., "SA->>User: Endend").
        # Only adjust when it occurs in a message context (there's a ':' earlier on the line).
        try:
            import re as _re
            content = _re.sub(r'(^[^\n]*?:[^\n]*?)\b[Ee]ndend(\s*$)', r'\1End\nend\2', content, flags=_re.MULTILINE)
        except Exception:
            pass

        # Auto-save diagram file if we have a workflow name
        saved_to = None
        if workflow_name and workflow_name.strip():
            try:
                # Find the workflow folder based on the workflow name using config-driven path
                try:
                    workflow_agents_base_dir = get_workflow_agents_dir()
                    workflow_agents_base = os.path.join(os.path.dirname(__file__), workflow_agents_base_dir)
                except Exception as e:
                    print(f"⚠️ Failed to resolve workflow agents directory: {e}")
                    workflow_agents_base = None
                    
                workflow_folder = None
                
                # Look for the workflow folder
                if workflow_agents_base and os.path.exists(workflow_agents_base):
                    for folder_name in os.listdir(workflow_agents_base):
                        folder_path = os.path.join(workflow_agents_base, folder_name)
                        if os.path.isdir(folder_path):
                            # Check if this folder contains a workflow YAML that matches our workflow name
                            workflow_file = os.path.join(folder_path, f"{workflow_name.lower()}-wfl.yaml")
                            if os.path.exists(workflow_file):
                                workflow_folder = folder_path
                                break
                
                if workflow_folder:
                    # Save the diagram file in the same folder as the workflow
                    diagram_filename = f"{workflow_name.lower()}-diagram.mmd"
                    diagram_path = os.path.join(workflow_folder, diagram_filename)
                    
                    with open(diagram_path, 'w', encoding='utf-8') as f:
                        f.write(content)
                    
                    saved_to = diagram_path
                    print(f"📊 Auto-saved Mermaid diagram to: {diagram_path}")
                else:
                    print(f"⚠️ Could not find workflow folder for: {workflow_name}")
                    
            except Exception as save_error:
                print(f"⚠️ Failed to auto-save diagram: {save_error}")
                # Don't fail the whole request if save fails
        
        response_data = {'success': True, 'diagram': content}
        if saved_to:
            response_data['savedTo'] = saved_to
            
        return jsonify(response_data)

    except Exception as e:
        return jsonify({ 'success': False, 'error': str(e) }), 500


def fetch_agent_resource(subscription_id: str, resource_group: str, agent_name: str) -> dict:
    """Fetch the Discovery agent resource JSON using Azure REST API.

    Returns a dict with keys: success(bool), resource(dict) on success, or error on failure.
    """
    from azure_auth_helpers import azure_rest_call
    from discovery_config_manager import DiscoveryConfigManager
    
    # Get tenant_id from config to avoid wrong-tenant authentication
    config_manager = DiscoveryConfigManager()
    azure_config = config_manager.get_azure_config()
    tenant_id = azure_config.get('tenant_id', '').strip() or None

    # Use provided tenant_id ONLY; error if missing
    if not tenant_id:
        return jsonify({
            'success': False,
            'error': 'Explicit tenant_id is required for all Azure resource operations. Please provide tenant_id in query parameters or configure it in Settings.'
        }), 400
    print(f"🔧 Using provided tenant_id {tenant_id[:8]}...")
    server_traces = []
    server_traces.append(f"🔧 Using provided tenant_id {tenant_id[:8]}...")
    # ...existing code...

    # Build the REST URL for the agent resource
    api_version = '2025-07-01-preview'
    url = (
        f"https://management.azure.com/subscriptions/{subscription_id}"
        f"/resourceGroups/{resource_group}/providers/Microsoft.Discovery/agents/{agent_name}?api-version={api_version}"
    )

    print(f"ℹ️ Fetching Azure resource: {agent_name} (subscription={subscription_id}, tenant={tenant_id[:8] if tenant_id else 'auto-detect'}...)")
    
    result = azure_rest_call(
        method='GET',
        url=url,
        subscription_id=subscription_id,
        tenant_id=tenant_id,
        server_traces=server_traces,
        timeout=60
    )
    
    # Print traces
    for trace in server_traces:
        print(trace)
    
    if result['success']:
        return {
            'success': True,
            'resource': result.get('data')
        }
    else:
        return {
            'success': False,
            'error': result.get('error'),
            'status_code': result.get('status_code')
        }


# call_llm_for_capability - now imported from llm_client module


@app.route('/api/discovery-publish/agent-capability', methods=['POST'])
def agent_capability():
    """Given subscription_id, resource_group, agent_name, return a short capabilities paragraph.

    Request JSON: { subscription_id, resource_group, agent_name }
    Response: { success: bool, capability: str }
    """
    try:
        data = request.get_json(silent=True) or {}
        subscription_id = data.get('subscription_id')
        resource_group = data.get('resource_group')
        agent_name = data.get('agent_name')

        if not subscription_id or not resource_group or not agent_name:
            return jsonify({'success': False, 'error': 'Missing required fields: subscription_id, resource_group, agent_name'}), 400

        # Support both single-agent and batch requests. If request contains 'agents' list, process in parallel.
        agents_payload = data.get('agents')

        def generate_capability_for_resource(sub_id, rg, ag_name):
            try:
                fetched = fetch_agent_resource(sub_id, rg, ag_name)
                if not fetched.get('success'):
                    return {'agent_name': ag_name, 'success': False, 'error': fetched.get('error')}

                resource = fetched.get('resource') or {}
                properties = resource.get('properties') or {}
                definition = properties.get('definitionContent') or {}

                description = ''
                instructions = ''
                if isinstance(definition, dict):
                    agent_block = definition.get('agent') or definition.get('Agent')
                    if isinstance(agent_block, dict):
                        description = agent_block.get('description') or agent_block.get('Description') or ''
                        instructions = agent_block.get('instructions') or agent_block.get('Instructions') or ''

                # Load prompt templates (once per call is fine)
                loader = get_prompt_loader()
                loader.prompts_dir = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'prompts')
                system_template = loader.load_prompt('tool-creation/agent_capabilities_system.txt')
                user_template = loader.load_prompt('tool-creation/agent_capabilities_user.txt')

                user_prompt = user_template.replace('{agent_resource_json}', description or '')
                user_prompt = user_prompt.replace('{agent_instructions}', instructions or '')

                llm_result = call_llm_for_capability(system_template, user_prompt, max_tokens=200)
                if not llm_result.get('success'):
                    return {'agent_name': ag_name, 'success': False, 'error': llm_result.get('error')}

                paragraph = llm_result.get('text', '').strip()
                words = paragraph.split()
                if len(words) > 200:
                    paragraph = ' '.join(words[:200])

                return {'agent_name': ag_name, 'success': True, 'capability': paragraph}
            except Exception as e:
                return {'agent_name': ag_name, 'success': False, 'error': str(e)}

        if isinstance(agents_payload, list):
            # Batch processing: run up to 10 workers in parallel
            max_workers = min(10, len(agents_payload)) if agents_payload else 1
            results = []
            with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as exe:
                futures = []
                for a in agents_payload:
                    sub_id = a.get('subscription_id') or subscription_id
                    rg = a.get('resource_group') or resource_group
                    ag = a.get('agent_name')
                    if not sub_id or not rg or not ag:
                        results.append({'agent_name': ag or '<missing>', 'success': False, 'error': 'Missing subscription_id/resource_group/agent_name'})
                        continue
                    futures.append(exe.submit(generate_capability_for_resource, sub_id, rg, ag))

                for f in concurrent.futures.as_completed(futures):
                    try:
                        results.append(f.result())
                    except Exception as e:
                        results.append({'agent_name': '<unknown>', 'success': False, 'error': str(e)})

            return jsonify({'success': True, 'results': results})
        else:
            # Single item processing
            single_result = generate_capability_for_resource(subscription_id, resource_group, agent_name)
            status_code = 200 if single_result.get('success') else 502
            return jsonify(single_result), status_code

    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


