# Helper function for consistent CodeSpaces authentication handling
def get_azure_token_with_codespaces_handling(tenant_id, subscription_id, purpose='azure-api'):
    """
    Get Azure token with CodeSpaces-aware error handling.
    Returns tuple: (token, error_response_or_none)
    If error_response is not None, the caller should return it immediately.
    """
    from azure_auth_helpers import get_token_for_tenant
    import os
    
    server_traces = []
    is_codespaces = os.environ.get('CODESPACES') == 'true'
    
    if is_codespaces:
        print(f"ℹ️ CodeSpaces detected - if authentication is needed for {purpose}, you'll see device code instructions")
        print("   The first request may timeout while you authenticate - just refresh after auth completes")
    
    token = get_token_for_tenant('https://management.azure.com/.default', tenant_id, server_traces, purpose=purpose)
    
    if not token:
        # In CodeSpaces with device code, provide helpful message
        if is_codespaces and any('device' in t.lower() for t in server_traces):
            error_response = jsonify({
                'success': False,
                'error': 'Authentication in progress - please complete device code authentication and refresh',
                'hint': 'Check terminal for device code instructions',
                'traces': server_traces
            }), 401
            return None, error_response
        
        # Standard error for non-CodeSpaces or other failures
        short_error = server_traces[-1] if server_traces else 'Failed to obtain token'
        print(f"❌ Failed to obtain management token for {purpose}: {short_error}")
        for trace in server_traces:
            print(f"  {trace}")
        
        error_response = jsonify({
            'success': False,
            'error': f'Failed to obtain Azure access token: {short_error}',
            'traces': server_traces
        }), 401
        return None, error_response
    
    return token, None


@app.route('/api/azure/auth-status', methods=['GET'])
def azure_auth_status():
    """Return which Azure authentication methods are usable and token claim previews.

    Useful for debugging why token acquisition is failing on a given host.
    """
    status = {
        'azure_identity_available': AZURE_IDENTITY_AVAILABLE,
        'default_credential': {'available': False, 'error': None},
        'rest_client_credentials': {'env_present': False, 'error': None},
        'token_claims': None
    }

    # Try DefaultAzureCredential (use quiet helper to avoid verbose diagnostics)
    if AZURE_IDENTITY_AVAILABLE:
        try:
            local_traces = []
            tok_str = _get_token_default_credential('https://management.azure.com/.default', local_traces, purpose='auth-status')
            if tok_str:
                status['default_credential']['available'] = True
                status['default_credential']['error'] = None
                status['token_claims'] = _safe_decode_jwt(tok_str)
            else:
                status['default_credential']['available'] = False
                status['default_credential']['error'] = local_traces[-1] if local_traces else 'DefaultAzureCredential failed'
        except Exception as e:
            status['default_credential']['available'] = False
            status['default_credential']['error'] = str(e)

    # Check REST client credentials env vars
    tenant = os.environ.get('AZURE_TENANT_ID')
    client_id = os.environ.get('AZURE_CLIENT_ID')
    client_secret = os.environ.get('AZURE_CLIENT_SECRET')
    if tenant and client_id and client_secret:
        status['rest_client_credentials']['env_present'] = True
        # Try to request a token
        try:
            token_url = f"https://login.microsoftonline.com/{tenant}/oauth2/v2.0/token"
            payload = {
                'client_id': client_id,
                'client_secret': client_secret,
                'grant_type': 'client_credentials',
                'scope': 'https://management.azure.com/.default'
            }
            resp = requests.post(token_url, data=payload, timeout=15)
            resp.raise_for_status()
            at = resp.json().get('access_token')
            if at:
                status['rest_client_credentials']['error'] = None
                if not status.get('token_claims'):
                    status['token_claims'] = _safe_decode_jwt(at)
            else:
                status['rest_client_credentials']['error'] = 'no access_token in response'
        except Exception as e:
            status['rest_client_credentials']['error'] = str(e)
    else:
        status['rest_client_credentials']['env_present'] = False

    return jsonify({'success': True, 'auth_status': status})


@app.route('/api/azure/discovery/dataassets', methods=['GET'])
def list_discovery_dataassets():
    """List data assets in a Microsoft.Discovery dataContainer.

    Query parameters:
      - tenant_id
      - subscription_id
      - resource_group
      - data_container (required)

    Returns JSON: { success: bool, dataassets: [ { name, id, properties... } ], error?: str }
    """
    try:
        tenant_id = request.args.get('tenant_id') or ''
        sub = request.args.get('subscription_id') or ''
        rg = request.args.get('resource_group') or ''
        data_container = request.args.get('data_container') or ''

        if not data_container:
            return jsonify({'success': False, 'error': 'Missing required query param: data_container'}), 400

        # If tenant, subscription or rg weren't passed, try to use discovery config
        try:
            cfg = None
            if DISCOVERY_AVAILABLE and config_manager:
                cfg = config_manager.get_azure_config()
        except Exception:
            cfg = None

        if not tenant_id:
            tenant_id = cfg.get('tenant_id') if isinstance(cfg, dict) else tenant_id
        if not sub:
            sub = cfg.get('subscription_id') if isinstance(cfg, dict) else sub
        if not rg:
            rg = cfg.get('resource_group') if isinstance(cfg, dict) else rg

        if not tenant_id or not sub or not rg:
            return jsonify({'success': False, 'error': 'tenant_id, subscription_id and resource_group are required (or configure in Settings)'}), 400

        # Acquire management token with tenant-specific authentication
        from azure_auth_helpers import get_token_for_tenant
        server_traces = []
        token = get_token_for_tenant('https://management.azure.com/.default', tenant_id, server_traces, purpose='list-dataassets')
        if not token:
            return jsonify({'success': False, 'error': 'Failed to obtain management token for data assets', 'traces': server_traces}), 401

        api_version = '2025-07-01-preview'
        url = f"https://management.azure.com/subscriptions/{sub}/resourceGroups/{rg}/providers/Microsoft.Discovery/dataContainers/{data_container}/dataAssets?api-version={api_version}"

        print(f"🔍 Fetching data assets from: {url}")
        headers = { 'Authorization': f'Bearer {token}' }
        resp = requests.get(url, headers=headers, timeout=20)

        if resp.status_code != 200:
            # Try to provide helpful error info
            try:
                body = resp.json()
            except Exception:
                body = resp.text
            print(f"❌ Azure API error {resp.status_code}: {body}")
            return jsonify({'success': False, 'error': f'Management API returned {resp.status_code}', 'body': body}), 502

        body = resp.json()
        # Normalize list of data assets
        assets = []
        try:
            values = body.get('value') if isinstance(body, dict) else []
            for it in values or []:
                assets.append({'id': it.get('id'), 'name': it.get('name'), 'properties': it.get('properties', {})})
        except Exception:
            # Fallback: return whole body if unexpected shape
            return jsonify({'success': True, 'dataassets': body})

        return jsonify({'success': True, 'dataassets': assets})

    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


