@app.route('/api/azure/discovery/dataasset-files', methods=['GET'])
def list_dataasset_files():
    """List files in a Microsoft.Discovery dataAsset by querying the blob storage.

    Query params:
      - tenant_id (required)
      - subscription_id
      - resource_group
      - data_container (required)
      - data_asset (required)

    Returns JSON: { success: bool, files: [ filenames ], error?: str }
    """
    try:
        tenant_id = request.args.get('tenant_id') or ''
        sub = request.args.get('subscription_id') or ''
        rg = request.args.get('resource_group') or ''
        data_container = request.args.get('data_container') or ''
        data_asset = request.args.get('data_asset') or ''
        
        print(f"🔍 list_dataasset_files: tenant_id={tenant_id}, sub={sub[:8] if sub else 'None'}..., rg={rg}, container={data_container}, asset={data_asset}")

        if not data_container or not data_asset:
            return jsonify({'success': False, 'error': 'Missing required query params: data_container and data_asset'}), 400
        
        if not tenant_id or tenant_id == 'undefined':
            return jsonify({'success': False, 'error': 'Missing or invalid tenant_id. Please configure Azure tenant in settings.'}), 400

        # Try discovery config fallback
        try:
            cfg = None
            if DISCOVERY_AVAILABLE and config_manager:
                cfg = config_manager.get_azure_config()
        except Exception:
            cfg = None

        if not sub:
            sub = cfg.get('subscription_id') if isinstance(cfg, dict) else sub
        if not rg:
            rg = cfg.get('resource_group') if isinstance(cfg, dict) else rg

        if not sub or not rg:
            return jsonify({'success': False, 'error': 'subscription_id and resource_group are required (or configure in Settings)'}), 400

        # Acquire management token for the specific tenant
        from azure_auth_helpers import get_token_for_tenant
        server_traces = []
        token = get_token_for_tenant(
            scope='https://management.azure.com/.default',
            tenant_id=tenant_id,
            server_traces=server_traces,
            purpose='list-dataasset-files'
        )
        if not token:
            return jsonify({'success': False, 'error': 'Failed to obtain management token for tenant', 'traces': server_traces}), 401

        api_version = '2025-07-01-preview'
        
        # Get the data asset details to find the path
        asset_url = f"https://management.azure.com/subscriptions/{sub}/resourceGroups/{rg}/providers/Microsoft.Discovery/dataContainers/{data_container}/dataAssets/{data_asset}?api-version={api_version}"
        headers = { 'Authorization': f'Bearer {token}' }
        asset_resp = requests.get(asset_url, headers=headers, timeout=20)

        if asset_resp.status_code != 200:
            try:
                body = asset_resp.json()
            except Exception:
                body = asset_resp.text
            return jsonify({'success': False, 'error': f'Failed to get data asset: {asset_resp.status_code}', 'body': body}), 502

        asset_data = asset_resp.json()
        asset_path = asset_data.get('properties', {}).get('path', '')
        
        print(f"📁 Data asset path: {asset_path}")
        
        if not asset_path:
            return jsonify({'success': False, 'error': 'Data asset has no path property'}), 400

        # Get the data container to find storage account
        container_url = f"https://management.azure.com/subscriptions/{sub}/resourceGroups/{rg}/providers/Microsoft.Discovery/dataContainers/{data_container}?api-version={api_version}"
        container_resp = requests.get(container_url, headers=headers, timeout=20)

        if container_resp.status_code != 200:
            return jsonify({'success': False, 'error': f'Failed to get data container: {container_resp.status_code}'}), 502

        container_data = container_resp.json()
        storage_account_id = container_data.get('properties', {}).get('dataStore', {}).get('storageAccountId', '')
        
        print(f"💾 Storage account ID: {storage_account_id}")
        
        if not storage_account_id:
            return jsonify({'success': False, 'error': 'Data container has no storage account'}), 400

        # Extract storage account name from resource ID
        # Format: /subscriptions/{sub}/resourceGroups/{rg}/providers/Microsoft.Storage/storageAccounts/{name}
        storage_account_name = storage_account_id.split('/')[-1]
        
        print(f"📦 Storage account name: {storage_account_name}")
        
        # Use Azure Storage Blob SDK to list blobs
        if not AZURE_IDENTITY_AVAILABLE:
            return jsonify({'success': False, 'error': 'Azure Identity SDK not available'}), 500

        try:
            from azure.storage.blob import BlobServiceClient
            
            # Get tenant-aware credential for blob storage access
            from azure_auth_helpers import get_credential_for_tenant
            storage_credential = get_credential_for_tenant(tenant_id, purpose='blob-list-files')
            if not storage_credential:
                return jsonify({'success': False, 'error': 'Failed to obtain storage credential'}), 401
            
            blob_service_client = BlobServiceClient(
                account_url=f"https://{storage_account_name}.blob.core.windows.net",
                credential=storage_credential
            )
            
            # Parse container and prefix from path (format: "container-name/prefix/" or "container-name/folder/")
            # If path points to a file, extract just the folder prefix
            original_path_is_dir = asset_path.rstrip('/') != asset_path.rstrip('/')[:len(asset_path.rstrip('/'))] or asset_path.endswith('/')
            path_parts = asset_path.strip('/').split('/', 1)
            if len(path_parts) < 2:
                container_name = path_parts[0] if path_parts else 'discovery-studio'
                prefix = ''
            else:
                container_name = path_parts[0]
                remaining_path = path_parts[1]
                
                # If the original path ended with /, it's a directory - use full remaining path
                if asset_path.endswith('/'):
                    prefix = remaining_path + '/' if not remaining_path.endswith('/') else remaining_path
                elif '/' in remaining_path:
                    # Path points to a file - extract directory prefix
                    prefix = remaining_path.rsplit('/', 1)[0] + '/'
                else:
                    # No subdirectories - list everything in the container
                    prefix = ''
            
            container_client = blob_service_client.get_container_client(container_name)
            
            # List blobs with the prefix
            print(f"🔍 Listing blobs in container '{container_name}' with prefix '{prefix}'")
            blobs = container_client.list_blobs(name_starts_with=prefix)
            files = []
            
            for blob in blobs:
                # Get just the filename (remove prefix)
                filename = blob.name
                if prefix and filename.startswith(prefix):
                    filename = filename[len(prefix):]
                # Skip if it's just a folder marker
                if filename and not filename.endswith('/'):
                    files.append(filename.lstrip('/'))
            
            return jsonify({'success': True, 'files': files})
            
        except Exception as blob_error:
            print(f"❌ Blob storage error: {str(blob_error)}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': f'Failed to list blobs: {str(blob_error)}'}), 500

    except Exception as e:
        print(f"❌ Error in list_dataasset_files: {str(e)}")
        import traceback
        traceback.print_exc()
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/azure/discovery/upload-to-dataasset', methods=['POST'])
def upload_to_dataasset():
    """Upload files to a data asset's blob storage location"""
    try:
        if 'file' not in request.files:
            return jsonify({'success': False, 'error': 'No file provided'}), 400
        
        file = request.files['file']
        if file.filename == '':
            return jsonify({'success': False, 'error': 'No file selected'}), 400
        
        tenant_id = request.form.get('tenant_id')
        sub = request.form.get('subscription_id')
        rg = request.form.get('resource_group')
        data_container = request.form.get('data_container')
        data_asset = request.form.get('data_asset')

        if not all([tenant_id, sub, rg, data_container, data_asset]):
            return jsonify({'success': False, 'error': 'Missing required parameters'}), 400

        # Acquire management token for the specific tenant
        from azure_auth_helpers import get_token_for_tenant
        server_traces = []
        token = get_token_for_tenant(
            scope='https://management.azure.com/.default',
            tenant_id=tenant_id,
            server_traces=server_traces,
            purpose='upload-to-dataasset'
        )
        if not token:
            return jsonify({'success': False, 'error': 'Failed to obtain Azure token', 'traces': server_traces}), 401

        headers = {
            'Authorization': f'Bearer {token}',
        }

        api_version = '2025-07-01-preview'

        # Get the data asset to find the path
        asset_url = f"https://management.azure.com/subscriptions/{sub}/resourceGroups/{rg}/providers/Microsoft.Discovery/dataContainers/{data_container}/dataAssets/{data_asset}?api-version={api_version}"
        asset_resp = requests.get(asset_url, headers=headers, timeout=20)

        if asset_resp.status_code != 200:
            return jsonify({'success': False, 'error': f'Failed to get data asset: {asset_resp.status_code}'}), 502

        asset_data = asset_resp.json()
        asset_path = asset_data.get('properties', {}).get('path', '')
        
        if not asset_path:
            return jsonify({'success': False, 'error': 'Data asset has no path property'}), 400

        # Get the data container to find storage account
        container_url = f"https://management.azure.com/subscriptions/{sub}/resourceGroups/{rg}/providers/Microsoft.Discovery/dataContainers/{data_container}?api-version={api_version}"
        container_resp = requests.get(container_url, headers=headers, timeout=20)

        if container_resp.status_code != 200:
            return jsonify({'success': False, 'error': f'Failed to get data container: {container_resp.status_code}'}), 502

        container_data = container_resp.json()
        storage_account_id = container_data.get('properties', {}).get('dataStore', {}).get('storageAccountId', '')
        
        if not storage_account_id:
            return jsonify({'success': False, 'error': 'Data container has no storage account'}), 400

        # Extract storage account name
        storage_account_name = storage_account_id.split('/')[-1]
        
        # Use Azure Storage Blob SDK to upload
        if not AZURE_IDENTITY_AVAILABLE:
            return jsonify({'success': False, 'error': 'Azure Identity SDK not available'}), 500

        try:
            from azure.storage.blob import BlobServiceClient
            
            # Get tenant-aware credential for blob storage access
            from azure_auth_helpers import get_credential_for_tenant
            storage_credential = get_credential_for_tenant(tenant_id, purpose='blob-upload')
            if not storage_credential:
                return jsonify({'success': False, 'error': 'Failed to obtain storage credential'}), 401
            
            blob_service_client = BlobServiceClient(
                account_url=f"https://{storage_account_name}.blob.core.windows.net",
                credential=storage_credential
            )
            
            # Parse container and prefix from path (same logic as list)
            path_parts = asset_path.strip('/').split('/', 1)
            if len(path_parts) < 2:
                container_name = path_parts[0] if path_parts else 'discovery-studio'
                prefix = ''
            else:
                container_name = path_parts[0]
                remaining_path = path_parts[1]
                
                # If path ends with a file extension, treat it as pointing to a folder
                if '/' in remaining_path:
                    # Has subdirectories - use the directory path only
                    prefix = remaining_path.rsplit('/', 1)[0] + '/'
                else:
                    # No subdirectories - list everything in the container
                    prefix = ''
            
            # Build the full blob name
            blob_name = f"{prefix}{file.filename}" if prefix else file.filename
            blob_name = blob_name.lstrip('/')
            
            print(f"⬆️ Uploading blob: container='{container_name}', blob='{blob_name}'")
            
            # Upload the file
            blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
            blob_client.upload_blob(file.stream, overwrite=True)
            
            print(f"✅ Successfully uploaded blob: {blob_name}")
            return jsonify({'success': True, 'message': f'Successfully uploaded {file.filename}', 'blob_name': blob_name})
            
        except Exception as upload_error:
            print(f"❌ Upload error: {str(upload_error)}")
            import traceback
            traceback.print_exc()
            return jsonify({'success': False, 'error': f'Failed to upload file: {str(upload_error)}'}), 500

    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


