# Discovery Docs Retriever (with persistent index and hybrid search)
# ─────────────────────────────────────────────────────────────────────────────


def _get_discovery_retriever():
    """Get or create the retriever with persistent index."""
    global _discovery_retriever_cache
    if _discovery_retriever_cache is not None:
        return _discovery_retriever_cache

    try:
        from discovery_docs_retriever import DiscoveryRetriever

        settings = _get_discovery_assistant_settings()
        base_dir = os.path.dirname(os.path.abspath(__file__))
        docs_path = os.path.join(base_dir, 'prompts', 'combined-discovery-docs.md')

        # Prepare embedding function if configured
        embedding_fn = None
        if settings.get('use_embeddings_rerank'):
            emb_dep = (settings.get('embeddings_deployment_name') or '').strip()
            emb_ver = (settings.get('embeddings_api_version') or '').strip()
            if emb_dep:
                embedding_fn = _make_embedding_fn(emb_dep, emb_ver, settings)

        # Prepare LLM rerank function if configured
        llm_rerank_fn = None
        if settings.get('use_llm_rerank') and llm_available():
            llm_rerank_fn = _make_llm_fn_for_rerank()

        retriever = DiscoveryRetriever(
            docs_path=docs_path,
            index_dir=os.path.join(base_dir, 'prompts', '.retrieval_index'),
            embedding_fn=embedding_fn,
            llm_rerank_fn=llm_rerank_fn,
            chunk_target_tokens=settings.get('chunk_token_target', 700),
            chunk_overlap_tokens=settings.get('chunk_token_overlap', 100),
            use_embeddings=settings.get('use_embeddings_rerank', False),
            use_llm_rerank=settings.get('use_llm_rerank', False),
        )

        _discovery_retriever_cache = retriever
        print(f"[OK] Retriever initialized: {retriever.chunk_count} chunks")
    except Exception as e:
        print(f"[WARN] Retriever init failed: {e}")
        import traceback
        traceback.print_exc()
        _discovery_retriever_cache = e

    return _discovery_retriever_cache


def _make_embedding_fn(deployment: str, api_version: str, settings: dict):
    """Create an embedding function for the v2 retriever."""
    def get_embeddings(texts):
        try:
            if not texts:
                return []
            cfg = config_manager.get_azure_openai_config() if config_manager else {}
            endpoint = (cfg.get('endpoint_url') or '').rstrip('/')
            if not endpoint:
                return None
            version = api_version or (cfg.get('api_version') or '2024-02-15-preview')
            url = f"{endpoint}/openai/deployments/{deployment}/embeddings?api-version={version}"
            headers = get_auth_headers()
            payload = {"input": texts}
            r = requests.post(url, headers=headers, json=payload, timeout=60)
            if r.status_code != 200:
                if settings.get('debug_retrieval'):
                    print(f"🔎 Embeddings call failed: status={r.status_code}")
                return None
            data = r.json() or {}
            rows = data.get('data') or []
            out = []
            for row in rows:
                emb = row.get('embedding')
                if isinstance(emb, list) and emb:
                    out.append(emb)
                else:
                    out.append([])
            return out
        except Exception as e:
            if settings.get('debug_retrieval'):
                print(f"🔎 Embeddings error: {e}")
            return None
    return get_embeddings


def _make_llm_fn_for_rerank():
    """Create an LLM function for the v2 retriever's reranking."""
    def llm_fn(system_prompt: str, user_prompt: str) -> str:
        try:
            resp = call_azure_openai_direct(
                messages=[
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": user_prompt},
                ],
                max_output_tokens=256,
                temperature=0.0,
                tools=None,
            )
            text = (((resp or {}).get("choices") or [{}])[0].get("message") or {}).get("content") or ""
            return text
        except Exception as e:
            print(f"⚠️ LLM rerank call failed: {e}")
            return ""
    return llm_fn


def _refresh_input_files_context(messages):
    """Refresh the input files listing in the system message before each API call.

    This ensures the LLM always sees the current state of the input folder,
    even if files were added/modified/removed after the session started.

    Args:
        messages: List of messages in OpenAI format

    Returns:
        Updated messages list with refreshed input file context
    """
    if not messages:
        return messages

    # Check if the current agent is a Docker/tool agent (not a KB agent)
    # Check agent type from multiple sources for robustness
    current_agent_type = None
    current_agent_name = None

    # Method 1: Check session (most reliable when set)
    sm = get_session_manager()
    if sm and sm.current_session_id:
        session = sm.get_session(sm.current_session_id)
        if session:
            current_agent_type = session.agent_type
            current_agent_name = session.agent_name

    # Method 2: If session doesn't have type, check agent_manager paths
    if not current_agent_type and current_agent_name and agent_manager:
        try:
            agent_paths = agent_manager.get_agent_paths(current_agent_name)
            if agent_paths:
                current_agent_type = agent_paths.get('type')
        except Exception:
            pass

    is_tool_agent = (current_agent_type == 'tool')

    # Only refresh for tool agents (Docker-based) since they use the input folder
    if not is_tool_agent:
        return messages

    # Get fresh input files context
    try:
        fresh_context = get_docker_data_handling_context()
    except Exception as e:
        print(f"⚠️ Failed to refresh input files context: {e}")
        return messages

    # Find and update the system message
    updated_messages = list(messages)
    for i, msg in enumerate(updated_messages):
        if msg.get('role') == 'system':
            content = msg.get('content', '')

            # Look for the data handling context section
            # Uses reliable markers: start marker and end marker (HTML comment)
            dir_paths_marker = "## Directory Paths (CRITICAL - Use these exact paths):"
            end_marker = "<!-- END_DATA_HANDLING_CONTEXT -->"
            # Fallback marker for when initial context was empty or used builtin tools context
            fallback_marker = "Data handling context:"

            if dir_paths_marker in content:
                # Find where the data handling context starts
                start_idx = content.find(dir_paths_marker)

                # Find where it ends using the end marker (most reliable)
                end_marker_pos = content.find(end_marker, start_idx)
                if end_marker_pos != -1:
                    # Include the end marker in what we replace
                    end_idx = end_marker_pos + len(end_marker)
                else:
                    # Fallback: end at next major section or end of content
                    # This handles prompts that were created before the end marker was added
                    end_idx = len(content)
                    next_sections = ["\n\n## CRITICAL:", "\n\n## AVAILABLE TOOL ACTIONS", "\n\n## Supplementary File Operations"]
                    for section_marker in next_sections:
                        next_section_pos = content.find(section_marker, start_idx + len(dir_paths_marker))
                        if next_section_pos != -1 and next_section_pos < end_idx:
                            end_idx = next_section_pos

                # Replace the old context with fresh context
                updated_content = content[:start_idx] + fresh_context + content[end_idx:]
                updated_messages[i] = {**msg, 'content': updated_content}
                print(f"🔄 Refreshed input files context in system message")
                break

            elif fallback_marker in content:
                # Initial context was empty or had builtin tools context - inject Docker context
                start_idx = content.find(fallback_marker)
                # The fallback_marker line ends with newlines, then possibly "## Supplementary File Operations"
                # We want to insert Docker context right after "Data handling context:"
                # and before "## Supplementary File Operations" if present

                # Find the end of "Data handling context:" section
                search_start = start_idx + len(fallback_marker)
                end_idx = len(content)

                # Look for next major section markers
                next_sections = ["\n\n## CRITICAL:", "\n\n## AVAILABLE TOOL ACTIONS", "\n\n## Supplementary File Operations"]
                for section_marker in next_sections:
                    next_section_pos = content.find(section_marker, search_start)
                    if next_section_pos != -1 and next_section_pos < end_idx:
                        end_idx = next_section_pos

                # Insert the fresh Docker context after "Data handling context:"
                # Replace any existing content between the marker and next section
                updated_content = content[:search_start] + "\n" + fresh_context + content[end_idx:]
                updated_messages[i] = {**msg, 'content': updated_content}
                print(f"🔄 Injected Docker data handling context (was missing/empty)")
                break

    return updated_messages


def _inject_discovery_docs_context(messages, user_query: str):
    """Inject retrieved Discovery documentation context into messages."""
    settings = _get_discovery_assistant_settings()
    if settings.get('docs_mode') != 'retrieval':
        return messages

    retriever = _get_discovery_retriever()
    if isinstance(retriever, Exception):
        print(f"[WARN] Retriever unavailable: {retriever}")
        return messages

    try:
        from discovery_docs_retriever import build_context_block
    except Exception as e:
        print(f"[WARN] Could not import retriever: {e}")
        return messages

    # Token counting
    def _count(text: str) -> int:
        try:
            return conversation_manager.count_tokens(text) if conversation_manager else len(text) // 4
        except Exception:
            return len(text) // 4

    # Estimate remaining context budget
    try:
        conv_cfg = config_manager.get_conversation_config() if config_manager else {}
        safety_fraction = float(conv_cfg.get('safety_fraction', 0.85)) if isinstance(conv_cfg, dict) else 0.85
    except Exception:
        safety_fraction = 0.85

    existing_tokens = 0
    for m in messages or []:
        try:
            existing_tokens += _count(m.get('content', '') or '')
        except Exception:
            pass

    max_context = int((conversation_manager.max_tokens if conversation_manager else 64000) * safety_fraction)
    remaining = max_context - existing_tokens - 500

    frac = float(settings.get('docs_context_fraction', 0.2) or 0.0)
    frac = max(0.0, min(1.0, frac))
    docs_cap = int(max_context * frac)

    budget = min(docs_cap, max(0, remaining))
    if budget <= 0:
        return messages

    # Retrieve and build context
    top_k = int(settings.get('docs_top_k', 12))
    top_k = max(1, min(25, top_k))
    rerank_candidates = int(settings.get('bm25_candidates', 64))

    results = retriever.retrieve(user_query, top_k=top_k, rerank_candidates=rerank_candidates)

    context_block = build_context_block(results, token_budget=budget, token_counter=_count)
    if not context_block:
        return messages

    if settings.get('debug_retrieval'):
        try:
            titles = [r.chunk.title_path for r in results[:5]]
            print(f"[DEBUG] Docs injected (budget={budget}) titles={titles}")
        except Exception:
            print(f"[DEBUG] Docs injected (budget={budget})")

    injected = list(messages or [])
    system_msg = {"role": "system", "content": context_block}
    if injected and injected[0].get('role') == 'system':
        injected.insert(1, system_msg)
    else:
        injected.insert(0, system_msg)
    return injected


@app.route('/api/prompts/notepad', methods=['GET'])
def get_notepad():
    """Return the content of prompts/notepad.md (create if missing)."""
    try:
        base_dir = os.path.dirname(os.path.abspath(__file__))
        prompts_dir = os.path.join(base_dir, 'prompts')
        if not os.path.exists(prompts_dir):
            os.makedirs(prompts_dir, exist_ok=True)
        notepad_path = os.path.join(prompts_dir, 'notepad.md')
        if not os.path.exists(notepad_path):
            # create an empty file with brief header
            with open(notepad_path, 'w', encoding='utf-8') as f:
                f.write('# Discovery Notepad\n\n')
        with open(notepad_path, 'r', encoding='utf-8') as f:
            content = f.read()
        return jsonify({'success': True, 'content': content})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/prompts/notepad', methods=['PUT'])
def put_notepad():
    """Save content to prompts/notepad.md. Expects JSON { content: '...' }"""
    try:
        data = request.get_json(silent=True) or {}
        content = data.get('content')
        if content is None:
            return jsonify({'success': False, 'error': 'Missing content field'}), 400
        base_dir = os.path.dirname(os.path.abspath(__file__))
        prompts_dir = os.path.join(base_dir, 'prompts')
        if not os.path.exists(prompts_dir):
            os.makedirs(prompts_dir, exist_ok=True)
        notepad_path = os.path.join(prompts_dir, 'notepad.md')
        tmp_path = notepad_path + '.tmp'
        with open(tmp_path, 'w', encoding='utf-8') as f:
            f.write(content)
        os.replace(tmp_path, notepad_path)
        return jsonify({'success': True})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500

# Initialize globals and Agent Manager (do this regardless of Docker availability)
docker_client = None
agent_name = ""
CONTAINER_NAME = "unknown-container"
conversation_manager = None
session_manager = None  # Multi-session manager instance

# Track active docker build subprocesses so the UI "Cancel" button can actually stop work.
# Keyed by agent_name; only one active build per agent is supported.
# Value shape: { proc: Popen, cmd: list[str], started_at: float, output_lines: list, reader_thread: Thread }
ACTIVE_DOCKER_BUILD_PROCS = {}
ACTIVE_DOCKER_BUILD_LOCK = threading.Lock()

# Shared build output storage - continuously updated by background threads even when SSE disconnects
# Keyed by (session_id, agent_name) tuple; value shape: { lines: list[str], last_saved_count: int, last_save_time: float, session_id: str }
ACTIVE_BUILD_OUTPUT = {}
ACTIVE_BUILD_OUTPUT_LOCK = threading.Lock()

# Track active ACR deployments so the same Cancel button can stop docker push/tag during publish.
# Keyed by agent_name; one active deployment per agent.
# Value shape: { cancel_event: threading.Event, started_at: float, tenant_id: str|None, acr_name: str|None, image: str|None }
ACTIVE_ACR_DEPLOYMENTS = {}
ACTIVE_ACR_DEPLOY_LOCK = threading.Lock()


def _get_active_deploy_record(agent_name: str):
    with ACTIVE_ACR_DEPLOY_LOCK:
        return ACTIVE_ACR_DEPLOYMENTS.get(agent_name)


def _set_active_deploy_record(agent_name: str, record: dict) -> None:
    with ACTIVE_ACR_DEPLOY_LOCK:
        ACTIVE_ACR_DEPLOYMENTS[agent_name] = record


def _clear_active_deploy_record(agent_name: str, expected_event: Optional[threading.Event] = None) -> None:
    with ACTIVE_ACR_DEPLOY_LOCK:
        rec = ACTIVE_ACR_DEPLOYMENTS.get(agent_name)
        if not rec:
            return
        if expected_event is not None and rec.get('cancel_event') is not expected_event:
            return
        ACTIVE_ACR_DEPLOYMENTS.pop(agent_name, None)


def _popen_docker_build(cmd: list[str]) -> subprocess.Popen:
    """Start docker build command in its own process group/session for reliable cancellation."""
    kwargs = {
        'stdout': subprocess.PIPE,
        'stderr': subprocess.STDOUT,
        'text': True,
        'bufsize': 1,
        'encoding': 'utf-8',
        'errors': 'replace'
    }
    if os.name == 'nt':
        # CREATE_NEW_PROCESS_GROUP allows taskkill /T to kill child processes as well.
        kwargs['creationflags'] = subprocess.CREATE_NEW_PROCESS_GROUP
    else:
        # start_new_session creates a new process group so we can killpg.
        kwargs['start_new_session'] = True
    return subprocess.Popen(cmd, **kwargs)


def _kill_process_tree(proc: subprocess.Popen) -> None:
    """Best-effort termination of a running subprocess and its children."""
    try:
        if proc.poll() is not None:
            return
    except Exception:
        return

    # Prefer platform-native tree termination
    try:
        if os.name == 'nt':
            subprocess.run(
                ["taskkill", "/PID", str(proc.pid), "/T", "/F"],
                capture_output=True,
                text=True,
                encoding='utf-8',
                errors='replace'
            )
        else:
            try:
                os.killpg(os.getpgid(proc.pid), signal.SIGTERM)
            except Exception:
                proc.terminate()
    except Exception:
        # Fallback to terminate/kill
        try:
            proc.terminate()
        except Exception:
            pass

    # Ensure it actually stops
    try:
        proc.wait(timeout=5)
    except Exception:
        try:
            proc.kill()
        except Exception:
            pass


def _get_active_build_record(agent_name: str):
    with ACTIVE_DOCKER_BUILD_LOCK:
        return ACTIVE_DOCKER_BUILD_PROCS.get(agent_name)


def _clear_active_build_record(agent_name: str, expected_proc: Optional[subprocess.Popen] = None) -> None:
    with ACTIVE_DOCKER_BUILD_LOCK:
        rec = ACTIVE_DOCKER_BUILD_PROCS.get(agent_name)
        if not rec:
            return
        if expected_proc is not None and rec.get('proc') is not expected_proc:
            return
        ACTIVE_DOCKER_BUILD_PROCS.pop(agent_name, None)


def _init_build_output(agent_name: str, session_id: str = None) -> None:
    """Initialize build output buffer for an agent in a specific session."""
    with ACTIVE_BUILD_OUTPUT_LOCK:
        key = (session_id, agent_name)
        ACTIVE_BUILD_OUTPUT[key] = {
            'lines': [],
            'last_saved_count': 0,
            'last_save_time': time.time(),
            'session_id': session_id
        }


def _append_build_output(agent_name: str, line: str, session_id: str = None) -> None:
    """Append a line to the build output buffer and periodically save to disk."""
    with ACTIVE_BUILD_OUTPUT_LOCK:
        key = (session_id, agent_name)
        if key not in ACTIVE_BUILD_OUTPUT:
            ACTIVE_BUILD_OUTPUT[key] = {
                'lines': [],
                'last_saved_count': 0,
                'last_save_time': time.time(),
                'session_id': session_id
            }
        buf = ACTIVE_BUILD_OUTPUT[key]
        buf['lines'].append(line)

        # Save to disk periodically (every 2 seconds or every 10 new lines)
        current_time = time.time()
        lines_since_save = len(buf['lines']) - buf['last_saved_count']
        time_since_save = current_time - buf['last_save_time']

        if lines_since_save >= 10 or time_since_save >= 2:
            try:
                _save_build_output(agent_name, buf['lines'], success=False, session_id=session_id)
                buf['last_saved_count'] = len(buf['lines'])
                buf['last_save_time'] = current_time
            except Exception:
                pass  # Don't let save failures interrupt the build


def _get_build_output_lines(agent_name: str, session_id: str = None) -> list:
    """Get current build output lines for an agent in a specific session."""
    with ACTIVE_BUILD_OUTPUT_LOCK:
        key = (session_id, agent_name)
        buf = ACTIVE_BUILD_OUTPUT.get(key)
        if buf:
            return list(buf['lines'])  # Return a copy
        return []


def _clear_build_output(agent_name: str, session_id: str = None) -> None:
    """Clear build output buffer for an agent in a specific session."""
    with ACTIVE_BUILD_OUTPUT_LOCK:
        key = (session_id, agent_name)
        ACTIVE_BUILD_OUTPUT.pop(key, None)


def _start_build_output_reader(agent_name: str, proc: subprocess.Popen, build_op=None, session_id: str = None) -> threading.Thread:
    """Start a background thread to read build output from subprocess.

    This thread continues reading even if the SSE client disconnects.
    """
    def reader_thread():
        try:
            assert proc.stdout is not None
            # Use readline() instead of iterating over stdout to avoid 8KB read-ahead buffering
            while True:
                line = proc.stdout.readline()
                if not line:
                    break
                line = line.rstrip()
                if line:
                    _append_build_output(agent_name, line, session_id=session_id)
                    # Update operation with meaningful build progress
                    if build_op:
                        line_lower = line.lower()
                        if line.startswith('Step ') or line.startswith('#') or any(kw in line_lower for kw in ['exporting', 'writing image', 'naming to', 'successfully built', 'successfully tagged']):
                            try:
                                step_msg = line[:80] + '...' if len(line) > 80 else line
                                build_op.step(step_msg)
                            except Exception:
                                pass
        except Exception as e:
            _append_build_output(agent_name, f"⚠️ Output reader error: {e}", session_id=session_id)
        finally:
            # Wait for process to fully complete
            try:
                proc.wait(timeout=5)
            except Exception:
                pass

            # Final save when build completes
            lines = _get_build_output_lines(agent_name, session_id=session_id)
            rc = proc.poll()
            success = (rc == 0) if rc is not None else False

            if lines:
                try:
                    _save_build_output(agent_name, lines, success=success, session_id=session_id)
                except Exception:
                    pass

            # Add final status message if client might reconnect
            if rc is not None:
                if rc == 0:
                    _append_build_output(agent_name, f"✅ Build completed successfully", session_id=session_id)
                else:
                    _append_build_output(agent_name, f"❌ Build failed with exit code {rc}", session_id=session_id)

    thread = threading.Thread(target=reader_thread, daemon=True)
    thread.start()
    return thread


def _save_build_output(agent_name: str, build_lines: list, success: bool = True, session_id: str = None) -> None:
    """Persist build output to the session's state directory for restoration.

    Args:
        agent_name: The name of the agent being built
        build_lines: List of build output lines
        success: Whether the build was successful
        session_id: The session ID to save output for (required for proper isolation)
    """
    try:
        sm = get_session_manager()
        # Use explicit session_id to avoid relying on current_session_id
        session_dirs = sm.get_session_dirs(session_id=session_id, agent_name=agent_name)
        state_dir = session_dirs['state']

        os.makedirs(state_dir, exist_ok=True)
        build_file = os.path.join(state_dir, 'build_output.json')
        build_data = {
            'agent_name': agent_name,
            'session_id': session_id,
            'output': '\n'.join(build_lines),
            'success': success,
            'timestamp': time.time()
        }
        with open(build_file, 'w', encoding='utf-8') as f:
            json.dump(build_data, f)
    except Exception as save_err:
        print(f"⚠️ Warning: Could not save build output to file: {save_err}")


