# Helper: try docker buildx path (kept at module level)
def _try_build_with_buildx(dockerfile_path, image_name, platform='linux/amd64', stream_fn=None):
    try:
        # Verify buildx is available
        bx = subprocess.run(["docker", "buildx", "version"], capture_output=True, text=True,
                            encoding='utf-8', errors='replace')
        if bx.returncode != 0:
            if stream_fn:
                stream_fn("   ⚠️  docker buildx not available; falling back to classic build")
            return False, "buildx not available"

        # Build command
        context_dir = os.path.dirname(dockerfile_path)
        dockerfile_name = os.path.basename(dockerfile_path)
        cmd = [
            "docker", "buildx", "build",
            "--platform", platform,
            "-t", image_name,
            "-f", dockerfile_path,
            "--load",
            context_dir
        ]
        if stream_fn:
            stream_fn(f"   🧱 Using buildx: {' '.join(cmd)}")
        proc = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
                               text=True, bufsize=1, encoding='utf-8', errors='replace')
        assert proc.stdout is not None
        # Use readline() instead of iterating over stdout to avoid 8KB read-ahead buffering
        while True:
            line = proc.stdout.readline()
            if not line:
                break
            line = line.rstrip()
            if line and stream_fn:
                stream_fn(f"      {line}")
        rc = proc.wait()
        if rc != 0:
            return False, f"buildx exited with code {rc}"
        return True, None
    except Exception as e:
        return False, str(e)

