# ============================================================================
# Azure CLI Detection for Cloud Builds
# ============================================================================
# Cloud builds require the Azure CLI to be installed and authenticated.
# This is an optional feature - the application will continue to work without it.

AZ_CLI_AVAILABLE = False
AZ_CLI_AUTHENTICATED = False
AZ_CLI_SUBSCRIPTION_NAME = None

def check_azure_cli_availability():
    """Check if Azure CLI is installed and authenticated (non-blocking).

    Cloud builds using Azure Container Registry (ACR) require:
    1. Azure CLI installed (az command available in PATH)
    2. User authenticated via 'az login'
    3. ACR configured in application settings

    This check runs at startup and stores results for UI consumption.
    """
    global AZ_CLI_AVAILABLE, AZ_CLI_AUTHENTICATED, AZ_CLI_SUBSCRIPTION_NAME

    # Check if az is in PATH
    if not shutil.which("az"):
        print("")
        print("ℹ️  Azure CLI not found - Cloud build feature will be disabled")
        print("   Cloud builds allow building Docker images in Azure instead of locally.")
        print("   To enable cloud builds:")
        if sys.platform == 'win32':
            print("     1. Install Azure CLI: winget install Microsoft.AzureCLI")
        elif sys.platform == 'darwin':
            print("     1. Install Azure CLI: brew install azure-cli")
        else:
            print("     1. Install Azure CLI: curl -sL https://aka.ms/InstallAzureCLIDeb | sudo bash")
        print("     2. Authenticate: az login")
        print("     3. Configure ACR in Settings > Azure")
        print("")
        return

    AZ_CLI_AVAILABLE = True
    print("✅ Azure CLI found in PATH")

    # Check if authenticated
    # On Windows, we need shell=True for proper command execution
    try:
        is_windows = sys.platform == 'win32'
        cmd = "az account show --output json" if is_windows else ["az", "account", "show", "--output", "json"]
        result = subprocess.run(
            cmd,
            capture_output=True, text=True, timeout=15,
            shell=is_windows
        )
        if result.returncode == 0:
            AZ_CLI_AUTHENTICATED = True
            try:
                account = json.loads(result.stdout)
                AZ_CLI_SUBSCRIPTION_NAME = account.get('name', 'Unknown')
                print(f"✅ Azure CLI authenticated (subscription: {AZ_CLI_SUBSCRIPTION_NAME})")
                print("   Cloud builds are available - toggle 'Build in Azure' when building Docker images")
            except json.JSONDecodeError:
                print("✅ Azure CLI authenticated")
        else:
            print("")
            print("ℹ️  Azure CLI installed but not authenticated - Cloud builds disabled")
            print("   To enable cloud builds, run: az login")
            print("")
    except subprocess.TimeoutExpired:
        print("ℹ️  Azure CLI auth check timed out - Cloud builds may be unavailable")
    except Exception as e:
        print(f"ℹ️  Could not verify Azure CLI authentication: {e}")

# Run Azure CLI check at startup (non-blocking, informational only)
check_azure_cli_availability()


def _derive_image_name_from_tool_definition(agent_name: str) -> tuple[str, list]:
    """Extract the ACR image name from tool definition infra.image.acr field.

    Steps:
      1. Resolve agent_name to catalog key (in case display_name was passed)
      2. Locate tools definition YAML via agent_manager paths.
      3. Extract infra[0].image.acr field.
      4. Parse the ACR URL to get registry/image:tag.
      5. If missing/unreadable: fallback to normalized agent_name.
      6. Docker normalize only if required (lowercase and allowed chars [a-z0-9_.-]).

    Returns (image_name, diagnostics[list[str]]).
    """
    print(f"\n🔍 TRACE: _derive_image_name_from_tool_definition called with agent_name='{agent_name}'")
    diagnostics = []
    acr_image_url = None
    
    # CRITICAL: Always resolve to catalog key first
    # The agent_name might be a display name (e.g., "rdkit-agent") but we need the catalog key (e.g., "RDKit")
    # This ensures we're always using the same identifier that the build process uses
    resolved_agent_key = agent_name
    try:
        if agent_manager:
            print(f"   📋 Agent manager available, registered catalog keys: {list(agent_manager.agents.keys())}")
            
            # First check: exact match (already a catalog key)
            if agent_name in agent_manager.agents:
                resolved_agent_key = agent_name
                print(f"   ✅ Agent name is already a valid catalog key: '{resolved_agent_key}'")
            else:
                # Second check: might be a display name, try to find catalog key by loading each agent
                print(f"   🔍 '{agent_name}' not in catalog keys, checking if it's a display name...")
                for catalog_key in agent_manager.agents.keys():
                    try:
                        info = agent_manager.get_agent_info(catalog_key)
                        if info.display_name == agent_name:
                            resolved_agent_key = catalog_key
                            print(f"   ✅ Resolved display name '{agent_name}' to catalog key '{catalog_key}'")
                            diagnostics.append(f"ℹ️ Resolved display name '{agent_name}' to catalog key '{catalog_key}'")
                            break
                    except Exception:
                        continue
                
                if resolved_agent_key == agent_name:
                    print(f"   ⚠️ Could not resolve '{agent_name}' to a catalog key")
                    diagnostics.append(f"⚠️ Agent '{agent_name}' not found in catalog")
            
            # Now use the resolved catalog key to get agent paths
            if resolved_agent_key in agent_manager.agents:
                paths = agent_manager.get_agent_paths(resolved_agent_key)
                print(f"   📂 Agent paths for '{resolved_agent_key}': {paths}")
                tools_path = paths.get('tools_definition') if paths else None
                if tools_path and not os.path.isabs(tools_path):
                    tools_path = os.path.abspath(os.path.join(os.path.dirname(__file__), tools_path))
                print(f"   📄 Tools definition path: {tools_path}")
                print(f"   📄 File exists: {os.path.exists(tools_path) if tools_path else False}")
                if tools_path and os.path.exists(tools_path):
                    try:
                        with open(tools_path, 'r', encoding='utf-8') as f:
                            data = yaml.safe_load(f) or {}
                        print(f"   📖 Loaded tool definition, keys: {list(data.keys())}")
                        
                        # Extract ACR image URL from infra[0].image.acr
                        infra = data.get('infra', [])
                        print(f"   🏗️ Infra config found: {len(infra) if infra else 0} entries")
                        if infra and isinstance(infra, list) and len(infra) > 0:
                            first_infra = infra[0]
                            image_config = first_infra.get('image', {})
                            acr_image_url = image_config.get('acr')
                            print(f"   🖼️ ACR image URL from tool definition: '{acr_image_url}'")
                            
                            if acr_image_url:
                                diagnostics.append(f"ℹ️ Found ACR image URL in tool definition: {acr_image_url}")
                            else:
                                print(f"   ⚠️ No ACR URL in infra[0].image.acr")
                                diagnostics.append("⚠️ No ACR image URL found in infra[0].image.acr; using tool name")
                        else:
                            print(f"   ⚠️ No infra configuration found")
                            diagnostics.append("⚠️ No infra configuration found in tool definition; using tool name")
                            
                    except Exception as e:
                        diagnostics.append(f"⚠️ failed reading tools definition '{os.path.basename(tools_path)}': {e}")
                else:
                    diagnostics.append("ℹ️ tools definition file not found; using agent key")
            else:
                diagnostics.append("ℹ️ agent not found in catalog; using agent key")
        else:
            diagnostics.append("ℹ️ agent manager not available; using agent key")
    except Exception as e:
        diagnostics.append(f"⚠️ unexpected error deriving name: {e}")

    # If we have an ACR image URL, extract the image name and tag from it
    if acr_image_url:
        print(f"   🔧 Parsing ACR URL to extract image name...")
        try:
            # Handle {name} placeholder in ACR URL (e.g., "{name}.azurecr.io/image:tag")
            # This is a template variable that should be replaced with the actual ACR name
            # For local Docker, we just extract the image part after the registry
            
            # Parse ACR URL: registry.azurecr.io/image:tag or {name}.azurecr.io/image:tag
            # Example: myregistry.azurecr.io/moltoolkit-tool:latest
            # Example: {name}.azurecr.io/rdkit-tool:latest
            if '/' in acr_image_url:
                # Split by '/' to get the image part after the registry
                parts = acr_image_url.split('/')
                print(f"   🔧 URL parts after split: {parts}")
                if len(parts) >= 2:
                    # Get everything after the first '/' (registry part)
                    # Keep the full image name including tag (e.g., gromacs:sp, rdkit-tool:latest)
                    image_with_tag = '/'.join(parts[1:])
                    print(f"   ✅ Extracted image name: '{image_with_tag}'")
                    return image_with_tag, diagnostics
            
            # Fallback: use the ACR URL as-is if parsing fails
            diagnostics.append("⚠️ Could not parse ACR URL; using raw URL")
            return acr_image_url, diagnostics
            
        except Exception as e:
            diagnostics.append(f"⚠️ Error parsing ACR URL: {e}")
    
    # Fallback to agent name if no ACR URL found
    print(f"   ⚠️ FALLBACK: No ACR URL found, using normalized agent_name")
    candidate = agent_name or 'unnamed'
    original = candidate
    # Docker image name must be lowercase and limited charset
    import re as _re
    safe = _re.sub(r'[^a-z0-9_.-]+', '-', candidate.lower()).strip('-.') or 'unnamed'
    if safe != original:
        diagnostics.append(f"ℹ️ Normalized tool name '{original}' -> '{safe}' for Docker compatibility")
    print(f"   ⚠️ FALLBACK RESULT: '{safe}'")
    print(f"   🏁 FINAL RETURN: image_name='{safe}'")
    # Avoid accidental suffix from prior policy: ensure we did NOT append '-tool'
    return safe, diagnostics


def build_agent_image(agent_name, dockerfile_path):
    """Build Docker image using ONLY the tool definition 'name' (no forced suffix).

    Replaces earlier suffix policies ('-agent', then '-tool'). Name source of truth:
      top-level 'name' field in the tools definition YAML. Fallbacks and any
      normalization are reported in build output.
    """
    import time
    import json
    start_time = time.time()

    # SSE trace for build start
    if SSE_AVAILABLE:
        try:
            trace_system(
                f"🔨 Building Docker image for {agent_name}",
                level='info',
                metadata={'context': 'Docker Build', 'agent': agent_name},
                details=json.dumps({
                    'agent_name': agent_name,
                    'dockerfile_path': dockerfile_path,
                    'started_at': time.strftime('%Y-%m-%d %H:%M:%S')
                }, indent=2)
            )
        except Exception:
            pass

    try:
        if not docker_client:
            return {'success': False, 'error': 'Docker client not available'}

        # Derive image name
        image_name, diag = _derive_image_name_from_tool_definition(agent_name)

        # Extract directory containing Dockerfile
        dockerfile_dir = os.path.dirname(dockerfile_path)

        # Handle both 'Dockerfile' and 'i-Dockerfile' naming
        dockerfile_name = os.path.basename(dockerfile_path)
        if dockerfile_name == 'i-Dockerfile':
            dockerfile_option = ['-f', dockerfile_name]
        else:
            dockerfile_option = []

        print(f"🔨 Building Docker image for {agent_name} (image: {image_name})")
        print(f"   📁 Build context: {dockerfile_dir}")
        print(f"   📄 Dockerfile: {dockerfile_name}")
        if diag:
            for d in diag:
                print(f"   {d}")
        print(f"   ⏱️  Started at: {time.strftime('%H:%M:%S')}")
        print(f"   📺 Build output (streaming):")
        print("   " + "="*60)
        
        # Prefer buildx single-platform build for linux/amd64 and load locally
        def _stream_fn(msg: str):
            print(msg)
        ok, bx_err = _try_build_with_buildx(dockerfile_path, image_name, platform="linux/amd64", stream_fn=_stream_fn)
        if not ok:
            print(f"   ⚠️  buildx path failed ({bx_err}); falling back to Docker SDK build")
            # Use docker_client to build image with real-time streaming
            build_args = {
                'path': dockerfile_dir,
                'tag': image_name,
                'rm': True,
                'forcerm': True
            }
            if dockerfile_option:
                build_args['dockerfile'] = dockerfile_name
            try:
                response = docker_client.api.build(decode=True, **build_args)
                step_counter = 0
                for log in response:
                    if 'stream' in log:
                        stream_content = log['stream'].strip()
                        if stream_content:
                            if stream_content.startswith('Step '):
                                step_counter += 1
                                print(f"   🔧 {stream_content}")
                            else:
                                for line in stream_content.split('\n'):
                                    if line.strip():
                                        print(f"      {line}")
                    elif 'error' in log:
                        error_msg = log['error']
                        print(f"   ❌ BUILD ERROR: {error_msg}")
                        return {'success': False, 'error': f"Docker build failed: {error_msg}"}
                    elif 'status' in log:
                        status = log['status']
                        if 'id' in log:
                            print(f"   📦 {log['id']}: {status}")
                        else:
                            print(f"   📦 {status}")
                    elif 'aux' in log and 'ID' in log['aux']:
                        image_id = log['aux']['ID']
                        print(f"   🎯 Image built successfully: {image_id[:12]}")
            except Exception as build_error:
                print(f"   ❌ BUILD FAILED: {str(build_error)}")
                return {'success': False, 'error': f"Docker build failed: {str(build_error)}"}
        
        # Get the built image (ensure it exists locally)
        image = docker_client.images.get(image_name)

        print("   " + "="*60)

        # Calculate build time
        build_time = time.time() - start_time
        minutes = int(build_time // 60)
        seconds = int(build_time % 60)
        time_str = f"{minutes}m {seconds}s" if minutes > 0 else f"{seconds}s"
        
        print(f"✅ Successfully built image: {image_name}")
        print(f"   ⏱️  Build completed in: {time_str}")
        if image and hasattr(image, 'id') and image.id:
            print(f"   🆔 Image ID: {image.id[:12]}")
        
        # SSE trace for build success
        if SSE_AVAILABLE:
            try:
                trace_system(
                    f"✅ Docker image built successfully: {image_name}",
                    level='success',
                    metadata={'context': 'Docker Build', 'agent': agent_name},
                    details=json.dumps({
                        'image_name': image_name,
                        'image_id': image.id[:12] if image and hasattr(image, 'id') and image.id else None,
                        'build_time': time_str,
                        'agent_name': agent_name
                    }, indent=2)
                )
            except Exception:
                pass
        
        return {'success': True, 'image_name': image_name, 'image_id': image.id if image else None}
        
    except Exception as e:
        error_msg = f"Failed to build Docker image for {agent_name}: {str(e)}"
        print(f"❌ {error_msg}")
        
        # SSE trace for build failure
        if SSE_AVAILABLE:
            try:
                trace_system(
                    f"❌ Docker image build failed for {agent_name}",
                    level='error',
                    metadata={'context': 'Docker Build', 'agent': agent_name},
                    details=json.dumps({
                        'agent_name': agent_name,
                        'error': str(e)[:500]
                    }, indent=2)
                )
            except Exception:
                pass
        
        return {'success': False, 'error': error_msg}


def _normalized_tool_image_name(agent_name: str) -> str:
    """Return normalized docker image name with unified '-tool' suffix.

    Ensures lowercase DNS-safe base (non a-z0-9 -> '-') and appends '-tool'.
    Example: 'Azure Quantum' -> 'azure-quantum-tool'
    """
    # Deprecated legacy helper: naming policy now derives EXACT name from tool definition.
    # Raising to surface any forgotten references during transition.
    raise RuntimeError("_normalized_tool_image_name is deprecated. Use _derive_image_name_from_tool_definition instead.")

def stop_and_remove_container(container_name):
    """Stop and remove existing container if it exists"""
    try:
        if not docker_client:
            return False
            
        try:
            container = docker_client.containers.get(container_name)
            if container.status == 'running':
                print(f"🛑 Stopping container: {container_name}")
                container.stop()
            print(f"🗑️ Removing container: {container_name}")
            container.remove()
            return True
        except Exception:
            # Container doesn't exist or other error, which is fine for our purposes
            return True
    except Exception as e:
        print(f"⚠️ Warning: Could not stop/remove container {container_name}: {e}")
        return False

def load_agent_env_vars(agent_name, paths=None):
    """Load environment variables for an agent from its env_vars file.

    Args:
        agent_name: Name of the agent
        paths: Optional paths dict. If not provided, will query agent_manager.

    Returns:
        dict: Environment variables dictionary (empty if no env vars file or error)
    """
    env_vars_dict = {}
    try:
        # Get paths if not provided
        if paths is None and agent_manager:
            paths = agent_manager.get_agent_paths(agent_name)

        if not paths:
            return env_vars_dict

        # Check if env_vars path exists
        env_vars_path = paths.get('env_vars')
        if not env_vars_path:
            return env_vars_dict

        # Resolve relative paths to absolute paths
        if not os.path.isabs(env_vars_path):
            env_vars_path = os.path.abspath(os.path.join(os.path.dirname(__file__), env_vars_path))

        # Load env vars from file
        if os.path.exists(env_vars_path):
            try:
                with open(env_vars_path, 'r', encoding='utf-8') as f:
                    env_vars_dict = json.load(f)
                print(f"✅ Loaded {len(env_vars_dict)} environment variable(s) from {env_vars_path}")
            except json.JSONDecodeError as e:
                print(f"⚠️ Warning: Failed to parse env vars file {env_vars_path}: {e}")
            except Exception as e:
                print(f"⚠️ Warning: Failed to load env vars file {env_vars_path}: {e}")
        else:
            print(f"ℹ️ Environment variables file specified but not found: {env_vars_path}")
    except Exception as e:
        print(f"⚠️ Error loading env vars for {agent_name}: {e}")

    return env_vars_dict

def restart_agent_container_with_env_vars(agent_name, env_vars_path):
    """Restart agent container with updated environment variables if it's currently running.

    Args:
        agent_name: Name of the agent
        env_vars_path: Path to the environment variables JSON file

    Returns:
        dict with 'restarted' (bool) and optional 'error' message
    """
    try:
        if not docker_client:
            return {'restarted': False, 'reason': 'Docker not available'}
        
        container_name = get_normalized_container_name(agent_name)
        
        # Check if container exists and is running
        try:
            container = docker_client.containers.get(container_name)
            if container.status != 'running':
                return {'restarted': False, 'reason': f'Container exists but not running (status: {container.status})'}
        except docker.errors.NotFound:
            return {'restarted': False, 'reason': 'Container not found'}
        
        # Get the image name from the running container
        image_name = container.image.tags[0] if container.image.tags else container.image.id
        
        print(f"🔄 Auto-restarting container {container_name} with updated environment variables...")
        
        # Load environment variables from file
        env_vars_dict = {}
        if env_vars_path and os.path.exists(env_vars_path):
            try:
                with open(env_vars_path, 'r') as f:
                    env_vars_dict = json.load(f)
                print(f"   Loaded {len(env_vars_dict)} environment variable(s) from {env_vars_path}")
            except Exception as e:
                print(f"⚠️ Warning: Could not load env vars from {env_vars_path}: {e}")
        
        # Stop and remove the existing container
        stop_and_remove_container(container_name)
        
        # Start new container with updated env vars
        result = start_agent_container(agent_name, image_name, container_name, env_vars_dict)
        
        if result.get('success'):
            print(f"✅ Container {container_name} restarted successfully with updated environment variables")
            return {'restarted': True, 'container_name': container_name}
        else:
            error_msg = result.get('error', 'Unknown error')
            print(f"❌ Failed to restart container: {error_msg}")
            return {'restarted': False, 'error': error_msg}
            
    except Exception as e:
        print(f"❌ Error restarting container for {agent_name}: {e}")
        return {'restarted': False, 'error': str(e)}

def get_conversation_file_path(session_id: str = None, agent_name: str = None) -> str:
    """Get the path to the conversation JSON file for a session and agent.

    Args:
        session_id: The session ID. Uses current session if not provided.
        agent_name: The agent name. Uses session's current agent if not provided.

    Returns:
        Path to the conversation file for the session/agent combination.
        Format: sessions/<session_id>/conversation_<agent_name>.json
    """
    sm = get_session_manager()
    if sm:
        sid = session_id or sm.current_session_id
        if sid:
            dirs = sm.get_session_dirs(sid)
            # Store conversation in the session's base directory (parent of input/output/workdir)
            session_base = os.path.dirname(dirs['input'])

            # Get agent name from parameter, session, or use default
            if not agent_name:
                session = sm.get_session(sid)
                agent_name = session.agent_name if session else None

            # Create agent-specific conversation file name
            if agent_name:
                # Sanitize agent name for filename
                safe_agent_name = agent_name.replace('/', '_').replace('\\', '_')
                return os.path.join(session_base, f'conversation_{safe_agent_name}.json')
            else:
                return os.path.join(session_base, 'conversation.json')

    # Fallback to legacy location
    script_dir = os.path.dirname(os.path.abspath(__file__))
    return os.path.join(script_dir, '.workbench', 'conversation.json')


def save_current_conversation():
    """Save the current conversation to the session's conversation file."""
    if not conversation_manager:
        return

    sm = get_session_manager()
    if not sm or not sm.current_session_id:
        return

    conv_file = get_conversation_file_path(sm.current_session_id)
    # Use the workbench session ID as the conversation session ID
    conversation_manager.save_session_to_file(sm.current_session_id, conv_file)


def ensure_shared_directories(agent_name: str = None) -> dict:
    """Ensure the shared docker directories exist and return the paths.

    Uses session-specific directories:
      - sessions/<session_id>/<agent_name>/input
      - sessions/<session_id>/<agent_name>/output
      - sessions/<session_id>/<agent_name>/workdir

    Returns a dict with 'input', 'output', 'workdir', 'state' paths.
    Raises an exception if directories cannot be created or no session is active.
    """
    try:
        sm = get_session_manager()
        if not sm:
            raise RuntimeError("Session manager not initialized")
        if not agent_name:
            agent_name = get_current_agent_name()
        dirs = sm.get_session_dirs(agent_name=agent_name)
        input_dir = dirs['input']
        output_dir = dirs['output']
        workdir = dirs['workdir']
        state_dir = dirs['state']

        os.makedirs(input_dir, exist_ok=True)
        os.makedirs(output_dir, exist_ok=True)
        os.makedirs(workdir, exist_ok=True)
        os.makedirs(state_dir, exist_ok=True)

        # Ensure directories are writable by container users (uid 999 for rdkituser, etc.)
        # Use mode 0o777 to allow read/write from any user inside containers
        try:
            os.chmod(input_dir, 0o777)
            os.chmod(output_dir, 0o777)
            os.chmod(workdir, 0o777)
            os.chmod(state_dir, 0o777)
        except Exception as chmod_err:
            # Non-fatal: permissions may already be correct
            if VERBOSE_TRACING:
                print(f"⚠️ Could not set permissions on shared dirs: {chmod_err}")

        if VERBOSE_TRACING:
            print(f"🔧 Ensured session dirs: {input_dir}, {output_dir}, {workdir}, {state_dir}")

        return {'input': input_dir, 'output': output_dir, 'workdir': workdir, 'state': state_dir}
    except Exception as e:
        # Surface a clear error for callers that depend on these paths
        raise Exception(f"Failed to ensure shared docker directories: {e}")

def start_agent_container(agent_name, image_name, container_name=None, env_vars_dict=None):
    """Start a new container for the agent
    
    Args:
        agent_name: Name of the agent
        image_name: Docker image name to use
        container_name: Optional custom container name
        env_vars_dict: Optional dictionary of environment variables to pass to container
    """
    print(f"\n🚀 TRACE: start_agent_container called:")
    print(f"   agent_name='{agent_name}'")
    print(f"   image_name='{image_name}'")
    print(f"   container_name='{container_name}'")

    # Initialize container_op before try block to avoid UnboundLocalError in exception handler
    container_op = None

    try:
        if not docker_client:
            return {'success': False, 'error': 'Docker is not available. Please ensure Docker Desktop is installed and running.'}
        
        # Additional check to verify Docker daemon is accessible
        try:
            docker_client.ping()
        except Exception as ping_error:
            if "Cannot connect to the Docker daemon" in str(ping_error) or "connection refused" in str(ping_error).lower():
                return {'success': False, 'error': 'Docker daemon is not running. Please start Docker Desktop or the Docker service.'}
            else:
                return {'success': False, 'error': f'Docker is not accessible: {str(ping_error)}'}
            
            
        # Use provided container name or generate default
        if not container_name:
            container_name = get_normalized_container_name(agent_name)
        print(f"   📦 Using container_name: '{container_name}'")
        shared_dirs = ensure_shared_directories(agent_name=agent_name)

        # Volume mounts - use session-specific directories
        volumes = {
            shared_dirs['input']: {'bind': '/input', 'mode': 'rw'},
            shared_dirs['output']: {'bind': '/output', 'mode': 'rw'},
            shared_dirs['workdir']: {'bind': '/workdir', 'mode': 'rw'}
        }
        
        # Prepare environment variables (if provided)
        environment = env_vars_dict if env_vars_dict else {}

        # Create consolidated operation for container start
        if SSE_AVAILABLE and container_operation:
            try:
                container_op = container_operation(agent_name, container_name, image_name)
                container_op.start(f"Starting container from {image_name}")
            except Exception:
                pass
        
        # Ensure no container with this name exists before creating
        try:
            existing_container = docker_client.containers.get(container_name)
            print(f"⚠️ Found existing container {container_name}, removing it...")
            if existing_container.status == 'running':
                existing_container.stop()
            existing_container.remove()
            print(f"🗑️ Removed existing container: {container_name}")
        except docker.errors.NotFound:
            # No existing container, which is what we want
            pass
        except Exception as e:
            print(f"⚠️ Warning: Error removing existing container: {e}")
        
        # Start container in detached mode
        try:
            container = docker_client.containers.run(
                image_name,
                command='sleep infinity',  # Keep container running indefinitely
                name=container_name,
                volumes=volumes,
                environment=environment,  # Pass environment variables
                platform='linux/amd64',  # Ensure consistent platform (uses emulation on ARM64)
                detach=True,
                remove=False
            )
        except docker.errors.ImageNotFound as e:
            # Specific error for when the Docker image doesn't exist
            error_msg = f"Docker image '{image_name}' not found. Please build the image first using the 'Build Container Image' button."
            print(f"🖼️ Image not found: {error_msg}")
            raise Exception(error_msg)
        except docker.errors.APIError as e:
            if "Conflict" in str(e) and "already in use" in str(e):
                print(f"🔄 Name conflict detected, attempting to resolve...")
                # Try one more time to remove conflicting container
                try:
                    conflicting_container = docker_client.containers.get(container_name)
                    conflicting_container.remove(force=True)
                    print(f"🗑️ Force removed conflicting container: {container_name}")
                    
                    # Try creating container again
                    container = docker_client.containers.run(
                        image_name,
                        command='sleep infinity',  # Keep container running indefinitely
                        name=container_name,
                        volumes=volumes,
                        environment=environment,  # Pass environment variables
                        platform='linux/amd64',  # Ensure consistent platform (uses emulation on ARM64)
                        detach=True,
                        remove=False
                    )
                except Exception as retry_error:
                    raise Exception(f"Failed to resolve container name conflict: {retry_error}")
            elif "Cannot connect to the Docker daemon" in str(e) or "connection refused" in str(e).lower():
                # Specific error for when Docker daemon is not running
                error_msg = "Docker daemon is not running. Please start Docker Desktop or the Docker service."
                print(f"🐋 Docker daemon error: {error_msg}")
                raise Exception(error_msg)
            else:
                raise e
        
        # Verify container is running
        container.reload()
        if container.status != 'running':
            raise Exception(f"Container failed to start properly. Status: {container.status}")

        # Update module-global pointers so execute endpoints can locate the container
        try:
            globals()['CONTAINER_NAME'] = container.name
            globals()['agent_name'] = agent_name
            print(f"🔧 Updated globals on new start: CONTAINER_NAME={container.name}, agent_name={agent_name}")
        except Exception:
            pass

        # Update operation as successful
        if container_op:
            try:
                container_op.complete(f"Container running (id: {container.id[:12] if container.id else 'unknown'})")
            except Exception:
                pass
        
        # Test container by listing /app directory
        try:
            result = container.exec_run('ls -la /app/', demux=True)
            if result.exit_code == 0:
                print(f"📁 Container /app contents verified")
            else:
                print(f"⚠️ Warning: Could not verify /app directory")
        except Exception as e:
            print(f"⚠️ Warning: Could not test container: {e}")
        
        return {
            'success': True,
            'container_name': container_name,
            'container_id': container.id,
            'status': container.status
        }
        
    except Exception as e:
        error_msg = f"Failed to start container for {agent_name}: {str(e)}"
        # Update operation as failed
        if container_op:
            try:
                container_op.fail(str(e)[:500])
            except Exception:
                pass

        return {'success': False, 'error': error_msg}

def get_existing_agent_container(agent_name):
    """Check for existing container without building - used for auto-start"""
    try:
        if not docker_client:
            return {'success': False, 'error': 'Docker client not available'}
            
        container_name = get_normalized_container_name(agent_name)
        
        # Check if container already exists and is running
        try:
            container = docker_client.containers.get(container_name)
            if container.status == 'running':
                print(f"✅ Using existing running container: {container_name}")
                return {
                    'success': True,
                    'container_info': {
                        'name': container_name,
                        'id': container.id,
                        'status': container.status,
                        'image': container.image.tags[0] if container.image.tags else 'unknown',
                        'reused': True
                    }
                }
            elif container.status in ['exited', 'stopped']:
                # Need to recreate container with current env vars instead of just starting it
                # because env vars may have been updated since the container was created
                print(f"🔄 Recreating stopped container with current env vars: {container_name}")
                image_name = container.image.tags[0] if container.image.tags else container.image.id

                # Load current environment variables
                env_vars_dict = load_agent_env_vars(agent_name)

                # Remove old container
                stop_and_remove_container(container_name)

                # Start new container with current env vars
                result = start_agent_container(agent_name, image_name, container_name, env_vars_dict)

                if result.get('success'):
                    return {
                        'success': True,
                        'container_info': {
                            'name': container_name,
                            'id': result['container_id'],
                            'status': result['status'],
                            'image': image_name,
                            'restarted': True
                        }
                    }
                else:
                    print(f"⚠️ Failed to restart container: {container_name}")
                    return {'success': False, 'error': result.get('error', f'Failed to restart container {container_name}')}
            else:
                print(f"⚠️ Container in unexpected state ({container.status}): {container_name}")
                return {'success': False, 'error': f'Container {container_name} in unexpected state: {container.status}'}
        except docker.errors.NotFound:
            print(f"🔧 Container not found: {container_name}")
            return {'success': False, 'error': f'Container {container_name} not found'}
        except Exception as e:
            print(f"⚠️ Error checking container {container_name}: {e}")
            return {'success': False, 'error': f'Error checking container {container_name}: {str(e)}'}
        
    except Exception as e:
        error_msg = f"Failed to check container for {agent_name}: {str(e)}"
        print(f"❌ {error_msg}")
        return {'success': False, 'error': error_msg}

def get_or_ensure_agent_container(agent_name, paths):
    """Get existing container or build/start if needed - optimized for fast switching"""
    try:
        if not docker_client:
            return {'success': False, 'error': 'Docker client not available'}
            
        container_name = get_normalized_container_name(agent_name)
        
        # Check if container already exists and is running
        try:
            container = docker_client.containers.get(container_name)
            if container.status == 'running':
                print(f"✅ Using existing running container: {container_name}")
                return {
                    'success': True,
                    'container_info': {
                        'name': container_name,
                        'id': container.id,
                        'status': container.status,
                        'image': container.image.tags[0] if container.image.tags else 'unknown',
                        'reused': True
                    }
                }
            elif container.status in ['exited', 'stopped']:
                print(f"🔄 Starting existing stopped container: {container_name}")
                container.start()
                container.reload()
                if container.status == 'running':
                    return {
                        'success': True,
                        'container_info': {
                            'name': container_name,
                            'id': container.id,
                            'status': container.status,
                            'image': container.image.tags[0] if container.image.tags else 'unknown',
                            'restarted': True
                        }
                    }
                else:
                    print(f"⚠️ Failed to restart container, will rebuild: {container_name}")
                    # Fall through to rebuild
            else:
                print(f"⚠️ Container in unexpected state ({container.status}), will rebuild: {container_name}")
                # Remove problematic container
                try:
                    container.remove(force=True)
                except:
                    pass
                # Fall through to rebuild
        except docker.errors.NotFound:
            print(f"🔧 Container not found, will build: {container_name}")
            # Fall through to build new container
        except Exception as e:
            print(f"⚠️ Error checking container {container_name}: {e}, will rebuild")
            # Fall through to rebuild
        
        # Need to build/start container
        return build_and_start_agent_container(agent_name, paths)
        
    except Exception as e:
        error_msg = f"Failed to get or ensure container for {agent_name}: {str(e)}"
        print(f"❌ {error_msg}")
        return {'success': False, 'error': error_msg}

def build_and_start_agent_container(agent_name, paths):
    """Complete container lifecycle: build image and start container"""
    try:
        # Stop and remove existing container
        container_name = get_normalized_container_name(agent_name)
        stop_and_remove_container(container_name)
        
        # Build Docker image
        build_result = build_agent_image(agent_name, paths['dockerfile'])
        if not build_result['success']:
            return build_result

        # Load environment variables from env_vars file if present
        env_vars_dict = load_agent_env_vars(agent_name, paths)

        # Start new container with environment variables
        start_result = start_agent_container(agent_name, build_result['image_name'], env_vars_dict=env_vars_dict)
        if not start_result['success']:
            return start_result
        
        return {
            'success': True,
            'container_info': {
                'name': start_result['container_name'],
                'id': start_result['container_id'],
                'status': start_result['status'],
                'image': build_result['image_name']
            }
        }
        
    except Exception as e:
        error_msg = f"Failed to build and start container for {agent_name}: {str(e)}"
        print(f"❌ {error_msg}")
        return {'success': False, 'error': error_msg}

class ExecutionState:
    """Track the state of a running execution for real-time updates"""
    def __init__(self, execution_id: str, script_filename: str, container=None, exec_id=None):
        self.execution_id = execution_id
        self.script_filename = script_filename
        self.stdout_buffer = ""
        self.stderr_buffer = ""
        self.is_running = True
        self.is_completed = False
        self.exit_code = None
        self.error_message = None
        self.output_files = []
        self.start_time = datetime.now(timezone.utc)
        self.end_time = None
        self.lock = threading.Lock()
        self.container = container  # Track container for cancellation
        self.exec_id = exec_id  # Track exec_id for cancellation
        self.cancel_requested = False  # Track if cancellation was requested
        self.last_save_time = time.time()  # Track last save time for periodic persistence
        self.save_interval = 2.0  # Save every 2 seconds

    def append_stdout(self, data: str):
        with self.lock:
            self.stdout_buffer += data

    def append_stderr(self, data: str):
        with self.lock:
            self.stderr_buffer += data

    def save_stdout_if_needed(self, state_dir: str):
        """Periodically save stdout to state file for session restoration during execution"""
        current_time = time.time()
        if current_time - self.last_save_time >= self.save_interval:
            self.last_save_time = current_time
            try:
                os.makedirs(state_dir, exist_ok=True)
                stdout_file = os.path.join(state_dir, 'stdout.json')
                with self.lock:
                    output_data = {
                        'stdout': self.stdout_buffer,
                        'stderr': self.stderr_buffer,
                        'exit_code': None,  # Still running
                        'execution_id': self.execution_id,
                        'is_running': True
                    }
                with open(stdout_file, 'w', encoding='utf-8') as f:
                    json.dump(output_data, f)
            except Exception as save_err:
                pass  # Silently ignore save errors during execution
    
    def get_current_output(self):
        with self.lock:
            return {
                'stdout': self.stdout_buffer,
                'stderr': self.stderr_buffer,
                'is_running': self.is_running,
                'is_completed': self.is_completed,
                'exit_code': self.exit_code,
                'error_message': self.error_message,
                'output_files': self.output_files.copy(),
                'execution_id': self.execution_id,
                'start_time': self.start_time.isoformat(),
                'end_time': self.end_time.isoformat() if self.end_time else None
            }
    
    def mark_completed(self, exit_code: int = 0, error_message: Optional[str] = None):
        with self.lock:
            self.is_running = False
            self.is_completed = True
            self.exit_code = exit_code
            self.error_message = error_message
            self.end_time = datetime.now(timezone.utc)
    
    def update_output_files(self, files: list):
        with self.lock:
            self.output_files = files.copy()
    
    def cancel_execution(self):
        """Request cancellation of the running execution"""
        with self.lock:
            if self.is_completed:
                return False  # Already completed
            self.cancel_requested = True
            
            # Try to stop the Docker exec if we have the exec_id
            if self.container and self.exec_id:
                try:
                    # Docker doesn't have a direct "stop exec" API, but we can try to kill the process in the container
                    # We'll send a kill signal to the script process
                    self.container.exec_run(
                        f"pkill -f {self.script_filename}",
                        detach=True
                    )
                    print(f"Sent kill signal for execution {self.execution_id}")
                except Exception as e:
                    print(f"Error sending kill signal: {e}")
            
            return True

# Globals used to track background execution states
execution_states = {}
execution_lock = threading.Lock()

def get_azure_ad_token(azure_ad_config, subscription_id=None):
    """Get Azure AD access token for Azure OpenAI authentication"""
    if not AZURE_IDENTITY_AVAILABLE:
        raise Exception("azure-identity library not available for Azure AD authentication")
    
    try:
        tenant_id = azure_ad_config.get('tenant_id')
        client_id = azure_ad_config.get('client_id')
        client_secret = azure_ad_config.get('client_secret')
        scope = azure_ad_config.get('scope', 'https://cognitiveservices.azure.com/.default')
        
        if client_id and client_secret and tenant_id:
            # Use client credentials flow
            credential = ClientSecretCredential(
                tenant_id=tenant_id,
                client_id=client_id,
                client_secret=client_secret
            )
        else:
            # Use default Azure credential (managed identity, Azure CLI, etc.)
            # Use the quiet helper to avoid verbose SDK diagnostics
            tok = _get_token_default_credential(scope, None, purpose='azure_ad_token')
            if not tok:
                raise Exception('Failed to obtain Azure AD token via DefaultAzureCredential')
            return tok
        
    except Exception as e:
        error_msg = f"Failed to obtain Azure AD token: {str(e)}"
        if subscription_id:
            error_msg += f"\nNote: Resource is in subscription {subscription_id}. Ensure your identity has access to this subscription."
        raise Exception(error_msg)

