def split_content_into_items(answer_text):
    """Split answer text into alternating text and code segments."""
    if not answer_text:
        return []

    answer_items = []

    # Use a pattern to find complete code blocks with language specification
    code_pattern = r"```(\w+)?\n?([\s\S]*?)```"

    # Find all complete code blocks
    matches = list(re.finditer(code_pattern, answer_text, re.MULTILINE | re.DOTALL))

    if not matches:
        # No complete code blocks found - check for incomplete code block (opening ``` without closing)
        incomplete_pattern = r"```(\w+)?\n?([\s\S]*)$"
        incomplete_match = re.search(incomplete_pattern, answer_text)

        if incomplete_match and incomplete_match.start() < len(answer_text) - 10:
            # Found an incomplete code block - extract text before and the code
            text_before = answer_text[:incomplete_match.start()].strip()
            if text_before:
                answer_items.append({'type': 'text', 'content': text_before})

            language = incomplete_match.group(1) if incomplete_match.group(1) else None
            code_content = incomplete_match.group(2).strip()
            if code_content:
                code_item = {'type': 'code', 'content': code_content}
                if language:
                    code_item['language'] = language.lower()
                answer_items.append(code_item)
            return answer_items

        # No code blocks at all, treat entire content as text
        answer_items.append({'type': 'text', 'content': answer_text.strip()})
        return answer_items

    # Process matches in order
    last_end = 0
    for match in matches:
        # Add text before this code block
        if match.start() > last_end:
            text_content = answer_text[last_end:match.start()].strip()
            if text_content:
                answer_items.append({'type': 'text', 'content': text_content})

        # Add the complete code block with language information
        language = match.group(1) if match.group(1) else None
        code_content = match.group(2).strip()
        if code_content:
            code_item = {'type': 'code', 'content': code_content}
            if language:
                code_item['language'] = language.lower()
            answer_items.append(code_item)

        last_end = match.end()

    # Add any remaining text after the last code block
    if last_end < len(answer_text):
        remaining_text = answer_text[last_end:].strip()
        if remaining_text:
            # Check if remaining text contains an incomplete code block
            incomplete_pattern = r"```(\w+)?\n?([\s\S]*)$"
            incomplete_match = re.search(incomplete_pattern, remaining_text)

            if incomplete_match and incomplete_match.start() < len(remaining_text) - 10:
                # Text before incomplete code block
                text_before = remaining_text[:incomplete_match.start()].strip()
                if text_before:
                    answer_items.append({'type': 'text', 'content': text_before})

                # The incomplete code block
                language = incomplete_match.group(1) if incomplete_match.group(1) else None
                code_content = incomplete_match.group(2).strip()
                if code_content:
                    code_item = {'type': 'code', 'content': code_content}
                    if language:
                        code_item['language'] = language.lower()
                    answer_items.append(code_item)
            else:
                answer_items.append({'type': 'text', 'content': remaining_text})

    return answer_items

