def load_workflow_agent_workflow_config(workflow_agent_name, inline_workflow_yaml=None):
    """Load Workflow Agent workflow configuration and extract referenced agents
    
    Args:
        workflow_agent_name: Name of the Workflow Agent
        inline_workflow_yaml: Optional inline YAML content (takes precedence over file)
        
    Returns:
        dict: {
            'success': bool,
            'workflow_config': dict,  # Parsed YAML content
            'referenced_agents': list,  # External agent names (excluding internal ones)
            'workflow_source': str,  # Description of source used
            'error': str  # Error message if success=False
        }
    """
    
    # Legacy duplicate key detection removed (Aug 2025) in favor of centralized JSON Schema validation.
    
    try:
        workflow_config = None
        workflow_source = "inline YAML"
        
        # Option 1: Use inline YAML if provided
        if inline_workflow_yaml and isinstance(inline_workflow_yaml, str) and 'states:' in inline_workflow_yaml:
            try:
                # VALIDATION NOTE (Aug 2025): Legacy format checks removed - now handled by JSON schema validation
                # This eliminates false positives where 'workflow:' or 'agent:' appear in string values
                print(f"DEBUG: Loading inline YAML (schema validation handled separately)")
                # VALIDATION CHECK 2 (Deprecated Aug 2025): Duplicate key check now superseded by centralized schema validation.
                # duplicate_error = check_yaml_duplicate_keys(inline_workflow_yaml)
                # if duplicate_error:
                #     return {
                #         'success': False,
                #         'error': f'YAML structure error: {duplicate_error}',
                #         'workflow_config': None,
                #         'referenced_agents': [],
                #         'workflow_source': workflow_source
                #     }
                # Keeping the code commented for reference; remove after confirming frontend uses /api/workflow/validate exclusively.
                print(f"DEBUG: (Skipped legacy duplicate key check) Proceeding with YAML load")
                    
                workflow_config = yaml.safe_load(inline_workflow_yaml)
            except Exception as e:
                return {
                    'success': False,
                    'error': f'Invalid {workflow_source}: {e}',
                    'workflow_config': None,
                    'referenced_agents': [],
                    'workflow_source': workflow_source
                }
        else:
            # Option 2: Load from file system
            if not agent_manager:
                return {'success': False, 'error': 'Agent manager not available'}

            workflow_agent_config_obj = agent_manager.get_workflow_agent_config(workflow_agent_name)
            if not workflow_agent_config_obj or not workflow_agent_config_obj.agent_config:
                return {
                    'success': False,
                    'error': f'Workflow configuration path not found for workflow agent "{workflow_agent_name}" in catalog.',
                    'workflow_config': None,
                    'referenced_agents': [],
                    'workflow_source': 'catalog'
                }

            # Resolve the relative path from the catalog directory
            workflow_file = os.path.normpath(os.path.join(agent_manager.catalog_dir, workflow_agent_config_obj.agent_config))
            workflow_source = f"workflow file: {workflow_file}"
            
            if not os.path.exists(workflow_file):
                return {
                    'success': False,
                    'error': f'Workflow file not found: {workflow_file}',
                    'workflow_config': None,
                    'referenced_agents': [],
                    'workflow_source': workflow_source
                }
                
            try:
                # Use robust YAML loading with encoding detection and normalization
                file_content = None
                try:
                    with open(workflow_file, 'r', encoding='utf-8') as f:
                        file_content = f.read()
                except UnicodeDecodeError:
                    # Fallback: try loading with robust encoding detection
                    print(f"⚠️ UTF-8 decode failed for workflow {workflow_file}, trying auto-detection...")
                    from file_utils import load_text_file_robust
                    file_content = load_text_file_robust(workflow_file, normalize_chars=True)
                    print(f"✅ Loaded workflow with alternative encoding")
                
                # Centralized schema validation for file-based content (config-driven WorkflowDefinitionSchema path)
                schema_file = None
                if validate_yaml is not None and config_manager:
                    try:
                        t_files = config_manager.get_template_files()
                        rel_schema = t_files.get('WorkflowDefinitionSchema') if t_files else None
                        if rel_schema:
                            candidate = Path(__file__).parent / rel_schema
                            if candidate.exists():
                                schema_file = candidate
                            else:
                                print(f"⚠️ Workflow schema configured but not found at: {candidate}")
                        else:
                            print("⚠️ template_files.WorkflowDefinitionSchema not set; skipping workflow schema validation")
                    except Exception as cfg_err:
                        print(f"⚠️ Failed to resolve WorkflowDefinitionSchema path from config: {cfg_err}")
                if validate_yaml is not None and schema_file and schema_file.exists():
                    v_result = validate_yaml(str(schema_file), file_content)
                    if not v_result.valid:
                        summarized = '; '.join(f"{e.path}: {e.message}" for e in v_result.errors[:5])
                        if len(v_result.errors) > 5:
                            summarized += ' ...'
                        return {
                            'success': False,
                            'error': f'Schema validation failed for {workflow_file}: {summarized}',
                            'workflow_config': None,
                            'referenced_agents': [],
                            'workflow_source': workflow_source
                        }
                workflow_config = yaml.safe_load(file_content)
            except Exception as e:
                return {
                    'success': False,
                    'error': f'Invalid {workflow_source}: {e}',
                    'workflow_config': None,
                    'referenced_agents': [],
                    'workflow_source': workflow_source
                }

        # Extract referenced external agents from workflow states
        referenced_agents = []
        
        # Only support new format (top-level states)
        workflow_states = []
        if 'states' in workflow_config:
            # New format: {states: [...], transitions: [...]}
            workflow_states = workflow_config['states']
        elif 'workflow' in workflow_config and 'states' in workflow_config['workflow']:
            # Legacy format detected - fail
            return {
                'success': False,
                'error': 'Legacy workflow format detected with workflow.states. Only the new format is supported with direct top-level keys: name, states, transitions, variables, startstate',
                'workflow_config': None,
                'referenced_agents': [],
                'workflow_source': workflow_source
            }
        
        # Debug logging
        print(f"DEBUG: load_workflow_agent_workflow_config - {workflow_agent_name}")
        print(f"DEBUG: Workflow source: {workflow_source}")
        print(f"DEBUG: Found {len(workflow_states)} states")
        
        for state in workflow_states:
            actors = state.get('actors', [])
            print(f"DEBUG: State '{state.get('name', 'unknown')}' has {len(actors)} actors")
            for actor in actors:
                agent_name = actor.get('agent')
                print(f"DEBUG: Found actor agent: {agent_name}")
                if agent_name and agent_name not in referenced_agents:
                    # Filter out internal workflow agents (planner, router, summarizer, workflow)
                    internal_agents = ['planner', 'router', 'summarizer', 'workflow']
                    if not any(internal in agent_name.lower() for internal in internal_agents):
                        referenced_agents.append(agent_name)
                        print(f"DEBUG: Added external agent: {agent_name}")
                    else:
                        print(f"DEBUG: Filtered internal agent: {agent_name}")
        
        print(f"DEBUG: Final referenced_agents: {referenced_agents}")
        
        return {
            'success': True,
            'workflow_config': workflow_config,
            'referenced_agents': referenced_agents,
            'workflow_source': workflow_source,
            'error': None
        }
        
    except Exception as e:
        print(f"ERROR: load_workflow_agent_workflow_config failed: {e}")
        return {
            'success': False,
            'error': f'Internal error: {str(e)}',
            'workflow_config': None,
            'referenced_agents': [],
            'workflow_source': 'unknown'
        }

def get_docker_data_handling_context() -> str:
    """Generate data handling context with input file information FOR DOCKER-BASED AGENTS.
    
    Scans sessions/<session_id>/input directory and provides file listing with previews.
    Returns formatted string for injection into agent prompts.
    
    Note: This is for Docker/tool agents. For KB agents, use get_data_handling_context() from builtin_tools.
    """
    base_context = """## Directory Paths (CRITICAL - Use these exact paths):
- Input files: `/input` (read-only) - or use `os.environ.get('INPUT_DIR', '/input')`
- Working directory: `/workdir` (read/write for intermediate files) - or use `os.environ.get('WORKDIR', '/workdir')` or `os.getcwd()`
- Output files: `/output` (write final results here) - or use `os.environ.get('OUTPUT_DIR', '/output')`

**IMPORTANT**: 
- Check environment variables (INPUT_DIR, WORKDIR, OUTPUT_DIR) first for flexibility
- Always create output directory with `os.makedirs(output_dir, exist_ok=True)` before writing"""

    # End marker for reliable refresh detection
    end_marker = "\n\n<!-- END_DATA_HANDLING_CONTEXT -->"

    # Get the correct path to input directory (session-aware)
    sm = get_session_manager()
    if not sm:
        print("⚠️ get_docker_data_handling_context: No session manager available")
        return base_context + end_marker

    agent_name = get_current_agent_name()
    try:
        dirs = sm.get_session_dirs(agent_name=agent_name)
        input_dir = dirs['input']
    except Exception as e:
        print(f"⚠️ get_docker_data_handling_context: Could not get session dirs: {e}")
        return base_context + end_marker

    if not os.path.exists(input_dir):
        return base_context + end_marker

    try:
        files = []
        for item in os.listdir(input_dir):
            item_path = os.path.join(input_dir, item)
            if os.path.isfile(item_path):
                files.append(item)

        if not files:
            return base_context + "\n\nNote: /input directory is currently empty." + end_marker
        
        # Build file listing with previews
        context_parts = [base_context, "\n\n## Available Input Files:"]

        # Scientific config file extensions (all use same max size, controlled by quota)
        scientific_extensions = {
            "mdp", "mdin", "conf", "in", "inp", "imd", "gjf", "com",
            "data", "lmp", "pot", "hex", "lj", "spce", "nw",
            "incar", "poscar", "kpoints"
        }

        # Total quota for all scientific file content: 20K characters
        # Divided equally among all files (scientific or not)
        total_content_quota = 20 * 1024  # 20K characters
        per_file_quota = total_content_quota // max(len(files), 1)
        # Cap per-file quota at 5K (individual file limit)
        per_file_max = min(per_file_quota, 5 * 1024)

        for filename in sorted(files):
            file_path = os.path.join(input_dir, filename)
            try:
                file_size = os.path.getsize(file_path)
                size_str = f"{file_size:,} bytes"

                # Check if this file matches a scientific config extension (case-insensitive)
                file_ext = filename.split('.')[-1].lower() if '.' in filename else filename.lower()
                is_scientific = file_ext in scientific_extensions or filename.lower() in scientific_extensions

                if is_scientific:
                    try:
                        # Read up to per_file_max characters
                        with open(file_path, 'r', encoding='utf-8') as f:
                            content = f.read(per_file_max + 1)
                        truncated = len(content) > per_file_max
                        safe_content = content[:per_file_max].replace('```', r'\`\`\`')
                        ext_for_code = file_ext if len(file_ext) < 10 else ''
                        truncated_marker = "\n[Truncated]" if truncated else ""
                        context_parts.append(
                            f"\n- **{filename}** ({size_str})\n  Content (up to {per_file_max // 1024}K):\n\n```{ext_for_code}\n{safe_content}{truncated_marker}\n```\n"
                        )
                    except Exception as e:
                        context_parts.append(f"\n- **{filename}** [Error reading scientific config file: {str(e)}]")
                    continue

                # Otherwise, show a preview as before
                preview = ""
                preview_size = 300
                try:
                    # Try UTF-8 first
                    with open(file_path, 'r', encoding='utf-8') as f:
                        content = f.read(preview_size)
                        preview = content.replace('\n', '\\n').replace('\r', '\\r')
                        if len(content) == preview_size:
                            preview += "..."
                except (UnicodeDecodeError, UnicodeError):
                    # If UTF-8 fails, try binary mode
                    try:
                        with open(file_path, 'rb') as f:
                            raw_bytes = f.read(preview_size)
                            # Try to decode as latin-1 (works for most binary)
                            preview = raw_bytes.decode('latin-1', errors='replace')[:preview_size]
                            preview = preview.replace('\n', '\\n').replace('\r', '\\r')
                            if len(raw_bytes) == preview_size:
                                preview += "..."
                            preview = f"[Binary/Non-UTF8] {preview}"
                    except Exception:
                        preview = "[Binary file - cannot preview]"
                except Exception as e:
                    preview = f"[Error reading file: {str(e)}]"

                context_parts.append(f"\n- **{filename}** ({size_str})")
                if preview:
                    context_parts.append(f"\n  Preview: {preview}")

            except Exception as e:
                context_parts.append(f"\n- **{filename}** [Error: {str(e)}]")

        # Add end marker for reliable refresh detection
        context_parts.append("\n\n<!-- END_DATA_HANDLING_CONTEXT -->")
        return ''.join(context_parts)
    
    except Exception as e:
        return base_context + f"\n\nNote: Could not scan /input directory: {str(e)}" + end_marker

def replace_template_variables(text: str, use_builtin_tools_context: bool = True) -> str:
    """Replace template variables in agent instructions with actual values

    Template variables:
    - {{dataHandlingContext}}: Replaced with input/output path instructions and file listing
    - {{nodePoolContext}}: Dynamic nodepool information with VM specs and optimization hints
    - {{agentTeam}}: Reserved for future use
    - {{workflowContext}}: Reserved for future use
    - {{userGoal}}: Reserved for future use

    Args:
        text: Template text with {{variables}}
        use_builtin_tools_context: If True, use builtin_tools context (write_file, read_file, list_files).
                                   If False, use Docker context (/input, /output dirs).
                                   Default is True for KB/query agents.
    """
    if not text:
        return text

    # Choose the appropriate data handling context
    if use_builtin_tools_context:
        # For KB agents and query interface - use function calling tools
        data_context = get_data_handling_context()  # From builtin_tools
    else:
        # For Docker/tool agents - use file system paths
        data_context = get_docker_data_handling_context()

    # Generate dynamic nodepool context if feature enabled, placeholder present, and service available
    nodepool_context = ''
    if '{{nodePoolContext}}' in text and NODEPOOL_CONTEXT_ENABLED and NODEPOOL_SERVICE_AVAILABLE:
        try:
            config_manager = DiscoveryConfigManager()
            nodepool_service = get_nodepool_service(config_manager)
            if nodepool_service is None:
                nodepool_service = initialize_nodepool_service(config_manager)
            nodepool_context = nodepool_service.get_nodepool_context_for_agent()
            print(f"[NodepoolContext] Generated nodepool context ({len(nodepool_context)} chars)")
        except Exception as e:
            print(f"[NodepoolContext] Warning: Failed to generate nodepool context: {e}")
            nodepool_context = "## Available Compute Nodepools\n\nNodepool information temporarily unavailable."

    # Define template variable replacements
    template_values = {
        'dataHandlingContext': data_context,
        'nodePoolContext': nodepool_context,
        'agentTeam': '',
        'workflowContext': '',
        'userGoal': '',
    }

    # Replace each template variable
    result = text
    for var_name, var_value in template_values.items():
        placeholder = f'{{{{{var_name}}}}}'
        if placeholder in result:
            result = result.replace(placeholder, var_value)

    return result


def load_agent_config(agent_name=None, agent_type=None):
    """Load agent configuration from YAML file and tools definition.

    Args:
        agent_name: Name of the agent to load. Uses current session agent if not provided.
        agent_type: Type of agent ('tool', 'entry', 'kb'). Important when agents share names.
    """
    global TOOL_ACTIONS
    try:
        instructions = None

        # Built-in Discovery assistant short-circuit
        if (_builtin_discovery_active and (agent_name is None or agent_name == BUILTIN_DISCOVERY_AGENT_KEY)) or (
            agent_name == BUILTIN_DISCOVERY_AGENT_KEY
        ):
            TOOL_ACTIONS.clear()
            return build_builtin_discovery_system_prompt()

        # Clear existing tool actions to avoid conflicts
        TOOL_ACTIONS.clear()

        # Resolve current agent (use session-based if not explicitly provided)
        current_agent = agent_name or get_current_agent_name()
        if not current_agent:
            print("WARNING: No current agent specified or available")
            return (
                "You are an expert in data analysis and computational science, with deep knowledge of scientific computing methods and data processing workflows."
            )

        # Get agent paths - pass agent_type to correctly resolve when names overlap
        paths = agent_manager.get_agent_paths(current_agent, agent_type)

        # Load tools definition from agent manager paths
        tools_def_path = paths.get('tools_definition', '')
        if tools_def_path:
            print(f"INFO: Loading tools definition from agent manager: {tools_def_path}")
            if not os.path.isabs(tools_def_path):
                tools_def_path = os.path.abspath(tools_def_path)
            if os.path.exists(tools_def_path):
                try:
                    with open(tools_def_path, 'r', encoding='utf-8') as f:
                        tools_config = yaml.safe_load(f) or {}
                    if 'actions' in tools_config and isinstance(tools_config['actions'], list):
                        for action in tools_config['actions']:
                            if 'name' in action:
                                action_name = action['name']
                                TOOL_ACTIONS[action_name] = action
                except Exception as e:
                    print(f"ERROR: Failed to load tools definition from agent manager: {str(e)}")
            else:
                print(f"ERROR: Tools definition file not found: {tools_def_path}")

        # Load agent configuration for instructions
        config_path = paths.get('agent_config', '')
        if config_path:
            print(f"INFO: Loading agent configuration from agent manager: {config_path}")
            if os.path.exists(config_path):
                try:
                    with open(config_path, 'r', encoding='utf-8') as f:
                        config = yaml.safe_load(f) or {}

                    # Load additional tools definition if specified in agent config
                    if config and 'agent' in config and 'tools_definition' in config['agent']:
                        additional_tools_def_path = config['agent']['tools_definition']
                        if not os.path.isabs(additional_tools_def_path):
                            config_dir = os.path.dirname(config_path)
                            additional_tools_def_path = os.path.join(config_dir, additional_tools_def_path)

                        if os.path.exists(additional_tools_def_path):
                            try:
                                with open(additional_tools_def_path, 'r', encoding='utf-8') as f:
                                    additional_tools_config = yaml.safe_load(f) or {}
                                if 'actions' in additional_tools_config and isinstance(additional_tools_config['actions'], list):
                                    for action in additional_tools_config['actions']:
                                        if 'name' in action:
                                            action_name = action['name']
                                            if action_name not in TOOL_ACTIONS:
                                                TOOL_ACTIONS[action_name] = action
                                                print(f"Loaded additional tool action: {action_name}")
                                            else:
                                                print(f"Skipping duplicate tool action: {action_name} (already loaded from main tools)")
                                print(f"SUCCESS: Loaded additional tools from agent config: {additional_tools_def_path}")
                            except Exception as e:
                                print(f"WARNING: Failed to load additional tools from agent config: {str(e)}")
                        else:
                            print(f"WARNING: Additional tools definition file not found: {additional_tools_def_path}")

                    # Extract instructions from the configuration
                    if config and 'agent' in config and 'instructions' in config['agent']:
                        instructions = config['agent']['instructions'].strip()
                        print(f"SUCCESS: Loaded agent instructions from {config_path}")
                    else:
                        print(f"WARNING: No agent instructions found in {config_path}")
                except Exception as e:
                    print(f"WARNING: Failed to load agent configuration: {str(e)}")
            else:
                print(f"WARNING: Agent configuration file not found: {config_path}")
        else:
            print("INFO: No agent config path specified")

        print(f"SUMMARY: Total tool actions loaded: {len(TOOL_ACTIONS)}")

        # Build tool actions documentation to append to instructions
        tool_actions_doc = ""
        if len(TOOL_ACTIONS) > 0:
            tool_actions_doc = "\n\n## AVAILABLE TOOL ACTIONS - COMMAND REFERENCE\n\n"
            tool_actions_doc += "When generating commands for tool actions, you MUST use the exact command format specified below.\n"
            tool_actions_doc += "Each action has a specific command template that must be followed precisely.\n\n"
            
            for action_name, action_config in TOOL_ACTIONS.items():
                tool_actions_doc += f"### Action: {action_name}\n"
                
                # Add description
                if 'description' in action_config:
                    tool_actions_doc += f"**Description:** {action_config['description']}\n\n"
                
                # Add command template - this is the critical part!
                if 'command' in action_config:
                    tool_actions_doc += f"**Command Format:**\n```bash\n{action_config['command']}\n```\n\n"
                    
                    # Parse the command to extract parameter placeholders
                    command_str = action_config['command']
                    # Find all {{variable}} patterns
                    params = re.findall(r'\{\{(\w+)\}\}', command_str)
                    if params:
                        unique_params = sorted(set(params))
                        tool_actions_doc += f"**Required Parameters:** {', '.join(unique_params)}\n\n"
                
                # Add input schema information
                if 'input_schema' in action_config and isinstance(action_config['input_schema'], dict):
                    schema = action_config['input_schema']
                    if 'properties' in schema:
                        tool_actions_doc += "**Input Schema Parameters:**\n"
                        for prop_name, prop_info in schema['properties'].items():
                            prop_type = prop_info.get('type', 'unknown')
                            prop_desc = prop_info.get('description', '')
                            tool_actions_doc += f"- `{prop_name}` ({prop_type}): {prop_desc}\n"
                        
                        if 'required' in schema and schema['required']:
                            tool_actions_doc += f"\n**Required:** {', '.join(schema['required'])}\n"
                        tool_actions_doc += "\n"
                
                tool_actions_doc += "---\n\n"
            
            tool_actions_doc += "\n**CRITICAL - ACTION PRIORITIZATION:**\n"
            tool_actions_doc += "When answering user questions, ALWAYS check if any of the available tool actions above can help achieve the user's goal.\n"
            tool_actions_doc += "If one or more actions match the user's intent, you MUST prioritize using those actions to accomplish the task rather than just providing explanations or general guidance.\n"
            tool_actions_doc += "You may generate MULTIPLE actions in a single response if the user's goal requires several steps or if multiple actions together best serve the user's needs.\n\n"
            tool_actions_doc += "**IMPORTANT:** When executing tool actions, you must:\n"
            tool_actions_doc += "1. Use the EXACT command format shown above for that action\n"
            tool_actions_doc += "2. Replace {{variable}} placeholders with actual values from the user's request\n"
            tool_actions_doc += "3. For Handlebars conditionals like {{#if variable}}, include that part only if the variable is provided\n"
            tool_actions_doc += "4. **CRITICAL: Always include the COMPLETE command starting with the executable.** For example, if the command format shows `python3 /app/scripts/entrypoint.py --name action`, you MUST include `python3 /app/scripts/entrypoint.py` - do NOT output just `--name action` without the executable prefix.\n"
            tool_actions_doc += "5. Ensure all required parameters from the input schema are included\n"
            tool_actions_doc += "6. When the user's goal can be achieved through actions, prefer executing actions over providing theoretical explanations\n\n"
            tool_actions_doc += "**WARNING: NEVER omit the executable prefix from commands.** Commands like `--name calculate_descriptors --input ...` are INVALID. The correct format is `python3 /app/scripts/entrypoint.py --name calculate_descriptors --input ...`\n\n"

        # Critical instruction to ensure code blocks are completed (addresses model truncation issue)
        completion_instruction = "\n\n## CRITICAL: RESPONSE COMPLETION REQUIREMENT\n"
        completion_instruction += "**ALWAYS complete your entire response in a single turn.** When you start generating code (Python scripts, bash commands, etc.), you MUST include the complete code in your response.\n"
        completion_instruction += "- NEVER stop after saying 'Here is the code:' or 'Here is the Python script:' without providing the actual code\n"
        completion_instruction += "- NEVER ask for confirmation before providing code that was requested\n"
        completion_instruction += "- ALWAYS include the full, complete, runnable code in your response\n"
        completion_instruction += "- If generating a script, include ALL imports, ALL functions, and the COMPLETE implementation\n\n"

        # Determine what to return based on what we loaded
        if instructions:
            # Apply template variable replacement to instructions
            # Use Docker context (/input, /output) for tool agents, builtin context for KB and Entry agents
            # Check agent type from multiple sources for robustness
            current_agent_type = None

            # Method 1: Check session (most reliable when set)
            sm = get_session_manager()
            if sm and sm.current_session_id:
                session = sm.get_session(sm.current_session_id)
                if session:
                    current_agent_type = session.agent_type

            # Method 2: If session doesn't have type, check agent_manager paths
            if not current_agent_type and current_agent:
                try:
                    agent_paths = agent_manager.get_agent_paths(current_agent)
                    if agent_paths:
                        current_agent_type = agent_paths.get('type')
                        print(f"🔧 Agent type from paths: {current_agent_type}")
                except Exception as e:
                    print(f"⚠️ Could not get agent type from paths: {e}")

            is_tool_agent = (current_agent_type == 'tool')
            use_builtin = not is_tool_agent  # Use builtin context for KB and Entry agents
            print(f"🔧 Agent type detection: current_agent_type={current_agent_type}, is_tool_agent={is_tool_agent}, use_builtin_context={use_builtin}")
            instructions_with_replacements = replace_template_variables(instructions, use_builtin_tools_context=use_builtin)

            # Append completion instruction and tool actions documentation to the instructions
            return instructions_with_replacements + completion_instruction + tool_actions_doc
        elif len(TOOL_ACTIONS) > 0:
            base_prompt = "You are a helpful assistant with access to specialized tools for scientific computing and quantum processing."
            return base_prompt + completion_instruction + tool_actions_doc
        else:
            print("ERROR: No tools definition loaded from agent manager")
            raise ValueError("No tools definition found")
    except Exception as e:
        print(f"ERROR: Failed to load agent configuration: {str(e)}")
        print("TRACE: Will use default system prompt as fallback")
        return (
            "You are an expert in data analysis and computational science, with deep knowledge of scientific computing methods and data processing workflows. "
            "Your goal is to assist users in data analysis and scientific computing using both pre-built functions and open-source packages available in the computational container."
        )

# Load system prompt from agent configuration once at startup
print("🔄 Loading agent configuration...")
SYSTEM_PROMPT = load_agent_config()
print(f"✅ System prompt loaded ({len(SYSTEM_PROMPT)} characters)")

