@app.route('/api/docker/running-local-builds', methods=['GET'])
def get_running_local_builds():
    """Get all running local Docker builds.

    Returns list of agents with active local builds.
    Used by frontend to check for builds to reconnect on page load.
    """
    try:
        running = []
        with ACTIVE_DOCKER_BUILD_LOCK:
            for agent_name, rec in ACTIVE_DOCKER_BUILD_PROCS.items():
                if not isinstance(rec, dict):
                    continue
                proc = rec.get('proc')
                if proc is None:
                    continue
                # Check if still running
                if proc.poll() is None:
                    running.append({
                        'agent_name': agent_name,
                        'pid': proc.pid,
                        'started_at': rec.get('started_at'),
                        'cmd': rec.get('cmd')
                    })

        return jsonify({'running_builds': running}), 200
    except Exception as e:
        return jsonify({'error': str(e), 'running_builds': []}), 200


@app.route('/api/agents/<agent_name>/docker/build/logs', methods=['GET'])
def get_agent_docker_build_logs(agent_name):
    """Stream logs from a running local Docker build.

    Used to reconnect to an active build when switching agents or on page reload.
    Returns SSE stream with build output.
    """
    try:
        # Get session_id from query parameter
        request_session_id = request.args.get('session_id')
        sm = get_session_manager()
        session_id = request_session_id or (sm.current_session_id if sm else None)

        rec = _get_active_build_record(agent_name)
        if not isinstance(rec, dict) or rec.get('proc') is None:
            return jsonify({'error': 'No active build found'}), 404

        proc = rec.get('proc')
        if proc.poll() is not None:
            # Build already finished - return final output
            lines = _get_build_output_lines(agent_name, session_id=session_id)
            return_code = proc.returncode
            success = return_code == 0
            _clear_active_build_record(agent_name, expected_proc=proc)
            return jsonify({
                'status': 'completed',
                'success': success,
                'return_code': return_code,
                'output': lines
            }), 200

        # Build still running - stream output
        def generate():
            import time
            last_line_count = 0
            poll_interval = 0.5
            max_wait = 3600  # 1 hour max
            start_time = time.time()

            # First, send any existing output
            existing_lines = _get_build_output_lines(agent_name, session_id=session_id)
            if existing_lines:
                yield "data: 🔄 Reconnected to running build...\n\n"
                yield f"data: ── Previous output ({len(existing_lines)} lines) ──\n\n"
                for line in existing_lines:
                    yield f"data: {line}\n\n"
                yield "data: ── Continuing live output ──\n\n"
                last_line_count = len(existing_lines)

            # Then stream new output as it arrives
            while True:
                # Check if build is still running
                rec = _get_active_build_record(agent_name)
                if not rec:
                    yield "data: ⚠️ Build record not found\n\n"
                    yield "event: end\ndata: done\n\n"
                    break

                proc = rec.get('proc')
                if proc is None or proc.poll() is not None:
                    # Build finished - send final output and status
                    final_lines = _get_build_output_lines(agent_name, session_id=session_id)
                    for line in final_lines[last_line_count:]:
                        yield f"data: {line}\n\n"

                    return_code = proc.returncode if proc else -1
                    if return_code == 0:
                        yield "event: success\n"
                        yield "data: Build completed successfully\n\n"
                    else:
                        yield "event: error\n"
                        yield f"data: Build failed with exit code {return_code}\n\n"
                    yield "event: end\ndata: done\n\n"
                    _clear_active_build_record(agent_name, expected_proc=proc)
                    break

                # Get new output
                current_lines = _get_build_output_lines(agent_name, session_id=session_id)
                if len(current_lines) > last_line_count:
                    for line in current_lines[last_line_count:]:
                        yield f"data: {line}\n\n"
                    last_line_count = len(current_lines)

                # Check timeout
                if time.time() - start_time > max_wait:
                    yield "data: ⚠️ Streaming timeout reached\n\n"
                    yield "event: end\ndata: timeout\n\n"
                    break

                time.sleep(poll_interval)

        return Response(
            stream_with_context(generate()),
            mimetype='text/event-stream',
            headers={
                'Cache-Control': 'no-cache',
                'Connection': 'keep-alive',
                'X-Accel-Buffering': 'no'
            }
        )

    except Exception as e:
        return jsonify({'error': str(e)}), 500


