        if tenant_id:
            token = get_token_for_tenant('https://management.azure.com/.default', tenant_id, server_traces, purpose='subscriptions-list')
        else:
            token = get_token_default_credential('https://management.azure.com/.default', server_traces, purpose='subscriptions-list')
        
        if not token:
            error_msg = f"Cannot obtain authentication token. Traces: {'; '.join(server_traces)}"
            print(f"❌ {error_msg}")
            return jsonify({'success': False, 'error': error_msg, 'traces': server_traces}), 401
        
        # Query Azure subscriptions endpoint
        url = 'https://management.azure.com/subscriptions?api-version=2022-12-01'
