        # Helper function to trace both to server_traces and SSE
        def job_trace(message, level='info', details=None):
            """
            Trace a message to server_traces, console, and SSE.
            
            Args:
                message: The trace message
                level: 'debug', 'info', 'success', 'warning', 'error', 'progress'
                details: Optional details string (e.g., JSON) that can be expanded in Activity panel
            """
            server_traces.append(message)
            print(message)
            if SSE_AVAILABLE:
                try:
                    trace_job(message, temp_job_id, agent_name, level=level, details=details)
                except Exception:
                    pass
        
        # Track interactive session info
        interactive_session_info = None
        shell_wrapper_content = None

