        import uuid
        run_prefix = f"run-{datetime.now(timezone.utc).strftime('%Y%m%d-%H%M%S')}-{str(uuid.uuid4())[:8]}"
        
        # Update temp_job_id now that we have run_prefix
        temp_job_id = run_prefix

        # Echo request-level info for debugging (avoid printing full code)
