                                mgmt_resp2 = requests.get(mgmt_api2, headers={ 'Authorization': f'Bearer {access_token}' }, timeout=15)
                                if mgmt_resp2.status_code == 200:
                                    mgmt_body2 = mgmt_resp2.json()
                                    path_prop2 = mgmt_body2.get('properties', {}).get('path')
                                    if path_prop2:
                                        p2 = str(path_prop2).strip('/')
                                        parts2 = p2.split('/') if p2 else []
                                        if len(parts2) >= 1 and parts2[0]:
                                            out_container = parts2[0]
