# -------------------------------------------------------------
# Centralized Workflow YAML Schema Validation Endpoint
# -------------------------------------------------------------
# Frontend (discovery_client.js performValidation) calls this endpoint with:
#   POST /api/workflow/validate  body: { "yaml": "...inline workflow yaml..." }
# Optional: { "yaml": "...", "schema_path": "relative/or/abs/path" }
# If no schema_path provided we default to Utils/agent-workbench/yaml-schemas/workflow-schema.json
# Helper methods for agent input validation
def _should_use_local_definition(agent_name, agent_manager):
    """
    Determine if an agent should use local definition vs Azure published definition.
    Local definitions are ONLY used for:
    - Components (planner, router, summarizer, workflow) - these are not published individually
      and always have suffixes like -pln, -rtr, -sum, -wfl
    
    All other agents (tool agents, functional agents) should use Azure published definitions.
    """
    # Check if agent name suggests it's a component (common naming patterns)
    component_suffixes = ['-pln', '-rtr', '-sum', '-wfl']
    if any(agent_name.endswith(suffix) for suffix in component_suffixes):
        return True
    
    # All non-component agents should use Azure published definitions
    # This includes tool agents, KB agents, and other functional agents
    return False

def _get_inputs_from_local_definition(agent_name, agent_manager):
    """Get agent inputs from local YAML definition file using the proper agent manager catalog structure."""
    defined_inputs = set()
    
    if not agent_manager:
        return defined_inputs
    
    agent_config_path = None
    
    # First try to find the agent in the main tool agents catalog
    if hasattr(agent_manager, 'agents') and agent_name in agent_manager.agents:
        agent_entry = agent_manager.agents[agent_name]
        agent_config_path = getattr(agent_entry, 'agent_config', None)
    else:
        # If not found in main catalog, search through workflow agent components
        if hasattr(agent_manager, 'workflow_agents'):
            # workflow_agents is a dictionary: workflow_agent_name -> workflow_agent_object
            for workflow_agent_name, entry_agent in agent_manager.workflow_agents.items():
                if hasattr(entry_agent, 'components') and entry_agent.components:
                    for component in entry_agent.components:
                        # Components have 'name' field for identification
                        component_name = component.get('name') if isinstance(component, dict) else getattr(component, 'name', None)
                        
                        if component_name == agent_name:
                            agent_config_path = component.get('agent_config') if isinstance(component, dict) else getattr(component, 'agent_config', None)
                            break
                
                if agent_config_path:
                    break
    
    if not agent_config_path:
        return defined_inputs
    
    # Resolve relative path using the same method as the working code
    if not os.path.isabs(agent_config_path):
        catalog_dir = os.path.dirname(os.path.abspath(agent_manager.catalog_path))
        agent_config_path = os.path.normpath(os.path.join(catalog_dir, agent_config_path))
    
    if not os.path.exists(agent_config_path):
        return defined_inputs
    
    try:
        # Use robust YAML loading with encoding detection and normalization
        agent_data = load_yaml_robust(agent_config_path, normalize_chars=True)
        
        if agent_data and 'extension' in agent_data and 'inputs' in agent_data['extension']:
            for input_def in agent_data['extension']['inputs']:
                if isinstance(input_def, dict) and 'name' in input_def:
                    defined_inputs.add(input_def['name'])
    except FileEncodingError as e:
        print(f"⚠️ Encoding error reading agent config {agent_config_path}: {e}")
        pass  # Return empty set if file cannot be read
    except Exception:
        pass  # Return empty set if file cannot be read or parsed
    
    return defined_inputs

def _get_inputs_from_azure_definition(agent_name):
    """
    Get agent inputs from Azure published definition using fetch_agent_resource.
    
    Returns:
        tuple: (defined_inputs, status_info)
        - defined_inputs: set of input names
        - status_info: dict with keys 'success', 'agent_found', 'error_message'
    """
    defined_inputs = set()
    status_info = {
        'success': False,
        'agent_found': False,
        'error_message': None
    }
    
    # Get Azure configuration for fetching agent definitions
    if not (DISCOVERY_AVAILABLE and config_manager):
        status_info['error_message'] = "Azure configuration unavailable"
        return defined_inputs, status_info
    
    azure_cfg = config_manager.get_azure_config()
    subscription_id = azure_cfg.get('subscription_id')
    resource_group = azure_cfg.get('resource_group')
    
    if not (subscription_id and resource_group):
        status_info['error_message'] = "Missing Azure subscription ID or resource group"
        return defined_inputs, status_info
    
    try:
        # Fetch agent definition from Azure using the fixed fetch_agent_resource function
        fetched = fetch_agent_resource(subscription_id, resource_group, agent_name)
        
        if fetched.get('success'):
            status_info['agent_found'] = True
            
            # Extract agent definition from Azure response
            resource = fetched.get('resource', {})
            properties = resource.get('properties', {})
            definition = properties.get('definitionContent', {})
            
            # Navigate to the agent inputs in the JSON structure
            if isinstance(definition, dict):
                extension_block = definition.get('extension')
                
                # Check extension.inputs (primary location for inputs in Azure definitions)
                if extension_block and 'inputs' in extension_block:
                    inputs_data = extension_block['inputs']
                    
                    if isinstance(inputs_data, list):
                        for input_def in inputs_data:
                            if isinstance(input_def, dict) and 'name' in input_def:
                                defined_inputs.add(input_def['name'])
                    elif isinstance(inputs_data, dict):
                        defined_inputs = set(inputs_data.keys())
                    
                    status_info['success'] = True
                else:
                    # Agent found but has no inputs or empty inputs array
                    status_info['success'] = True
                    status_info['error_message'] = "Agent found but declares 0 inputs (inputs: [] or missing)"
        else:
            status_info['error_message'] = f"Agent '{agent_name}' not found in Azure"
    except Exception as e:
        status_info['error_message'] = f"Exception while fetching agent: {str(e)}"
    
    return defined_inputs, status_info

def validate_workflow_agent_inputs(workflow_yaml_text, workflow_agent_name=None):
    """
    Validate that all inputs defined in agents match their usage in workflow actors,
    and vice versa.
    
    Args:
        workflow_yaml_text: The workflow YAML content to validate
        workflow_agent_name: Name of the workflow agent being published (will be skipped from validation)
    
    Returns:
        tuple: (is_valid, errors, warnings)
        - is_valid: bool indicating if validation passed
        - errors: list of validation error messages
        - warnings: list of validation warning messages
    """
    import yaml
    
    errors = []
    warnings = []
    
    try:
        # Parse the workflow YAML
        workflow_data = yaml.safe_load(workflow_yaml_text)
        if not workflow_data or 'states' not in workflow_data:
            print("ℹ️ No workflow states found, skipping agent input validation")
            return True, [], []  # Skip validation if workflow structure is invalid
        
        # Extract all agent references from workflow actors
        workflow_agents = {}  # agent_name -> {inputs: set, state_name: str}
        
        for state in workflow_data.get('states', []):
            state_name = state.get('name', 'Unknown State')
            for actor in state.get('actors', []):
                agent_name = actor.get('agent')
                if agent_name:
                    actor_inputs = set(actor.get('inputs', {}).keys())
                    if agent_name in workflow_agents:
                        # Agent appears in multiple states, combine inputs
                        workflow_agents[agent_name]['inputs'].update(actor_inputs)
                        workflow_agents[agent_name]['states'].append(state_name)
                    else:
                        workflow_agents[agent_name] = {
                            'inputs': actor_inputs,
                            'states': [state_name]
                        }
        
        if not workflow_agents:
            print("ℹ️ No agents found in workflow, skipping agent input validation")
            return True, [], []
        
        print(f"🔍 Validating inputs for {len(workflow_agents)} agent(s): {', '.join(workflow_agents.keys())}")
        
        # Built-in variables that don't need to be declared in agent inputs
        builtin_variables = {'dataHandlingContext', 'messageId', 'nodePoolContext'}
        
        # Component types that should use local definitions (not published to Azure individually)
        local_component_types = {'planner', 'router', 'summarizer', 'workflow'}
        
        # For each agent referenced in workflow, validate against agent definition
        if agent_manager:
            for agent_name, workflow_info in workflow_agents.items():
                # Skip the workflow agent being published since it's not in Azure yet
                if workflow_agent_name and agent_name == workflow_agent_name:
                    print(f"  ⏭️  Skipping workflow agent '{agent_name}' - not yet published to Azure")
                    continue
                workflow_inputs = workflow_info['inputs']
                states_list = workflow_info['states']
                
                # Filter out built-in variables from workflow inputs for validation
                filtered_workflow_inputs = workflow_inputs - builtin_variables
                
                # Determine if this agent should use local or remote definition
                use_local_definition = _should_use_local_definition(agent_name, agent_manager)
                source_type = "local" if use_local_definition else "published"
                
                # Show validation info to user
                if filtered_workflow_inputs:
                    print(f"  📝 Agent '{agent_name}': checking {len(filtered_workflow_inputs)} input(s) [{', '.join(sorted(filtered_workflow_inputs))}] against {source_type} definition")
                else:
                    print(f"  📝 Agent '{agent_name}': no custom inputs to validate (only built-in variables used)")
                
                try:
                    defined_inputs = set()
                    azure_fetch_failed = False  # Track if Azure fetch failed for functional agents
                    
                    if use_local_definition:
                        # Use local agent definition (for components like planner, router, etc.)
                        defined_inputs = _get_inputs_from_local_definition(agent_name, agent_manager)
                        if defined_inputs:
                            print(f"      ✅ Found {len(defined_inputs)} input(s) in local definition: {sorted(defined_inputs)}")
                        else:
                            print(f"      ❌ Found 0 inputs in local definition - check agent config path")
                    else:
                        # Use published Azure definition (for functional/tool agents)
                        # NO FALLBACK TO LOCAL - functional agents MUST be published to Azure first
                        defined_inputs, status_info = _get_inputs_from_azure_definition(agent_name)
                        
                        if status_info['success']:
                            if defined_inputs:
                                print(f"      ✅ Found {len(defined_inputs)} input(s) in published definition: {sorted(defined_inputs)}")
                            else:
                                print(f"      ⚠️  Agent found but declares 0 inputs")
                                if status_info['error_message']:
                                    print(f"      ℹ️  {status_info['error_message']}")
                        else:
                            # Agent not found or error occurred
                            if status_info['agent_found']:
                                # Agent exists but something wrong with definition
                                print(f"      ❌ Agent found in Azure but failed to parse inputs")
                                if status_info['error_message']:
                                    print(f"      ℹ️  {status_info['error_message']}")
                            else:
                                # Agent doesn't exist in Azure
                                print(f"      ❌ Could not retrieve published definition from Azure")
                                print(f"      ⚠️  Agent '{agent_name}' must be published to Azure before it can be referenced in an workflow agent workflow")
                                if status_info['error_message']:
                                    print(f"      ℹ️  {status_info['error_message']}")
                            azure_fetch_failed = True  # Mark that Azure fetch failed
                    
                    # Validate inputs
                    missing_inputs = filtered_workflow_inputs - defined_inputs
                    if missing_inputs:
                        # For functional agents where Azure fetch failed
                        if not use_local_definition and azure_fetch_failed:
                            if status_info and status_info.get('agent_found'):
                                # Agent exists but input mismatch
                                errors.append(
                                    f"Agent '{agent_name}' input mismatch: workflow passes {len(filtered_workflow_inputs)} input(s) "
                                    f"[{', '.join(sorted(filtered_workflow_inputs))}] but agent declares {len(defined_inputs)} input(s) "
                                    f"[{', '.join(sorted(defined_inputs)) if defined_inputs else 'none'}]. "
                                    f"Update the agent definition to include: {', '.join(sorted(missing_inputs))}"
                                )
                            else:
                                # Agent doesn't exist
                                errors.append(f"Agent '{agent_name}' does not exist in Azure or has not been published. All functional agents must be published before being referenced in an workflow agent workflow.")
                        else:
                            # For local agents or successful Azure fetch with missing inputs
                            for missing in missing_inputs:
                                validation_message = (
                                    f"Input '{missing}' used in workflow states [{', '.join(states_list)}] "
                                    f"but not defined in agent '{agent_name}' {source_type} definition"
                                )
                                errors.append(validation_message)
                    else:
                        print(f"      ✅ All inputs validated successfully")
                    
                    # Check for unused inputs (informational warning)
                    if defined_inputs:
                        unused_inputs = defined_inputs - workflow_inputs
                        for unused_input in unused_inputs:
                            warnings.append(
                                f"Input '{unused_input}' defined in agent '{agent_name}' "
                                f"but not used in workflow (states: {', '.join(states_list)})"
                            )
                
                except Exception as agent_err:
                    warnings.append(f"Error validating inputs for agent '{agent_name}': {str(agent_err)}")
        else:
            warnings.append("Agent manager not available - skipping agent input validation")
    
    except Exception as e:
        errors.append(f"Error during workflow agent input validation: {str(e)}")
    
    is_valid = len(errors) == 0
    return is_valid, errors, warnings


def validate_workflow_agent_inputs_with_traces(workflow_yaml_text, workflow_agent_name=None):
    """
    Enhanced version of validate_workflow_agent_inputs that also returns detailed traces
    for frontend display.
    
    Returns:
        tuple: (is_valid, errors, warnings, traces)
        - is_valid: bool indicating if validation passed
        - errors: list of validation error messages
        - warnings: list of validation warning messages
        - traces: list of detailed trace messages for frontend display
    """
    import yaml
    
    errors = []
    warnings = []
    traces = []
    
    try:
        # Parse the workflow YAML
        workflow_data = yaml.safe_load(workflow_yaml_text)
        if not workflow_data or 'states' not in workflow_data:
            traces.append("ℹ️ No workflow states found, skipping agent input validation")
            return True, [], [], traces  # Skip validation if workflow structure is invalid
        
        # Extract all agent references from workflow actors
        workflow_agents = {}  # agent_name -> {inputs: set, state_name: str}
        
        for state in workflow_data.get('states', []):
            state_name = state.get('name', 'Unknown State')
            for actor in state.get('actors', []):
                agent_name = actor.get('agent')
                if agent_name:
                    actor_inputs = set(actor.get('inputs', {}).keys())
                    if agent_name in workflow_agents:
                        # Agent appears in multiple states, combine inputs
                        workflow_agents[agent_name]['inputs'].update(actor_inputs)
                        workflow_agents[agent_name]['states'].append(state_name)
                    else:
                        workflow_agents[agent_name] = {
                            'inputs': actor_inputs,
                            'states': [state_name]
                        }
        
        if not workflow_agents:
            traces.append("ℹ️ No agents found in workflow, skipping agent input validation")
            return True, [], [], traces
        
        agent_names = ', '.join(workflow_agents.keys())
        traces.append(f"🔍 Validating inputs for {len(workflow_agents)} agent(s): {agent_names}")
        
        # Built-in variables that don't need to be declared in agent inputs
        builtin_variables = {'dataHandlingContext', 'messageId', 'nodePoolContext'}
        
        # For each agent referenced in workflow, validate against agent definition
        if agent_manager:
            for agent_name, workflow_info in workflow_agents.items():
                # Skip the workflow agent being published since it's not in Azure yet
                if workflow_agent_name and agent_name == workflow_agent_name:
                    traces.append(f"  ⏭️  Skipping workflow agent '{agent_name}' - not yet published to Azure")
                    continue
                workflow_inputs = workflow_info['inputs']
                states_list = workflow_info['states']
                
                # Filter out built-in variables from workflow inputs for validation
                filtered_workflow_inputs = workflow_inputs - builtin_variables
                
                # Determine if this agent should use local or remote definition
                use_local_definition = _should_use_local_definition(agent_name, agent_manager)
                source_type = "local" if use_local_definition else "published"
                
                # Show validation info to user
                if filtered_workflow_inputs:
                    input_list = ', '.join(sorted(filtered_workflow_inputs))
                    traces.append(f"  📝 Agent '{agent_name}': checking {len(filtered_workflow_inputs)} input(s) [{input_list}] against {source_type} definition")
                else:
                    traces.append(f"  📝 Agent '{agent_name}': no custom inputs to validate (only built-in variables used)")
                
                try:
                    defined_inputs = set()
                    azure_fetch_failed = False  # Track if Azure fetch failed for functional agents
                    
                    if use_local_definition:
                        # Use local agent definition (for components like planner, router, etc.)
                        defined_inputs = _get_inputs_from_local_definition(agent_name, agent_manager)
                        if defined_inputs:
                            input_list = sorted(defined_inputs)
                            traces.append(f"      ✅ Found {len(defined_inputs)} input(s) in local definition: {input_list}")
                        else:
                            traces.append(f"      ❌ Found 0 inputs in local definition - check agent config path")
                    else:
                        # Use published Azure definition (for functional/tool agents)
                        # NO FALLBACK TO LOCAL - functional agents MUST be published to Azure first
                        traces.append(f"ℹ️ Fetching Azure resource: {agent_name}")
                        defined_inputs, status_info = _get_inputs_from_azure_definition(agent_name)
                        
                        if status_info['success']:
                            if defined_inputs:
                                input_list = sorted(defined_inputs)
                                traces.append(f"      ✅ Found {len(defined_inputs)} input(s) in published definition: {input_list}")
                            else:
                                traces.append(f"      ⚠️  Agent found but declares 0 inputs")
                                if status_info['error_message']:
                                    traces.append(f"      ℹ️  {status_info['error_message']}")
                        else:
                            # Agent not found or error occurred
                            if status_info['agent_found']:
                                # Agent exists but something wrong with definition
                                traces.append(f"      ❌ Agent found in Azure but failed to parse inputs")
                                if status_info['error_message']:
                                    traces.append(f"      ℹ️  {status_info['error_message']}")
                            else:
                                # Agent doesn't exist in Azure
                                traces.append(f"      ❌ Could not retrieve published definition from Azure")
                                traces.append(f"      ⚠️  Agent '{agent_name}' must be published to Azure before it can be referenced in an workflow agent workflow")
                                if status_info['error_message']:
                                    traces.append(f"      ℹ️  {status_info['error_message']}")
                            azure_fetch_failed = True  # Mark that Azure fetch failed
                    
                    # Validate inputs
                    missing_inputs = filtered_workflow_inputs - defined_inputs
                    if missing_inputs:
                        # For functional agents where Azure fetch failed
                        if not use_local_definition and azure_fetch_failed:
                            if status_info and status_info.get('agent_found'):
                                # Agent exists but input mismatch
                                errors.append(
                                    f"Agent '{agent_name}' input mismatch: workflow passes {len(filtered_workflow_inputs)} input(s) "
                                    f"[{', '.join(sorted(filtered_workflow_inputs))}] but agent declares {len(defined_inputs)} input(s) "
                                    f"[{', '.join(sorted(defined_inputs)) if defined_inputs else 'none'}]. "
                                    f"Update the agent definition to include: {', '.join(sorted(missing_inputs))}"
                                )
                            else:
                                # Agent doesn't exist
                                errors.append(f"Agent '{agent_name}' does not exist in Azure or has not been published. All functional agents must be published before being referenced in an workflow agent workflow.")
                        else:
                            # For local agents or successful Azure fetch with missing inputs
                            for missing in missing_inputs:
                                validation_message = (
                                    f"Input '{missing}' used in workflow states [{', '.join(states_list)}] "
                                    f"but not defined in agent '{agent_name}' {source_type} definition"
                                )
                                errors.append(validation_message)
                    else:
                        traces.append(f"      ✅ All inputs validated successfully")
                    
                    # Check for unused inputs (informational warning)
                    if defined_inputs:
                        unused_inputs = defined_inputs - workflow_inputs
                        if unused_inputs:
                            for unused_input in unused_inputs:
                                warning_msg = (
                                    f"Input '{unused_input}' defined in agent '{agent_name}' "
                                    f"but not used in workflow (states: {', '.join(states_list)})"
                                )
                                warnings.append(warning_msg)
                                traces.append(f"      ⚠️  {warning_msg}")
                
                except Exception as agent_err:
                    warnings.append(f"Error validating inputs for agent '{agent_name}': {str(agent_err)}")
        else:
            warnings.append("Agent manager not available - skipping agent input validation")
    
    except Exception as e:
        errors.append(f"Error during workflow agent input validation: {str(e)}")
    
    is_valid = len(errors) == 0
    return is_valid, errors, warnings, traces


# Response shape expected by UI:
#   { valid: bool, errors?: [ { path, message } ], error?: str }
# NOTE: Returns 400 for client input issues, 500 for internal errors.
@app.route('/api/workflow/validate', methods=['POST'])
def api_validate_workflow_yaml():  # pragma: no cover - HTTP route
    if validate_yaml is None:
        return jsonify({ 'valid': False, 'error': 'Validator module not available on server.' }), 500
    try:
        payload = request.get_json(silent=True) or {}
        yaml_text = payload.get('yaml')
        workflow_agent_name = payload.get('workflow_agent_name')  # Optional: agent being published
        if not yaml_text or not isinstance(yaml_text, str):
            return jsonify({
                'valid': False,
                'error': 'Missing required field "yaml" (string) in request body.'
            }), 400

        # Determine schema path (allow override) using config template_files.WorkflowDefinitionSchema as default
        schema_path = payload.get('schema_path')
        if schema_path:
            schema_file = Path(schema_path)
            if not schema_file.is_absolute():
                repo_root = Path(__file__).resolve().parents[3]
                schema_file = (repo_root / schema_path).resolve()
        else:
            schema_file = None
            if config_manager:
                try:
                    t_files = config_manager.get_template_files()
                    rel_schema = t_files.get('WorkflowDefinitionSchema') if t_files else None
                    if rel_schema:
                        candidate = Path(__file__).parent / rel_schema
                        if candidate.exists():
                            schema_file = candidate
                        else:
                            return jsonify({'valid': False, 'error': f'Configured WorkflowDefinitionSchema not found: {candidate}'}), 500
                    else:
                        return jsonify({'valid': False, 'error': 'WorkflowDefinitionSchema not configured (template_files.WorkflowDefinitionSchema missing)'}), 500
                except Exception as cfg_err:
                    return jsonify({'valid': False, 'error': f'Failed to resolve WorkflowDefinitionSchema path: {cfg_err}'}), 500
            else:
                return jsonify({'valid': False, 'error': 'Configuration manager unavailable to resolve WorkflowDefinitionSchema'}), 500

        if not schema_file or not schema_file.exists():
            return jsonify({ 'valid': False, 'error': f'Schema file not found: {schema_file}' }), 500

        result: ValidationResult = validate_yaml(str(schema_file), yaml_text)  # type: ignore
        
        # Initialize validation traces early so it can be used throughout
        validation_traces = []
        
        # Additional workflow pattern validation
        pattern_warnings = []
        pattern_errors = []
        
        try:
            from workflow_pattern_validator import validate_workflow_transitions, validate_messageid_requirements, validate_thread_variable_references
            
            # Validate workflow transition patterns
            is_pattern_valid, pattern_validation_errors, pattern_validation_warnings = validate_workflow_transitions(yaml_text)
            
            # Convert pattern validation results to the expected format
            for error in pattern_validation_errors:
                pattern_errors.append({
                    'path': 'workflow.transitions',
                    'message': f'Workflow Pattern Issue: {error}'
                })
            
            # Filter out informational messages that are not actual warnings
            # (e.g., "Good patterns found: X" or lines starting with "✅")
            for warning in pattern_validation_warnings:
                # Skip positive/informational messages
                if warning.startswith('Good patterns found:') or warning.strip().startswith('✅'):
                    # These are informational success messages, add to traces but not warnings
                    validation_traces.append(warning)
                    continue
                    
                pattern_warnings.append({
                    'path': 'workflow.transitions', 
                    'message': f'Workflow Pattern Warning: {warning}'
                })
            
            # Validate messageId requirements
            is_messageid_valid, messageid_errors, messageid_warnings = validate_messageid_requirements(yaml_text)
            
            # Add messageId validation results
            for error in messageid_errors:
                pattern_errors.append({
                    'path': 'workflow.messageId',
                    'message': error
                })
            
            for warning in messageid_warnings:
                pattern_warnings.append({
                    'path': 'workflow.messageId',
                    'message': warning
                })

            # Validate thread variable references
            is_thread_valid, thread_errors, thread_warnings = validate_thread_variable_references(yaml_text)

            for error in thread_errors:
                pattern_errors.append({
                    'path': 'workflow.variables.thread',
                    'message': error
                })

            for warning in thread_warnings:
                pattern_warnings.append({
                    'path': 'workflow.variables.thread',
                    'message': warning
                })

        except ImportError:
            # Workflow pattern validator not available, skip pattern validation
            pass
        except Exception as pattern_err:
            pattern_warnings.append({
                'path': 'workflow.validation',
                'message': f'Pattern validation error: {pattern_err}'
            })

        # Agent input validation with detailed tracing
        print("🔧 Running workflow agent input validation...")
        input_validation_errors = []
        input_validation_warnings = []
        # validation_traces already initialized above, don't reinitialize
        
        try:
            # Call validation and get detailed traces directly
            is_input_valid, input_errors, input_warnings, detailed_traces = validate_workflow_agent_inputs_with_traces(yaml_text, workflow_agent_name)
            
            # Use the detailed traces for frontend display
            if detailed_traces:
                validation_traces = detailed_traces
                print(f"DEBUG: Got {len(validation_traces)} trace lines from validation")  # Debug info
            
            # Convert input validation results to the expected format
            for error in input_errors:
                input_validation_errors.append({
                    'path': 'workflow.actors.inputs',
                    'message': f'Agent Input Issue: {error}'
                })
            
            for warning in input_warnings:
                input_validation_warnings.append({
                    'path': 'workflow.actors.inputs',
                    'message': f'Agent Input Warning: {warning}'
                })
                
            # Print summary of input validation results
            if len(input_errors) == 0 and len(input_warnings) == 0:
                print("✅ Agent input validation passed (no issues found)")
            else:
                if len(input_errors) > 0:
                    print(f"❌ Agent input validation found {len(input_errors)} error(s)")
                    for error in input_errors:
                        print(f"    ❌ {error}")
                if len(input_warnings) > 0:
                    print(f"⚠️ Agent input validation found {len(input_warnings)} warning(s)")
                    for warning in input_warnings:
                        print(f"    ⚠️  {warning}")
                
        except Exception as input_err:
            print(f"⚠️ Agent input validation error: {input_err}")
            # Fallback to original validation function if the new one fails
            try:
                is_input_valid, input_errors, input_warnings = validate_workflow_agent_inputs(yaml_text, workflow_agent_name)
                
                # Convert input validation results to the expected format
                for error in input_errors:
                    input_validation_errors.append({
                        'path': 'workflow.actors.inputs',
                        'message': f'Agent Input Issue: {error}'
                    })
                
                for warning in input_warnings:
                    input_validation_warnings.append({
                        'path': 'workflow.actors.inputs',
                        'message': f'Agent Input Warning: {warning}'
                    })
            except Exception as fallback_err:
                input_validation_warnings.append({
                    'path': 'workflow.validation',
                    'message': f'Input validation error: {fallback_err}'
                })

        # Combine schema, pattern, and input validation results
        all_errors = []
        all_warnings = []
        if not result.valid:
            all_errors.extend([{ 'path': e.path, 'message': e.message } for e in result.errors])
        all_errors.extend(pattern_errors)
        all_errors.extend(input_validation_errors)
        all_warnings.extend(pattern_warnings)
        all_warnings.extend(input_validation_warnings)

        # Add pattern warnings to validation traces so they're visible to user
        if pattern_warnings:
            validation_traces.append(f"⚠️ Workflow pattern validation found {len(pattern_warnings)} warning(s)")
            for pw in pattern_warnings:
                validation_traces.append(f"    ⚠️  {pw.get('message', 'Unknown warning')}")

        # Check for emoji warnings and add to response
        emoji_warnings = None
        if hasattr(result, 'emoji_validation') and result.emoji_validation is not None:
            if result.emoji_validation.has_emojis:
                emoji_warnings = result.emoji_validation.to_dict()
                validation_traces.append(f"⚠️ Emoji characters detected: {result.emoji_validation.emoji_count} emoji(s) found in {len(result.emoji_validation.fields_with_emojis)} field(s)")
                for ew in result.emoji_validation.warnings:
                    replacement_hint = f" (suggested: '{ew.suggested_replacement}')" if ew.suggested_replacement else ""
                    validation_traces.append(f"    ⚠️  {ew.path}.{ew.field}: emoji '{ew.emoji}' at line {ew.line}{replacement_hint}")
        
        # Return results
        if result.valid and len(pattern_errors) == 0 and len(input_validation_errors) == 0:
            response = { 'valid': True }
            if all_warnings:
                response['warnings'] = all_warnings
            if validation_traces:
                response['validation_traces'] = validation_traces
            if emoji_warnings:
                response['emoji_warnings'] = emoji_warnings
            return jsonify(response)
        else:
            response = {
                'valid': False,
                'errors': all_errors
            }
            if all_warnings:
                response['warnings'] = all_warnings
            if validation_traces:
                response['validation_traces'] = validation_traces
            if emoji_warnings:
                response['emoji_warnings'] = emoji_warnings
            return jsonify(response)
    except Exception as e:
        return jsonify({ 'valid': False, 'error': f'Internal validation error: {e}' }), 500

def execute_code_background(container, exec_command, execution_id, script_filename):
    """Execute code in background and stream output to ExecutionState"""
    print(f"TRACE: execute_code_background started - execution_id={execution_id}")
    try:
        # Get the execution state
        with execution_lock:
            if execution_id not in execution_states:
                print(f"ERROR: Execution state {execution_id} not found in background thread")
                return
            state = execution_states[execution_id]
            print(f"TRACE: execution state retrieved successfully")
        
        print(f"Starting background execution: {execution_id}")
        print(f"TRACE: container={container.name}, exec_command={exec_command}")

        # Get state directory for periodic stdout persistence
        try:
            sm = get_session_manager()
            agent_name = get_current_agent_name()
            session_dirs = sm.get_session_dirs(agent_name=agent_name)
            state_dir = session_dirs['state']
        except Exception:
            state_dir = None

        # Execute with streaming output
        exec_result = container.exec_run(
            exec_command,
            stdout=True,
            stderr=True,
            stream=True,  # Enable streaming
            demux=True
        )
        
        # Store exec_id in state for cancellation support
        if hasattr(exec_result, 'id'):
            with execution_lock:
                state.exec_id = exec_result.id
        
        # Stream output in real-time
        try:
            if hasattr(exec_result, 'output') and exec_result.output is not None:
                for chunk in exec_result.output:
                    # Check for cancellation request
                    if state.cancel_requested:
                        print(f"Execution {execution_id} cancelled by user")
                        state.append_stderr("\n🛑 Execution cancelled by user\n")
                        break
                    
                    if chunk is None:
                        continue
                    
                    # Handle tuple format: when demux=True, Docker returns (stdout_data, stderr_data)
                    if isinstance(chunk, tuple) and len(chunk) == 2:
                        stdout_data, stderr_data = chunk
                        if stdout_data:
                            chunk_str = stdout_data.decode('utf-8')
                            state.append_stdout(chunk_str)
                        if stderr_data:
                            chunk_str = stderr_data.decode('utf-8')
                            state.append_stderr(chunk_str)
                    else:
                        # Handle raw data (fallback for non-demux mode)
                        if chunk:
                            chunk_str = chunk.decode('utf-8') if isinstance(chunk, bytes) else str(chunk)
                            state.append_stdout(chunk_str)

                    # Periodically save stdout for session restoration during execution
                    if state_dir:
                        state.save_stdout_if_needed(state_dir)

            # Get final exit code
            exit_code = getattr(exec_result, 'exit_code', 0)
            if exit_code is None:
                exit_code = 0  # Default to success if exit_code is None
            
            # Initialize error message
            error_msg = None
            
            # Mark as cancelled if cancellation was requested
            if state.cancel_requested:
                exit_code = -1  # Use -1 to indicate cancellation
                error_msg = "Execution cancelled by user"
            
        except Exception as streaming_error:
            print(f"Error during streaming for {execution_id}: {streaming_error}")
            # Fallback to non-streaming
            try:
                exec_result = container.exec_run(
                    exec_command,
                    stdout=True,
                    stderr=True,
                    stream=False,
                    demux=True
                )
                
                if exec_result.output:
                    if isinstance(exec_result.output, tuple):
                        stdout_bytes, stderr_bytes = exec_result.output
                        if stdout_bytes:
                            state.append_stdout(stdout_bytes.decode('utf-8'))
                        if stderr_bytes:
                            state.append_stderr(stderr_bytes.decode('utf-8'))
                    else:
                        state.append_stdout(exec_result.output.decode('utf-8'))
                
                exit_code = getattr(exec_result, 'exit_code', 0)
                if exit_code is None:
                    exit_code = 0  # Default to success if exit_code is None
            except Exception as fallback_error:
                print(f"Fallback execution failed for {execution_id}: {fallback_error}")
                exit_code = 1
                state.mark_completed(exit_code, str(fallback_error))
                return
        
        # Update output files and persist stdout
        try:
            # Get session-specific directories
            sm = get_session_manager()
            agent_name = get_current_agent_name()
            session_dirs = sm.get_session_dirs(agent_name=agent_name)
            shared_output_dir = session_dirs['output']
            state_dir = session_dirs['state']
            files = []
            if os.path.exists(shared_output_dir):
                for file in os.listdir(shared_output_dir):
                    if os.path.isfile(os.path.join(shared_output_dir, file)):
                        files.append(file)
            state.update_output_files(files)

            # Persist execution output to state directory for session restoration (JSON format)
            try:
                os.makedirs(state_dir, exist_ok=True)
                stdout_file = os.path.join(state_dir, 'stdout.json')
                output_data = {
                    'stdout': state.stdout_buffer,
                    'stderr': state.stderr_buffer,
                    'exit_code': exit_code,
                    'execution_id': execution_id
                }
                with open(stdout_file, 'w', encoding='utf-8') as f:
                    json.dump(output_data, f)
            except Exception as save_err:
                print(f"⚠️ Warning: Could not save stdout to file: {save_err}")
        except Exception as file_error:
            print(f"Warning: Could not update output files for {execution_id}: {file_error}")

        # Mark execution as completed
        # Note: error_msg may already be set by cancellation logic above
        if error_msg is None and exit_code != 0:
            error_msg = f"Process exited with code {exit_code}"
        
        state.mark_completed(exit_code, error_msg)
        print(f"Background execution completed: {execution_id} (exit code: {exit_code})")
        
    except Exception as e:
        print(f"Background execution failed for {execution_id}: {e}")
        with execution_lock:
            if execution_id in execution_states:
                execution_states[execution_id].mark_completed(1, str(e))

@app.route('/api/execute', methods=['POST'])
def execute_code():
    """Execute Python code in Docker container with background execution and real-time streaming"""
    try:
        # Defensive: ensure background-execution globals exist. In some partial-import or
        # error-during-import scenarios the module-level declarations may not have run,
        # which causes NameError when referencing these names. Create them on demand.
        if 'execution_lock' not in globals():
            try:
                globals()['execution_lock'] = threading.Lock()
                print("NOTE: created missing execution_lock at runtime")
            except Exception:
                # If threading isn't available for some reason, set a dummy lock object
                class _DummyLock:
                    def __enter__(self): pass
                    def __exit__(self, exc_type, exc, tb): return False
                globals()['execution_lock'] = _DummyLock()

        if 'execution_states' not in globals():
            globals()['execution_states'] = {}

        data = request.get_json()

        code = data.get('code', '')
        language = data.get('language', None)  # Let auto-detection work if not specified
        background = data.get('background', True)  # Default to background execution

        if not code:
            return jsonify({'error': 'No code provided'}), 400

        # Auto-detect language if not explicitly provided
        if not language:
            script_type, is_action_command = detect_script_type(code)
            if script_type == 'shell' or is_action_command:
                language = 'bash'
            else:
                language = 'python'
            print(f"🔍 Auto-detected language: {language} (script_type={script_type}, is_action={is_action_command})")
        else:
            print(f"🔍 Using provided language: {language}")
        
        if not docker_client:
            return jsonify({'error': 'Docker client not available'}), 500

        # Ensure shared directories exist so writing the script will succeed
        try:
            print("Ensuring shared directories exist...")
            shared_dirs = ensure_shared_directories(agent_name=get_current_agent_name())

            # Clear contents of workdir and output directories before each run (keep directories)
            workdir_path = shared_dirs['workdir']
            output_path = shared_dirs['output']
            
            # Clear workdir contents (remove all files, keep directory)
            if os.path.exists(workdir_path):
                for filename in os.listdir(workdir_path):
                    file_path = os.path.join(workdir_path, filename)
                    try:
                        if os.path.isfile(file_path) or os.path.islink(file_path):
                            os.unlink(file_path)
                        elif os.path.isdir(file_path):
                            import shutil
                            shutil.rmtree(file_path)
                    except Exception as e:
                        print(f"⚠️ Failed to delete {file_path}: {e}")
            
            # Clear output directory contents (remove all files, keep directory)
            if os.path.exists(output_path):
                for filename in os.listdir(output_path):
                    file_path = os.path.join(output_path, filename)
                    try:
                        if os.path.isfile(file_path) or os.path.islink(file_path):
                            os.unlink(file_path)
                        elif os.path.isdir(file_path):
                            import shutil
                            shutil.rmtree(file_path)
                    except Exception as e:
                        print(f"⚠️ Failed to delete {file_path}: {e}")
            
            print(f"✅ Cleared workdir and output directory contents")
            
        except Exception as edir:
            print(f"⚠️ Warning: Directory preparation failed: {edir}")
            return jsonify({'error': f'Failed to prepare shared directories: {edir}'}), 500
        
        # Optional explicit container name provided by client
        explicit_container_name = None
        if isinstance(data.get('containerName', None), str):
            explicit_container_name = data.get('containerName')
        elif isinstance(data.get('container_name', None), str):
            explicit_container_name = data.get('container_name')

        # Resolve the running container using several fallbacks so we don't fail on minor name mismatches
        container = None
        resolve_attempts = []
        try:
            # If caller provided an explicit container name, try to use it first
            if explicit_container_name:
                resolve_attempts.append(('explicit container', explicit_container_name))
                try:
                    c = docker_client.containers.get(explicit_container_name)
                    if c.status == 'running':
                        container = c
                    else:
                        return jsonify({'error': f'Explicit container {explicit_container_name} is not running'}), 400
                except Exception as ex_cont:
                    print(f"Warning: explicit container lookup failed for {explicit_container_name}: {ex_cont}")
                    # continue to resolver if explicit lookup fails
                    pass

            # Get the current agent from session (session-scoped, not global)
            authoritative_agent = get_current_agent_name()

            # Track if we found an exited container (for better error messages)
            exited_container = None

            # 1) Try the module-global CONTAINER_NAME if set and not the placeholder
            current_container_name = globals().get('CONTAINER_NAME')
            if current_container_name and current_container_name != 'unknown-container':
                resolve_attempts.append(('global CONTAINER_NAME', current_container_name))
                try:
                    c = docker_client.containers.get(current_container_name)
                    if c.status == 'running':
                        container = c
                    elif c.status == 'exited' and not exited_container:
                        exited_container = c  # Track for error reporting
                except Exception:
                    pass

            # 2) Try catalog current agent first (most authoritative)
            if not container and authoritative_agent:
                candidate = get_normalized_container_name(authoritative_agent)
                resolve_attempts.append(('catalog current agent', candidate))
                try:
                    c = docker_client.containers.get(candidate)
                    if c.status == 'running':
                        container = c
                    elif c.status == 'exited' and not exited_container:
                        exited_container = c
                except Exception:
                    pass

            # 3) Try agent_name global (fallback for compatibility)
            if not container:
                last_agent = globals().get('agent_name')
                if last_agent and last_agent != authoritative_agent:  # Avoid duplicate attempt
                    candidate = get_normalized_container_name(last_agent)
                    resolve_attempts.append(('fallback global agent_name', candidate))
                    try:
                        c = docker_client.containers.get(candidate)
                        if c.status == 'running':
                            container = c
                        elif c.status == 'exited' and not exited_container:
                            exited_container = c
                    except Exception:
                        pass

            # 4) Search running containers by matching image tag from tool definition
            if not container:
                resolve_attempts.append(('search by tool-derived image', 'scanning local containers'))
                try:
                    # Derive the authoritative image name from the tool definition (source of truth)
                    agent_key = authoritative_agent or globals().get('agent_name')
                    if agent_key:
                        try:
                            derived_image, _ = _derive_image_name_from_tool_definition(agent_key)
                            if derived_image:
                                # List containers and try to find a running container with this exact image
                                all_containers = docker_client.containers.list()
                                for c in all_containers:
                                    try:
                                        tags = c.image.tags or []
                                        # Only match containers that use the tool-derived image name
                                        if c.status == 'running' and any(derived_image in t for t in tags):
                                            container = c
                                            break
                                    except Exception:
                                        continue
                        except Exception:
                            print(f"Warning: could not derive image name from tool definition for {agent_key}")
                except Exception as scan_err:
                    print(f"Warning: error scanning local containers for execution target: {scan_err}")

            # If still not found, provide a helpful error including attempted candidates
            if not container:
                attempts_text = ', '.join([f"{k}={v}" for k, v in resolve_attempts])

                # If we found an exited container, provide more helpful diagnostics
                if exited_container:
                    try:
                        # Get container exit info
                        exit_code = exited_container.attrs.get('State', {}).get('ExitCode', 'unknown')
                        # Get last few lines of logs for diagnosis
                        logs = exited_container.logs(tail=20).decode('utf-8', errors='replace').strip()
                        error_msg = (
                            f"Container '{exited_container.name}' crashed immediately after starting (exit code: {exit_code}). "
                            f"This usually means the Dockerfile's ENTRYPOINT/CMD conflicts with the workbench's 'sleep infinity' keep-alive command. "
                            f"Fix: Ensure your Dockerfile ends with 'CMD [\"/bin/bash\"]' (no ENTRYPOINT). "
                            f"Last logs: {logs[-500:] if len(logs) > 500 else logs}"
                        )
                        return jsonify({'error': error_msg}), 500
                    except Exception as log_err:
                        return jsonify({'error': f"Container '{exited_container.name}' crashed immediately. Check Dockerfile ENTRYPOINT/CMD. (Log fetch failed: {log_err})"}), 500

                return jsonify({'error': f'Discovery agent container not found or not running. Attempts: {attempts_text}'}), 500

            # If we found a container, ensure globals AND session reflect it for future calls
            try:
                globals()['CONTAINER_NAME'] = container.name
                # If agent_name not set, try to infer from container name (strip suffix)
                inferred_agent = None
                if not globals().get('agent_name'):
                    inferred_agent = container.name.replace('-container', '')
                    globals()['agent_name'] = inferred_agent
                else:
                    inferred_agent = globals().get('agent_name')

                # CRITICAL FIX: Sync session agent with resolved container's agent
                # This fixes the case where session shows 'discovery_assistant' but container is 'psi4-container'
                if inferred_agent:
                    session_agent = get_current_agent_name()
                    if session_agent != inferred_agent:
                        print(f"🔄 Session agent mismatch detected: session={session_agent}, container={inferred_agent}")
                        sm = get_session_manager()
                        if sm and sm.current_session_id:
                            # Determine agent type
                            agent_type = 'tool'
                            if agent_manager and agent_manager.agent_exists(inferred_agent, 'kb'):
                                agent_type = 'kb'
                            elif agent_manager and agent_manager.agent_exists(inferred_agent, 'entry'):
                                agent_type = 'entry'
                            sm.update_session(sm.current_session_id, agent_name=inferred_agent, agent_type=agent_type)
                            print(f"✅ Synced session agent to: {inferred_agent} (type: {agent_type})")

                if VERBOSE_TRACING:
                    try:
                        img_tags = container.image.tags if container.image else 'unknown'
                    except Exception:
                        img_tags = 'unknown'
                    print(f"🔧 Resolved execution container: {container.name} (image: {img_tags})")
            except Exception:
                pass
        except Exception as e:
            print(f"❌ Error resolving execution container: {e}")
            return jsonify({'error': f'Error resolving execution container: {str(e)}'}), 500

        # Validate container mounts match current session directories
        current_agent = get_current_agent_name()
        mounts_valid, mount_msg = validate_container_mounts(container, current_agent)
        if not mounts_valid:
            print(f"🔄 Container {container.name} has stale mounts for execute, auto-recreating...")
            print(f"   {mount_msg}")

            # Auto-recreate container with correct mounts
            container_name_to_recreate = container.name
            try:
                # Stop and remove the stale container
                if container.status == 'running':
                    container.stop()
                container.remove()
                print(f"🗑️ Removed container with stale mounts: {container_name_to_recreate}")

                # Get the image name for this agent
                try:
                    image_name, _ = _derive_image_name_from_tool_definition(current_agent)
                except Exception as img_err:
                    return jsonify({'error': f'Could not determine image for agent {current_agent}: {img_err}'}), 500

                # Recreate the container with correct session mounts
                result = start_agent_container(current_agent, image_name, container_name_to_recreate)
                if not result.get('success'):
                    return jsonify({'error': f'Failed to recreate container: {result.get("error", "Unknown error")}'}), 500

                # Get the newly created container
                container = docker_client.containers.get(container_name_to_recreate)
                print(f"✅ Recreated container {container_name_to_recreate} with correct session mounts")

            except Exception as recreate_err:
                print(f"❌ Failed to auto-recreate container: {recreate_err}")
                return jsonify({
                    'error': f'Failed to recreate container with correct mounts: {recreate_err}',
                    'details': mount_msg
                }), 500

        # Create a unique filename for this execution
        execution_id = str(uuid.uuid4())[:8]
        
        # Determine file extension and execution command based on language
        if language == 'bash' or language == 'sh' or language == 'shell':
            # For bash commands, create a .sh file and execute it
            script_filename = f"user_script_{execution_id}.sh"
            script_extension = 'sh'
            exec_command = f"bash -c 'cd /workdir && bash {script_filename}'"
            print(f"📝 Executing bash script: {script_filename}")
        else:
            # Default to Python execution
            script_filename = f"user_script_{execution_id}.py"
            script_extension = 'py'
            exec_command = f"bash -c 'cd /workdir && python3 -u {script_filename}'"
            print(f"📝 Executing Python script: {script_filename}")
        
        # Write code to shared workdir directory (mounted as /workdir in container)
        # Use session-aware directories
        shared_workdir = shared_dirs['workdir']
        script_path = os.path.join(shared_workdir, script_filename)
        
        with open(script_path, 'w', encoding='utf-8', newline='\n') as f:
            # Add shebang for bash scripts if not present
            if script_extension == 'sh' and not code.strip().startswith('#!'):
                f.write('#!/bin/bash\n')
            f.write(code)
        
        # Ensure file is fully written to disk
        import time
        time.sleep(0.3)  # Increased delay to ensure file is flushed and visible to container
        
        # Make bash scripts executable
        if script_extension == 'sh':
            import stat
            os.chmod(script_path, os.stat(script_path).st_mode | stat.S_IEXEC)
        
        # Verify container can see the script file (Docker-in-Docker volume mount propagation check)
        # Try quick retries first before expensive container restart
        file_visible = False
        quick_retries = 3
        try:
            # Reload container object to ensure fresh state before file checks
            container.reload()
            
            for quick_attempt in range(quick_retries):
                # Add small delay before first check to let Docker settle
                if quick_attempt == 0:
                    time.sleep(0.1)
                
                # Use ls command instead of test -f (more reliable with Docker SDK)
                check_result = container.exec_run(f"ls /workdir/{script_filename}", stdout=True, stderr=True)
                print(f"TRACE: quick file check attempt {quick_attempt + 1}/{quick_retries} - exit_code={check_result.exit_code}")
                
                if check_result.exit_code == 0:
                    file_visible = True
                    print(f"✅ File visible to container on quick attempt {quick_attempt + 1}")
                    break
                else:
                    # File not found or exec issue - wait a bit for sync
                    if quick_attempt < quick_retries - 1:
                        time.sleep(0.3)
                        continue
            
            # Only proceed with fallback if quick retries failed
            if not file_visible:
                # Check if the container's volume mount matches the current session's workdir
                # This can happen when the session changes but an existing container is reused
                try:
                    container_mounts = container.attrs.get('Mounts', [])
                    container_workdir_source = None
                    for mount in container_mounts:
                        if mount.get('Destination') == '/workdir':
                            container_workdir_source = mount.get('Source')
                            break

                    expected_workdir = os.path.abspath(shared_workdir)

                    if container_workdir_source and os.path.abspath(container_workdir_source) != expected_workdir:
                        # Volume mount mismatch detected - need to recreate container with correct mounts
                        print(f"⚠️ Volume mount mismatch detected:")
                        print(f"   Container mount: {container_workdir_source}")
                        print(f"   Current session: {expected_workdir}")
                        print(f"🔄 Recreating container with correct volume mounts...")

                        # Get current agent name and container name
                        current_agent = get_current_agent_name()
                        current_container_name = container.name

                        # Get the image name from the current container
                        container_image = container.image.tags[0] if container.image.tags else container.image.id

                        # Stop and remove the container
                        try:
                            container.stop(timeout=5)
                        except Exception:
                            pass
                        try:
                            container.remove(force=True)
                        except Exception as rm_err:
                            print(f"⚠️ Could not remove container: {rm_err}")

                        # Start a new container with correct mounts
                        start_result = start_agent_container(current_agent, container_image, current_container_name)
                        if start_result.get('success'):
                            print(f"✅ Container recreated with correct mounts")
                            # Get the new container
                            container = docker_client.containers.get(current_container_name)
                            file_visible = True  # Script should now be visible via correct mount
                        else:
                            return jsonify({'error': f"Failed to recreate container: {start_result.get('error')}"}), 500
                    else:
                        # Volume mount matches but file still not visible - try docker cp as fallback
                        print(f"⚠️ Volume mount appears correct but file not visible, trying docker cp as fallback...")
                        try:
                            # Use put_archive to copy the file into the container
                            import tarfile
                            import io

                            # Read the script content
                            with open(script_path, 'rb') as f:
                                script_content = f.read()

                            # Create a tar archive in memory containing the script
                            tar_stream = io.BytesIO()
                            with tarfile.open(fileobj=tar_stream, mode='w') as tar:
                                tarinfo = tarfile.TarInfo(name=script_filename)
                                tarinfo.size = len(script_content)
                                tarinfo.mode = 0o755 if script_extension == 'sh' else 0o644
                                tar.addfile(tarinfo, io.BytesIO(script_content))
                            tar_stream.seek(0)

                            # Copy to container's /workdir
                            container.put_archive('/workdir', tar_stream)
                            print(f"✅ Script copied to container via docker cp (fallback)")

                            # Verify the file is now visible
                            verify_result = container.exec_run(f"ls /workdir/{script_filename}", stdout=True, stderr=True)
                            if verify_result.exit_code == 0:
                                file_visible = True
                                print(f"✅ File verified in container after docker cp")
                        except Exception as cp_err:
                            print(f"⚠️ Docker cp fallback failed: {cp_err}")
                except Exception as mount_check_error:
                    print(f"⚠️ Could not check container mounts: {mount_check_error}")

                # If docker cp didn't resolve it, try container restart as last resort
                if not file_visible:
                    print(f"⚠️ Attempting container restart as last resort...")
                    container.restart(timeout=10)
                    print(f"✅ Container restarted: {container.name}")

                    # Retry mechanism with exponential backoff (only if file still not visible)
                    max_retries = 3
                    wait_times = [3, 5, 8]  # Progressive wait times: 3s, 5s, 8s

                    for retry in range(max_retries):
                        wait_time = wait_times[retry]
                        print(f"TRACE: retry {retry + 1}/{max_retries} - waiting {wait_time} seconds for container to be ready...")
                        time.sleep(wait_time)

                        # Verify the container is actually running
                        container.reload()
                        print(f"TRACE: container status after restart (attempt {retry + 1}): {container.status}")
                        if container.status != 'running':
                            print(f"⚠️ Container not running on attempt {retry + 1}, status: {container.status}")
                            if retry == max_retries - 1:  # Last attempt
                                return jsonify({'error': f'Container failed to start properly after restart. Status: {container.status}'}), 500
                            continue

                        # Try the file check again with error handling
                        try:
                            check_result = container.exec_run(f"test -f /workdir/{script_filename}", stdout=False, stderr=False)
                            print(f"TRACE: file check attempt {retry + 1} - exit_code={check_result.exit_code}")

                            if check_result.exit_code is None:
                                # Docker exec failed - try a simpler command first
                                print(f"TRACE: exec_run returned None on attempt {retry + 1}, testing container connectivity...")
                                test_result = container.exec_run("echo 'test'", stdout=True, stderr=False)
                                print(f"TRACE: simple test command - exit_code={test_result.exit_code}")
                                if test_result.exit_code is None:
                                    print(f"⚠️ Container not responding to exec commands on attempt {retry + 1}")
                                    if retry == max_retries - 1:  # Last attempt
                                        return jsonify({'error': f'Container is not responding to exec commands after restart. Docker may need to be restarted.'}), 500
                                    continue
                                else:
                                    # Container works but file check returned None - this can happen with some Docker versions
                                    # Try a more robust file check using ls
                                    print(f"TRACE: Container responsive, trying alternative file check...")
                                    ls_result = container.exec_run(f"ls -la /workdir/{script_filename}", stdout=True, stderr=True)
                                    print(f"TRACE: ls command - exit_code={ls_result.exit_code}")
                                    if ls_result.exit_code == 0:
                                        print(f"✅ File found via ls command on attempt {retry + 1}")
                                        break  # Success! File is visible
                                    else:
                                        print(f"⚠️ File not found via ls command on attempt {retry + 1}")
                                        if retry == max_retries - 1:  # Last attempt
                                            return jsonify({'error': f'Container cannot access script file even after restart and retries. Volume mount may be misconfigured.'}), 500
                                        continue
                            elif check_result.exit_code != 0:
                                print(f"⚠️ File not visible on attempt {retry + 1}")
                                if retry == max_retries - 1:  # Last attempt
                                    print(f"❌ Container still cannot see script after restart and all retries")
                                    return jsonify({'error': f'Container cannot access script file after restart and {max_retries} retries. Volume mount may be misconfigured.'}), 500
                                continue
                            else:
                                print(f"✅ Container can see script file after restart (attempt {retry + 1})")
                                break  # Success! Exit the retry loop

                        except Exception as exec_err:
                            print(f"❌ Error executing commands in container on attempt {retry + 1}: {exec_err}")
                            if retry == max_retries - 1:  # Last attempt
                                import traceback
                                print(f"Full traceback: {traceback.format_exc()}")
                                return jsonify({'error': f'Failed to execute commands in container after restart and retries: {exec_err}'}), 500
                            continue
                        
        except Exception as check_err:
            print(f"⚠️ Warning: Could not verify script visibility in container: {check_err}")
            import traceback
            print(f"Full traceback: {traceback.format_exc()}")
            # Don't fail here - continue with execution attempt
        
        if background:
            # Background execution with real-time streaming
            # Create execution state
            try:
                state = ExecutionState(execution_id, script_filename, container=container)
                with execution_lock:
                    execution_states[execution_id] = state
                    print(f"TRACE: execution state stored, total states: {len(execution_states)}")
                
                # Start background execution
                thread = threading.Thread(
                    target=execute_code_background,
                    args=(container, exec_command, execution_id, script_filename),
                    daemon=True
                )
                thread.start()
            except Exception as bg_err:
                print(f"❌ Error in background execution setup: {bg_err}")
                import traceback
                print(f"Full traceback: {traceback.format_exc()}")
                raise
            
            # Return immediately with execution ID for polling
            return jsonify({
                'success': True,
                'execution_id': execution_id,
                'message': 'Execution started in background',
                'background': True,
                'polling_url': f'/api/execution-status/{execution_id}'
            })
        
        else:
            # Legacy synchronous execution (kept for compatibility)
            exec_result = container.exec_run(
                exec_command,
                stdout=True,
                stderr=True,
                stream=True,
                demux=True
            )
            
            # Collect outputs from stream
            stdout_output = ""
            stderr_output = ""
            
            try:
                if hasattr(exec_result, 'output') and exec_result.output is not None:
                    for chunk in exec_result.output:
                        if chunk is None:
                            continue
                        
                        if isinstance(chunk, tuple) and len(chunk) == 2:
                            stdout_data, stderr_data = chunk
                            if stdout_data:
                                chunk_str = stdout_data.decode('utf-8')
                                stdout_output += chunk_str
                            if stderr_data:
                                chunk_str = stderr_data.decode('utf-8')
                                stderr_output += chunk_str
                        else:
                            if chunk:
                                chunk_str = chunk.decode('utf-8') if isinstance(chunk, bytes) else str(chunk)
                                stdout_output += chunk_str
                
            except Exception as e:
                print(f"Error during streaming: {e}")
                # Fallback to non-streaming
                exec_result = container.exec_run(
                    exec_command,
                    stdout=True,
                    stderr=True,
                    stream=False,
                    demux=True
                )
                
                if exec_result.output:
                    if isinstance(exec_result.output, tuple):
                        stdout_bytes, stderr_bytes = exec_result.output
                        stdout_output = stdout_bytes.decode('utf-8') if stdout_bytes else ""
                        stderr_output = stderr_bytes.decode('utf-8') if stderr_bytes else ""
                    else:
                        stdout_output = exec_result.output.decode('utf-8')
            
            # Check for output files (use session-aware directories)
            output_files = []
            try:
                shared_output_dir = shared_dirs['output']
                if os.path.exists(shared_output_dir):
                    for file in os.listdir(shared_output_dir):
                        if os.path.isfile(os.path.join(shared_output_dir, file)):
                            output_files.append(file)
            except Exception as e:
                print(f"Warning: Could not process output files: {e}")
            
            # Determine exit code
            exit_code = getattr(exec_result, 'exit_code', 0)
            # Some Docker SDK calls return exit_code=None for successful runs when using streaming.
            # Treat None as success (0) to avoid incorrectly marking executions as failed.
            if exit_code is None:
                exit_code = 0
            if stderr_output and "Error" in stderr_output:
                exit_code = 1

            if VERBOSE_TRACING:
                try:
                    print(f"TRACE: execute_code sync result - execution_id={execution_id}, exit_code={exit_code}, stdout_len={len(stdout_output)}, stderr_len={len(stderr_output)}")
                except Exception:
                    pass

            # Persist stdout to state directory for session restoration (JSON format)
            try:
                os.makedirs(shared_dirs['state'], exist_ok=True)
                stdout_file = os.path.join(shared_dirs['state'], 'stdout.json')
                output_data = {
                    'stdout': stdout_output,
                    'stderr': stderr_output,
                    'exit_code': exit_code,
                    'execution_id': execution_id
                }
                with open(stdout_file, 'w', encoding='utf-8') as f:
                    json.dump(output_data, f)
            except Exception as save_err:
                print(f"Warning: Could not save stdout to file: {save_err}")

            if exit_code == 0:
                return jsonify({
                    'success': True,
                    'output': stdout_output,
                    'errors': stderr_output if stderr_output else None,
                    'output_files': output_files,
                    'execution_id': execution_id,
                    'execution_completed': True,
                    'background': False
                })
            else:
                return jsonify({
                    'success': False,
                    'output': stdout_output,
                    'errors': stderr_output,
                    'output_files': output_files,
                    'execution_id': execution_id,
                    'execution_completed': True,
                    'background': False
                })
            
    except Exception as e:
        print(f"❌ /api/execute unexpected error: {e}")
        import traceback
        print(f"Full traceback: {traceback.format_exc()}")
        return jsonify({'error': str(e)}), 500


# ============================================================================
# LOCAL DOCKER INTERACTIVE MODE
# ============================================================================
# These endpoints support interactive debugging sessions for local Docker
# containers, similar to the supercomputer interactive mode.

class InteractiveSession:
    """Track state of a local Docker interactive debugging session"""
    def __init__(self, session_id: str, container_name: str, tunnel_name: str):
        self.session_id = session_id
        self.container_name = container_name
        self.tunnel_name = tunnel_name
        self.stdout_buffer = ""
        self.stderr_buffer = ""
        self.is_running = True
        self.is_connected = False
        self.auth_code = None
        self.auth_url = "https://github.com/login/device"
        self.workspace_dir = '/workspace'  # Will be updated when parsed from logs
        self.access_url = f"https://vscode.dev/tunnel/{tunnel_name}/workspace"
        self.vscode_command = f"code --remote tunnel+{tunnel_name} /workspace"
        self.workspace_ready = False  # True when "Final workspace directory" is detected
        self.exec_id = None  # Docker exec ID for inspection
        self.start_time = datetime.now(timezone.utc)
        self.timeout_minutes = 30
        self.lock = threading.Lock()
        self.script_path = None  # Path to user's script (if any)
        self.session_stdout_event_id = f"session-stdout-{self.session_id}"  # Unique event ID for all stdout
        self._session_stdout_sent = False  # Track if we've sent the first stdout event
        self._session_stdout_details = ""  # Accumulated stdout history for details field
    
    def append_stdout(self, data: str):
        with self.lock:
            self.stdout_buffer += data
            # Also keep _session_stdout_details in sync (normalized line endings)
            data_normalized = data.replace('\r\n', '\n').replace('\r', '')
            self._session_stdout_details += data_normalized
            # Try to extract auth code from output
            self._parse_auth_code()
    
    def append_stderr(self, data: str):
        with self.lock:
            self.stderr_buffer += data
    
    def _parse_auth_code(self):
        """Parse auth code from tunnel output, or detect if no auth required or tunnel failed"""
        
        import re
        
        # Always extract the actual workspace directory from logs (even if auth_code already set)
        # Try multiple patterns to handle different log formats
        workspace_path = None
        
        # Pattern 1: Look for "[tunnel] Final workspace directory: /path/to/workspace"
        workspace_match = re.search(r'\[tunnel\] Final workspace directory:\s*(/[^\s]+)', self.stdout_buffer)
        if workspace_match:
            workspace_path = workspace_match.group(1)
        
        # Pattern 2: Extract from "code --remote tunnel+{tunnel_name} /path" commands
        if not workspace_path:
            code_cmd_match = re.search(r'code\s+--remote\s+tunnel\+\w+\s+(/[^\s]+)', self.stdout_buffer)
            if code_cmd_match:
                workspace_path = code_cmd_match.group(1)
        
        # Pattern 3: Extract from "Workspace directory:" or "Workspace path:" patterns
        if not workspace_path:
            workspace_label_match = re.search(r'(?:workspace\s+(?:directory|path)\s*:\s*)(/[^\s]+)', self.stdout_buffer, re.IGNORECASE)
            if workspace_label_match:
                workspace_path = workspace_label_match.group(1)
        
        # Pattern 4: Extract from "select: /path" patterns
        if not workspace_path:
            select_match = re.search(r'select:\s+(/[^\s]+)', self.stdout_buffer)
            if select_match:
                workspace_path = select_match.group(1)
        
        # If we found a workspace path, update the URLs and commands
        if workspace_path:
            self.workspace_dir = workspace_path
            new_access_url = f"https://vscode.dev/tunnel/{self.tunnel_name}{workspace_path}"
            new_vscode_command = f"code --remote tunnel+{self.tunnel_name} {workspace_path}"
            if new_access_url != self.access_url:
                self.access_url = new_access_url
                self.vscode_command = new_vscode_command
                print(f"   📂 Updated workspace path to: {workspace_path}")
            # Mark workspace as ready once we've found the workspace path
            if not self.workspace_ready:
                self.workspace_ready = True
                print(f"   ✅ Workspace ready: {workspace_path}")
                # Emit SSE event for workspace ready
                if SSE_AVAILABLE:
                    event_bus.publish(
                        EventChannel.INTERACTIVE,
                        f"Workspace ready at {workspace_path}",
                        level=EventLevel.SUCCESS,
                        context={
                            'session_id': self.session_id,
                            'workspace_ready': True,
                            'workspace_path': workspace_path,
                            'workspace_dir': workspace_path,
                            'access_url': new_access_url,
                            'vscode_command': new_vscode_command
                        },
                        event_id=f"workspace-ready-{self.session_id}"
                    )
        
        # If auth_code already found (and not NO_AUTH_REQUIRED), don't re-parse auth status
        if self.auth_code and self.auth_code != 'NO_AUTH_REQUIRED':
            return
        
        # Check if tunnel download/setup failed
        if 'ERROR: Failed to download VS Code CLI' in self.stdout_buffer or \
           'Could not set up VS Code tunnel' in self.stdout_buffer:
            if self.auth_code != 'TUNNEL_FAILED':
                self.auth_code = 'TUNNEL_FAILED'
                print(f"   ❌ Tunnel setup failed for session {self.session_id}")
                # Emit SSE event for tunnel failure
                if SSE_AVAILABLE:
                    event_bus.publish(
                        EventChannel.INTERACTIVE,
                        "Tunnel setup failed",
                        level=EventLevel.ERROR,
                        context={
                            'session_id': self.session_id,
                            'auth_code': 'TUNNEL_FAILED',
                            'tunnel_failed': True
                        }
                    )
            return
        
        # Check if no auth is required (tunnel already authenticated or session ready)
        if 'No auth required' in self.stdout_buffer or \
           'TUNNEL READY' in self.stdout_buffer or \
           'INTERACTIVE SESSION READY' in self.stdout_buffer:
            if self.auth_code != 'NO_AUTH_REQUIRED':
                self.auth_code = 'NO_AUTH_REQUIRED'
                # Emit SSE event for no auth required
                if SSE_AVAILABLE:
                    event_bus.publish(
                        EventChannel.INTERACTIVE,
                        "Tunnel authenticated - no auth code required",
                        level=EventLevel.SUCCESS,
                        context={
                            'session_id': self.session_id,
                            'auth_code': 'NO_AUTH_REQUIRED',
                            'no_auth_required': True
                        },
                        event_id=f"tunnel-auth-{self.session_id}"
                    )
                # If session is ready, also mark workspace as ready
                if 'INTERACTIVE SESSION READY' in self.stdout_buffer and not self.workspace_ready:
                    self.workspace_ready = True
                    print(f"   ✅ Interactive session ready")
                    if SSE_AVAILABLE:
                        event_bus.publish(
                            EventChannel.INTERACTIVE,
                            "Interactive session ready",
                            level=EventLevel.SUCCESS,
                            context={
                                'session_id': self.session_id,
                                'workspace_ready': True,
                                'access_url': self.access_url,
                                'vscode_command': self.vscode_command
                            }
                        )
            return
        
        # Look for GitHub device code pattern
        # VS Code CLI outputs: "use code XXXX-XXXX" or "enter the code XXXX-XXXX"
        patterns = [
            r'use code\s+([A-Z0-9]{4}-[A-Z0-9]{4})',  # "use code 108A-26C7"
            r'enter the code\s+([A-Z0-9]{4}-[A-Z0-9]{4})',
            r'code:\s*([A-Z0-9]{4}-[A-Z0-9]{4})',
            r'\[TUNNEL_AUTH_CODE\]\s*([A-Z0-9]{4}-[A-Z0-9]{4})',
            r'and use code\s+([A-Z0-9]{4}-[A-Z0-9]{4})',  # "and use code 108A-26C7"
        ]
        for pattern in patterns:
            match = re.search(pattern, self.stdout_buffer, re.IGNORECASE)
            if match:
                detected_code = match.group(1)
                if self.auth_code != detected_code:
                    self.auth_code = detected_code
                    print(f"   🔐 Detected auth code: {self.auth_code}")
                    # Emit SSE event for auth code
                    if SSE_AVAILABLE:
                        event_bus.publish(
                            EventChannel.INTERACTIVE,
                            f"Authentication required - use code {self.auth_code}",
                            level=EventLevel.INFO,
                            context={
                                'session_id': self.session_id,
                                'auth_code': self.auth_code,
                                'auth_url': self.auth_url,
                                'auth_required': True
                            }
                        )
                break
    
    def get_status(self):
        with self.lock:
            elapsed = (datetime.now(timezone.utc) - self.start_time).total_seconds() / 60
            remaining = max(0, self.timeout_minutes - elapsed)
            
            return {
                'session_id': self.session_id,
                'container_name': self.container_name,
                'tunnel_name': self.tunnel_name,
                'is_running': self.is_running,
                'is_connected': self.is_connected,
                'auth_code': self.auth_code,
                'auth_url': self.auth_url,
                'access_url': self.access_url,
                'vscode_command': self.vscode_command,
                'workspace_dir': self.workspace_dir,
                'workspace_ready': self.workspace_ready,
                'stdout': self.stdout_buffer,
                'stderr': self.stderr_buffer,
                'start_time': self.start_time.isoformat(),
                'timeout_minutes': self.timeout_minutes,
                'elapsed_minutes': round(elapsed, 1),
                'remaining_minutes': round(remaining, 1),
                'script_path': self.script_path
            }
    
    def mark_stopped(self):
        with self.lock:
            self.is_running = False

# Global storage for interactive sessions
interactive_sessions = {}
interactive_sessions_lock = threading.Lock()

# Global storage for active supercomputer jobs
active_supercomputer_jobs = {}  # {job_id: {'subscription_id': ..., 'resource_group': ..., 'supercomputer_name': ...}}
active_supercomputer_jobs_lock = threading.Lock()

# Counter to ensure unique tunnel names after resets (keyed by container_hash)
# This allows us to generate different tunnel names after a reset to avoid
# conflicts with orphaned tunnel registrations on Microsoft's servers
tunnel_reset_counters = {}
tunnel_reset_counters_lock = threading.Lock()


def cleanup_interactive_sessions():
    """Clean up all active interactive sessions gracefully.
    
    Called during server shutdown to ensure tunnels are properly closed
    and containers are stopped.
    """
    with interactive_sessions_lock:
        if not interactive_sessions:
            return
        
        print("\n🧹 Cleaning up active interactive sessions...")
        session_ids = list(interactive_sessions.keys())
        
        for session_id in session_ids:
            try:
                session = interactive_sessions.get(session_id)
                if not session:
                    continue
                    
                print(f"   Stopping session {session_id} (container: {session.container_name})...")
                
                # Mark session as stopped
                session.mark_stopped()
                
                # Try to stop the container gracefully
                try:
                    client = docker.from_env()
                    container = client.containers.get(session.container_name)
                    
                    # Try graceful stop with timeout
                    container.stop(timeout=5)
                    print(f"   ✓ Container {session.container_name} stopped")
                except docker.errors.NotFound:
                    print(f"   ℹ️ Container {session.container_name} not found (already stopped)")
                except Exception as e:
                    print(f"   ⚠️ Could not stop container {session.container_name}: {e}")
                
                # Remove from tracking
                del interactive_sessions[session_id]
                print(f"   ✓ Session {session_id} cleaned up")
                
            except Exception as e:
                print(f"   ⚠️ Error cleaning up session {session_id}: {e}")
        
        print(f"✓ Cleaned up {len(session_ids)} interactive session(s)")


def cleanup_supercomputer_jobs():
    """Cancel all active supercomputer jobs gracefully (non-blocking).

    Called during server shutdown to ensure jobs don't continue running
    after the web server stops. Fires cancellation requests without waiting
    for responses since success/failure is irrelevant during shutdown.
    """
    from azure_auth_helpers import get_token_for_tenant

    def fire_cancellation(job_id, job_info):
        """Fire a cancellation request without blocking."""
        try:
            tenant_id = job_info.get('tenant_id')
            if not tenant_id:
                return

            scope = 'https://management.azure.com/.default'
            access_token = get_token_for_tenant(scope, tenant_id, [], purpose='job-cancel')

            if not access_token:
                return

            cancel_url = (
                f"https://management.azure.com/subscriptions/{job_info['subscription_id']}"
                f"/resourceGroups/{job_info['resource_group']}"
                f"/providers/Microsoft.Discovery/supercomputers/{job_info['supercomputer_name']}"
                f"/jobs/{job_id}/cancel"
            )

            headers = {
                'Authorization': f'Bearer {access_token}',
                'Content-Type': 'application/json'
            }
            params = {'api-version': '2025-07-01-preview'}

            # Fire request with short timeout - we don't care about the response
            requests.post(cancel_url, headers=headers, params=params, timeout=2)
        except Exception:
            pass  # Ignore errors during shutdown

    with active_supercomputer_jobs_lock:
        if not active_supercomputer_jobs:
            return

        print("\n🧹 Cancelling active supercomputer jobs...")
        job_ids = list(active_supercomputer_jobs.keys())

        # Fire all cancellation requests in background threads (non-blocking)
        for job_id in job_ids:
            job_info = active_supercomputer_jobs.get(job_id)
            if job_info:
                print(f"   Sending cancel request for job {job_id[:12]}...")
                thread = threading.Thread(target=fire_cancellation, args=(job_id, job_info), daemon=True)
                thread.start()

        # Clear tracking immediately - don't wait for responses
        active_supercomputer_jobs.clear()

        print(f"✓ Sent cancellation requests for {len(job_ids)} supercomputer job(s)")



def run_interactive_session_background(session: InteractiveSession, container):
    """Background thread to run the interactive tunnel in a container"""
    try:
        # Generate tunnel wrapper script content
        from devtunnel.vscode_layer import generate_shell_tunnel_wrapper
        wrapper_script = generate_shell_tunnel_wrapper()
        
        # Ensure shared directories exist
        try:
            shared_dir = ensure_shared_directories(agent_name=get_current_agent_name())
        except Exception as edir:
            print(f"❌ Failed to prepare shared directories: {edir}")
            return

        shared_workdir = shared_dir['workdir']
        
        # Write the wrapper script to the shared workdir
        wrapper_path = os.path.join(shared_workdir, f"tunnel-wrapper-{session.session_id}.sh")
        try:
            with open(wrapper_path, 'w', encoding='utf-8', newline='\n') as f:
                f.write(wrapper_script)
        except Exception as write_err:
            print(f"❌ Failed to write tunnel wrapper to {wrapper_path}: {write_err}")
            return
        
        # Make it executable
        import stat
        os.chmod(wrapper_path, os.stat(wrapper_path).st_mode | stat.S_IEXEC)
        
        print(f"🔧 Written tunnel wrapper to {wrapper_path}")
        
        # Emit SSE event for session start
        if SSE_AVAILABLE:
            event_bus.publish(
                EventChannel.INTERACTIVE,
                f"Starting interactive session {session.session_id}...",
                level=EventLevel.INFO,
                context={'session_id': session.session_id, 'container': container.name}
            )
        
        # Execute the tunnel wrapper in the container
        # The script is mounted at /workdir in the container
        exec_command = (
            f"TUNNEL_SESSION_ID={session.tunnel_name} "
            f"TUNNEL_TIMEOUT_MINUTES={session.timeout_minutes} "
            f"TUNNEL_MODE=vscode "
            f"bash /workdir/tunnel-wrapper-{session.session_id}.sh"
        )
        
        print(f"🚀 Starting interactive session in container {session.container_name}")
        print(f"   Command: {exec_command[:100]}...")
        
        # Use exec_create + exec_start to get exec ID for later inspection
        exec_id = container.client.api.exec_create(
            container.id,
            f"sh -c '{exec_command}'",
            stdout=True,
            stderr=True,
        )['Id']
        
        print(f"📝 Created exec {exec_id}")
        
        # Start the exec and get streaming output
        exec_output = container.client.api.exec_start(
            exec_id,
            stream=True,
            demux=True
        )
        
        session.exec_id = exec_id
        
        # Stream output in background with SSE emission
        try:
            if exec_output is not None:
                for chunk in exec_output:
                    if chunk is None:
                        continue
                    
                    if not session.is_running:
                        break  # Session was stopped
                    
                    if isinstance(chunk, tuple) and len(chunk) == 2:
                        stdout_data, stderr_data = chunk
                        if stdout_data:
                            chunk_str = stdout_data.decode('utf-8', errors='replace')
                            session.append_stdout(chunk_str)
                            print(f"[interactive-{session.session_id}] {chunk_str.strip()}")
                            
                            # Emit SSE event for stdout
                            if SSE_AVAILABLE:
                                # Extract current status for message (last meaningful line)
                                # Use normalized version from _session_stdout_details for parsing
                                lines = [l.strip() for l in session._session_stdout_details.strip().split('\n') if l.strip()]
                                current_status = lines[-1] if lines else ""
                                
                                # Update the single stdout event with accumulated details
                                event_bus.publish(
                                    EventChannel.INTERACTIVE,
                                    current_status,
                                    level=EventLevel.INFO,
                                    context={
                                        'session_id': session.session_id,
                                        'stream': 'stdout',
                                        'container': container.name
                                    },
                                    metadata={'raw_output': True},
                                    event_id=session.session_stdout_event_id,
                                    is_update=session._session_stdout_sent,
                                    details=session._session_stdout_details
                                )
                                session._session_stdout_sent = True
                        if stderr_data:
                            chunk_str = stderr_data.decode('utf-8', errors='replace')
                            session.append_stderr(chunk_str)
                            
                            # Emit SSE event for stderr
                            if SSE_AVAILABLE:
                                event_bus.publish(
                                    EventChannel.INTERACTIVE,
                                    chunk_str,
                                    level=EventLevel.WARNING,
                                    context={
                                        'session_id': session.session_id,
                                        'stream': 'stderr',
                                        'container': container.name
                                    },
                                    metadata={'raw_output': True}
                                )
                    else:
                        if chunk:
                            chunk_str = chunk.decode('utf-8', errors='replace') if isinstance(chunk, bytes) else str(chunk)
                            session.append_stdout(chunk_str)
                            print(f"[interactive-{session.session_id}] {chunk_str.strip()}")
                            
                            # Emit SSE event
                            if SSE_AVAILABLE:
                                # Normalize line endings (remove \r) before accumulating
                                chunk_str_normalized = chunk_str.replace('\r\n', '\n').replace('\r', '')
                                
                                # Accumulate all stdout in details, ensuring each chunk ends with newline
                                if not chunk_str_normalized.endswith('\n'):
                                    session._session_stdout_details += chunk_str_normalized + '\n'
                                else:
                                    session._session_stdout_details += chunk_str_normalized
                                
                                # Extract current status for message (last meaningful line)
                                lines = [l.strip() for l in chunk_str_normalized.strip().split('\n') if l.strip()]
                                current_status = lines[-1] if lines else chunk_str_normalized.strip()
                                
                                # Update the single stdout event with accumulated details
                                event_bus.publish(
                                    EventChannel.INTERACTIVE,
                                    current_status,
                                    level=EventLevel.INFO,
                                    context={
                                        'session_id': session.session_id,
                                        'stream': 'stdout',
                                        'container': container.name
                                    },
                                    metadata={'raw_output': True},
                                    event_id=session.session_stdout_event_id,
                                    is_update=session._session_stdout_sent,
                                    details=session._session_stdout_details
                                )
                                session._session_stdout_sent = True
        except Exception as stream_err:
            print(f"⚠️ Stream error for session {session.session_id}: {stream_err}")
            if SSE_AVAILABLE:
                event_bus.publish(
                    EventChannel.INTERACTIVE,
                    f"Stream error: {stream_err}",
                    level=EventLevel.ERROR,
                    context={'session_id': session.session_id, 'container': container.name}
                )
        
        # Stream ended but exec might still be running
        # Keep the session alive by checking if exec is still running
        print(f"📡 Stream ended for session {session.session_id}, checking if exec still running...")
        try:
            exec_inspect = container.client.api.exec_inspect(session.exec_id)
            if exec_inspect and exec_inspect.get('Running'):
                print(f"✅ Exec {session.exec_id} still running, keeping session alive")
                # Keep session alive - don't mark as stopped yet
                # The user will need to explicitly close it
                return
            else:
                print(f"🛑 Exec {session.exec_id} has exited (exit code: {exec_inspect.get('ExitCode')})")
                if SSE_AVAILABLE:
                    event_bus.publish(
                        EventChannel.INTERACTIVE,
                        f"Session ended with exit code {exec_inspect.get('ExitCode', 'unknown')}",
                        level=EventLevel.INFO,
                        context={'session_id': session.session_id, 'container': container.name}
                    )
        except Exception as inspect_err:
            print(f"⚠️ Could not inspect exec: {inspect_err}")
        
        session.mark_stopped()
        print(f"✅ Interactive session {session.session_id} ended")
        
    except Exception as e:
        print(f"❌ Error in interactive session {session.session_id}: {e}")
        import traceback
        print(f"Full traceback: {traceback.format_exc()}")
        session.append_stderr(f"\n\nError: {str(e)}")
        session.mark_stopped()
        
        if SSE_AVAILABLE:
            event_bus.publish(
                EventChannel.INTERACTIVE,
                f"Session error: {str(e)}",
                level=EventLevel.ERROR,
                context={'session_id': session.session_id}
            )


@app.route('/api/execute-interactive', methods=['POST'])
def execute_interactive():
    """Start an interactive debugging session in local Docker container
    
    This endpoint starts a VS Code tunnel in the container, allowing users to
    connect via browser or VS Code desktop for interactive debugging.
    
    Request body:
        - code (optional): Python code to save as a run script
        - timeout_minutes (optional): Session timeout (default: 30)
        - container_name (optional): Explicit container name to use
    
    Returns:
        - session_id: Unique session identifier
        - tunnel_name: Name of the VS Code tunnel
        - auth_url: GitHub device auth URL
        - access_url: URL to open VS Code in browser
        - vscode_command: Command to connect via VS Code desktop
    """
    try:
        print("🔧 Starting local Docker interactive session...")
        
        if not docker_client:
            return jsonify({'error': 'Docker client not available'}), 500
        
        data = request.get_json() or {}
        code = data.get('code', '')
        timeout_minutes = data.get('timeout_minutes', 30)
        explicit_container = data.get('container_name')
        
        print(f"   Request data: code_len={len(code)}, timeout={timeout_minutes}, container_name={explicit_container}")
        
        # Ensure shared directories exist
        try:
            shared_dir = ensure_shared_directories(agent_name=get_current_agent_name())
        except Exception as edir:
            return jsonify({'error': f'Failed to prepare shared directories: {edir}'}), 500
        
        # Resolve the container to use
        container = None
        try:
            if explicit_container:
                print(f"   Looking for explicit container: {explicit_container}")
                container = docker_client.containers.get(explicit_container)
                if container.status != 'running':
                    return jsonify({'error': f'Container {explicit_container} is not running (status: {container.status})'}), 400
                print(f"   ✅ Found container: {container.name} (status: {container.status})")
                
                # Don't kill existing tunnels - they will be reused
                # Only kill old wrapper script processes
                print(f"   🧹 Cleaning up any old wrapper script processes...")
                container.exec_run("sh -c 'pkill -f \"tunnel-wrapper\" 2>/dev/null || true'", detach=False)
                print(f"   ✅ Cleanup complete (tunnel preserved for reuse)")
            else:
                # Try to find a running container using the same logic as /api/execute
                container_name_global = globals().get('CONTAINER_NAME')
                if container_name_global:
                    try:
                        container = docker_client.containers.get(container_name_global)
                        if container.status != 'running':
                            container = None
                    except Exception:
                        pass
                
                if not container:
                    # Try agent_name
                    agent_name_global = globals().get('agent_name')
                    if agent_name_global:
                        try:
                            container = docker_client.containers.get(get_normalized_container_name(agent_name_global))
                            if container.status != 'running':
                                container = None
                        except Exception:
                            pass
                
                if not container:
                    return jsonify({
                        'error': 'No running Docker container found. Please start a container first using "Start Container" button.'
                    }), 400
        except Exception as e:
            return jsonify({'error': f'Error finding container: {e}'}), 500

        # Validate container mounts match current session directories
        current_agent = get_current_agent_name()
        mounts_valid, mount_msg = validate_container_mounts(container, current_agent)
        if not mounts_valid:
            print(f"🔄 Container {container.name} has stale mounts for Interactive mode, auto-recreating...")
            print(f"   {mount_msg}")

            # Auto-recreate container with correct mounts
            container_name_to_recreate = container.name
            try:
                # Stop and remove the stale container
                if container.status == 'running':
                    container.stop()
                container.remove()
                print(f"🗑️ Removed container with stale mounts: {container_name_to_recreate}")

                # Get the image name for this agent
                try:
                    image_name, _ = _derive_image_name_from_tool_definition(current_agent)
                except Exception as img_err:
                    return jsonify({'error': f'Could not determine image for agent {current_agent}: {img_err}'}), 500

                # Recreate the container with correct session mounts
                result = start_agent_container(current_agent, image_name, container_name_to_recreate)
                if not result.get('success'):
                    return jsonify({'error': f'Failed to recreate container: {result.get("error", "Unknown error")}'}), 500

                # Get the newly created container
                container = docker_client.containers.get(container_name_to_recreate)
                print(f"✅ Recreated container {container_name_to_recreate} with correct session mounts")

            except Exception as recreate_err:
                print(f"❌ Failed to auto-recreate container: {recreate_err}")
                return jsonify({
                    'error': f'Failed to recreate container with correct mounts: {recreate_err}',
                    'details': mount_msg
                }), 500

        # Generate unique session and tunnel names
        # Note: VS Code CLI tunnel names must be <= 20 characters
        session_id = str(uuid.uuid4())[:8]
        
        # Use a stable tunnel name based on agent name
        # Format: loc-{agent_name} truncated to 20 chars max
        # This allows browser auth cache to be reused across sessions
        # The reset process properly cleans up server-side state with logout + unregister
        import re
        # Extract agent name from container name (remove any registry prefix, tags, etc.)
        agent_name = container.name.lower()
        # Sanitize: only keep alphanumeric and hyphens, replace underscores with hyphens
        agent_name = re.sub(r'[^a-z0-9-]', '-', agent_name)
        agent_name = re.sub(r'-+', '-', agent_name).strip('-')  # Collapse multiple hyphens
        # Truncate to fit: "loc-" = 4 chars, so agent_name can be max 16 chars
        agent_name = agent_name[:16].rstrip('-')  # Don't end with hyphen
        tunnel_name = f"loc-{agent_name}"
        
        print(f"   🔗 Using tunnel name: {tunnel_name} (from container {container.name})")
        
        # Create session object
        session = InteractiveSession(
            session_id=session_id,
            container_name=container.name,
            tunnel_name=tunnel_name
        )
        session.timeout_minutes = timeout_minutes
        
        # If code was provided, save it as a run script
        if code.strip():
            shared_workdir = shared_dir['workdir']
            
            # Ensure workdir exists
            try:
                os.makedirs(shared_workdir, exist_ok=True)
                os.chmod(shared_workdir, 0o777)
            except Exception as e:
                print(f"⚠️ Warning: Could not ensure workdir permissions: {e}")
            
            # Detect if this is a bash/shell command or Python code
            script_type, _ = detect_script_type(code)
            is_bash = (script_type == 'shell')
            code_stripped = code.strip()
            
            # Determine file extension based on detected language
            if is_bash:
                script_filename = f"user_script_{session_id}.sh"
                script_extension = 'sh'
                script_path = os.path.join(shared_workdir, script_filename)
                with open(script_path, 'w', encoding='utf-8', newline='\n') as f:
                    # Add shebang for bash scripts if not present
                    if not code_stripped.startswith('#!'):
                        f.write('#!/bin/bash\n')
                    f.write(code)
                # Make bash scripts executable
                import stat
                os.chmod(script_path, os.stat(script_path).st_mode | stat.S_IEXEC)
                session.script_path = f"/workdir/user_script_{session_id}.sh"
                print(f"📝 Saved user bash script to {script_path}")
            else:
                script_filename = f"user_script_{session_id}.py"
                script_extension = 'py'
                script_path = os.path.join(shared_workdir, script_filename)
                with open(script_path, 'w', encoding='utf-8') as f:
                    f.write(code)
                session.script_path = f"/workdir/user_script_{session_id}.py"
                print(f"📝 Saved user Python script to {script_path}")
        
        # Store session
        with interactive_sessions_lock:
            interactive_sessions[session_id] = session
        
        # Start background thread for the tunnel
        thread = threading.Thread(
            target=run_interactive_session_background,
            args=(session, container),
            daemon=True
        )
        thread.start()
        
        print(f"✅ Interactive session {session_id} started")
        
        return jsonify({
            'success': True,
            'session_id': session_id,
            'tunnel_name': tunnel_name,
            'container_name': container.name,
            'auth_url': session.auth_url,
            'access_url': session.access_url,
            'vscode_command': session.vscode_command,
            'workspace_dir': '/workspace',  # Will be updated when tunnel sets up
            'timeout_minutes': timeout_minutes,
            'script_path': session.script_path,
            'message': 'Interactive session starting. Check session status for auth code.',
            'status_url': f'/api/interactive-session/{session_id}'
        })
        
    except Exception as e:
        print(f"❌ /api/execute-interactive error: {e}")
        import traceback
        print(f"Full traceback: {traceback.format_exc()}")
        return jsonify({'error': str(e)}), 500


@app.route('/api/interactive-session/<session_id>')
def get_interactive_session(session_id):
    """Get status of an interactive debugging session"""
    try:
        with interactive_sessions_lock:
            if session_id not in interactive_sessions:
                return jsonify({'error': 'Session not found'}), 404
            session = interactive_sessions[session_id]
        
        return jsonify({
            'success': True,
            **session.get_status()
        })
        
    except Exception as e:
        print(f"❌ Error getting session {session_id}: {e}")
        return jsonify({'error': str(e)}), 500


@app.route('/api/interactive-session/<session_id>/close', methods=['POST'])
def close_interactive_session(session_id):
    """Close an interactive debugging session"""
    try:
        with interactive_sessions_lock:
            if session_id not in interactive_sessions:
                return jsonify({'error': 'Session not found'}), 404
            session = interactive_sessions[session_id]
        
        print(f"🔧 Closing interactive session {session_id}...")
        
        # Mark session as stopped
        session.mark_stopped()
        
        # Kill only the wrapper script exec process, but KEEP the tunnel running for reuse
        try:
            if docker_client and session.exec_id:
                container = docker_client.containers.get(session.container_name)
                if container.status == 'running':
                    try:
                        # Find and kill the wrapper script bash process
                        exec_inspect = container.client.api.exec_inspect(session.exec_id)
                        if exec_inspect.get('Pid'):
                            container.exec_run(f"kill -TERM {exec_inspect['Pid']}", detach=False)
                            print(f"   Terminated wrapper script process PID {exec_inspect['Pid']}")
                            print(f"   ℹ️  Tunnel process left running for reuse")
                    except Exception as e:
                        print(f"   Could not kill wrapper script: {e}")
        except Exception as kill_err:
            print(f"⚠️ Error during session cleanup: {kill_err}")
        
        # Clean up session from storage (after a delay to allow final status reads)
        def cleanup_session():
            import time
            time.sleep(5)  # Wait 5 seconds before cleanup
            with interactive_sessions_lock:
                if session_id in interactive_sessions:
                    del interactive_sessions[session_id]
                    print(f"🗑️ Cleaned up session {session_id}")
        
        cleanup_thread = threading.Thread(target=cleanup_session, daemon=True)
        cleanup_thread.start()
        
        print(f"✅ Interactive session {session_id} closed")
        
        return jsonify({
            'success': True,
            'message': f'Session {session_id} closed',
            'session_id': session_id
        })
        
    except Exception as e:
        print(f"❌ Error closing session {session_id}: {e}")
        import traceback
        print(f"Full traceback: {traceback.format_exc()}")
        return jsonify({'error': str(e)}), 500


# Removed reset-tunnel endpoint - was used for debugging only
        import traceback
        print(f"Full traceback: {traceback.format_exc()}")
        return jsonify({'error': str(e)}), 500


