@app.route('/api/file/<path:filename>')
def file_access(filename):
    """Unified file access endpoint for preview, download, and raw access of input/output files.

    Query parameters:
        source: 'inputs' or 'outputs' (REQUIRED - no default)
        download: 'true' to download file as attachment (default: 'false')
        raw: 'true' to get raw file content (for images, binary files) (default: 'false')
        session_id: Session ID for session-specific directories
        agent_name: Agent name for agent-specific directories

    Modes:
        - download=true: Returns file as download attachment
        - raw=true: Returns raw file content inline (for img tags, etc.)
        - Neither: Returns file content as text/plain (preview mode)
    """
    try:
        # Get parameters from query string
        source = request.args.get('source')
        if not source:
            return jsonify({'error': "Missing required parameter 'source'. Must be 'inputs' or 'outputs'."}), 400
        if source not in ('inputs', 'outputs'):
            return jsonify({'error': f"Invalid source '{source}'. Must be 'inputs' or 'outputs'."}), 400
        download = request.args.get('download', 'false').lower() == 'true'
        raw = request.args.get('raw', 'false').lower() == 'true'
        session_id = request.args.get('session_id', None)
        agent_name = request.args.get('agent_name', None)

        # Get session-specific directory based on source
        sm = get_session_manager()
        session_dirs = sm.get_session_dirs(session_id=session_id, agent_name=agent_name or get_current_agent_name())

        if source == 'inputs':
            base_dir = session_dirs['input']  # Note: session_dirs uses 'input' (singular)
        else:
            base_dir = session_dirs['output']

        # Normalize and secure the requested path to prevent directory traversal
        requested = os.path.normpath(os.path.join(base_dir, filename))
        base_abs = os.path.abspath(base_dir)
        req_abs = os.path.abspath(requested)
        if not (req_abs == base_abs or req_abs.startswith(base_abs + os.sep)):
            return jsonify({'error': 'Access denied'}), 403
        file_path = req_abs

        if not os.path.exists(file_path):
            return jsonify({'error': 'File not found'}), 404

        # Download mode: return file as attachment
        if download:
            return send_file(file_path, as_attachment=True)

        # Raw mode: return file content inline (for images, binary files)
        if raw:
            return send_file(file_path, as_attachment=False)

        # Preview mode: return file content as text
        encodings = ['utf-8', 'latin-1', 'cp1252']
        content = None

        for encoding in encodings:
            try:
                with open(file_path, 'r', encoding=encoding) as f:
                    content = f.read()
                break
            except UnicodeDecodeError:
                continue

        if content is None:
            # If all text encodings fail, treat as binary and show info
            file_size = os.path.getsize(file_path)
            content = f"Binary file ({file_size} bytes)\nDownload the file to view its contents."

        return content, 200, {'Content-Type': 'text/plain; charset=utf-8'}

    except Exception as e:
        return jsonify({'error': str(e)}), 500

# Workflow Agent Creation API Endpoints
def _get_detailed_agent_descriptions(selected_agents, agent_manager):
    """Get detailed descriptions for selected agents from their YAML definitions"""
    descriptions = []

    for agent_name in selected_agents:
        # Try Azure first (source of truth). If that yields useful definitionContent
        # we'll use it. Otherwise fall back to local YAML/catalog data.
        fetched_paragraph = None

        try:
            if DISCOVERY_AVAILABLE and config_manager:
                azure_cfg = config_manager.get_azure_config()
                sub = azure_cfg.get('subscription_id')
                rg = azure_cfg.get('resource_group')
                if sub and rg:
                    print(f"ℹ️ Azure-first: attempting to fetch agent resource from Azure: {agent_name} ({sub}/{rg})")
                    fetched = fetch_agent_resource(sub, rg, agent_name)
                    if fetched.get('success'):
                        resource = fetched.get('resource', {})

                        properties = resource.get('properties', {})
                        definition = properties.get('definitionContent', {})

                        if isinstance(definition, dict):
                            # Only use nested agent block; if not present leave empty
                            agent_block = definition.get('agent') or definition.get('Agent')
                            if isinstance(agent_block, dict):
                                desc = agent_block.get('description') or agent_block.get('Description') or ''
                                instr = agent_block.get('instructions') or agent_block.get('Instructions') or ''
                            else:
                                desc = ''
                                instr = ''
                        else:
                            desc = ''
                            instr = ''

                        # If we have at least some content, call the LLM to synthesize a paragraph
                        try:
                            if definition:
                                loader = get_prompt_loader()
                                loader.prompts_dir = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'prompts')
                                system_template = loader.load_prompt('tool-creation/agent_capabilities_system.txt')
                                user_template = loader.load_prompt('tool-creation/agent_capabilities_user.txt')

                                # Only provide the description and instructions (no full JSON)
                                user_prompt = user_template.replace('{agent_resource_json}', desc or '')
                                user_prompt = user_prompt.replace('{agent_instructions}', instr or '')

                                llm_res = call_llm_for_capability(system_template, user_prompt, max_tokens=300)
                                # Diagnostic: log LLM response status and size
                                try:
                                    print(f"DEBUG: LLM response for {agent_name}: success={llm_res.get('success')}, keys={list(llm_res.keys())}")
                                    txt = llm_res.get('text', '') if isinstance(llm_res, dict) else ''
                                    print(f"DEBUG: LLM text length for {agent_name}: {len(txt)}")
                                except Exception:
                                    pass

                                if llm_res.get('success'):
                                    paragraph = llm_res.get('text', '').strip()
                                    # Keep paragraph intact but cap at 200 words
                                    words = paragraph.split()
                                    if len(words) > 200:
                                        paragraph = ' '.join(words[:200])
                                    fetched_paragraph = f"**{agent_name}**: {paragraph}"
                        except Exception as e:
                            print(f"⚠️ Failed to generate capability paragraph via LLM for {agent_name}: {e}")
                    else:
                        print(f"⚠️ Could not fetch agent resource for {agent_name}: {fetched.get('error')}")
                else:
                    print(f"ℹ️ Discovery subscription/resource not configured; skipping Azure fetch for {agent_name}")
            else:
                print(f"ℹ️ Discovery configuration not available; skipping Azure fetch for {agent_name}")
        except Exception as e:
            print(f"⚠️ Error while attempting Azure fetch for {agent_name}: {e}")

        if fetched_paragraph:
            descriptions.append(fetched_paragraph)
            continue

        # Azure didn't provide useful details — fall back to local catalog/YAML
        yaml_desc = None
        instructions_preview = "No detailed instructions available."
        capabilities = []
        found_local = False

        try:
            if agent_manager and agent_name in agent_manager.agents:
                # Prefer using agent_manager helper which may cache parsed YAML
                try:
                    info = agent_manager._load_agent_info(agent_name)
                except Exception:
                    info = None

                if info:
                    found_local = True
                    yaml_desc = getattr(info, 'description', None) or 'Specialized agent'
                    # _config_cache is used by agent_manager to store parsed YAML if available
                    agent_yaml = getattr(info, '_config_cache', None)
                else:
                    entry = agent_manager.agents.get(agent_name)
                    yaml_desc = getattr(entry, 'description', 'Specialized agent')
                    agent_yaml = None
                    # Strict fallback: only try explicit file_path or agent_config fields
                    cfg_path = getattr(entry, 'file_path', None) or getattr(entry, 'agent_config', None)
                    if cfg_path:
                        try:
                            import yaml
                            abs_path = cfg_path
                            if not os.path.isabs(cfg_path):
                                abs_path = os.path.abspath(os.path.join(os.path.dirname(__file__), cfg_path))
                            if os.path.exists(abs_path):
                                with open(abs_path, 'r', encoding='utf-8') as f:
                                    agent_yaml = yaml.safe_load(f)
                                    found_local = True
                        except Exception:
                            agent_yaml = None

                # If we have a parsed YAML dict, extract richer fields
                if isinstance(agent_yaml, dict):
                    yaml_agent = agent_yaml.get('agent', {})
                    yaml_desc = yaml_agent.get('description', yaml_desc)
                    instructions = yaml_agent.get('instructions', '')
                    if instructions:
                        instructions_preview = instructions[:200].replace('\n', ' ').strip()
                        if len(instructions) > 200:
                            instructions_preview += "..."

                    events = agent_yaml.get('extension', {}).get('events', [])
                    for event in events or []:
                        if isinstance(event, dict) and 'condition' in event:
                            cond = event.get('condition', '')
                            capabilities.append(f"- {event.get('name','unnamed')}: {cond[:100]}{'...' if len(cond) > 100 else ''}")

                if found_local:
                    detailed_desc = f"**{agent_name}**:\n- Description: {yaml_desc}\n- Instructions Preview: {instructions_preview}"
                    if capabilities:
                        detailed_desc += f"\n- Capabilities:\n  " + "\n  ".join(capabilities)
                    descriptions.append(detailed_desc)
                    continue
        except Exception as e:
            print(f"⚠️ Error loading local YAML for {agent_name}: {e}")

        # Nothing useful from Azure or local catalog
        descriptions.append(f"**{agent_name}**: Specialized agent (definition not found)")

    return "\n\n".join(descriptions)

@app.route('/api/generate-agent-instructions', methods=['POST'])
def generate_agent_instructions():
    """Generate AI instructions for Workflow Agent based on selected agents"""
    try:
        data = request.json
        agent_name = data.get('agentName', '')
        description = data.get('description', '')
        selected_agents = data.get('selectedAgents', [])
        
        if not agent_name or not description or not selected_agents:
            return jsonify({
                'success': False,
                'error': 'Missing required fields: agentName, description, or selectedAgents'
            }), 400
        
    # Load RouterAgent template from discovery configuration
        try:
            config_mgr = DiscoveryConfigManager()  # Uses repository config
            template_files = config_mgr.get_template_files() if config_mgr else {}
            router_rel_path = template_files.get('RouterAgent')
        except Exception as cfg_err:
            router_rel_path = None
            print(f"ERROR: Could not load template_files for RouterAgent: {cfg_err}")

        if not router_rel_path:
            return jsonify({
                'success': False,
                'error': 'RouterAgent template not configured (template_files.RouterAgent missing)'
            }), 500

        template_path = os.path.normpath(os.path.join(os.path.dirname(__file__), router_rel_path))

        if not os.path.exists(template_path):
            return jsonify({
                'success': False,
                'error': f'RouterAgent template path not found: {template_path}'
            }), 500
        
        with open(template_path, 'r', encoding='utf-8') as f:
            template_content = f.read()
        
        # Create routing instruction prompt for LLM
        agent_descriptions = []
        agent_details = []
        for agent_name_sel in selected_agents:
            if agent_manager and agent_name_sel in agent_manager.agents:
                agent_info = agent_manager.agents[agent_name_sel]
                # agent_info is an AgentInfo object with description attribute
                desc = getattr(agent_info, 'description', 'Specialized agent')
                if not desc:
                    desc = 'Specialized agent'
                agent_descriptions.append(f"- {agent_name_sel}: {desc}")
                agent_details.append(f"  * {agent_name_sel}: {desc}")
        
        # Use LLM to generate instructions instead of template
        ai_generated = False
        instructions = ""
        
        if llm_available():
            try:
                # Load prompts from external files
                system_prompt, user_prompt_template = load_main_agent_prompts()

                # Get detailed agent descriptions before creating the prompt
                detailed_agent_descriptions = _get_detailed_agent_descriptions(selected_agents, agent_manager)

                # Prepare variables for prompt substitution
                prompt_variables = {
                    'agent_name': agent_name,
                    'description': description,
                    'description_lower': description.lower(),
                    'selected_agents_joined': ', '.join(selected_agents),
                    'agent_details': '\n'.join([f"  * {agent}: Specialized agent" for agent in selected_agents]),
                    'template_content': template_content,
                    'detailed_agent_descriptions': detailed_agent_descriptions
                }

                # Substitute variables in the user prompt
                user_prompt = substitute_prompt_variables(user_prompt_template, prompt_variables)

                # Create a temporary session for instruction generation
                temp_session_id = conversation_manager.create_session(system_prompt)
                conversation_manager.add_message("user", user_prompt, temp_session_id)
                
                # Get messages for API call
                messages = conversation_manager.get_conversation_for_api(temp_session_id)
                
                # Debug output: Full LLM context
                print("\n" + "="*80)
                print("🤖 LLM INSTRUCTION GENERATION - FULL CONTEXT")
                print("="*80)
                print(f"Agent Name: {agent_name}")
                print(f"Description: {description}")
                print(f"Selected Agents: {', '.join(selected_agents)}")
                print("\n📤 SYSTEM PROMPT:")
                print("-" * 40)
                print(system_prompt)
                print("\n📤 USER PROMPT:")
                print("-" * 40)
                print(user_prompt)
                print("\n📤 FULL MESSAGES SENT TO LLM:")
                print("-" * 40)
                for i, msg in enumerate(messages):
                    print(f"Message {i+1} ({msg['role']}):")
                    print(msg['content'])
                    print("-" * 20)
                print("="*80)
                
                # Call Azure OpenAI with instruction generation context (require ConversationManager)
                # Use runtime conversation_manager temperature if available, else discovery config
                try:
                    temp = getattr(conversation_manager, 'temperature', None)
                except Exception:
                    temp = None
                if temp is None:
                    temp = DiscoveryConfigManager().get_conversation_config().get('temperature')
                response_data = call_azure_openai_direct(messages, max_output_tokens=conversation_manager.max_output_tokens, temperature=temp)

                # Debug output: Full LLM response
                print("\n🤖 LLM RESPONSE - FULL OUTPUT")
                print("="*80)
                print("📥 RAW RESPONSE DATA:")
                print("-" * 40)
                print(f"Response type: {type(response_data)}")
                print(f"Response data: {response_data}")
                print("-" * 40)
                
                # Parse the response
                instructions = parse_llm_response_direct(response_data)
                
                # Debug output: Parsed instructions
                print("📥 PARSED INSTRUCTIONS:")
                print("-" * 40)
                print(f"Instructions type: {type(instructions)}")
                print(f"Instructions length: {len(instructions) if instructions else 0}")
                print("Instructions content:")
                print(instructions if instructions else "None")
                print("="*80)
                print("🤖 LLM INSTRUCTION GENERATION - COMPLETE\n")
                
                if instructions:
                    ai_generated = True
                
            except Exception as e:
                print(f"LLM instruction generation failed: {str(e)}")
                # Will fall back to template generation below
                pass
            finally:
                # Clean up temporary session
                try:
                    if 'temp_session_id' in locals() and temp_session_id in conversation_manager.sessions:
                        del conversation_manager.sessions[temp_session_id]
                except:
                    pass
        
        # Return error if LLM generation fails - no fallback
        if not instructions:
            return jsonify({
                'success': False,
                'error': 'Failed to generate instructions using LLM. Please check your Azure OpenAI configuration and try again.'
            }), 500
        
        # Final result logging
        print("\n" + "="*80)
        print("✅ FINAL INSTRUCTION GENERATION RESULT")
        print("="*80)
        print(f"Agent Name: {agent_name}")
        print(f"AI Generated: {ai_generated}")
        print(f"Instructions Length: {len(instructions) if instructions else 0}")
        print("="*80)
        
        return jsonify({
            'success': True,
            'instructions': instructions,
            'aiGenerated': ai_generated
        })
        
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

def _generate_event_names(selected_agents):
    """Generate deterministic event names for workflow agent transitions.

    Maps each agent name to a consistent event name following the rules:
    - Format: Run{PascalCaseName}
    - Max 15 characters
    - Only letters, underscores, hyphens (no digits)
    - GenerateSummary is always added for the Summary transition

    Returns a dict mapping agent name -> event name, plus a formatted string
    for prompt injection.
    """
    import re as _re

    def _to_pascal(name):
        """Convert agent name to PascalCase, preserving camelCase segments."""
        # Split on hyphens and underscores
        parts = _re.split(r'[-_]', name)
        # Capitalize first letter of each part, preserve rest (keeps camelCase)
        return ''.join(p[0].upper() + p[1:] if p else '' for p in parts)

    def _smart_truncate(pascal, max_total=15):
        """Truncate by dropping trailing PascalCase segments rather than mid-word."""
        candidate = f'Run{pascal}'
        if len(candidate) <= max_total:
            return candidate
        # Split on PascalCase boundaries (e.g. "MolecularGroups" -> ["Molecular", "Groups"])
        segments = _re.split(r'(?<=[a-z])(?=[A-Z])', pascal)
        while len(segments) > 1 and len('Run' + ''.join(segments)) > max_total:
            segments.pop()
        result = 'Run' + ''.join(segments)
        # Final hard truncate if single segment is still too long
        if len(result) > max_total:
            result = result[:max_total]
        return result

    event_map = {}
    used_names = set()

    for agent in selected_agents:
        pascal = _to_pascal(agent)
        # Strip common suffixes
        for suffix in ('Agent', 'Service'):
            if pascal.endswith(suffix) and len(pascal) > len(suffix):
                pascal = pascal[:-len(suffix)]
        # Remove any digits
        pascal = _re.sub(r'\d+', '', pascal)
        event_name = _smart_truncate(pascal)
        # Ensure uniqueness
        base = event_name
        counter = 0
        while event_name in used_names:
            counter += 1
            tag = chr(ord('A') + counter - 1)
            event_name = base[:14] + tag
        used_names.add(event_name)
        event_map[agent] = event_name

    return event_map


def _format_event_name_mapping(event_map):
    """Format event name mapping as a readable string for prompt injection."""
    lines = []
    for agent, event in event_map.items():
        lines.append(f'  - Agent `{agent}` → event name: `{event}`')
    lines.append(f'  - Summary → event name: `GenerateSummary`')
    return '\n'.join(lines)


def _load_data_handling_context():
    """Load the canonical dataHandlingContext content from the prompts file."""
    dhc_path = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                            'prompts', 'dataHandlingContext.txt')
    if os.path.exists(dhc_path):
        with open(dhc_path, 'r', encoding='utf-8') as f:
            return f.read()
    logger.warning(f"dataHandlingContext.txt not found at {dhc_path}")
    return ''


def _inject_canonical_data_handling_context(yaml_content: str) -> str:
    """Append the canonical dataHandlingContext variable to the workflow YAML variables section.

    Removes any LLM-generated dataHandlingContext variable (including placeholder values)
    and appends the canonical content from prompts/dataHandlingContext.txt to the end
    of the variables list.
    """
    import re as _re

    canonical = _load_data_handling_context()
    if not canonical:
        return yaml_content

    # Step 1: Remove any existing dataHandlingContext variable block the LLM may have generated.
    # This handles both placeholder values and any LLM-expanded content.
    # Pattern: match "- Type: userDefined" + "name: dataHandlingContext" + optional value block
    # We use a multi-pass approach on lines for robustness.
    lines = yaml_content.split('\n')
    cleaned_lines = []
    skip_until_next_var = False
    i = 0
    while i < len(lines):
        line = lines[i]
        stripped = line.strip()

        # Detect start of a dataHandlingContext variable entry
        if stripped == '- Type: userDefined' or stripped == '- name: dataHandlingContext':
            # Look ahead to confirm this is the dataHandlingContext variable
            block_start = i
            block_lines = [lines[i]]
            j = i + 1
            is_dhc = False
            while j < len(lines) and j < i + 5:
                next_stripped = lines[j].strip()
                if next_stripped.startswith('name: dataHandlingContext'):
                    is_dhc = True
                if next_stripped.startswith('- ') and j > i:
                    break  # Start of next variable
                if next_stripped and not next_stripped.startswith('-') and not next_stripped.startswith('#'):
                    block_lines.append(lines[j])
                j += 1

            if is_dhc:
                # Skip the entire dataHandlingContext block (including value: and its content)
                block_indent = len(lines[block_start]) - len(lines[block_start].lstrip())
                i = block_start + 1
                while i < len(lines):
                    l = lines[i]
                    if not l.strip():
                        i += 1
                        continue
                    current_indent = len(l) - len(l.lstrip())
                    # If we hit a line at same or lesser indent that starts a new entry, stop
                    if current_indent <= block_indent and l.strip().startswith('- '):
                        break
                    # If we hit a top-level key, stop
                    if current_indent == 0 and not l[0].isspace():
                        break
                    i += 1
                continue

        cleaned_lines.append(line)
        i += 1

    # Also remove any standalone placeholder line
    cleaned_lines = [
        l for l in cleaned_lines
        if '__DHC_PLACEHOLDER__' not in l
    ]

    # Step 2: Find the end of the variables section and append canonical content
    result_lines = cleaned_lines
    canonical_block = canonical.strip('\n').split('\n')

    # Find where variables section ends (next top-level key after 'variables:')
    insert_idx = None
    in_variables = False
    for idx, line in enumerate(result_lines):
        stripped = line.strip()
        if stripped.startswith('variables:'):
            in_variables = True
            continue
        if in_variables and line and not line[0].isspace() and line[0] != '#':
            insert_idx = idx
            break

    # Detect variable indent from existing entries
    var_indent = '  '  # default
    for line in result_lines:
        stripped = line.strip()
        if stripped.startswith('- Type:') or (stripped.startswith('- name:') and 'messageId' in stripped):
            var_indent = ' ' * (len(line) - len(line.lstrip()))
            break

    # Re-indent canonical content to match
    canonical_base_indent = len(canonical_block[0]) - len(canonical_block[0].lstrip())
    indent_diff = len(var_indent) - canonical_base_indent

    reindented = []
    for line in canonical_block:
        if line.strip():
            old_indent = len(line) - len(line.lstrip())
            new_indent = old_indent + indent_diff
            reindented.append(' ' * max(0, new_indent) + line.lstrip())
        else:
            reindented.append('')

    if insert_idx is not None:
        for ri, rline in enumerate(reindented):
            result_lines.insert(insert_idx + ri, rline)
    else:
        result_lines.extend(reindented)

    return '\n'.join(result_lines)


@app.route('/api/generate-component-instructions', methods=['POST'])
def generate_component_instructions():
    """Generate instructions for a specific Workflow Agent component"""
    try:
        data = request.json
        agent_name = data.get('agentName', '')
        description = data.get('description', '')
        selected_agents = data.get('selectedAgents', [])
        component = data.get('component', '')
        unique_component_names = data.get('unique_component_names', {})  # Get unique names from frontend
        
        if not agent_name or not selected_agents or not component:
            return jsonify({
                'success': False,
                'error': 'Missing required fields: agentName, selectedAgents, component'
            }), 400
        
        # Load the appropriate sample template for the component
        # Get template file paths from configuration instead of hardcoded mapping
        config_manager = DiscoveryConfigManager()
        template_files = config_manager.get_template_files()
        
        # Strict mapping: no legacy key fallback and no implicit sample path fallback
        sample_file_map = {
            'planner': template_files.get('PlannerAgent'),
            'router': template_files.get('RouterAgent'),
            'summarizer': template_files.get('SummarizerAgent'),
            'workflow': template_files.get('WorkflowAgent')
        }
        
        if component not in sample_file_map:
            return jsonify({
                'success': False,
                'error': f'Invalid component: {component}'
            }), 400
            
        sample_file = sample_file_map[component]
        if not sample_file:
            return jsonify({
                'success': False,
                'error': f"Required template_files entry missing for component '{component}'. Configure template_files.{component.capitalize()}Agent."
            }), 500
        sample_path = os.path.join(os.path.dirname(__file__), sample_file)
        
        if not os.path.exists(sample_path):
            return jsonify({
                'success': False,
                'error': f'Sample template not found: {sample_file}'
            }), 500
        
        with open(sample_path, 'r', encoding='utf-8') as f:
            sample_content = f.read()
        
        # Generate component-specific instructions using LLM
        instructions = ""
        ai_generated = False
        error_message = "Unknown error"
        
        if llm_available():
            try:
                # Load prompts from external files
                system_prompt, user_prompt_template = load_component_prompts(component)
                
                # Get detailed agent descriptions
                detailed_agent_descriptions = _get_detailed_agent_descriptions(selected_agents, agent_manager)
                
                # Pre-compute deterministic event names for all agents
                event_map = _generate_event_names(selected_agents)
                event_name_mapping = _format_event_name_mapping(event_map)

                # Prepare variables for prompt substitution
                prompt_variables = {
                    'agent_name': agent_name,  # Base name for building references (e.g., "Surfactant22")
                    'component_agent_name': unique_component_names[component],  # Always use unique name
                    'description': description,
                    'description_lower': description.lower(),
                    'selected_agents_list': '\n'.join([f"  * {agent}: Specialized agent" for agent in selected_agents]),
                    'selected_agents_joined': ', '.join(selected_agents),
                    'selected_agents_capabilities': detailed_agent_descriptions,
                    'sample_content': sample_content,
                    'event_name_mapping': event_name_mapping,
                    # Pass all unique component names for cross-references
                    'unique_planner_name': unique_component_names['planner'],
                    'unique_router_name': unique_component_names['router'],
                    'unique_summarizer_name': unique_component_names['summarizer'],
                    'unique_workflow_name': unique_component_names['workflow']
                }

                # Substitute variables in the user prompt
                user_prompt = substitute_prompt_variables(user_prompt_template, prompt_variables)

                # Use new validation function with retry logic
                # determine max_retries from runtime manager or discovery config
                try:
                    retries = getattr(conversation_manager, 'max_retries', None)
                except Exception:
                    retries = None
                if retries is None:
                    retries = DiscoveryConfigManager().get_conversation_config().get('max_retries', 2)

                instructions, ai_generated, error_message = validate_and_retry_yaml_generation(
                    component, system_prompt, user_prompt, conversation_manager, max_retries=retries
                )

                # Post-process: inject canonical dataHandlingContext for workflow
                if component == 'workflow' and instructions:
                    instructions = _inject_canonical_data_handling_context(instructions)

                if not instructions:
                    print(f"LLM {component} instruction generation failed after retries: {error_message}")

            except Exception as e:
                print(f"LLM {component} instruction generation failed: {str(e)}")
                error_message = str(e)

        # Return error if LLM generation fails - no fallback
        if not instructions:
            return jsonify({
                'success': False,
                'error': f'Failed to generate {component} instructions using LLM after multiple attempts. Last error: {error_message if "error_message" in locals() else "Unknown error"}. Please check your Azure OpenAI configuration and try again.',
                'component': component
            }), 500
        
        return jsonify({
            'success': True,
            'instructions': instructions,
            'aiGenerated': ai_generated,
            'component': component
        })
        
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


@app.route('/api/generate-all-component-instructions', methods=['POST'])
def generate_all_component_instructions():
    """Generate instructions for all Workflow Agent components simultaneously"""
    import concurrent.futures
    import time
    
    try:
        data = request.json
        agent_name = data.get('agentName', '')
        description = data.get('description', '')
        selected_agents = data.get('selectedAgents', [])
        unique_component_names = data.get('unique_component_names', {})  # Get unique names from frontend
        
        if not agent_name or not selected_agents:
            return jsonify({
                'success': False,
                'error': 'Missing required fields: agentName, selectedAgents'
            }), 400

        # Get template file paths from configuration
        config_manager = DiscoveryConfigManager()
        template_files = config_manager.get_template_files()
        
        # Component mapping
        components = ['planner', 'router', 'summarizer', 'workflow']
        sample_file_map = {
            'planner': template_files.get('PlannerAgent'),
            'router': template_files.get('RouterAgent'),
            'summarizer': template_files.get('SummarizerAgent'),
            'workflow': template_files.get('WorkflowAgent')
        }
        
        # Get conversation manager and configuration
        if not llm_available():
            return jsonify({
                'success': False,
                'error': 'Conversation manager or Azure OpenAI configuration not available'
            }), 500
        
        # Get detailed agent descriptions for context
        detailed_agent_descriptions = _get_detailed_agent_descriptions(selected_agents, agent_manager)

        # Pre-compute deterministic event names once — shared by all components
        event_map = _generate_event_names(selected_agents)
        event_name_mapping = _format_event_name_mapping(event_map)

        def generate_single_component(component):
            """Generate instructions for a single component"""
            try:
                sample_file = sample_file_map.get(component)
                if not sample_file:
                    return {
                        'component': component,
                        'success': False,
                        'error': f"Required template_files entry missing for component '{component}'. Configure template_files.{component.capitalize()}Agent."
                    }

                sample_path = os.path.join(os.path.dirname(__file__), sample_file)
                if not os.path.exists(sample_path):
                    return {
                        'component': component,
                        'success': False,
                        'error': f'Sample template not found: {sample_file}'
                    }

                with open(sample_path, 'r', encoding='utf-8') as f:
                    sample_content = f.read()

                # Load prompts from external files
                system_prompt, user_prompt_template = load_component_prompts(component)

                # Prepare variables for prompt substitution
                prompt_variables = {
                    'agent_name': agent_name,  # Base name for building references (e.g., "Surfactant22")
                    'component_agent_name': unique_component_names[component],  # Always use unique name
                    'description': description,
                    'description_lower': description.lower(),
                    'selected_agents_list': '\n'.join([f"  * {agent}: Specialized agent" for agent in selected_agents]),
                    'selected_agents_joined': ', '.join(selected_agents),
                    'selected_agents_capabilities': detailed_agent_descriptions,
                    'sample_content': sample_content,
                    'event_name_mapping': event_name_mapping,
                    # Pass all unique component names for cross-references
                    'unique_planner_name': unique_component_names['planner'],
                    'unique_router_name': unique_component_names['router'],
                    'unique_summarizer_name': unique_component_names['summarizer'],
                    'unique_workflow_name': unique_component_names['workflow']
                }

                # Substitute variables in the user prompt
                user_prompt = substitute_prompt_variables(user_prompt_template, prompt_variables)

                # Use new validation function with retry logic
                try:
                    retries = getattr(conversation_manager, 'max_retries', None)
                except Exception:
                    retries = None
                if retries is None:
                    retries = DiscoveryConfigManager().get_conversation_config().get('max_retries', 2)

                instructions, ai_generated, error_message = validate_and_retry_yaml_generation(
                    component, system_prompt, user_prompt, conversation_manager, max_retries=retries
                )

                # Post-process: inject canonical dataHandlingContext for workflow
                if component == 'workflow' and instructions:
                    instructions = _inject_canonical_data_handling_context(instructions)

                if not instructions:
                    print(f"LLM {component} instruction generation failed after retries: {error_message}")
                    return {
                        'component': component,
                        'success': False,
                        'error': error_message or f"Failed to generate {component} instructions"
                    }

                return {
                    'component': component,
                    'success': True,
                    'instructions': instructions,
                    'aiGenerated': ai_generated
                }
                
            except Exception as e:
                print(f"Error generating {component} instructions: {str(e)}")
                return {
                    'component': component,
                    'success': False,
                    'error': str(e)
                }
        
        # Generate all components in parallel using ThreadPoolExecutor
        print(f"🔄 Starting parallel generation for all 4 components...")
        start_time = time.time()
        
        with concurrent.futures.ThreadPoolExecutor(max_workers=4) as executor:
            # Submit all component generation tasks
            future_to_component = {
                executor.submit(generate_single_component, component): component 
                for component in components
            }
            
            # Collect results as they complete
            results = {}
            for future in concurrent.futures.as_completed(future_to_component):
                component = future_to_component[future]
                try:
                    result = future.result()
                    results[component] = result
                    print(f"✅ Completed {component} generation (Success: {result['success']})")
                except Exception as e:
                    print(f"❌ Exception in {component} generation: {str(e)}")
                    results[component] = {
                        'component': component,
                        'success': False,
                        'error': str(e)
                    }
        
        end_time = time.time()
        print(f"✅ All component generation completed in {end_time - start_time:.2f} seconds")
        
        # Check if all components were generated successfully
        all_success = all(result['success'] for result in results.values())
        
        return jsonify({
            'success': all_success,
            'results': results,
            'generation_time': end_time - start_time
        })
    
    except Exception as e:
        print(f"Error in generate_all_component_instructions: {str(e)}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

@app.route('/api/create-workflow-agent', methods=['POST'])
def create_workflow_agent():
    """Create a new Workflow Agent with generated files"""
    try:
        data = request.json
        agent_name = data.get('agentName', '')
        description = data.get('description', '')
        selected_agents = data.get('selectedAgents', [])
        instructions = data.get('instructions', '')
        component_instructions = data.get('componentInstructions', {})
        unique_component_names = data.get('unique_component_names', {})  # Get unique names
        overwrite = data.get('overwrite', False)  # Add overwrite parameter
        
        if not agent_name or not selected_agents:
            return jsonify({
                'success': False,
                'error': 'Missing required fields: agentName, selectedAgents'
            }), 400

        # Check if we have component instructions (new 4-component system)
        if component_instructions:
            # Validate that we have all 4 components and their unique names
            required_components = ['planner', 'router', 'summarizer', 'workflow']
            missing_components = [comp for comp in required_components if not component_instructions.get(comp)]
            if missing_components:
                return jsonify({
                    'success': False,
                    'error': f'Missing component instructions: {", ".join(missing_components)}'
                }), 400

            missing_unique_names = [comp for comp in required_components if not unique_component_names.get(comp)]
            if missing_unique_names:
                return jsonify({
                    'success': False,
                    'error': f'Missing unique names for components: {", ".join(missing_unique_names)}'
                }), 400
        elif not instructions:
            return jsonify({
                'success': False,
                'error': 'Missing instructions or component instructions'
            }), 400
        
        # Prepare to create Workflow Agent files in a temporary directory first.
        # This enables safe validation before overwriting any existing agent files.
        import tempfile
        workflow_agents_base_dir = os.path.join(os.path.dirname(__file__), get_workflow_agents_dir())
        agent_specific_dir = os.path.join(workflow_agents_base_dir, agent_name)

        tmpdir = tempfile.mkdtemp(prefix=f"workflow_agent_build_{agent_name}_")
        created_files = []

        try:
            # Determine instructions to use (prioritize workflow for main entry point)
            final_instructions = instructions
            if component_instructions and component_instructions.get('workflow'):
                final_instructions = component_instructions['workflow']
            elif component_instructions and component_instructions.get('router'):
                final_instructions = component_instructions['router']

            # Create agent file path (workflow component as main entry point) in tmpdir
            agent_file_name = f"{unique_component_names['workflow']}.yaml"
            agent_file_path_tmp = os.path.join(tmpdir, agent_file_name)

            # If workflow content looks like full YAML, use it as-is (no server-side name enforcement)
            if isinstance(final_instructions, str) and final_instructions.strip().startswith('name:'):
                agent_yaml_content = final_instructions
            else:
                # Generate agent YAML content (traditional agent format)
                agent_yaml_content = generate_workflow_agent_yaml(
                    agent_name=agent_name,
                    description=f"{description} - Workflow orchestrator",
                    selected_agents=selected_agents,
                    instructions=final_instructions
                )

            # Write the main workflow file into temp dir
            with open(agent_file_path_tmp, 'w', encoding='utf-8') as f:
                f.write(agent_yaml_content)
            created_files.append(agent_file_path_tmp)

            # If we have component instructions, create separate files for each component in tmpdir
            if component_instructions:
                for component, component_instruction in component_instructions.items():
                    if not component_instruction:
                        continue

                    if component == 'workflow':
                        # If workflow is provided separately and differs, overwrite temp workflow file
                        if component_instruction != final_instructions:
                            if isinstance(component_instruction, str) and component_instruction.strip().startswith('name:'):
                                workflow_yaml_content = component_instruction
                            else:
                                workflow_yaml_content = generate_workflow_agent_yaml(
                                    agent_name=agent_name,
                                    description=f"{description} - Workflow orchestrator",
                                    selected_agents=selected_agents,
                                    instructions=component_instruction
                                )
                            with open(agent_file_path_tmp, 'w', encoding='utf-8') as f:
                                f.write(workflow_yaml_content)
                    else:
                        # Create other component files using their unique names
                        component_file_name = f"{unique_component_names[component]}.yaml"
                        component_file_path_tmp = os.path.join(tmpdir, component_file_name)
                        # If component content appears to be full YAML (has 'agent:' root), use as-is; otherwise wrap
                        if isinstance(component_instruction, str) and ('agent:' in component_instruction or component_instruction.strip().startswith('agent:')):
                            component_yaml_content = component_instruction
                        else:
                            component_yaml_content = generate_workflow_agent_yaml(
                                agent_name=unique_component_names.get(component, f"{agent_name}{component.capitalize()}Agent"),
                                description=f"{description} - {component.capitalize()} component",
                                selected_agents=selected_agents,
                                instructions=component_instruction
                            )

                        with open(component_file_path_tmp, 'w', encoding='utf-8') as f:
                            f.write(component_yaml_content)

                        created_files.append(component_file_path_tmp)

            # Perform event-name consistency validation against the files in tmpdir
            validation_messages = validate_workflow_agent_event_consistency(tmpdir, agent_name, unique_component_names)
            hard_errors = [m for m in validation_messages if not m.startswith('Warning:')]
            warnings = [m for m in validation_messages if m.startswith('Warning:')]

            # If there are hard errors, abort and do not move files to final location
            if hard_errors:
                # Clean up tmpdir but preserve for debugging by raising the errors in the response
                return jsonify({
                    'success': False,
                    'error': 'Event name validation failed',
                    'validation_errors': hard_errors,
                    'warnings': warnings,
                    'createdFiles': created_files
                }), 400

            # At this point validation passed or only warnings exist. Move files into final workflow_agents dir.
            os.makedirs(agent_specific_dir, exist_ok=True)

            # For each generated file, validate (schema or YAML syntax) then write/overwrite into agent_specific_dir
            final_created_files = []
            try:
                t_files = None
                try:
                    if config_manager:
                        t_files = config_manager.get_template_files()
                except Exception:
                    t_files = None

                for tmp_file in created_files:
                    # Read generated content
                    try:
                        with open(tmp_file, 'r', encoding='utf-8') as tf:
                            content = tf.read()
                    except Exception as read_err:
                        print(f"Failed to read generated temp file {tmp_file}: {read_err}")
                        return jsonify({'success': False, 'error': f'Failed to read generated file: {tmp_file}'}), 500

                    # Determine schema to use
                    schema_checked = False
                    try:
                        file_name = os.path.basename(tmp_file)
                        if t_files:
                            if file_name == f"{unique_component_names.get('workflow')}.yaml":
                                rel_schema = t_files.get('WorkflowDefinitionSchema')
                            else:
                                rel_schema = t_files.get('AgentDefinitionSchema')

                            if rel_schema:
                                candidate = Path(__file__).parent / rel_schema
                                if candidate.exists():
                                    vres = validate_yaml(str(candidate), content)
                                    schema_checked = True
                                    if not vres.valid:
                                        summarized = '; '.join(f"{e.path}: {e.message}" for e in vres.errors[:6])
                                        if len(vres.errors) > 6:
                                            summarized += ' ...'
                                        return jsonify({'success': False, 'error': f'Generated file failed schema validation: {file_name}: {summarized}'}), 400
                    except Exception as e:
                        print(f"Warning: schema validation check failed for {tmp_file}: {e}")

                    if not schema_checked:
                        try:
                            yaml.safe_load(content)
                        except Exception as ve:
                            return jsonify({'success': False, 'error': f'Generated file has invalid YAML: {file_name}: {ve}'}), 400

                    # Copy file into final dir
                    target_file = os.path.join(agent_specific_dir, os.path.basename(tmp_file))
                    try:
                        shutil.copy2(tmp_file, target_file)
                        final_created_files.append(target_file)
                    except Exception as copy_err:
                        print(f"Failed to copy {tmp_file} to {target_file}: {copy_err}")
                        # Continue attempting to copy other files; surface copy errors later if needed
            except Exception as top_err:
                print(f"Error during validation/copy of generated files: {top_err}")
                return jsonify({'success': False, 'error': str(top_err)}), 500

            created_files = final_created_files

        finally:
            # Remove temporary dir if it still exists
            try:
                if os.path.exists(tmpdir):
                    shutil.rmtree(tmpdir)
            except Exception:
                pass
        
        # At this point we've already validated the tmpdir contents. Proceed to update the agents catalog
        # and return the result. Use the final created files as authoritative.
    
    # Update the agents catalog to register this Workflow Agent (append or replace existing)
        try:
            catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
            
            # Load current catalog (initialize empty structure if missing/empty)
            import yaml
            catalog_data = {}
            if os.path.exists(catalog_path):
                with open(catalog_path, 'r', encoding='utf-8') as f:
                    loaded = yaml.safe_load(f)
                    if isinstance(loaded, dict):
                        catalog_data = loaded
            
            # Ensure workflow_agents section exists
            if 'workflow_agents' not in catalog_data or not isinstance(catalog_data['workflow_agents'], list):
                catalog_data['workflow_agents'] = []
            
            # Build new/updated workflow agent record (no azure_resource_id)
            # POLICY UPDATE (Aug 2025): Re-introduce explicit 'name' field for workflow agents in the catalog
            # to keep structure consistent with existing entries and simplify client-side lookup.
            # The YAML still serves as the authoritative source for display metadata, but catalog 'name'
            # is retained for uniformity and backward compatibility with UI expectations.
            new_entry = {
                'name': agent_name,
                'description': description,
                'agent_config': f"{get_workflow_agents_dir()}{agent_name}/{agent_file_name}",
                'components': []
            }
            
            # Discover component files that were created and add to components
            component_types = ['planner', 'router', 'summarizer', 'workflow']
            for component_type in component_types:
                # Use unique component names, which are guaranteed to exist at this point
                component_name = unique_component_names[component_type]
                component_file = f"{component_name}.yaml"
                
                component_path = os.path.join(agent_specific_dir, component_file)
                if os.path.exists(component_path):
                    new_entry['components'].append({
                        'name': component_name,
                        'agent_config': f"{get_workflow_agents_dir()}{agent_name}/{component_file}",
                        'type': component_type
                    })
            
            # Replacement logic respecting catalog name deprecation:
            # 1. Prefer match by agent_config (canonical path based key)
            # 2. Fallback to legacy 'name' match if present (backward compatibility)
            # We intentionally do NOT re-introduce 'name' on write.
            replaced = False
            new_agent_config_path = new_entry['agent_config']
            for i, entry_agent in enumerate(catalog_data['workflow_agents']):
                if not isinstance(entry_agent, dict):
                    continue
                existing_cfg = entry_agent.get('agent_config')
                if existing_cfg == new_agent_config_path:
                    catalog_data['workflow_agents'][i] = new_entry
                    replaced = True
                    break
            if not replaced:
                for i, entry_agent in enumerate(catalog_data['workflow_agents']):
                    if not isinstance(entry_agent, dict):
                        continue
                    legacy_name = entry_agent.get('name')  # legacy field
                    if legacy_name == agent_name:
                        catalog_data['workflow_agents'][i] = new_entry
                        replaced = True
                        break
            if not replaced:
                catalog_data['workflow_agents'].append(new_entry)
            
            # Save updated catalog
            with open(catalog_path, 'w', encoding='utf-8') as f:
                yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False, indent=2)
            
            print(f"✅ {'Updated' if replaced else 'Added'} workflow agent '{agent_name}' in catalog (name field omitted; YAML is source of display name)")
            
            # Reload the agent manager (if available) to pick up the changes
            if agent_manager:
                agent_manager.reload_catalog()
        except Exception as cataprint:
            print(f"⚠️ Warning: Failed to update catalog: {cataprint}")
            # Don't fail the entire operation if catalog update fails
        
        action_word = "overwritten" if overwrite else "created"
        # Determine a sensible filePath to return (main workflow file if available)
        agent_file_path_final = created_files[0] if created_files else os.path.join(agent_specific_dir, f"{unique_component_names.get('workflow', agent_name)}.yaml")
        return jsonify({
            'success': True,
            'agentName': agent_name,
            'filePath': agent_file_path_final,
            'createdFiles': created_files,
            'componentCount': len(created_files),
            'message': f'Workflow Agent "{agent_name}" {action_word} successfully with {len(created_files)} component(s)',
            'overwritten': overwrite,
            # Surface any non-fatal warnings so the UI can inform the user.
            'warnings': warnings if 'warnings' in locals() and warnings else []
        })
        
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

@app.route('/api/resolve-file-path', methods=['POST'])
def resolve_file_path():
    """Resolve a filename to possible relative paths from the web server's perspective"""
    try:
        data = request.json
        file_name = data.get('fileName', '').strip()
        context_path = data.get('contextPath', '').strip()  # Path to agent config for context
        
        if not file_name:
            return jsonify({
                'success': False,
                'error': 'Missing fileName parameter'
            }), 400
        
        # Get the web server's working directory
        web_server_dir = os.getcwd()
        # Get the project root (go up from Utils/agent-workbench to project root)
        project_root = os.path.abspath(os.path.join(web_server_dir, '..', '..'))
        
        found_paths = []
        
        # If we have a context path (agent config file), prioritize the same directory
        if context_path:
            try:
                # Convert context path to absolute path
                context_abs_path = os.path.abspath(os.path.join(web_server_dir, context_path))
                context_dir = os.path.dirname(context_abs_path)
                
                # Check if the file exists in the same directory as the context file
                potential_file = os.path.join(context_dir, file_name)
                if os.path.exists(potential_file):
                    # Found in same directory - this gets highest priority
                    rel_path = os.path.relpath(potential_file, web_server_dir)
                    rel_path = rel_path.replace('\\', '/')
                    found_paths.append(rel_path)
                    print(f"✅ Context-aware match: {rel_path} (same directory as {context_path})")
            except Exception as e:
                print(f"Warning: Could not process context path {context_path}: {e}")
        
        # Search for the file in configured directories (but lower priority than context match)
        if DISCOVERY_AVAILABLE and config_manager:
            search_dirs = config_manager.get_agent_search_directories()
        else:
            raise ValueError("DiscoveryConfigManager not available - cannot load configured directories")
        
        for search_dir in search_dirs:
            # If search_dir is a relative path (starts with ../), resolve it relative to web_server_dir
            if search_dir.startswith('../'):
                search_path = os.path.abspath(os.path.join(web_server_dir, search_dir))
            else:
                # If it's not a relative path, join with project_root
                search_path = os.path.join(project_root, search_dir)
            
            if os.path.exists(search_path):
                # Walk through subdirectories to find the file
                for root, dirs, files in os.walk(search_path):
                    if file_name in files:
                        # Found the file, now convert to relative path from web server
                        full_file_path = os.path.join(root, file_name)
                        # Calculate relative path from web server directory
                        try:
                            rel_path = os.path.relpath(full_file_path, web_server_dir)
                            # Normalize path separators for web
                            rel_path = rel_path.replace('\\', '/')
                            # Don't add duplicates (context match might already be included)
                            if rel_path not in found_paths:
                                found_paths.append(rel_path)
                        except ValueError:
                            # Handle case where paths are on different drives on Windows
                            continue
        
        # Remove duplicates while preserving order
        unique_paths = []
        for path in found_paths:
            if path not in unique_paths:
                unique_paths.append(path)
        
        return jsonify({
            'success': True,
            'paths': unique_paths,
            'fileName': file_name
        })
        
    except Exception as e:
        print(f"Error resolving file path: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

@app.route('/api/validate-emojis', methods=['POST'])
def validate_emojis_endpoint():
    """
    Validate YAML content for emoji characters.

    Request body:
        { "content": "yaml content string" }

    Response:
        {
            "success": true,
            "has_emojis": bool,
            "emoji_count": int,
            "unique_emojis": [str],
            "fields_with_emojis": [str],
            "warnings": [
                {
                    "path": str,
                    "field": str,
                    "emoji": str,
                    "line": int,
                    "column": int,
                    "suggested_replacement": str or null,
                    "message": str
                }
            ]
        }
    """
    try:
        data = request.json
        content = data.get('content', '').strip()

        if not content:
            return jsonify({
                'success': False,
                'error': 'Missing content parameter'
            }), 400

        # Try to import emoji detection utilities
        try:
            from file_utils import detect_emojis, detect_emojis_in_yaml_fields, EMOJI_ASCII_REPLACEMENTS
        except ImportError:
            return jsonify({
                'success': False,
                'error': 'Emoji detection module not available'
            }), 500

        # Parse YAML first
        try:
            yaml_doc = yaml.safe_load(content)
        except yaml.YAMLError as e:
            return jsonify({
                'success': True,
                'has_emojis': False,
                'emoji_count': 0,
                'unique_emojis': [],
                'fields_with_emojis': [],
                'warnings': [],
                'yaml_error': f'Invalid YAML syntax: {str(e)}'
            })

        # Detect emojis in YAML fields
        emoji_fields = detect_emojis_in_yaml_fields(yaml_doc)

        warnings = []
        unique_emojis = set()
        fields_with_emojis = []

        for field_info in emoji_fields:
            path = field_info['path']
            field_name = field_info['field']
            emoji_result = field_info['emoji_result']

            field_path = f"{path}.{field_name}" if path != '<root>' else field_name
            fields_with_emojis.append(field_path)

            for emoji_data in emoji_result.get('emojis', []):
                unique_emojis.add(emoji_data['emoji'])
                replacement = emoji_data.get('suggested_replacement')
                replacement_hint = f" (suggested: '{replacement}')" if replacement else ""
                warnings.append({
                    'path': path,
                    'field': field_name,
                    'emoji': emoji_data['emoji'],
                    'line': emoji_data['line'],
                    'column': emoji_data['column'],
                    'suggested_replacement': replacement,
                    'message': f"Emoji '{emoji_data['emoji']}' found at line {emoji_data['line']}, column {emoji_data['column']}{replacement_hint}"
                })

        return jsonify({
            'success': True,
            'has_emojis': len(warnings) > 0,
            'emoji_count': len(warnings),
            'unique_emojis': list(unique_emojis),
            'fields_with_emojis': fields_with_emojis,
            'warnings': warnings
        })

    except Exception as e:
        print(f"Error validating emojis: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


@app.route('/api/replace-emojis', methods=['POST'])
def replace_emojis_endpoint():
    """
    Replace emojis in content with ASCII equivalents.

    Request body:
        { "content": "yaml content string" }

    Response:
        {
            "success": true,
            "replaced_content": str,
            "replacement_count": int,
            "replacements": [
                {
                    "emoji": str,
                    "replacement": str
                }
            ]
        }
    """
    try:
        data = request.json
        content = data.get('content', '')

        if not content:
            return jsonify({
                'success': False,
                'error': 'Missing content parameter'
            }), 400

        # Try to import emoji replacement utilities
        try:
            from file_utils import replace_emojis_with_ascii, detect_emojis, EMOJI_ASCII_REPLACEMENTS
        except ImportError:
            return jsonify({
                'success': False,
                'error': 'Emoji replacement module not available'
            }), 500

        # First detect what emojis are present to report replacements
        detection_result = detect_emojis(content)

        # Build list of replacements that will be made
        replacements = []
        seen_emojis = set()
        for emoji_match in detection_result.emojis:
            emoji = emoji_match.emoji
            if emoji not in seen_emojis:
                seen_emojis.add(emoji)
                replacement = EMOJI_ASCII_REPLACEMENTS.get(emoji, '[?]')
                replacements.append({
                    'emoji': emoji,
                    'replacement': replacement
                })

        # Perform the replacement
        replaced_content, replacement_count = replace_emojis_with_ascii(content)

        return jsonify({
            'success': True,
            'replaced_content': replaced_content,
            'replacement_count': replacement_count,
            'replacements': replacements
        })

    except Exception as e:
        print(f"Error replacing emojis: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


@app.route('/api/validate-file-content', methods=['POST'])
def validate_file_content():
    """Determine file type based on YAML content structure instead of filename"""
    try:
        data = request.json
        content = data.get('content', '').strip()
        
        if not content:
            return jsonify({
                'success': False,
                'error': 'Missing content parameter'
            }), 400
        
        try:
            import yaml
            yaml_doc = yaml.safe_load(content)
            
            if not yaml_doc or not isinstance(yaml_doc, dict):
                return jsonify({
                    'success': True,
                    'fileType': 'unknown',
                    'message': 'Content is not a valid YAML dictionary'
                })
            
            # Check for agent definition characteristics
            agent_indicators = ['agents', 'agent_type', 'assistant_role', 'system_message', 'agent_description']
            if any(key in yaml_doc for key in agent_indicators):
                return jsonify({
                    'success': True,
                    'fileType': 'agent',
                    'confidence': 'high'
                })
            
            # Check for tool definition characteristics
            tool_indicators = ['infra', 'code_environments', 'actions']
            basic_tool_structure = ('name' in yaml_doc and 'version' in yaml_doc and 'category' in yaml_doc)
            if any(key in yaml_doc for key in tool_indicators) or basic_tool_structure:
                return jsonify({
                    'success': True,
                    'fileType': 'tool',
                    'confidence': 'high'
                })
            
            # Check for workflow definition characteristics
            workflow_indicators = ['states', 'transitions', 'variables', 'workflow', 'startstate']
            if any(key in yaml_doc for key in workflow_indicators):
                return jsonify({
                    'success': True,
                    'fileType': 'workflow',
                    'confidence': 'high'
                })
            
            return jsonify({
                'success': True,
                'fileType': 'unknown',
                'confidence': 'low',
                'message': 'Could not determine file type from content structure'
            })
            
        except yaml.YAMLError as e:
            return jsonify({
                'success': True,
                'fileType': 'invalid',
                'error': f'Invalid YAML syntax: {str(e)}'
            })
        
    except Exception as e:
        print(f"Error validating file content: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

@app.route('/api/load-agent', methods=['POST'])
def load_agent():
    """Load an existing agent configuration into the catalog"""
    global agent_manager
    try:
        data = request.json
        
        agent_type = data.get('agentType', '')
        
        if not agent_type:
            return jsonify({
                'success': False,
                'error': 'Missing required field: agentType'
            }), 400
        
        # Validate agent type
        valid_types = ['tool', 'entry', 'kb']
        if agent_type not in valid_types:
            return jsonify({
                'success': False,
                'error': f'Invalid agent type. Must be one of: {", ".join(valid_types)}'
            }), 400

        # Extract agent name from config file
        agent_config = data.get('agentConfig', '').strip()
        if not agent_config:
            return jsonify({
                'success': False,
                'error': 'Missing required field: agentConfig'
            }), 400

        # Convert relative path to absolute and read the config file
        script_dir = os.path.dirname(__file__)
        config_abs_path = os.path.abspath(os.path.join(script_dir, agent_config))
        
        if not os.path.exists(config_abs_path):
            return jsonify({
                'success': False,
                'error': f'Agent config file not found: {agent_config}'
            }), 400

        try:
            with open(config_abs_path, 'r', encoding='utf-8') as f:
                agent_yaml = yaml.safe_load(f)
            
            # Extract agent name from YAML based on agent type
            if agent_type == 'entry':
                # Entry agents have workflow files with top-level 'name' field
                if 'name' not in agent_yaml:
                    return jsonify({
                        'success': False,
                        'error': 'Invalid workflow agent config file: missing name field'
                    }), 400
                agent_name = agent_yaml['name']
            else:
                # Tool and KB agents have 'agent.name' structure
                if 'agent' not in agent_yaml or 'name' not in agent_yaml['agent']:
                    return jsonify({
                        'success': False,
                        'error': f'Invalid {agent_type} agent config file: missing agent.name field'
                    }), 400
                agent_name = agent_yaml['agent']['name']
            
        except Exception as e:
            return jsonify({
                'success': False,
                'error': f'Failed to parse agent config file: {str(e)}'
            }), 400
        
        # Get catalog path
        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        
        # Load existing catalog
        if os.path.exists(catalog_path):
            with open(catalog_path, 'r', encoding='utf-8') as f:
                catalog = yaml.safe_load(f) or {}
        else:
            catalog = {}
        
        # Ensure all required sections exist and are lists
        if 'tool_agents' not in catalog or not isinstance(catalog['tool_agents'], list):
            catalog['tool_agents'] = []
        if 'workflow_agents' not in catalog or not isinstance(catalog['workflow_agents'], list):
            catalog['workflow_agents'] = []
        if 'kb_agents' not in catalog or not isinstance(catalog['kb_agents'], list):
            catalog['kb_agents'] = []
        
        # Get script directory for relative path calculation
        script_dir = os.path.dirname(__file__)
        
        # Process based on agent type
        if agent_type == 'tool':
            tools_definition = data.get('toolsDefinition', '').strip()
            dockerfile = data.get('dockerfile', '').strip()
            env_vars = data.get('envVars', '').strip() if data.get('envVars') else None
            
            if not all([tools_definition, dockerfile]):
                return jsonify({
                    'success': False,
                    'error': 'Missing required fields for tool agent: toolsDefinition, dockerfile'
                }), 400
            
            # Validate files exist
            tools_definition_path = os.path.join(script_dir, tools_definition)
            dockerfile_path = os.path.join(script_dir, dockerfile)
            
            missing_files = []
            if not os.path.exists(tools_definition_path):
                missing_files.append(f"Tools definition: {tools_definition}")
            if not os.path.exists(dockerfile_path):
                missing_files.append(f"Dockerfile: {dockerfile}")
            
            # Validate env vars file if provided
            if env_vars:
                env_vars_path = os.path.join(script_dir, env_vars)
                if not os.path.exists(env_vars_path):
                    missing_files.append(f"Environment variables: {env_vars}")
            
            if missing_files:
                return jsonify({
                    'success': False,
                    'error': f'Files not found: {", ".join(missing_files)}'
                }), 400
            
            # Initialize tool_agents section if it doesn't exist or is None
            if 'tool_agents' not in catalog or not isinstance(catalog['tool_agents'], list):
                catalog['tool_agents'] = []
            
            # Convert paths to forward slashes for consistency
            agent_config_rel = agent_config.replace('\\', '/')
            tools_definition_rel = tools_definition.replace('\\', '/')
            dockerfile_rel = dockerfile.replace('\\', '/')
            env_vars_rel = env_vars.replace('\\', '/') if env_vars else None
            
            new_tool_agent = {
                'name': agent_name,
                'agent_config': agent_config_rel,
                'tools_definition': tools_definition_rel,
                'dockerfile': dockerfile_rel
            }
            
            # Add env_vars if provided
            if env_vars_rel:
                new_tool_agent['env_vars'] = env_vars_rel
            
            # Add env_vars if provided
            if env_vars_rel:
                new_tool_agent['env_vars'] = env_vars_rel
            
            # Check if agent already exists
            existing_agent = next((agent for agent in catalog['tool_agents'] if agent.get('name') == agent_name), None)
            
            if existing_agent:
                # Update existing entry
                existing_agent.update(new_tool_agent)
                action = 'updated'
            else:
                # Add new entry
                catalog['tool_agents'].append(new_tool_agent)
                action = 'added'
        
        elif agent_type == 'entry':
            # Initialize workflow_agents section if it doesn't exist or is None
            if 'workflow_agents' not in catalog or not isinstance(catalog['workflow_agents'], list):
                catalog['workflow_agents'] = []
            
            # Convert path to forward slashes for consistency
            agent_config_rel = agent_config.replace('\\', '/')
            
            new_workflow_agent = {
                'name': agent_name,
                'agent_config': agent_config_rel
            }
            
            # Auto-discover planner, router, and summarizer components
            # If agent name is "simplehlgap-wfl", components will be "simplehlgap-pln", "simplehlgap-rtr", "simplehlgap-sum"
            agent_dir = os.path.dirname(config_abs_path)
            base_name = agent_name.replace('-wfl', '')  # Remove workflow suffix to get base name
            
            components = []
            component_types = {
                'pln': 'planner',
                'rtr': 'router', 
                'sum': 'summarizer'
            }
            
            for suffix, component_type in component_types.items():
                component_name = f'{base_name}-{suffix}'
                component_file = f'{component_name}.yaml'
                component_path = os.path.join(agent_dir, component_file)
                
                if os.path.exists(component_path):
                    relative_path = os.path.relpath(component_path, script_dir).replace('\\', '/')
                    components.append({
                        'name': component_name,
                        'type': component_type,
                        'agent_config': relative_path
                    })
            
            # Add components to the workflow agent if any were found
            if components:
                new_workflow_agent['components'] = components
            
            # Check if agent already exists
            existing_agent = next((agent for agent in catalog['workflow_agents'] if agent.get('name') == agent_name), None)
            if existing_agent:
                # Update existing entry
                existing_agent.update(new_workflow_agent)
                action = 'updated'
            else:
                # Add new entry
                catalog['workflow_agents'].append(new_workflow_agent)
                action = 'added'
        
        elif agent_type == 'kb':
            # Initialize kb_agents section if it doesn't exist or is None
            if 'kb_agents' not in catalog or not isinstance(catalog['kb_agents'], list):
                catalog['kb_agents'] = []
            
            # Convert path to forward slashes for consistency
            agent_config_rel = agent_config.replace('\\', '/')
            
            new_kb_agent = {
                'name': agent_name,
                'agent_config': agent_config_rel
            }
            
            # Check if agent already exists
            existing_agent = next((agent for agent in catalog['kb_agents'] if agent.get('name') == agent_name), None)
            if existing_agent:
                # Update existing entry
                existing_agent.update(new_kb_agent)
                action = 'updated'
            else:
                # Add new entry
                catalog['kb_agents'].append(new_kb_agent)
                action = 'added'
        
        # Write updated catalog
        with open(catalog_path, 'w', encoding='utf-8') as f:
            yaml.dump(catalog, f, default_flow_style=False, sort_keys=False, allow_unicode=True)
        
        print(f"📝 {action.capitalize()} {agent_type} agent in catalog: {agent_name}")
        
        # Reload the agent manager catalog to pick up the new agent
        try:
            if agent_manager:
                agent_manager.reload_catalog()
                print(f"🔄 Reloaded agent catalog after loading {agent_type} agent")
            else:
                # Initialize agent manager if it doesn't exist (e.g., empty catalog scenario)
                print(f"ℹ️ Initializing agent manager after loading first agent")
                catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
                agent_manager = StaticAgentManager(catalog_path)
                print(f"✅ Agent manager initialized with {len(agent_manager.list_agents()['tool_agents']) + len(agent_manager.list_agents()['workflow_agents']) + len(agent_manager.list_agents()['kb_agents'])} agents")
        except Exception as reload_error:
            print(f"⚠️ Warning: Could not reload agents catalog: {reload_error}")
        
        return jsonify({
            'success': True,
            'agentName': agent_name,
            'agentType': agent_type,
            'action': action,
            'message': f'{agent_type.capitalize()} agent "{agent_name}" {action} successfully'
        })
        
    except Exception as e:
        print(f"❌ Error loading agent: {str(e)}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

def validate_tool_agent_yaml_with_schema(yaml_content, definition_type):
    """
    Validate tool or agent definition YAML against JSON schema.
    
    Args:
        yaml_content (str): The YAML content to validate
        definition_type (str): Either 'tool' or 'agent'
        
    Returns:
        tuple: (is_valid: bool, error_message: str or None)
    """
    try:
        # Parse YAML content
        yaml_data = yaml.safe_load(yaml_content)
        if not yaml_data:
            return False, "Empty or invalid YAML content"

        # Additional semantic validation for agent definitions
        # NOTE: These values are reserved runtime context placeholders and must not be declared
        # as user-provided inputs under extension.inputs.
        if definition_type == 'agent':
            forbidden = _find_forbidden_extension_input_names(yaml_data)
            if forbidden:
                forbidden_list = ", ".join(sorted(forbidden))
                return (
                    False,
                    (
                        "Reserved inputs are not allowed in agent definition extension.inputs: "
                        f"{forbidden_list}. "
                        "Remove them from extension.inputs (they may still be referenced in instructions as template variables)."
                    ),
                )

        # Get schema path from configuration
        from discovery_config_manager import DiscoveryConfigManager
        config_manager = DiscoveryConfigManager()
        template_files = config_manager.get_template_files()

        if definition_type == 'tool':
            schema_path = template_files.get('ToolDefinitionSchema')
        elif definition_type == 'agent':
            schema_path = template_files.get('AgentDefinitionSchema')
        else:
            return False, f"Invalid definition type: {definition_type}. Must be 'tool' or 'agent'"

        # Resolve full schema path
        full_schema_path = os.path.join(os.path.dirname(__file__), schema_path)
        if not os.path.exists(full_schema_path):
            return False, f"Schema file not found: {full_schema_path}"

        # Prefer the centralized validator which returns structured errors
        try:
            v_result = validate_yaml(str(full_schema_path), yaml_content)
            if v_result and getattr(v_result, 'valid', False):
                return True, None
            else:
                # Summarize first few errors for brevity
                if v_result and getattr(v_result, 'errors', None):
                    summarized = '; '.join(f"{e.path}: {e.message}" for e in v_result.errors[:5])
                    if len(v_result.errors) > 5:
                        summarized += ' ...'
                    return False, summarized
                return False, 'Schema validation failed (see validator for details)'
        except Exception:
            # Fallback: attempt jsonschema validation to provide a readable error
            try:
                with open(full_schema_path, 'r', encoding='utf-8') as f:
                    schema = json.load(f)
                jsonschema.validate(instance=yaml_data, schema=schema)
                return True, None
            except jsonschema.ValidationError as e:
                error_path = " -> ".join(str(p) for p in e.absolute_path) if e.absolute_path else "root"
                return False, f"Schema validation error at '{error_path}': {e.message}"
            except Exception as e:
                return False, f"Validation error: {str(e)}"
    except yaml.YAMLError as e:
        return False, f"YAML parsing error: {str(e)}"


def _find_forbidden_extension_input_names(agent_yaml: dict) -> set:
    """Return any forbidden input names declared under extension.inputs.

    Forbidden names are reserved runtime context fields that must NOT be declared as user inputs.
    This does not restrict usage of {{nodePoolContext}}, {{dataHandlingContext}}, or {{messageId}}
    inside agent.instructions text.
    """
    forbidden_names = {"nodePoolContext", "dataHandlingContext", "messageId"}
    found: set = set()

    if not isinstance(agent_yaml, dict):
        return found

    extension_block = agent_yaml.get('extension')
    if not isinstance(extension_block, dict):
        return found

    inputs_block = extension_block.get('inputs')
    if not inputs_block:
        return found

    # Schema commonly uses a list of {name, type, ...} dicts, but tolerate dict-of-inputs too.
    if isinstance(inputs_block, list):
        for item in inputs_block:
            if isinstance(item, dict):
                name = item.get('name')
                if isinstance(name, str) and name in forbidden_names:
                    found.add(name)
    elif isinstance(inputs_block, dict):
        for name in inputs_block.keys():
            if isinstance(name, str) and name in forbidden_names:
                found.add(name)

    return found

def validate_and_retry_tool_agent_generation(definition_type, system_prompt, user_prompt_base, conversation_manager, max_retries=2):
    """
    Generate and validate tool or agent definition YAML with schema validation and retry logic.
    
    This function is specifically designed for tool and agent definition generation,
    separate from the generic validate_and_retry_yaml_generation function.
    
    Args:
        definition_type (str): Either 'tool' or 'agent'
        system_prompt (str): System prompt for LLM
        user_prompt_base (str): Base user prompt for LLM
        conversation_manager: Conversation manager instance
        max_retries (int): Maximum number of retry attempts
        
    Returns:
        tuple: (yaml_content: str or None, success: bool, error_message: str or None)
    """
    previous_error = ""
    last_yaml_content = None

    for attempt in range(max_retries + 1):
        temp_session_id = None
        try:
            # Create a temporary session for generation
            temp_session_id = conversation_manager.create_session(system_prompt)
            
            # Prepare user prompt (add error feedback on retries)
            if attempt == 0:
                user_prompt = user_prompt_base
            else:
                error_feedback = f"""

CRITICAL VALIDATION ERROR DETECTED:
Your previous attempt failed validation with: {previous_error}

SCHEMA VALIDATION REQUIREMENTS:
- For TOOL definitions: Must include name, description, version, infra, and code_environments
- For AGENT definitions: Must include agent object with name, description, model, and instructions
- Names must follow naming conventions (tool: lowercase with underscores, agent: CamelCase)
- Version must be semantic (x.y.z format)
- Model must be Azure ML endpoint format
- **CRITICAL ACR Format**: infra[0].image.acr MUST be `<registry>.azurecr.io/<image>:<tag>` (NOT Docker Hub format like `registry/image:tag`)
  - Correct: `contoso.azurecr.io/myapp:v1.0`
  - Wrong: `contoso/myapp:v1.0` (missing .azurecr.io)
- All required fields must be present and properly formatted

Please fix these validation errors and generate valid YAML that conforms to the schema."""
                user_prompt = user_prompt_base + error_feedback
            
            conversation_manager.add_message("user", user_prompt, temp_session_id)
            
            # Get messages for API call
            messages = conversation_manager.get_conversation_for_api(temp_session_id)
            
            # Call Azure OpenAI (require ConversationManager)
            try:
                temp = getattr(conversation_manager, 'temperature', None)
            except Exception:
                temp = None
            if temp is None:
                temp = DiscoveryConfigManager().get_conversation_config().get('temperature')
            response_data = call_azure_openai_direct(messages, max_output_tokens=conversation_manager.max_output_tokens, temperature=temp)

            # Token diagnostics: estimate prompt tokens and extract API usage if available
            try:
                estimated_prompt_tokens = None
                try:
                    if conversation_manager:
                        estimated_prompt_tokens = sum(conversation_manager.count_tokens(m.get('content','') if isinstance(m, dict) else m) for m in messages)
                    else:
                        estimated_prompt_tokens = sum(len(m.get('content','')) // 4 for m in messages)
                except Exception:
                    estimated_prompt_tokens = None

                finish_reason = None
                usage = {}
                prompt_usage = None
                completion_usage = None
                total_usage = None
                try:
                    if isinstance(response_data, dict):
                        choices = response_data.get('choices') or []
                        if choices:
                            finish_reason = choices[0].get('finish_reason')
                        usage = response_data.get('usage') or {}
                        prompt_usage = usage.get('prompt_tokens')
                        completion_usage = usage.get('completion_tokens')
                        total_usage = usage.get('total_tokens')
                except Exception:
                    pass

                print(f"DEBUG: {definition_type} generation tokens estimate: prompt_est={estimated_prompt_tokens}, usage_prompt={prompt_usage}, usage_completion={completion_usage}, usage_total={total_usage}, finish_reason={finish_reason}")

                # Persist raw LLM response and token diagnostics for debugging (best-effort)
                try:
                    if temp_session_id:
                        tmp_root = os.path.join(os.path.dirname(__file__), 'user-session', temp_session_id, 'generated')
                        os.makedirs(tmp_root, exist_ok=True)
                        raw_out = os.path.join(tmp_root, f'raw_llm_response_{definition_type}_attempt{attempt+1}.json')
                        with open(raw_out, 'w', encoding='utf-8') as rf:
                            json.dump(response_data, rf, default=str)
                        diag = {
                            'estimated_prompt_tokens': estimated_prompt_tokens,
                            'usage_prompt_tokens': prompt_usage,
                            'usage_completion_tokens': completion_usage,
                            'usage_total_tokens': total_usage,
                            'finish_reason': finish_reason,
                            'attempt': attempt + 1,
                            'definition_type': definition_type
                        }
                        diag_out = os.path.join(tmp_root, f'token_diag_{definition_type}_attempt{attempt+1}.json')
                        with open(diag_out, 'w', encoding='utf-8') as df:
                            json.dump(diag, df, indent=2)
                except Exception:
                    pass
            except Exception:
                # Non-fatal: proceed even if diagnostics fail
                pass

            # Parse the response
            raw_response = parse_llm_response_direct(response_data)
            if not raw_response:
                raise Exception("No response from LLM")
                
            # Extract YAML content
            yaml_content = extract_yaml_from_llm_response(raw_response)
            # Keep the last YAML the LLM produced (even if invalid)
            last_yaml_content = yaml_content
            if not yaml_content:
                raise Exception("No YAML content found in LLM response")
            
            # Validate YAML syntax first
            try:
                yaml.safe_load(yaml_content)
            except yaml.YAMLError as yaml_error:
                previous_error = f"YAML syntax error: {str(yaml_error)}"
                print(f"{definition_type} generation failed on attempt {attempt + 1}: {previous_error}")

                if attempt == max_retries:
                    # On final attempt, still return the last YAML produced so it can be placed
                    return last_yaml_content, False, previous_error
                continue
            
            # Validate against schema
            is_valid, schema_error = validate_tool_agent_yaml_with_schema(yaml_content, definition_type)
            
            if is_valid:
                # print(f"✅ {definition_type.capitalize()} definition validation passed on attempt {attempt + 1}")  # Reduced verbosity
                return yaml_content, True, None
            else:
                previous_error = f"Schema validation failed: {schema_error}"
                print(f"❌ {definition_type.capitalize()} definition validation failed on attempt {attempt + 1}: {previous_error}")

                if attempt == max_retries:
                    # On final attempt, return the last YAML produced so it can be placed
                    return last_yaml_content, False, previous_error
                continue
                
        except Exception as e:
            previous_error = f"Generation error: {str(e)}"
            print(f"{definition_type.capitalize()} generation failed on attempt {attempt + 1}: {previous_error}")

            if attempt == max_retries:
                # Return whatever YAML we have from the last attempt, if any
                return last_yaml_content, False, previous_error
            continue
        finally:
            # Clean up temporary session
            try:
                if temp_session_id and temp_session_id in conversation_manager.sessions:
                    del conversation_manager.sessions[temp_session_id]
            except:
                pass
    
    return None, False, "Max retries exceeded"

def _get_schema_for_component(component):
    """
    Get the appropriate JSON schema path for a component type.
    Returns (schema_path, schema_exists) tuple.
    Similar to the mermaid validation pattern, this enables schema-based validation
    with clear error feedback for LLM retry.
    """
    try:
        config_manager = DiscoveryConfigManager()
        template_files = config_manager.get_template_files()
        
        # Map component types to their schema keys
        if component == 'workflow':
            schema_key = 'WorkflowDefinitionSchema'
        else:
            # planner, router, summarizer all use agent schema
            schema_key = 'AgentDefinitionSchema'
        
        rel_schema = template_files.get(schema_key)
        if not rel_schema:
            return None, False
        
        schema_path = Path(__file__).parent / rel_schema
        return str(schema_path) if schema_path.exists() else None, schema_path.exists()
    except Exception as e:
        print(f"⚠️ Error getting schema for {component}: {e}")
        return None, False


def _validate_component_yaml_against_schema(yaml_content, component):
    """
    Validate YAML content against the appropriate JSON schema.
    Returns (is_valid, error_message) tuple.
    This validation pattern mirrors the mermaid validation approach where we:
    1. Validate the generated content
    2. Return structured error feedback
    3. Allow LLM to retry with specific error guidance
    """
    try:
        schema_path, schema_exists = _get_schema_for_component(component)
        
        if not schema_exists or not schema_path:
            # If no schema available, only do basic YAML syntax check
            try:
                yaml.safe_load(yaml_content)
                return True, None
            except yaml.YAMLError as e:
                return False, f"YAML syntax error: {str(e)}"
        
        # Perform schema validation using centralized validator
        if not validate_yaml:
            return False, "Schema validator not available"
        
        result = validate_yaml(schema_path, yaml_content)
        
        if result.valid:
            return True, None
        
        # Format validation errors for LLM feedback (similar to mermaid error formatting)
        # Provide specific, actionable error messages
        error_details = []
        for idx, error in enumerate(result.errors[:5]):  # Limit to first 5 errors
            path_str = error.path if error.path else '<root>'
            error_details.append(f"  {idx+1}. At '{path_str}': {error.message}")
        
        if len(result.errors) > 5:
            error_details.append(f"  ... and {len(result.errors) - 5} more errors")
        
        error_summary = "\n".join(error_details)
        error_message = f"Schema validation failed for {component} component:\n{error_summary}\n\nCommon fixes:\n- Ensure all required fields are present\n- Check field names match schema exactly\n- Verify data types (strings, lists, objects)\n- Remove any extra/unknown fields"
        
        return False, error_message
        
    except Exception as e:
        return False, f"Schema validation error: {str(e)}"


def validate_and_retry_yaml_generation(component, system_prompt, user_prompt_base, conversation_manager, max_retries=2):
    """
    Validate generated YAML and retry with error feedback if invalid.
    
    Enhanced validation pipeline (similar to mermaid diagram validation):
    1. YAML syntax validation
    2. JSON Schema validation (structural correctness)
    3. Event name validation (format and length)
    4. Structured error feedback to LLM for automated retry
    
    This mirrors the mermaid validation approach where validation errors are fed back
    to the LLM automatically, enabling it to self-correct without manual intervention.
    """
    previous_error = ""

    for attempt in range(max_retries + 1):
        temp_session_id = None
        try:
            temp_session_id = conversation_manager.create_session(system_prompt)

            if attempt == 0:
                user_prompt = user_prompt_base
            else:
                # Inject previous error feedback (similar to mermaid retry prompt)
                error_feedback = (
                    f"\n\nIMPORTANT - PREVIOUS ATTEMPT FAILED:\n"
                    f"Your previous YAML output caused the following validation error:\n"
                    f"Error: {previous_error}\n\n"
                    f"Please fix this specific issue in your new output.\n"
                    f"Return ONLY the corrected YAML content (no explanations or markdown)."
                )
                user_prompt = user_prompt_base + error_feedback

            conversation_manager.add_message("user", user_prompt, temp_session_id)
            messages = conversation_manager.get_conversation_for_api(temp_session_id)
            try:
                temp = getattr(conversation_manager, 'temperature', None)
            except Exception:
                temp = None
            if temp is None:
                temp = DiscoveryConfigManager().get_conversation_config().get('temperature')
            response_data = call_azure_openai_direct(messages, max_output_tokens=conversation_manager.max_output_tokens, temperature=temp)
            raw_response = parse_llm_response_direct(response_data)
            if not raw_response:
                raise Exception("No response from LLM")

            yaml_content = extract_yaml_from_llm_response(raw_response)
            if not yaml_content:
                raise Exception("No YAML content found in LLM response")

            # Step 1: Basic YAML syntax check (allow template placeholders)
            try:
                test_yaml = yaml_content
                template_vars = ['{{userGoal}}', '{{nodePoolContext}}', '{{dataHandlingContext}}', '{{agentTeam}}', '{{workflowContext}}']
                for var in template_vars:
                    test_yaml = test_yaml.replace(var, f'"{var}"')
                parsed_yaml = yaml.safe_load(test_yaml)
            except yaml.YAMLError as yaml_error:
                previous_error = f"YAML syntax error: {str(yaml_error)}"
                print(f"❌ YAML syntax validation failed on attempt {attempt + 1}: {previous_error}")
                if attempt == max_retries:
                    return None, False, previous_error
                continue
            
            # Step 2: JSON Schema validation (new - mirrors create_workflow_agent validation)
            schema_valid, schema_error = _validate_component_yaml_against_schema(yaml_content, component)
            if not schema_valid:
                previous_error = schema_error
                print(f"❌ Schema validation failed on attempt {attempt + 1}: {previous_error}")
                if attempt == max_retries:
                    return None, False, previous_error
                continue
            
            # Step 3: Event name validation (format and length)
            if component in ['router', 'workflow']:
                import re
                event_name_pattern = re.compile(r'^[A-Za-z_-]+$')
                event_validation_errors = []
                
                # Check router actions
                if component == 'router' and isinstance(parsed_yaml, dict):
                    actions = parsed_yaml.get('actions', [])
                    if isinstance(actions, list):
                        for action in actions:
                            if isinstance(action, dict) and 'name' in action:
                                action_name = action['name']
                                if len(action_name) > 15:
                                    event_validation_errors.append(
                                        f"Router action '{action_name}' exceeds 15 character limit (length: {len(action_name)})"
                                    )
                                if not event_name_pattern.match(action_name):
                                    event_validation_errors.append(
                                        f"Router action '{action_name}' contains invalid characters (only letters, underscores, hyphens allowed; NO NUMBERS)"
                                    )
                
                # Check workflow events/transitions
                if component == 'workflow' and isinstance(parsed_yaml, dict):
                    # Check transitions (new format)
                    transitions = parsed_yaml.get('transitions', [])
                    if isinstance(transitions, list):
                        for transition in transitions:
                            if isinstance(transition, dict) and 'event' in transition:
                                event_name = transition['event']
                                if len(event_name) > 15:
                                    event_validation_errors.append(
                                        f"Workflow event '{event_name}' exceeds 15 character limit (length: {len(event_name)})"
                                    )
                                if not event_name_pattern.match(event_name):
                                    event_validation_errors.append(
                                        f"Workflow event '{event_name}' contains invalid characters (only letters, underscores, hyphens allowed; NO NUMBERS)"
                                    )
                    
                    # Check events in extension (if present)
                    extension = parsed_yaml.get('extension', {})
                    if isinstance(extension, dict):
                        events = extension.get('events', [])
                        if isinstance(events, list):
                            for event in events:
                                if isinstance(event, dict) and 'name' in event:
                                    event_name = event['name']
                                    if len(event_name) > 15:
                                        event_validation_errors.append(
                                            f"Extension event '{event_name}' exceeds 15 character limit (length: {len(event_name)})"
                                        )
                                    if not event_name_pattern.match(event_name):
                                        event_validation_errors.append(
                                            f"Extension event '{event_name}' contains invalid characters (only letters, underscores, hyphens allowed; NO NUMBERS)"
                                        )
                
                if event_validation_errors:
                    previous_error = "Event name validation failed:\n" + "\n".join(f"  - {err}" for err in event_validation_errors) + "\n\nFix: Use only letters, underscores, hyphens (max 15 chars, NO NUMBERS). Example: 'RunStepOne' not 'RunStep1'."
                    print(f"❌ Event name validation failed on attempt {attempt + 1}")
                    if attempt == max_retries:
                        return None, False, previous_error
                    continue
            
            # Step 4: Workflow-specific structural validation (thread refs, messageId)
            if component == 'workflow':
                try:
                    from workflow_pattern_validator import validate_thread_variable_references, validate_messageid_requirements

                    structural_errors = []

                    is_thread_valid, thread_errors, _ = validate_thread_variable_references(yaml_content)
                    structural_errors.extend(thread_errors)

                    is_mid_valid, mid_errors, _ = validate_messageid_requirements(yaml_content)
                    structural_errors.extend(mid_errors)

                    if structural_errors:
                        previous_error = "Workflow structural validation failed:\n" + "\n".join(f"  - {err}" for err in structural_errors)
                        print(f"❌ Workflow structural validation failed on attempt {attempt + 1}")
                        if attempt == max_retries:
                            return None, False, previous_error
                        continue
                except ImportError:
                    pass  # Validator not available, skip

            # All validations passed!
            print(f"✅ {component} component validation passed on attempt {attempt + 1}")
            return yaml_content, True, None

        except Exception as e:
            previous_error = f"Generation error: {str(e)}"
            print(f"❌ {component} generation failed on attempt {attempt + 1}: {previous_error}")
            if attempt == max_retries:
                return None, False, previous_error
            continue
        finally:
            try:
                if temp_session_id and temp_session_id in conversation_manager.sessions:
                    del conversation_manager.sessions[temp_session_id]
            except:
                pass

    return None, False, "Max retries exceeded"

def validate_workflow_agent_event_consistency(agent_dir, agent_name, unique_component_names):
    """
    Validate that event names in router agents match workflow event definitions.
    Returns a list of validation errors, empty if no issues found.
    """
    validation_errors = []
    
    try:
        # Find router and workflow files using unique names
        if 'router' not in unique_component_names or 'workflow' not in unique_component_names:
            validation_errors.append("Validation error: Missing unique name for router or workflow component.")
            return validation_errors

        router_file = os.path.join(agent_dir, f"{unique_component_names['router']}.yaml")
        workflow_file = os.path.join(agent_dir, f"{unique_component_names['workflow']}.yaml")
        
        if not os.path.exists(router_file) or not os.path.exists(workflow_file):
            # This might not be an error if components are optional or not yet created
            return []  # Skip validation if files don't exist
        
        # Parse router file to extract action names
        with open(router_file, 'r', encoding='utf-8') as f:
            router_content = yaml.safe_load(f)
        
        # Parse workflow file to extract event names
        with open(workflow_file, 'r', encoding='utf-8') as f:
            workflow_content = yaml.safe_load(f)
        
        # Extract action names from router and validate format/length
        import re
        event_name_pattern = re.compile(r'^[A-Za-z_-]+$')
        router_actions = set()
        if isinstance(router_content, dict) and 'actions' in router_content:
            for action in router_content['actions']:
                if isinstance(action, dict) and 'name' in action:
                    action_name = action['name']
                    router_actions.add(action_name)
                    # Validate event name length (15 characters maximum)
                    if len(action_name) > 15:
                        validation_errors.append(
                            f"Router action '{action_name}' exceeds 15 character limit (length: {len(action_name)}). "
                            f"Use abbreviations for longer agent names."
                        )
                    # Validate event name format (only letters, underscores, hyphens)
                    if not event_name_pattern.match(action_name):
                        validation_errors.append(
                            f"Router action '{action_name}' contains invalid characters. "
                            f"Only letters, underscores, and hyphens are allowed. Numbers are NOT allowed."
                        )
        
        # Extract event names from workflow and validate format/length
        workflow_events = set()
        if isinstance(workflow_content, dict) and 'workflow' in workflow_content:
            workflow_def = workflow_content['workflow']
            if isinstance(workflow_def, dict) and 'events' in workflow_def:
                for event in workflow_def['events']:
                    if isinstance(event, dict) and 'name' in event:
                        event_name = event['name']
                        workflow_events.add(event_name)
                        # Validate event name length (15 characters maximum)
                        if len(event_name) > 15:
                            validation_errors.append(
                                f"Workflow event '{event_name}' exceeds 15 character limit (length: {len(event_name)}). "
                                f"Use abbreviations for longer agent names."
                            )
                        # Validate event name format
                        if not event_name_pattern.match(event_name):
                            validation_errors.append(
                                f"Workflow event '{event_name}' contains invalid characters. "
                                f"Only letters, underscores, and hyphens are allowed. Numbers are NOT allowed."
                            )
        
        # Check for mismatches (case-sensitive)
        router_not_in_workflow = router_actions - workflow_events
        if router_not_in_workflow:
            for action in router_not_in_workflow:
                # Look for case-insensitive matches to suggest corrections
                potential_matches = [event for event in workflow_events 
                                   if event.lower() == action.lower()]
                if potential_matches:
                    validation_errors.append(
                        f"Router action '{action}' not found in workflow events. "
                        f"Did you mean '{potential_matches[0]}'? (Case mismatch)"
                    )
                else:
                    validation_errors.append(
                        f"Router action '{action}' not defined in workflow events"
                    )
        
        # Check for unused workflow events (warning, not error)
        workflow_not_in_router = workflow_events - router_actions
        if workflow_not_in_router:
            for event in workflow_not_in_router:
                validation_errors.append(
                    f"Warning: Workflow event '{event}' not used by any router action"
                )
    
    except Exception as e:
        validation_errors.append(f"Validation error: {str(e)}")
    
    return validation_errors

def generate_workflow_agent_yaml(agent_name, description, selected_agents, instructions):
    """Generate YAML content for Workflow Agent"""
    # Normalize placeholders in instructions regardless of source
    instructions = _normalize_placeholders(instructions)
    
    # Check if this is a workflow component (should generate workflow structure)
    if 'workflow' in agent_name.lower() and ('states:' in instructions and 'transitions:' in instructions and 'startstate:' in instructions.lower()):
        # For workflow components, the instructions contain the complete workflow YAML
        # Extract the workflow content and format it properly
        return instructions
    
    # Generate actions section (not tools)
    actions = []
    for agent in selected_agents:
        # Preserve original casing of agent names when creating action names
        # This is critical for event name consistency between router and workflow
        agent_name_clean = agent.replace('Agent', '')
        actions.append({
            'name': f'Run{agent_name_clean}',
            'description': f'Route to {agent} for specialized tasks'
        })
    
    # Create the agent structure
    agent_data = {
        'agent': {
            'name': agent_name,
            'description': description,
            # MODEL ENDPOINT FOR GENERATED AGENTS (not for testbed runtime)
            # This endpoint comes from discovery_config.json and defines what model
            # the generated agents will use when they are deployed and running
            'model': config_manager.get_llm_endpoint(),  # e.g., azureml://registries/azure-openai/models/gpt-4o/versions/2024-11-20
            'instructions': instructions
        }
    }
    
    # Only add actions if we have any
    if actions: 
        agent_data['actions'] = actions
    
    # Generate YAML with proper formatting
    yaml_content = yaml.dump(agent_data, default_flow_style=False, sort_keys=False, allow_unicode=True)
    
    # Fix the instructions field to use literal block scalar (|) for multi-line content
    if '\n' in instructions:
        lines = yaml_content.split('\n')
        new_lines = []
        i = 0
        
        while i < len(lines):
            line = lines[i]
            
            # Find the instructions field
            if line.strip().startswith('instructions:') and line.strip() != 'instructions: |':
                # Replace with literal block scalar
                new_lines.append('  instructions: |')
                
                # Skip the original instructions content that yaml.dump generated
                i += 1
                while i < len(lines) and (lines[i].startswith('    ') or lines[i].strip() == ''):
                    i += 1
                i -= 1  # Back up one since we'll increment at end of loop
                
                # Add properly indented instructions
                for instruction_line in instructions.split('\n'):
                    if instruction_line.strip():  # Skip empty lines
                        new_lines.append(f'    {instruction_line}')
                    else:
                        new_lines.append('')
            else:
                new_lines.append(line)
            
            i += 1
        
        yaml_content = '\n'.join(new_lines)
    
    return yaml_content

@app.route('/api/logs')
def get_logs():
    """Get the content of log files from the output directory"""
    try:
        # Get session ID from query parameter (preferred) or fall back to session manager
        session_id = request.args.get('session_id', None)
        agent_name = request.args.get('agent_name', None)

        sm = get_session_manager()

        # If session_id provided, temporarily set it on the session manager
        if session_id:
            sm.current_session_id = session_id

        # Get session-specific output directory
        session_dirs = sm.get_session_dirs(session_id=session_id, agent_name=agent_name or get_current_agent_name())
        shared_output_dir = session_dirs['output']

        if not os.path.exists(shared_output_dir):
            return jsonify({'logs': [], 'success': True}), 200

        log_files = []

        # Find all .log files in the output directory
        for filename in os.listdir(shared_output_dir):
            if filename.endswith('.log'):
                file_path = os.path.join(shared_output_dir, filename)
                if os.path.isfile(file_path):
                    try:
                        with open(file_path, 'r', encoding='utf-8') as f:
                            content = f.read()
                        
                        file_size = os.path.getsize(file_path)
                        modification_time = os.path.getmtime(file_path)
                        
                        log_files.append({
                            'filename': filename,
                            'content': content,
                            'size': file_size,
                            'modified': modification_time
                        })
                    except Exception as e:
                        print(f"Error reading log file {filename}: {e}")
                        continue
        
        # Sort by modification time (newest first)
        log_files.sort(key=lambda x: x['modified'], reverse=True)
        
        return jsonify({'logs': log_files})

    except Exception as e:
        print(f"Error retrieving log files: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/execution-status/<execution_id>')
def get_execution_status(execution_id):
    """Get the current status and output of a running execution"""
    try:
        with execution_lock:
            if execution_id not in execution_states:
                return jsonify({'error': 'Execution not found'}), 404
            
            state = execution_states[execution_id]
        
        # Get current output without blocking
        output_data = state.get_current_output()
        
        # Update output files if execution is still running
        if state.is_running:
            try:
                # Get session-specific output directory
                sm = get_session_manager()
                session_dirs = sm.get_session_dirs(agent_name=get_current_agent_name())
                shared_output_dir = session_dirs['output']
                files = []
                if os.path.exists(shared_output_dir):
                    for file in os.listdir(shared_output_dir):
                        if os.path.isfile(os.path.join(shared_output_dir, file)):
                            files.append(file)
                state.update_output_files(files)
                output_data['output_files'] = files
            except Exception as e:
                print(f"Warning: Could not update output files for {execution_id}: {e}")
        
        return jsonify({
            'success': True,
            **output_data
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/execution/<execution_id>/cancel', methods=['POST'])
def cancel_local_execution(execution_id):
    """Cancel a running local Docker execution"""
    try:
        with execution_lock:
            if execution_id not in execution_states:
                return jsonify({
                    'success': False,
                    'error': f'Execution {execution_id} not found'
                }), 404
            
            state = execution_states[execution_id]
            
            # Check if already completed
            if state.is_completed:
                return jsonify({
                    'success': False,
                    'error': 'Execution already completed'
                }), 400
            
            # Request cancellation
            cancelled = state.cancel_execution()
            
        if cancelled:
            print(f"🛑 Cancellation requested for local execution: {execution_id}")
            return jsonify({
                'success': True,
                'message': 'Cancellation requested'
            })
        else:
            return jsonify({
                'success': False,
                'error': 'Could not cancel execution'
            }), 500
            
    except Exception as e:
        print(f"Error cancelling execution {execution_id}: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

@app.route('/api/output')
def get_output():
    """Get the latest execution output from stdout (persisted to session state directory)"""
    try:
        # Get session-specific state directory
        sm = get_session_manager()
        session_dirs = sm.get_session_dirs(agent_name=get_current_agent_name())
        state_dir = session_dirs['state']

        # Try JSON format in state directory
        json_file = os.path.join(state_dir, 'stdout.json')
        if os.path.exists(json_file):
            with open(json_file, 'r', encoding='utf-8', errors='replace') as f:
                data = json.load(f)
                # Check if execution is still running (saved during execution)
                is_running = data.get('is_running', False)
                return jsonify({
                    'success': True,
                    'stdout': data.get('stdout', ''),
                    'stderr': data.get('stderr', ''),
                    'exit_code': data.get('exit_code', 0),
                    'execution_id': data.get('execution_id', ''),
                    'is_completed': not is_running,
                    'is_running': is_running
                })

        return jsonify({
            'success': True,
            'stdout': '',
            'stderr': '',
            'exit_code': None,
            'is_completed': False
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/build-output')
def get_build_output():
    """Get the latest Docker build output (from live buffer or persisted file)"""
    try:
        # Allow explicit agent_name and session_id parameters
        agent_name = request.args.get('agent_name') or get_current_agent_name()
        request_session_id = request.args.get('session_id')

        # Get session_id from request or fall back to current session
        sm = get_session_manager()
        session_id = request_session_id or (sm.current_session_id if sm else None)

        # First, check if there's a live build with output in memory (more up-to-date)
        live_lines = _get_build_output_lines(agent_name, session_id=session_id)
        if live_lines:
            return jsonify({
                'success': True,
                'output': '\n'.join(live_lines),
                'agent_name': agent_name,
                'session_id': session_id,
                'build_success': False,  # Still in progress
                'timestamp': time.time(),
                'source': 'live'
            })

        # Fall back to persisted file
        # Get session-specific state directory
        session_dirs = sm.get_session_dirs(session_id=session_id, agent_name=agent_name)
        state_dir = session_dirs['state']

        build_file = os.path.join(state_dir, 'build_output.json')
        if os.path.exists(build_file):
            with open(build_file, 'r', encoding='utf-8', errors='replace') as f:
                data = json.load(f)
                return jsonify({
                    'success': True,
                    'output': data.get('output', ''),
                    'agent_name': data.get('agent_name', ''),
                    'session_id': data.get('session_id', ''),
                    'build_success': data.get('success', False),
                    'timestamp': data.get('timestamp', 0)
                })

        return jsonify({
            'success': True,
            'output': '',
            'agent_name': '',
            'session_id': session_id,
            'build_success': False,
            'timestamp': 0
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/build-output', methods=['DELETE'])
def clear_build_output():
    """Clear the Docker build output (both in-memory buffer and persisted file)"""
    try:
        agent_name = request.args.get('agent_name') or get_current_agent_name()
        request_session_id = request.args.get('session_id')

        # Get session_id from request or fall back to current session
        sm = get_session_manager()
        session_id = request_session_id or (sm.current_session_id if sm else None)

        # Clear in-memory buffer (session-specific)
        _clear_build_output(agent_name, session_id=session_id)

        # Clear persisted file
        session_dirs = sm.get_session_dirs(session_id=session_id, agent_name=agent_name)
        state_dir = session_dirs['state']

        build_file = os.path.join(state_dir, 'build_output.json')
        if os.path.exists(build_file):
            os.remove(build_file)

        return jsonify({
            'success': True,
            'message': f'Build output cleared for {agent_name} (session: {session_id})'
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/results')
def get_results():
    """Get list of generated output files"""
    try:
        # Get session ID from query parameter (preferred) or fall back to session manager
        session_id = request.args.get('session_id', None)
        agent_name = request.args.get('agent_name', None)

        sm = get_session_manager()
        if not sm:
            # Session manager not initialized - return empty list
            return jsonify({'files': [], 'success': True})

        # If session_id provided, temporarily set it on the session manager
        if session_id:
            sm.current_session_id = session_id

        # Check if we have a session
        if not session_id and not sm.current_session_id:
            # No session yet - return empty list
            return jsonify({'files': [], 'success': True})

        # Get session-specific output directory
        session_dirs = sm.get_session_dirs(session_id=session_id, agent_name=agent_name or get_current_agent_name())
        shared_output_dir = session_dirs['output']

        files = []
        if os.path.exists(shared_output_dir):
            # Walk the directory tree so nested files are included
            for root, dirs, filenames in os.walk(shared_output_dir):
                for fname in filenames:
                    # Skip placeholder files
                    if fname == '.placeholder' or fname.endswith('.placeholder'):
                        continue

                    file_path = os.path.join(root, fname)
                    if os.path.isfile(file_path):
                        try:
                            stat = os.stat(file_path)
                            # Build relative path using forward slashes for consistency
                            rel = os.path.relpath(file_path, shared_output_dir).replace('\\', '/')
                            files.append({
                                'name': rel,
                                'size': stat.st_size,
                                'modified': int(stat.st_mtime)
                            })
                        except Exception:
                            files.append({ 'name': fname, 'size': None, 'modified': None })

        return jsonify({
            'files': files,
            'success': True
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/write-file', methods=['POST'])
def write_file():
    """Write content to a file in the output directory
    
    Expected JSON payload:
    {
        "filename": "myfile.txt",
        "content": "file content here",
        "overwrite": true/false (optional, default: true)
    }
    """
    try:
        data = request.get_json()
        
        if not data:
            return jsonify({'error': 'No JSON data provided'}), 400
        
        filename = data.get('filename')
        content = data.get('content')
        overwrite = data.get('overwrite', True)
        
        if not filename:
            return jsonify({'error': 'No filename provided'}), 400
        
        if content is None:
            return jsonify({'error': 'No content provided'}), 400
        
        # Sanitize filename to prevent directory traversal
        filename = os.path.basename(filename)
        if not filename or filename in ['.', '..']:
            return jsonify({'error': 'Invalid filename'}), 400

        # Get session-specific output directory
        sm = get_session_manager()
        session_dirs = sm.get_session_dirs(agent_name=get_current_agent_name())
        shared_output_dir = session_dirs['output']

        # Create output directory if it doesn't exist
        os.makedirs(shared_output_dir, exist_ok=True)

        file_path = os.path.join(shared_output_dir, filename)
        
        # Check if file exists and overwrite is False
        if os.path.exists(file_path) and not overwrite:
            return jsonify({
                'error': f'File {filename} already exists and overwrite is disabled',
                'success': False
            }), 409
        
        # Write the content to file
        with open(file_path, 'w', encoding='utf-8') as f:
            f.write(content)
        
        # Get file stats
        stat = os.stat(file_path)
        
        return jsonify({
            'message': f'File {filename} written successfully',
            'filename': filename,
            'size': stat.st_size,
            'path': file_path,
            'success': True
        })
        
    except Exception as e:
        return jsonify({'error': str(e), 'success': False}), 500

@app.route('/api/config')
def get_config():
    """Get agent configuration for the frontend"""
    try:
        # Use the agent name exactly as specified in the YAML, no manipulation
        agent_display_name = agent_name if agent_name else "Discovery Agent"
        
        # Include multi-agent information if available
        multi_agent_info = {}
        if agent_manager:
            try:
                # Get current agent from session (session-scoped)
                current_agent = get_current_agent_name()
                agents_count = len(agent_manager.agents)
                multi_agent_info = {
                    'multi_agent_enabled': True,
                    'current_agent': current_agent,
                    'total_agents': agents_count,
                    'agents_available': list(agent_manager.agents.keys())
                }

                # If we have a current agent, get its display name
                if current_agent and agent_manager.agent_exists(current_agent):
                    info = agent_manager.get_agent_info(current_agent)
                    agent_display_name = info.display_name

            except Exception as e:
                print(f"Warning: Could not get multi-agent info: {e}")
                multi_agent_info = {'multi_agent_enabled': False}
        else:
            multi_agent_info = {'multi_agent_enabled': False}
            
        return jsonify({
            'agent_name': agent_display_name,
            'agent_id': agent_name,
            'status': 'success',
            **multi_agent_info
        })
    except Exception as e:
        return jsonify({
            'agent_name': 'Discovery Agent',
            'agent_id': 'unknown',
            'status': 'error',
            'message': str(e),
            'multi_agent_enabled': False
        })

@app.route('/api/config/directories')
def get_directories_config():
    """Get directory configuration for the frontend"""
    try:
        if not DISCOVERY_AVAILABLE or not config_manager:
            return jsonify({
                'status': 'error',
                'message': 'Discovery configuration manager not available'
            }), 500
        
        config = config_manager.load_config()
        directories = config.get('directories', {})
        
        # Validate that all required directories are configured in the JSON file
        required_dirs = ['tool_agents_dir', 'kb_agents_dir', 'workflow_agents_dir']
        missing_dirs = []
        
        for dir_key in required_dirs:
            if not directories.get(dir_key):
                missing_dirs.append(dir_key)
        
        if missing_dirs:
            return jsonify({
                'status': 'error',
                'message': f'Missing required directory configuration in discovery_config.json: {", ".join(missing_dirs)}'
            }), 500
        
        # Return configured directories without fallbacks
        return jsonify({
            'status': 'success',
            'directories': {
                'tool_agents_dir': directories['tool_agents_dir'],
                'kb_agents_dir': directories['kb_agents_dir'],
                'workflow_agents_dir': directories['workflow_agents_dir']
            }
        })
        
    except Exception as e:
        return jsonify({
            'status': 'error',
            'message': f'Error loading directory configuration: {str(e)}'
        }), 500

