def switch_profile():
    """Switch to a different profile"""
    try:
        if not config_manager or not hasattr(config_manager, 'profile_manager'):
            return jsonify({
                'success': False,
                'error': 'Profile manager not available'
            }), 500
        
        data = request.get_json()
        profile_name = data.get('profile_name')
        
        if not profile_name:
            return jsonify({
                'success': False,
                'error': 'profile_name is required'
            }), 400
        
        result = config_manager.profile_manager.switch_profile(profile_name)
        
        if result['success']:
            # Reload the config after switching
            config_manager.config = config_manager.profile_manager.get_active_profile()
            # Reset LLM client to pick up new Azure OpenAI config
            reset_default_client()
            return jsonify(result)
        else:
            return jsonify(result), 400
            
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500

