@app.route('/api/tool-agent/upload', methods=['POST'])
def upload_tool_agent_file():
    """Upload a file into a per-session user folder for tool-agent creation."""
    try:
        if 'file' not in request.files:
            return jsonify({'error': 'No file provided'}), 400

        file = request.files['file']
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400

        # Accept sessionId in form data; if missing, create a new session on-the-fly
        session_id = request.form.get('sessionId') or request.args.get('sessionId')
        script_dir = os.path.dirname(os.path.abspath(__file__))
        if not session_id:
            import uuid
            session_id = uuid.uuid4().hex

        session_dir = os.path.join(script_dir, 'user-session', session_id, 'uploads')
        os.makedirs(session_dir, exist_ok=True)

        # Preserve folder structure when clients upload directories. Many browsers/tools
        # include 'webkitRelativePath' or 'relativePath' in the multipart form data.
        relative_path = None
        try:
            relative_path = request.form.get('relativePath') or request.form.get('webkitRelativePath')
        except Exception:
            relative_path = None

        filename_raw = file.filename or ''
        if not relative_path:
            # Fallback to the provided filename
            relative_path = filename_raw

        # Normalize slashes and strip leading slashes
        relative_path = relative_path.replace('\\', '/').lstrip('/')

        # Normalize path to remove redundant segments
        safe_norm = os.path.normpath(relative_path)
        safe_norm = safe_norm.replace('\\', '/').lstrip('/')

        # If path is absolute or attempts to escape, fall back to basename
        if os.path.isabs(safe_norm) or any(part == '..' for part in safe_norm.split('/')):
            safe_norm = os.path.basename(filename_raw) or str(uuid.uuid4())

        # Build destination path under the session uploads folder, creating subfolders as needed
        dest_rel_parts = [p for p in safe_norm.split('/') if p]
        if not dest_rel_parts:
            dest_rel_parts = [os.path.basename(filename_raw) or str(uuid.uuid4())]

        dest_path = os.path.join(session_dir, *dest_rel_parts)
        dest_folder = os.path.dirname(dest_path)
        os.makedirs(dest_folder, exist_ok=True)

        # Save uploaded file
        file.save(dest_path)

        # Return the stored relative path (relative to the session uploads folder)
        stored_rel = os.path.relpath(dest_path, session_dir).replace('\\', '/')

        # Also print a compact tree of the uploads folder for this session to show actual storage layout
        try:
            def _print_tree(base_dir, max_items=200):
                printed = 0
                for root, dirs, files in os.walk(base_dir):
                    rel = os.path.relpath(root, base_dir).replace('\\', '/')
                    indent = '' if rel == '.' else ('  ' + rel + '/')
                    for f in files:
                        if printed >= max_items:
                            return
                        print(f"    {indent}{f}")
                        printed += 1
            # Skip individual file tree prints for cleaner output
            # print(f"📂 Current upload folder tree for session {session_id}:")
            # _print_tree(os.path.join(os.path.dirname(os.path.abspath(__file__)), 'user-session', session_id, 'uploads'))
        except Exception:
            pass

        return jsonify({
            'message': f'File {stored_rel} uploaded successfully',
            'filename': stored_rel,
            'sessionId': session_id,
            'success': True
        })

    except Exception as e:
        return jsonify({'error': f'Upload failed: {str(e)}'}), 500


@app.route('/api/tool-agent/delete/<session_id>/<path:filename>', methods=['DELETE'])
def delete_tool_agent_file(session_id, filename):
    """Delete an uploaded file from a user session folder."""
    try:
        import urllib.parse
        script_dir = os.path.dirname(os.path.abspath(__file__))
        uploads_root = os.path.join(script_dir, 'user-session', session_id, 'uploads')

        # URL-decode provided filename (Dropzone sends encoded path components)
        decoded = urllib.parse.unquote(filename)

        # Prevent path traversal attempts
        if '..' in decoded.split('/'):
            return jsonify({'error': 'Invalid path'}), 400

        # Support nested paths (e.g., app/entrypoint.sh) but constrain to uploads_root
        candidate_path = os.path.normpath(os.path.join(uploads_root, decoded))

        # Ensure the resolved path is still under uploads_root
        if not candidate_path.startswith(os.path.abspath(uploads_root)):
            return jsonify({'error': 'Path outside session scope'}), 400

        if not os.path.exists(candidate_path):
            return jsonify({'error': 'File not found'}), 404

        if not os.path.isfile(candidate_path):
            return jsonify({'error': 'Not a file'}), 400

        os.remove(candidate_path)

        return jsonify({
            'message': f'File {decoded} deleted successfully',
            'filename': decoded,
            'sessionId': session_id,
            'success': True
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/tool-agent/delete-session/<session_id>', methods=['DELETE'])
def delete_tool_agent_session(session_id):
    """Delete an entire user-session directory and its uploads."""
    try:
        import shutil
        script_dir = os.path.dirname(os.path.abspath(__file__))
        session_root = os.path.join(script_dir, 'user-session', session_id)

        if not os.path.exists(session_root):
            return jsonify({'success': True, 'message': 'Session already removed or not found', 'sessionId': session_id})

        # Recursively remove session folder
        shutil.rmtree(session_root)

        return jsonify({'success': True, 'message': f'Session {session_id} removed', 'sessionId': session_id})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/tool-agent/session/<session_id>/files', methods=['GET'])
def list_tool_agent_session_files(session_id):
    """Return a JSON list of files uploaded for a given session (debugging helper)."""
    try:
        script_dir = os.path.dirname(os.path.abspath(__file__))
        session_upload_dir = os.path.join(script_dir, 'user-session', session_id, 'uploads')
        if not os.path.exists(session_upload_dir) or not os.path.isdir(session_upload_dir):
            return jsonify({'success': False, 'error': 'Session not found or uploads missing', 'files': []}), 404

        # Walk recursively and return relative paths for all files under the session uploads folder
        result_files = []
        for root, dirs, files in os.walk(session_upload_dir):
            for f in files:
                full = os.path.join(root, f)
                rel = os.path.relpath(full, session_upload_dir).replace('\\', '/')
                result_files.append(rel)

        return jsonify({'success': True, 'sessionId': session_id, 'files': result_files})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e), 'files': []}), 500

