@app.route('/api/execute-tool-action', methods=['POST'])
def execute_tool_action():
    """Execute a specific tool action with parameters"""
    try:
        data = request.get_json()
        action_name = data.get('action_name', '')
        parameters = data.get('parameters', {})
        background = data.get('background', True)
        
        if not action_name:
            return jsonify({'error': 'No action name provided'}), 400
            
        if action_name not in TOOL_ACTIONS:
            return jsonify({'error': f'Unknown tool action: {action_name}'}), 400
        
        action_config = TOOL_ACTIONS[action_name]
        
        # All tool actions now use the generic approach with their defined commands
        code = generate_generic_tool_code(action_name, action_config, parameters)
        
        if not docker_client:
            return jsonify({'error': 'Docker client not available'}), 500
        
        # Get the running container
        try:
            container = docker_client.containers.get(CONTAINER_NAME)
            if container.status != 'running':
                return jsonify({'error': 'Discovery agent container is not running. Please restart the application.'}), 500
        except Exception as e:
            return jsonify({'error': f'Discovery agent container not found: {str(e)}. Please restart the application.'}), 500
        
        # Create a unique filename for this execution
        execution_id = str(uuid.uuid4())[:8]
        script_filename = f"tool_action_{action_name}_{execution_id}.py"
        
        # Write code to shared workdir directory
        # Get session-specific workdir
        sm = get_session_manager()
        session_dirs = sm.get_session_dirs(agent_name=get_current_agent_name())
        shared_workdir = session_dirs['workdir']
        script_path = os.path.join(shared_workdir, script_filename)
        
        with open(script_path, 'w', encoding='utf-8') as f:
            f.write(code)
        
        # Execute the code in the conda environment
        exec_command = f"bash -c 'cd /workdir && python3 -u {script_filename}'"
        
        if background:
            # Background execution with real-time streaming
            from dataclasses import dataclass, field
            from typing import Dict, Optional, List
            
            # Create execution state
            state = ExecutionState(execution_id, script_filename)
            with execution_lock:
                execution_states[execution_id] = state
            
            # Start background execution
            thread = threading.Thread(
                target=execute_code_background,
                args=(container, exec_command, execution_id, script_filename),
                daemon=True
            )
            thread.start()
            
            # Return immediately with execution ID for polling
            return jsonify({
                'success': True,
                'execution_id': execution_id,
                'action_name': action_name,
                'message': f'Tool action {action_name} started in background',
                'background': True,
                'polling_url': f'/api/execution-status/{execution_id}'
            })
        
        else:
            # Synchronous execution
            exec_result = container.exec_run(
                exec_command,
                stdout=True,
                stderr=True,
                stream=True,
                demux=True
            )
            
            stdout_content = ""
            stderr_content = ""
            
            for stdout_chunk, stderr_chunk in exec_result.output:
                if stdout_chunk:
                    stdout_content += stdout_chunk.decode('utf-8', errors='ignore')
                if stderr_chunk:
                    stderr_content += stderr_chunk.decode('utf-8', errors='ignore')
            
            # Clean up the script file
            try:
                os.remove(script_path)
            except:
                pass
            
            return jsonify({
                'success': True,
                'action_name': action_name,
                'output': stdout_content,
                'error': stderr_content,
                'exit_code': exec_result.exit_code,
                'background': False
            })
        
    except Exception as e:
        return jsonify({'error': f'Failed to execute tool action: {str(e)}'}), 500


def generate_generic_tool_code(action_name, action_config, parameters):
    """Generate generic tool execution code"""
    # Safely convert parameters and config to JSON strings, then fix boolean values for Python
    parameters_json = json.dumps(parameters, indent=2)
    action_config_json = json.dumps(action_config, indent=2)
    
    # Convert JSON boolean values to Python boolean values
    parameters_python = parameters_json.replace('"true"', 'True').replace('"false"', 'False').replace('true', 'True').replace('false', 'False')
    action_config_python = action_config_json.replace('"true"', 'True').replace('"false"', 'False').replace('true', 'True').replace('false', 'False')
    
    code = f'''#!/usr/bin/env python3
"""
Tool Action: {action_name}
Generated execution code for tool action
"""
import json
import sys
import subprocess
import os
import tempfile

def main():
    print("=== Tool Action: {action_name} ===")
    
    # Action name for this execution
    action_name = "{action_name}"
    
    # Parameters passed to this action
    parameters = {parameters_python}
    print(f"Parameters: {{json.dumps(parameters, indent=2)}}")
    print()
    
    # Action configuration from tools definition
    action_config = {action_config_python}
    
    # For actions with commands, execute the command
    if 'command' in action_config:
        command = action_config['command']
        
        # Special handling for Q# processor that needs qsharp_code parameter
        if action_name == 'process_qsharp_algorithm' and 'qsharp_code' in parameters:
            # Create temporary file for Q# code
            temp_dir = '/workdir' if os.path.exists('/workdir') else None
            with tempfile.NamedTemporaryFile(mode='w', suffix='.qs', delete=False, dir=temp_dir) as f:
                f.write(parameters['qsharp_code'])
                qs_file = f.name
            
            # Replace {{{{qsharp_file}}}} placeholder with actual file path
            command = command.replace('{{{{qsharp_file}}}}', qs_file)
            
            # Replace {{{{target}}}} placeholder with target parameter
            target = parameters.get('target', 'local')
            command = command.replace('{{{{target}}}}', target)
            
            print(f"Created Q# file: {{qs_file}}")
            print(f"Executing command: {{command}}")
            
            try:
                # Execute the command
                result = subprocess.run(command, shell=True, capture_output=True, text=True, cwd='/workdir',
                                       encoding='utf-8', errors='replace')
                
                print("=== Command Output ===")
                if result.stdout:
                    print(result.stdout)
                
                if result.stderr:
                    print("=== Errors/Warnings ===")
                    print(result.stderr)
                
                print(f"\\n=== Command Completed (Exit Code: {{result.returncode}}) ===")
                return result.returncode
                
            except Exception as e:
                print(f"Error executing command: {{e}}")
                return 1
            finally:
                # Clean up temporary file
                try:
                    os.unlink(qs_file)
                except:
                    pass
        else:
            # Regular command execution for other actions
            print(f"Executing command: {{command}}")
            
            try:
                # Execute the command defined in the action
                result = subprocess.run(command, shell=True, capture_output=True, text=True, cwd='/workdir',
                                       encoding='utf-8', errors='replace')
                
                print("=== Command Output ===")
                if result.stdout:
                    print(result.stdout)
                
                if result.stderr:
                    print("=== Errors/Warnings ===")
                    print(result.stderr)
                
                print(f"\\n=== Command Completed (Exit Code: {{result.returncode}}) ===")
                return result.returncode
                
            except Exception as e:
                print(f"Error executing command: {{e}}")
                return 1
    else:
        # Fallback for actions without commands
        print("This action does not have a command defined.")
        print("Action configuration:")
        print(json.dumps(action_config, indent=2))
        
        print("\\n=== Tool Action Completed ===")
        return 0

if __name__ == "__main__":
    sys.exit(main())
'''
    return code

