def _strip_data_handling_context(system_prompt: str) -> str:
    """Strip the dataHandlingContext file listings from system prompt, keeping markers.

    This reduces token count on clear. The context will be refreshed by
    _refresh_input_files_context() when the user sends their next message.
    """
    if not system_prompt:
        return system_prompt

    # Markers used by _refresh_input_files_context to find and replace the context
    dir_paths_marker = "## Directory Paths (CRITICAL - Use these exact paths):"
    end_marker = "<!-- END_DATA_HANDLING_CONTEXT -->"

    if dir_paths_marker not in system_prompt:
        return system_prompt

    start_idx = system_prompt.find(dir_paths_marker)
    end_marker_pos = system_prompt.find(end_marker, start_idx)

    if end_marker_pos == -1:
        # No end marker - can't safely strip
        return system_prompt

    # Replace content between markers with minimal placeholder (keeps markers for refresh)
    minimal_context = f"{dir_paths_marker}\n(Input files context will be loaded on next message)\n{end_marker}"
    end_idx = end_marker_pos + len(end_marker)
    result = system_prompt[:start_idx] + minimal_context + system_prompt[end_idx:]

    return result


@app.route('/api/conversation/clear', methods=['POST'])
def clear_conversation():
    """Clear the conversation history for the current session without clearing files.

    This is a lighter-weight reset that only clears the chat messages,
    preserving input/output files and staying in the same session.

    The dataHandlingContext is cleared (not rebuilt) to minimize tokens.
    It will be refreshed by _refresh_input_files_context when the user sends
    their next message.
    """
    global SYSTEM_PROMPT
    try:
        if not conversation_manager:
            return jsonify({'error': 'Conversation manager not available'}), 500

        # Get session ID and agent name from request
        data = request.get_json() or {}
        session_id = data.get('session_id')
        agent_name = data.get('agent_name')

        # If no session_id provided, use current session
        sm = get_session_manager()
        if not session_id and sm:
            session_id = sm.current_session_id

        # If no agent_name provided, get from current session
        agent_type = None
        if not agent_name and sm and session_id:
            session = sm.get_session(session_id)
            if session:
                agent_name = session.agent_name
                agent_type = session.agent_type

        # Reload system prompt (will include current files)
        if _builtin_discovery_active:
            SYSTEM_PROMPT = build_builtin_discovery_system_prompt()
        else:
            SYSTEM_PROMPT = load_agent_config(agent_name, agent_type)

        # Strip the dataHandlingContext to minimize tokens
        # It will be refreshed when user sends their next message
        SYSTEM_PROMPT = _strip_data_handling_context(SYSTEM_PROMPT)

        # Reset conversation session (clears message history but preserves session)
        if session_id:
            conversation_manager.reset_session(session_id, SYSTEM_PROMPT)
        else:
            # Create new conversation session
            session_id = conversation_manager.create_session(SYSTEM_PROMPT)

        # Save cleared conversation to the agent-specific file
        conv_file = get_conversation_file_path(session_id, agent_name)
        conversation_manager.save_session_to_file(session_id, conv_file)

        # Get updated session info to return to client for stats reset
        session_info = conversation_manager.get_session_info(session_id)

        return jsonify({
            'success': True,
            'message': 'Conversation cleared',
            'session_id': session_id,
            'session_info': session_info
        })

    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/execution/clear', methods=['POST'])
def clear_execution_state():
    """Clear execution state including stdout, output files, and logs for the current session.

    This clears:
    - stdout.json state file
    - Output folder files (Results tab)
    - Log files in the state directory

    Preserves:
    - Input folder files
    """
    try:
        data = request.get_json() or {}
        session_id = data.get('session_id')
        agent_name = data.get('agent_name') or get_current_agent_name()

        sm = get_session_manager()
        if not sm:
            return jsonify({'error': 'Session manager not available'}), 500

        # Get session directories
        sid = session_id or sm.current_session_id
        if not sid:
            return jsonify({'error': 'No active session'}), 400

        dirs = sm.get_session_dirs(session_id=sid, agent_name=agent_name)

        cleared_items = []

        # Clear stdout.json state file
        state_dir = dirs.get('state', '')
        if state_dir and os.path.exists(state_dir):
            stdout_file = os.path.join(state_dir, 'stdout.json')
            if os.path.exists(stdout_file):
                try:
                    os.remove(stdout_file)
                    cleared_items.append('stdout.json')
                except Exception as e:
                    print(f"Warning: Failed to remove stdout.json: {e}")

            # Clear any log files in state directory
            for filename in os.listdir(state_dir):
                if filename.endswith('.log'):
                    try:
                        os.remove(os.path.join(state_dir, filename))
                        cleared_items.append(filename)
                    except Exception as e:
                        print(f"Warning: Failed to remove {filename}: {e}")

        # Clear output folder (Results)
        output_dir = dirs.get('output', '')
        if output_dir and os.path.exists(output_dir):
            for filename in os.listdir(output_dir):
                file_path = os.path.join(output_dir, filename)
                try:
                    if os.path.isfile(file_path):
                        os.remove(file_path)
                        cleared_items.append(f'output/{filename}')
                    elif os.path.isdir(file_path):
                        shutil.rmtree(file_path)
                        cleared_items.append(f'output/{filename}/')
                except Exception as e:
                    print(f"Warning: Failed to remove {file_path}: {e}")

        # Clear workdir (but preserve the directory itself)
        workdir = dirs.get('workdir', '')
        if workdir and os.path.exists(workdir):
            for filename in os.listdir(workdir):
                file_path = os.path.join(workdir, filename)
                try:
                    if os.path.isfile(file_path):
                        os.remove(file_path)
                        cleared_items.append(f'workdir/{filename}')
                    elif os.path.isdir(file_path):
                        shutil.rmtree(file_path)
                        cleared_items.append(f'workdir/{filename}/')
                except Exception as e:
                    print(f"Warning: Failed to remove {file_path}: {e}")

        return jsonify({
            'success': True,
            'message': 'Execution state cleared',
            'cleared_items': cleared_items,
            'session_id': sid
        })

    except Exception as e:
        import traceback
        traceback.print_exc()
        return jsonify({'error': str(e)}), 500


@app.route('/api/conversation/strategy', methods=['POST'])
def update_conversation_strategy():
    """Update conversation management strategy"""
    try:
        if not conversation_manager:
            return jsonify({'error': 'Conversation manager not available'}), 500
            
        data = request.get_json()
        strategy_name = data.get('strategy', 'hybrid')
        max_tokens = data.get('max_tokens', 64000)
        target_tokens = data.get('target_tokens', 48000)
        
        # Update conversation manager settings
        conversation_manager.max_tokens = max_tokens
        conversation_manager.target_tokens = target_tokens
        
        if strategy_name == 'sliding_window':
            conversation_manager.strategy = ContextStrategy.SLIDING_WINDOW
        elif strategy_name == 'summarization':
            conversation_manager.strategy = ContextStrategy.SUMMARIZATION
        else:
            conversation_manager.strategy = ContextStrategy.HYBRID
        
        return jsonify({
            'success': True,
            'message': 'Conversation strategy updated',
            'settings': {
                'strategy': conversation_manager.strategy.value,
                'max_tokens': conversation_manager.max_tokens,
                'target_tokens': conversation_manager.target_tokens
            }
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/settings', methods=['GET'])
def get_settings():
    """Get global application settings including conversation, Azure, and Azure OpenAI configuration"""
    try:
        # Get conversation settings from runtime manager or discovery config
        from discovery_config_manager import DiscoveryConfigManager
        if conversation_manager:
            conversation_settings = {
                'max_tokens': getattr(conversation_manager, 'max_tokens', None),
                'target_tokens': getattr(conversation_manager, 'target_tokens', None),
                'max_output_tokens': getattr(conversation_manager, 'max_output_tokens', None),
                'strategy': getattr(conversation_manager, 'strategy').value if getattr(conversation_manager, 'strategy', None) else None,
                'max_retries': getattr(conversation_manager, 'max_retries', None),
                'temperature': getattr(conversation_manager, 'temperature', None)
            }
        else:
            # Prefer config_manager when available; otherwise load directly
            if DISCOVERY_AVAILABLE and config_manager:
                conversation_settings = config_manager.get_conversation_config()
            else:
                conversation_settings = DiscoveryConfigManager().get_conversation_config()
        
        # Get Azure configuration
        azure_config = {'subscription_id': '', 'subscription_name': '', 'resource_group': '', 'location': '', 'acr_name': ''}
        if DISCOVERY_AVAILABLE and config_manager:
            try:
                azure_config = config_manager.get_azure_config()
            except Exception as e:
                print(f"Warning: Could not load Azure config: {e}")
        
    # Get Azure OpenAI configuration
        azure_openai_config = {
            'endpoint_url': endpoint or '',
            'deployment_name': deployment or '',
            'api_key': subscription_key or '',
            'api_version': '2024-02-15-preview'
        }
        if DISCOVERY_AVAILABLE and config_manager:
            try:
                azure_openai_config = config_manager.get_azure_openai_config()
                # Mask the API key for security
                if azure_openai_config.get('api_key'):
                    azure_openai_config['api_key'] = '***masked***'
                print(f"[Settings GET] Loaded Azure OpenAI config - api_version: {azure_openai_config.get('api_version', '')}")
            except Exception as e:
                print(f"Warning: Could not load Azure OpenAI config: {e}")
        
        # Get directories configuration
        try:
            directories_config = {
                'tool_agents_dir': get_discovery_tool_output_dir(),
                'kb_agents_dir': get_kb_agent_output_dir(),
                'workflow_agents_dir': get_workflow_agents_dir()
            }
                
        except Exception as e:
            print(f"Warning: Could not load directories config: {e}")
            directories_config = {}
        
        # Get Azure Compute configuration
        azure_compute_config = {
            'auto_cleanup': False
        }
        if DISCOVERY_AVAILABLE and config_manager:
            try:
                azure_compute_config = config_manager.get_azure_compute_config()
            except Exception as e:
                print(f"Warning: Could not load Azure Compute config: {e}")
        
        return jsonify({
            'success': True,
            'settings': {
                'conversation': conversation_settings,
                'azure': azure_config,
                'azure_openai': azure_openai_config,
                'directories': directories_config,
                'azure_compute': azure_compute_config
            }
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/settings', methods=['POST'])
def update_settings():
    """Update global application settings including conversation, Azure, and Azure OpenAI configuration"""
    # No module-level CONVERSATION_* globals are used. Persist updates via DiscoveryConfigManager
    global endpoint, deployment, subscription_key
    
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Invalid JSON data in request'}), 400
        
        conversation_settings = data.get('conversation', {})
        azure_settings = data.get('azure', {})
        azure_openai_settings = data.get('azure_openai', {})
        azure_compute_settings = data.get('azure_compute', {})
        directories_settings = data.get('directories', {})
        
        # Update conversation settings in config (Discovery) and runtime ConversationManager
        if conversation_settings and DISCOVERY_AVAILABLE and config_manager:
            max_tokens = conversation_settings.get('max_tokens')
            target_tokens = conversation_settings.get('target_tokens')
            max_output_tokens = conversation_settings.get('max_output_tokens')
            strategy = conversation_settings.get('strategy')
            max_retries = conversation_settings.get('max_retries')
            temperature = conversation_settings.get('temperature')
            
            # Update config file
            config_manager.update_conversation_config(
                max_tokens=max_tokens,
                target_tokens=target_tokens,
                max_output_tokens=max_output_tokens,
                strategy=strategy,
                max_retries=max_retries,
                temperature=temperature
            )
            # Update runtime conversation manager as well if available
            if conversation_manager:
                if max_tokens is not None:
                    conversation_manager.max_tokens = max_tokens
                if target_tokens is not None:
                    conversation_manager.target_tokens = target_tokens
                if max_output_tokens is not None:
                    setattr(conversation_manager, 'max_output_tokens', max_output_tokens)
                if strategy is not None:
                    if strategy == 'sliding_window':
                        conversation_manager.strategy = ContextStrategy.SLIDING_WINDOW
                    elif strategy == 'summarization':
                        conversation_manager.strategy = ContextStrategy.SUMMARIZATION
                    else:
                        conversation_manager.strategy = ContextStrategy.HYBRID
                if max_retries is not None:
                    setattr(conversation_manager, 'max_retries', max_retries)
                if temperature is not None:
                    setattr(conversation_manager, 'temperature', temperature)
        
        # Update conversation manager if available
        if conversation_settings and conversation_manager:
            max_tokens = conversation_settings.get('max_tokens', conversation_manager.max_tokens)
            target_tokens = conversation_settings.get('target_tokens', conversation_manager.target_tokens)
            strategy_name = conversation_settings.get('strategy', conversation_manager.strategy.value)
            
            conversation_manager.max_tokens = max_tokens
            conversation_manager.target_tokens = target_tokens
            
            if strategy_name == 'sliding_window':
                conversation_manager.strategy = ContextStrategy.SLIDING_WINDOW
            elif strategy_name == 'summarization':
                conversation_manager.strategy = ContextStrategy.SUMMARIZATION
            else:
                conversation_manager.strategy = ContextStrategy.HYBRID
        
        # Update Azure configuration
        if azure_settings and DISCOVERY_AVAILABLE and config_manager:
            subscription_id = azure_settings.get('subscription_id', '').strip()
            resource_group = azure_settings.get('resource_group', '').strip()
            location = azure_settings.get('location', '').strip()
            acr_name = azure_settings.get('acr_name', '').strip()
            acr_token_name = azure_settings.get('acr_token_name', '').strip()
            acr_token_password = azure_settings.get('acr_token_password', '').strip()
            discovery_supercomputer = azure_settings.get('discovery_supercomputer', '').strip()
            tenant_id = azure_settings.get('tenant_id', '').strip()

            if subscription_id and resource_group and location:
                try:
                    # Diagnostic log: show incoming discovery_supercomputer from azure settings
                    if discovery_supercomputer:
                        print(f"[Settings POST] Received azure.discovery_supercomputer = '{discovery_supercomputer}'")
                    if tenant_id:
                        print(f"[Settings POST] Received azure.tenant_id = '{tenant_id[:8]}...'")
                    config_manager.update_azure_config(
                        subscription_id, 
                        resource_group, 
                        location, 
                        acr_name=acr_name if acr_name else None,
                        acr_token_name=acr_token_name if acr_token_name else None,
                        acr_token_password=acr_token_password if acr_token_password else None,
                        discovery_supercomputer=discovery_supercomputer if discovery_supercomputer else None,
                        tenant_id=tenant_id if tenant_id else None
                    )
                except Exception as e:
                    print(f"Warning: Could not save Azure config: {e}")
        
        # Update Azure OpenAI configuration
        if azure_openai_settings and DISCOVERY_AVAILABLE and config_manager:
            try:
                # Get current config for merging
                current = config_manager.get_azure_openai_config() or {}
            except Exception:
                current = {}

            # Merge incoming settings with existing config
            merged_config = current.copy()
            
            # Update all fields that are provided in the incoming settings
            if 'endpoint_url' in azure_openai_settings:
                merged_config['endpoint_url'] = azure_openai_settings['endpoint_url'].strip() if isinstance(azure_openai_settings['endpoint_url'], str) else ''
            
            if 'deployment_name' in azure_openai_settings:
                merged_config['deployment_name'] = azure_openai_settings['deployment_name'].strip() if isinstance(azure_openai_settings['deployment_name'], str) else ''
            
            if 'auth_type' in azure_openai_settings:
                merged_config['auth_type'] = azure_openai_settings['auth_type']
            
            if 'api_key' in azure_openai_settings:
                merged_config['api_key'] = azure_openai_settings['api_key'].strip() if isinstance(azure_openai_settings['api_key'], str) else ''
            
            if 'api_version' in azure_openai_settings:
                merged_config['api_version'] = azure_openai_settings['api_version'].strip() if isinstance(azure_openai_settings['api_version'], str) else ''
            
            # Handle azure_ad configuration (includes subscription_id, resource_group, tenant_id, etc.)
            if 'azure_ad' in azure_openai_settings:
                if 'azure_ad' not in merged_config:
                    merged_config['azure_ad'] = {}
                merged_config['azure_ad'].update(azure_openai_settings['azure_ad'])

            # Save the full merged configuration
            try:
                config = config_manager.load_config()
                config['azure_openai'] = merged_config
                config_manager.save_config(config)
                print(f"[Settings POST] Saved Azure OpenAI config:")
                print(f"  - auth_type: {merged_config.get('auth_type', 'api_key')}")
                print(f"  - endpoint_url: {merged_config.get('endpoint_url', '')[:50]}...")
                print(f"  - deployment_name: {merged_config.get('deployment_name', '')}")
                print(f"  - api_version: {merged_config.get('api_version', '')}")
                print(f"  - has_api_key: {bool(merged_config.get('api_key'))}")

                # Update runtime globals AFTER save succeeds
                endpoint = merged_config.get('endpoint_url', endpoint)
                deployment = merged_config.get('deployment_name', deployment)
                # Only update subscription_key if using API key auth
                if merged_config.get('auth_type', 'api_key') == 'api_key':
                    subscription_key = merged_config.get('api_key', subscription_key)

                print(f"[Settings POST] Updated runtime globals - endpoint={'SET' if endpoint else 'NOT SET'}, deployment={'SET' if deployment else 'NOT SET'}, subscription_key={'SET' if subscription_key else 'NOT SET'}")

                # Verify that config was actually saved by reading it back
                try:
                    verify_config = config_manager.get_azure_openai_config()
                    print(f"[Settings POST] ✅ Verification read from disk - api_version: {verify_config.get('api_version', '')}")
                except Exception as verify_e:
                    print(f"[Settings POST] ⚠️ Failed to verify saved config: {verify_e}")
            except Exception as e:
                print(f"Warning: Could not save Azure OpenAI config: {e}")
        
        # Update directories configuration
        directories_changed = False
        if directories_settings and DISCOVERY_AVAILABLE and config_manager:
            discovery_tool_dir = directories_settings.get('tool_agents_dir', '').strip()
            kb_agent_dir = directories_settings.get('kb_agents_dir', '').strip()
            workflow_agent_dir = directories_settings.get('workflow_agents_dir', '').strip()
            
            try:
                config_manager.update_directories_config(
                    discovery_tool_output_dir=discovery_tool_dir if discovery_tool_dir else None,
                    kb_agent_output_dir=kb_agent_dir if kb_agent_dir else None,
                    workflow_agents_dir=workflow_agent_dir if workflow_agent_dir else None
                )
                directories_changed = True
            except Exception as e:
                print(f"Warning: Could not save directories config: {e}")
        
        # Reload agent catalog if directories changed
        if directories_changed and agent_manager:
            try:
                reload_agent_catalog()
                print("Agent catalog reloaded due to directory changes")
            except Exception as e:
                print(f"Warning: Could not reload agent catalog: {e}")
        
        # Update Azure Compute configuration
        if azure_compute_settings and DISCOVERY_AVAILABLE and config_manager:
            auto_cleanup = azure_compute_settings.get('auto_cleanup', False)
            use_script_upload = azure_compute_settings.get('use_script_upload', True)
            storage_account = azure_compute_settings.get('storage_account', '').strip()
            discovery_storage = azure_compute_settings.get('discovery_storage', '').strip()
            discovery_supercomputer = azure_compute_settings.get('discovery_supercomputer', '').strip()
            # Optional discovery workspace/project values (persist if provided)
            workspace = azure_compute_settings.get('workspace', '').strip()
            project = azure_compute_settings.get('project', '').strip()

            try:
                # Diagnostic log: show incoming discovery_supercomputer from azure_compute settings
                if discovery_supercomputer:
                    print(f"[Settings POST] Received azure_compute.discovery_supercomputer = '{discovery_supercomputer}'")
                if discovery_storage:
                    print(f"[Settings POST] Received azure_compute.discovery_storage = '{discovery_storage}'")
                # Optional input/output/data container for Discovery data assets
                inputs_asset = azure_compute_settings.get('inputs_asset', '').strip()
                outputs_asset = azure_compute_settings.get('outputs_asset', '').strip()
                data_container = azure_compute_settings.get('data_container', '').strip()
                if inputs_asset:
                    print(f"[Settings POST] Received azure_compute.inputs_asset = '{inputs_asset}'")
                if outputs_asset:
                    print(f"[Settings POST] Received azure_compute.outputs_asset = '{outputs_asset}'")
                if data_container:
                    print(f"[Settings POST] Received azure_compute.data_container = '{data_container}'")
                
                # Update the configuration
                config_manager.update_azure_compute_config(
                    auto_cleanup=auto_cleanup,
                    use_script_upload=use_script_upload,
                    storage_account=storage_account if storage_account else None,
                    discovery_storage=discovery_storage if discovery_storage else None,
                    discovery_supercomputer=discovery_supercomputer if discovery_supercomputer else None,
                    inputs_asset=inputs_asset if inputs_asset else None,
                    outputs_asset=outputs_asset if outputs_asset else None,
                    data_container=data_container if data_container else None,
                    workspace=workspace if workspace else None,
                    project=project if project else None
                )
                
                # Auto-create workbench assets if not provided
                # This is critical for job submission to work properly
                if data_container and not (inputs_asset or outputs_asset):
                    print("[Settings POST] No inputs_asset/outputs_asset configured - attempting auto-creation...")
                    server_traces = []
                    try:
                        asset_result = config_manager.ensure_workbench_assets(server_traces=server_traces)
                        
                        # Log all traces
                        for trace in server_traces:
                            print(f"[Asset Manager] {trace}")
                        
                        if asset_result.get('success'):
                            if asset_result.get('created_inputs') or asset_result.get('created_outputs'):
                                print(f"[Settings POST] ✅ Workbench assets created successfully")
                                print(f"  inputs_asset: {asset_result.get('inputs_asset')}")
                                print(f"  outputs_asset: {asset_result.get('outputs_asset')}")
                            else:
                                print(f"[Settings POST] ℹ️ Workbench assets already exist")
                        else:
                            print(f"[Settings POST] ⚠️ Failed to ensure workbench assets: {asset_result.get('error')}")
                    except Exception as asset_e:
                        print(f"[Settings POST] ⚠️ Exception ensuring workbench assets: {str(asset_e)}")
                        import traceback
                        traceback.print_exc()
                
            except Exception as e:
                print(f"Warning: Could not save Azure Compute config: {e}")
        
        # Reset LLM client if Azure OpenAI settings were updated
        if azure_openai_settings:
            # Force global config manager to reload from disk
            from discovery_config_manager import set_global_config_manager
            set_global_config_manager(DiscoveryConfigManager())
            print("[Settings POST] Updated global config manager to read fresh settings")

            reset_default_client()
            print("[Settings POST] LLM client reset to pick up new Azure OpenAI configuration")
        
        return jsonify({
            'success': True,
            'message': 'Settings updated successfully'
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/settings/optimization-preference', methods=['GET', 'POST'])
def optimization_preference_endpoint():
    """Get or set nodepool optimization preference

    GET: Returns current optimization preference
    POST: Updates optimization preference (accepts 'performance', 'cost', or 'balanced')
    """
    try:
        config_manager = DiscoveryConfigManager()

        if request.method == 'GET':
            azure_compute = config_manager.get_azure_compute_config()
            return jsonify({
                'success': True,
                'optimization_preference': azure_compute.get('optimization_preference', 'balanced'),
                'nodepool_cache_ttl_hours': azure_compute.get('nodepool_cache_ttl_hours', 24)
            })
        else:
            data = request.get_json() or {}
            preference = data.get('optimization_preference', 'balanced')

            # Validate preference value
            valid_preferences = ['performance', 'cost', 'balanced']
            if preference not in valid_preferences:
                return jsonify({
                    'success': False,
                    'error': f"Invalid optimization_preference. Must be one of: {', '.join(valid_preferences)}"
                }), 400

            # Update configuration
            success = config_manager.update_azure_compute_config(
                optimization_preference=preference
            )

            if success:
                # Clear nodepool cache to force refresh with new preference
                if NODEPOOL_SERVICE_AVAILABLE:
                    try:
                        nodepool_service = get_nodepool_service()
                        if nodepool_service:
                            cleared = nodepool_service.clear_cache()
                            print(f"[Optimization] Cleared {cleared} nodepool cache entries after preference change")
                    except Exception as cache_err:
                        print(f"[Optimization] Warning: Could not clear nodepool cache: {cache_err}")

                return jsonify({
                    'success': True,
                    'optimization_preference': preference,
                    'message': f"Optimization preference updated to '{preference}'"
                })
            else:
                return jsonify({
                    'success': False,
                    'error': 'Failed to save optimization preference'
                }), 500

    except Exception as e:
        print(f"[Optimization] Error: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500


# Agent Management API Endpoints

@app.route('/api/agents/list', methods=['GET'])
def list_agents():
    """Get list of all available agents"""
    try:
        if not agent_manager:
            # Gracefully handle missing agent manager - return empty agent lists
            print("ℹ️ Agent manager not initialized - returning empty agent lists")
            builtin_entry = {
                'name': BUILTIN_DISCOVERY_AGENT_KEY,
                'display_name': BUILTIN_DISCOVERY_AGENT_DISPLAY,
                'description': 'Built-in assistant for Microsoft Discovery documentation and agent development help',
                'is_current': _builtin_discovery_active,
                'type': 'builtin'
            }
            return jsonify({
                'success': True,
                'agents': {
                    'tool_agents': [builtin_entry],
                    'workflow_agents': [],
                    'kb_agents': [],
                    'tool_agents': []
                },
                'current_agent': BUILTIN_DISCOVERY_AGENT_KEY if _builtin_discovery_active else None,
                'total_count': 1
            })
        
        agents_data = agent_manager.list_agents()

        # Get current agent from session (session-scoped, not global)
        current_agent = get_current_agent_name()
        sm = get_session_manager()
        current_agent_type = None
        if sm and sm.current_session_id:
            session = sm.get_session(sm.current_session_id)
            if session:
                current_agent_type = session.agent_type

        # Add is_current flag based on session's current agent
        # Use case-insensitive matching to handle name vs display_name mismatches
        # Also check agent type to avoid marking agents with same name but different types
        current_agent_lower = current_agent.lower() if current_agent else None
        list_type_map = {'tool_agents': 'tool', 'workflow_agents': 'entry', 'kb_agents': 'kb'}
        for lst_name in ('tool_agents', 'workflow_agents', 'kb_agents'):
            lst = agents_data.get(lst_name) or []
            expected_type = list_type_map[lst_name]
            for agent in lst:
                if isinstance(agent, dict):
                    agent_name = agent.get('name', '')
                    display_name = agent.get('display_name', '')
                    # Match by name or display_name (case-insensitive) AND agent type must match
                    name_matches = current_agent_lower and (
                        agent_name.lower() == current_agent_lower or
                        display_name.lower() == current_agent_lower
                    )
                    # Type matches if: current_agent_type matches expected_type, OR no type info (legacy)
                    type_matches = (not current_agent_type) or (current_agent_type == expected_type)
                    agent['is_current'] = name_matches and type_matches

        # Inject builtin discovery assistant into list (as a pseudo entry under tool_agents top)
        builtin_entry = {
            'name': BUILTIN_DISCOVERY_AGENT_KEY,
            'display_name': BUILTIN_DISCOVERY_AGENT_DISPLAY,
            'description': 'Built-in assistant for Microsoft Discovery documentation and agent development help',
            'is_current': _builtin_discovery_active or (current_agent == BUILTIN_DISCOVERY_AGENT_KEY),
            'type': 'builtin'
        }
        # Prepend while avoiding duplicates
        agents_data['tool_agents'] = [builtin_entry] + [a for a in agents_data['tool_agents'] if a['name'] != BUILTIN_DISCOVERY_AGENT_KEY]

        # If builtin discovery assistant is active, ensure mutual-exclusivity of is_current flags
        if _builtin_discovery_active:
            for lst_name in ('tool_agents', 'workflow_agents', 'kb_agents'):
                lst = agents_data.get(lst_name) or []
                for a in lst:
                    if isinstance(a, dict) and a.get('name') != BUILTIN_DISCOVERY_AGENT_KEY:
                        a['is_current'] = False
            agents_data['tool_agents'][0]['is_current'] = True
            current_agent = BUILTIN_DISCOVERY_AGENT_KEY

        # Calculate total count
        total_count = len(agents_data['tool_agents']) + len(agents_data['workflow_agents']) + len(agents_data.get('kb_agents', []))

        return jsonify({
            'success': True,
            'agents': agents_data,
            'current_agent': current_agent,
            'total_count': total_count
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/reload-agent-catalog', methods=['POST'])
def reload_agent_catalog_endpoint():
    """Reload the agent catalog from disk - useful after directory path changes"""
    return reload_agent_catalog()

@app.route('/api/agents/<agent_name>', methods=['GET'])
def get_agent_info(agent_name):
    """Get detailed information about a specific agent"""
    try:
        if not agent_manager:
            return jsonify({'error': 'Agent manager not available'}), 500
        
        # Get current agent from session for comparison
        session_current_agent = get_current_agent_name()

        if agent_name == BUILTIN_DISCOVERY_AGENT_KEY:
            return jsonify({
                'success': True,
                'agent': {
                    'name': BUILTIN_DISCOVERY_AGENT_KEY,
                    'display_name': BUILTIN_DISCOVERY_AGENT_DISPLAY,
                    'description': 'Built-in documentation assistant',
                    'paths': {},
                    'files_exist': {},
                    'is_current': _builtin_discovery_active or (session_current_agent == BUILTIN_DISCOVERY_AGENT_KEY)
                }
            })

        info = agent_manager.get_agent_info(agent_name)
        paths = agent_manager.get_agent_paths(agent_name)
        validation = agent_manager.validate_agent_files(agent_name)

        return jsonify({
            'success': True,
            'agent': {
                'name': info.catalog_entry.key,
                'display_name': info.display_name,
                'description': info.description,
                'paths': paths,
                'files_exist': validation,
                'is_current': agent_name == session_current_agent
            }
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/agents/<agent_name>/switch', methods=['POST'])
def switch_agent(agent_name):
    """Switch to a different agent (container management is best-effort)."""
    try:
        global _builtin_discovery_active, SYSTEM_PROMPT, CONTAINER_NAME

        # Parse request body to get agent type and options
        request_data = request.get_json() or {}
        requested_agent_type = request_data.get('agent_type', 'tool')  # Default to 'tool' for backward compatibility
        preserve_conversation = request_data.get('preserve_conversation', False)  # Don't reset conversation if restoring session

        # Get current agent name for saving its UI state
        sm = get_session_manager()
        old_agent_name = None
        if sm and sm.current_session_id:
            old_session = sm.get_session(sm.current_session_id)
            old_agent_name = old_session.agent_name if old_session else None

        # Save current agent's UI state before switching agents (agent-specific)
        current_ui_state = request_data.get('ui_state')
        if current_ui_state and sm and sm.current_session_id and old_agent_name:
            sm.save_ui_state(sm.current_session_id, current_ui_state, agent_name=old_agent_name)
            print(f"💾 Saved UI state for agent '{old_agent_name}' in session {sm.current_session_id} before switching")

        # Normalize agent type names
        if requested_agent_type == 'regular':
            requested_agent_type = 'tool'

        # Built-in assistant path
        if agent_name == BUILTIN_DISCOVERY_AGENT_KEY:
            _builtin_discovery_active = True
            SYSTEM_PROMPT = build_builtin_discovery_system_prompt()

            sm = get_session_manager()
            old_agent_name = None
            if sm and sm.current_session_id:
                old_session = sm.get_session(sm.current_session_id)
                old_agent_name = old_session.agent_name if old_session else None

            conversation_loaded = False
            if conversation_manager and not preserve_conversation:
                # Save current conversation for the OLD agent before switching
                if old_agent_name:
                    old_conv_file = get_conversation_file_path(agent_name=old_agent_name)
                    conversation_manager.save_session_to_file(conversation_manager.current_session_id, old_conv_file)

                # Try to load existing conversation for the NEW agent, or create new
                new_conv_file = get_conversation_file_path(agent_name=BUILTIN_DISCOVERY_AGENT_KEY)
                if os.path.exists(new_conv_file):
                    conversation_manager.load_session_from_file(new_conv_file, sm.current_session_id if sm else None)
                    conversation_loaded = True
                else:
                    conversation_manager.create_session(SYSTEM_PROMPT)
                    conversation_loaded = False
            elif preserve_conversation and conversation_manager:
                # When preserving (session restore), load the agent's conversation file
                new_conv_file = get_conversation_file_path(agent_name=BUILTIN_DISCOVERY_AGENT_KEY)
                if os.path.exists(new_conv_file):
                    conversation_manager.load_session_from_file(new_conv_file, sm.current_session_id if sm else None)
                    conversation_loaded = True
                else:
                    conversation_loaded = False

            # Update session with agent info
            if sm and sm.current_session_id:
                sm.update_session(sm.current_session_id, agent_name=BUILTIN_DISCOVERY_AGENT_KEY, agent_type='builtin')
                print(f"📍 Updated session {sm.current_session_id} with agent: {BUILTIN_DISCOVERY_AGENT_KEY}")
            elif sm:
                print(f"⚠️ Cannot update session with builtin agent: current_session_id is None")

            # Get conversation history for frontend if conversation was loaded
            conversation_history = []
            if conversation_loaded and conversation_manager:
                conv_session = conversation_manager.get_session(sm.current_session_id if sm else conversation_manager.current_session_id)
                if conv_session:
                    for msg in conv_session.messages:
                        if msg.role in ('user', 'assistant'):
                            conversation_history.append({
                                'role': msg.role,
                                'content': msg.content,
                                'timestamp': msg.timestamp,
                                'message_id': msg.message_id
                            })

            # Get UI state for the new agent (if any)
            new_ui_state = None
            if sm and sm.current_session_id:
                new_ui_state = sm.get_ui_state(sm.current_session_id, agent_name=BUILTIN_DISCOVERY_AGENT_KEY)

            # Get session info for token count display
            session_info = None
            if conversation_manager:
                session_id = sm.current_session_id if sm else conversation_manager.current_session_id
                session_info = conversation_manager.get_session_info(session_id)

            return jsonify({
                'success': True,
                'message': f'Switched to agent: {BUILTIN_DISCOVERY_AGENT_DISPLAY}',
                'agent': {
                    'name': BUILTIN_DISCOVERY_AGENT_KEY,
                    'display_name': BUILTIN_DISCOVERY_AGENT_DISPLAY,
                    'description': 'Built-in documentation assistant',
                    'container_name': None,
                    'type': 'builtin'
                },
                'container': None,
                'tools_loaded': [],
                'conversation_reset': not conversation_loaded,  # Only reset if no existing conversation loaded
                'conversation_history': conversation_history if conversation_loaded else None,
                'ui_state': new_ui_state,  # Return UI state for this agent
                'session_info': session_info,  # Return session info for token count display
                'is_workflow_agent': False,
                'docker_image_needed': False,
                'has_dockerfile': False
            })

        if not agent_manager:
            return jsonify({'error': 'Agent manager not available'}), 500

        docker_available = bool(docker_client)

        # Validate agent exists and files based on specified type
        validation = agent_manager.validate_agent_files_by_type(agent_name, requested_agent_type)
        
        # Check if the agent exists for the specified type
        if not validation:
            return jsonify({'error': f'{requested_agent_type.title()} agent not found: {agent_name}'}), 404
        
        # Determine required files based on agent type
        agent_type = validation.get('type', 'unknown')
        if agent_type == 'kb':
            required_files = ['agent_config']  # KB agents only need agent config
        elif agent_type == 'entry':
            required_files = ['agent_config']  # Entry agents only need agent config
        else:
            required_files = ['agent_config', 'tools_definition']  # Tool agents need both
            
        missing_required = [k for k in required_files if k in validation and not validation[k]]
        if missing_required:
            return jsonify({'error': f'Cannot switch to {agent_name}: missing required files {missing_required}'}), 400

        has_dockerfile = bool(validation.get('dockerfile'))

        # Leaving builtin
        _builtin_discovery_active = False

        # Validate agent exists in catalog
        if not agent_manager.agent_exists(agent_name, requested_agent_type):
            return jsonify({'error': f'Agent not found: {agent_name}'}), 404

        # Update session with agent info (session-scoped, not global)
        if sm and sm.current_session_id:
            sm.update_session(sm.current_session_id, agent_name=agent_name, agent_type=requested_agent_type)
            print(f"📍 Updated session {sm.current_session_id} with agent: {agent_name} (type: {requested_agent_type})")
        else:
            print(f"⚠️ Cannot update session with agent '{agent_name}': sm={sm is not None}, current_session_id={sm.current_session_id if sm else 'N/A'}")

        paths = agent_manager.get_agent_paths(agent_name, agent_type=requested_agent_type)
        info = agent_manager.get_agent_info(agent_name, agent_type=requested_agent_type)
        is_workflow_agent = paths.get('type') == 'entry'
        is_kb_agent = paths.get('type') == 'kb'
        container_result = {'success': True}
        docker_image_needed = False

        # KB agents and workflow agents don't need Docker containers
        if not is_workflow_agent and not is_kb_agent and has_dockerfile:
            container_name = get_normalized_container_name(agent_name)
            globals()['CONTAINER_NAME'] = container_name  # Update global, not create local variable

            if not docker_available:
                # Switching agents should not require Docker; we only skip container operations.
                container_result = {'success': True, 'info': 'Docker not available: container start/inspect skipped'}
                docker_image_needed = True
            else:
                try:
                    try:
                        container = docker_client.containers.get(container_name)
                        if container.status == 'running':
                            container_result = {'success': True, 'container_info': {'name': container_name, 'id': container.id, 'status': container.status}}
                        elif container.status in ['exited', 'stopped', 'created']:
                            # Recreate container with current env vars instead of just starting
                            image_name = container.image.tags[0] if container.image.tags else container.image.id
                            env_vars_dict = load_agent_env_vars(agent_name)
                            stop_and_remove_container(container_name)
                            start_result = start_agent_container(agent_name, image_name, container_name, env_vars_dict)
                            if start_result.get('success'):
                                container_result = {'success': True, 'container_info': {'name': container_name, 'id': start_result['container_id'], 'status': start_result['status'], 'restarted': True}}
                            else:
                                docker_image_needed = True
                        else:
                            docker_image_needed = True
                    except docker.errors.NotFound:
                        image_name, _ = _derive_image_name_from_tool_definition(agent_name)
                        try:
                            docker_client.images.get(image_name)
                            # Load env vars before starting container
                            env_vars_dict = load_agent_env_vars(agent_name)
                            start_result = start_agent_container(agent_name, image_name, None, env_vars_dict)
                            if start_result['success']:
                                container_result = {'success': True, 'container_info': {'name': start_result['container_name'], 'id': start_result['container_id'], 'status': start_result['status'], 'image': image_name}}
                            else:
                                docker_image_needed = True
                        except docker.errors.ImageNotFound:
                            docker_image_needed = True
                except Exception as e:
                    print(f"⚠️ Docker status check failed: {e}")
                    docker_image_needed = True
        elif not is_workflow_agent and not is_kb_agent and not has_dockerfile:
            container_result = {'success': True, 'warning': 'Dockerfile missing: container build/start skipped'}
        elif is_kb_agent:
            container_result = {'success': True, 'info': 'Knowledge Base agent: no container needed'}

        # Load system prompt for selected agent (pass agent_type to handle name collisions)
        SYSTEM_PROMPT = load_agent_config(agent_name, agent_type=requested_agent_type)

        # Note: old_agent_name already determined at the top of this function
        conversation_loaded = False
        if conversation_manager and not preserve_conversation:
            # Save current conversation for the OLD agent before switching
            if old_agent_name and conversation_manager.current_session_id:
                old_conv_file = get_conversation_file_path(agent_name=old_agent_name)
                conversation_manager.save_session_to_file(conversation_manager.current_session_id, old_conv_file)

            # Try to load existing conversation for the NEW agent, or create new
            new_conv_file = get_conversation_file_path(agent_name=agent_name)
            if os.path.exists(new_conv_file):
                conversation_manager.load_session_from_file(new_conv_file, sm.current_session_id if sm else None)
                conversation_loaded = True
            else:
                # No existing conversation for this agent - create new
                current_session = conversation_manager.current_session_id
                if current_session:
                    conversation_manager.reset_session(current_session, SYSTEM_PROMPT)
                else:
                    conversation_manager.create_session(SYSTEM_PROMPT)
                conversation_loaded = False
        elif preserve_conversation and conversation_manager:
            # When preserving (session restore), load the agent's conversation file
            new_conv_file = get_conversation_file_path(agent_name=agent_name)
            if os.path.exists(new_conv_file):
                conversation_manager.load_session_from_file(new_conv_file, sm.current_session_id if sm else None)
                conversation_loaded = True

        # Update session with agent info
        if sm:
            agent_type_for_session = 'kb' if is_kb_agent else ('entry' if is_workflow_agent else 'tool')
            sm.update_session(sm.current_session_id, agent_name=agent_name, agent_type=agent_type_for_session)

        # Get conversation history for frontend if conversation was loaded
        conversation_history = []
        if conversation_loaded and conversation_manager:
            conv_session = conversation_manager.get_session(sm.current_session_id if sm else conversation_manager.current_session_id)
            if conv_session:
                for msg in conv_session.messages:
                    if msg.role in ('user', 'assistant'):
                        conversation_history.append({
                            'role': msg.role,
                            'content': msg.content,
                            'timestamp': msg.timestamp,
                            'message_id': msg.message_id
                        })

        # Get UI state for the new agent (if any)
        new_ui_state = None
        if sm and sm.current_session_id:
            new_ui_state = sm.get_ui_state(sm.current_session_id, agent_name=agent_name)

        # Get session info for token count display
        session_info = None
        if conversation_manager:
            session_id = sm.current_session_id if sm else conversation_manager.current_session_id
            session_info = conversation_manager.get_session_info(session_id)

        return jsonify({
            'success': True,
            'message': f'Switched to agent: {info.display_name}',
            'agent': {
                'name': agent_name,
                'display_name': info.display_name,
                'description': info.description,
                'container_name': CONTAINER_NAME if not is_workflow_agent and not is_kb_agent else None,
                'type': 'kb' if is_kb_agent else ('entry' if is_workflow_agent else 'tool')
            },
            'container': container_result.get('container_info', None),
            'tools_loaded': list(TOOL_ACTIONS.keys()),
            'conversation_reset': not conversation_loaded,  # Only reset if no existing conversation loaded
            'conversation_history': conversation_history if conversation_loaded else None,
            'ui_state': new_ui_state,  # Return UI state for this agent
            'session_info': session_info,  # Return session info for token count display
            'is_workflow_agent': is_workflow_agent,
            'is_kb_agent': is_kb_agent,
            'docker_image_needed': docker_image_needed,
            'has_dockerfile': has_dockerfile
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/agents/current', methods=['GET'])
def get_current_agent():
    """Get information about the currently active agent"""
    try:
        # Helper to get session_info for token count display
        def get_session_info_for_response():
            if conversation_manager:
                sm = get_session_manager()
                session_id = sm.current_session_id if sm else conversation_manager.current_session_id
                return conversation_manager.get_session_info(session_id)
            return None

        if not agent_manager:
            # Gracefully handle missing agent manager
            print("ℹ️ Agent manager not initialized - returning builtin discovery agent as current")
            return jsonify({
                'success': True,
                'current_agent': {
                    'name': BUILTIN_DISCOVERY_AGENT_KEY,
                    'display_name': BUILTIN_DISCOVERY_AGENT_DISPLAY,
                    'description': 'Built-in documentation assistant',
                    'paths': {},
                    'files_exist': {},
                    'container_name': None,
                    'type': 'builtin'
                },
                'session_info': get_session_info_for_response()
            })

        # Get current agent from session (session-scoped)
        current_agent_name = get_current_agent_name()
        sm = get_session_manager()
        current_agent_type = None
        if sm and sm.current_session_id:
            session = sm.get_session(sm.current_session_id)
            if session:
                current_agent_type = session.agent_type

        # Check if builtin assistant is active
        if _builtin_discovery_active or current_agent_name == BUILTIN_DISCOVERY_AGENT_KEY:
            return jsonify({
                'success': True,
                'current_agent': {
                    'name': BUILTIN_DISCOVERY_AGENT_KEY,
                    'display_name': BUILTIN_DISCOVERY_AGENT_DISPLAY,
                    'description': 'Built-in documentation assistant',
                    'paths': {},
                    'files_exist': {},
                    'container_name': None,
                    'type': 'builtin'
                },
                'session_info': get_session_info_for_response()
            })

        if not current_agent_name:
            return jsonify({
                'success': True,
                'current_agent': None,
                'message': 'No agent currently selected in this session',
                'session_info': get_session_info_for_response()
            })

        # Validate agent exists in catalog
        if not agent_manager.agent_exists(current_agent_name):
            return jsonify({
                'success': True,
                'current_agent': None,
                'message': f'Session agent "{current_agent_name}" not found in catalog',
                'session_info': get_session_info_for_response()
            })

        info = agent_manager.get_agent_info(current_agent_name)
        paths = agent_manager.get_agent_paths(current_agent_name, current_agent_type)
        validation = agent_manager.validate_agent_files(current_agent_name)

        return jsonify({
            'success': True,
            'current_agent': {
                'name': current_agent_name,
                'display_name': info.display_name,
                'description': info.description,
                'paths': paths,
                'files_exist': validation,
                'container_name': CONTAINER_NAME,
                'type': current_agent_type
            },
            'session_info': get_session_info_for_response()
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/agents/<agent_name>/yaml/<yaml_type>', methods=['GET', 'PUT'])
def agent_yaml_editor(agent_name, yaml_type):
    """Get or update YAML content (agent_config or tools_definition) for an agent.

    yaml_type must be one of: agent_config, tools_definition
    GET: returns { success, agent, type, path, content }
    PUT: body { content, validate(optional bool) } writes file, optionally validates YAML parse, reloads config if current agent.
    """
    try:
        if not agent_manager:
            return jsonify({'error': 'Agent manager not available'}), 500

        if yaml_type not in ['agent_config', 'tools_definition']:
            return jsonify({'error': f'Invalid yaml_type: {yaml_type}'}), 400

        # Ensure agent exists (support both regular and workflow agents)
        if agent_name == BUILTIN_DISCOVERY_AGENT_KEY:
            # Return empty stub so frontend doesn't error; editing disabled client-side
            if request.method == 'GET':
                return jsonify({'success': True, 'agent': agent_name, 'type': yaml_type, 'path': None, 'content': ''})
            else:
                return jsonify({'error': 'Builtin agent YAML is read-only'}), 400

        if agent_name not in agent_manager.agents and agent_name not in agent_manager.workflow_agents and agent_name not in agent_manager.kb_agents:
            return jsonify({'error': f'Agent not found: {agent_name}'}), 404

        paths = agent_manager.get_agent_paths(agent_name)
        
        # For KB agents, only agent_config is available, not tools_definition
        if agent_name in agent_manager.kb_agents and yaml_type == 'tools_definition':
            return jsonify({'error': 'Knowledge Base agents do not have tools definition'}), 400
            
        file_path = paths.get(yaml_type)
        if not file_path:
            return jsonify({'error': f'Path for {yaml_type} not set'}), 400

        # Normalize path (relative to this server file working directory)
        if not os.path.isabs(file_path):
            file_path = os.path.abspath(os.path.join(os.path.dirname(__file__), file_path))

        if request.method == 'GET':
            if not os.path.exists(file_path):
                return jsonify({'error': f'File not found: {file_path}'}), 404
            with open(file_path, 'r', encoding='utf-8') as f:
                content = f.read()
            return jsonify({'success': True, 'agent': agent_name, 'type': yaml_type, 'path': file_path, 'content': content})

        # PUT (update)
        data = request.get_json(force=True, silent=True) or {}
        new_content = data.get('content')
        validate_flag = data.get('validate', True)
        if new_content is None:
            return jsonify({'error': 'Missing content field'}), 400

        # Optional YAML validation before writing
        if validate_flag:
            try:
                schema_checked = False
                # Try to use config_manager to resolve appropriate schema
                if config_manager:
                    try:
                        t_files = config_manager.get_template_files()
                    except Exception:
                        t_files = None

                    schema_rel = None
                    if yaml_type == 'agent_config':
                        schema_rel = t_files.get('AgentDefinitionSchema') if t_files else None
                    elif yaml_type == 'tools_definition':
                        schema_rel = t_files.get('ToolDefinitionSchema') if t_files else None

                    if schema_rel:
                        candidate = Path(__file__).parent / schema_rel
                        if candidate.exists():
                            vres = validate_yaml(str(candidate), new_content)
                            schema_checked = True
                            if not vres.valid:
                                summarized = '; '.join(f"{e.path}: {e.message}" for e in vres.errors[:6])
                                if len(vres.errors) > 6:
                                    summarized += ' ...'
                                return jsonify({'error': f'Schema validation failed for file {file_path}: {summarized}'}), 400

                            # Additional semantic validation for agent definitions
                            if yaml_type == 'agent_config':
                                try:
                                    parsed = yaml.safe_load(new_content)
                                    forbidden = _find_forbidden_extension_input_names(parsed)
                                    if forbidden:
                                        forbidden_list = ', '.join(sorted(forbidden))
                                        return jsonify({
                                            'error': (
                                                'Reserved inputs are not allowed in agent definition extension.inputs: '
                                                f'{forbidden_list}.'
                                            )
                                        }), 400
                                except Exception:
                                    # If YAML can't be parsed, the schema/YAML validation above will already fail.
                                    pass

                if not schema_checked:
                    parsed = yaml.safe_load(new_content)

                    # Additional semantic validation for agent definitions
                    if yaml_type == 'agent_config':
                        forbidden = _find_forbidden_extension_input_names(parsed)
                        if forbidden:
                            forbidden_list = ', '.join(sorted(forbidden))
                            return jsonify({
                                'error': (
                                    'Reserved inputs are not allowed in agent definition extension.inputs: '
                                    f'{forbidden_list}.'
                                )
                            }), 400
            except yaml.YAMLError as ve:
                return jsonify({'error': f'YAML validation failed for file {file_path}: {ve}'}), 400
            except Exception:
                try:
                    yaml.safe_load(new_content)
                except Exception:
                    pass

        # Write file safely (atomic replace)
        tmp_path = file_path + '.tmp'
        with open(tmp_path, 'w', encoding='utf-8') as f:
            f.write(new_content)
        os.replace(tmp_path, file_path)

        # Invalidate cached info for this agent so display name/description refresh
        if agent_name in agent_manager.agent_info_cache:
            agent_manager.agent_info_cache.pop(agent_name, None)

        # If editing tools definition or agent_config for session's current agent, reload runtime config
        session_current_agent = get_current_agent_name()
        # Get agent_type from current session
        sm = get_session_manager()
        session_agent_type = None
        if sm and sm.current_session_id:
            session = sm.get_session(sm.current_session_id)
            if session:
                session_agent_type = session.agent_type
        reloaded = False
        reloaded_tools = []
        if session_current_agent == agent_name:
            if yaml_type == 'tools_definition':
                # Reload tool actions only
                load_agent_config(agent_name, session_agent_type)
                reloaded = True
                reloaded_tools = list(TOOL_ACTIONS.keys())
            elif yaml_type == 'agent_config':
                # Reload full system prompt and tools
                SYSTEM_PROMPT = load_agent_config(agent_name, session_agent_type)  # noqa: F841 (intentional assignment for global reload effect)
                reloaded = True
                reloaded_tools = list(TOOL_ACTIONS.keys())
                # Reset conversation sessions with updated system prompt if manager exists
                if conversation_manager:
                    sid = conversation_manager.current_session_id
                    if sid:
                        conversation_manager.reset_session(sid, SYSTEM_PROMPT)
                    else:
                        conversation_manager.create_session(SYSTEM_PROMPT)

        return jsonify({
            'success': True,
            'agent': agent_name,
            'type': yaml_type,
            'path': file_path,
            'reloaded': reloaded,
            'tools_loaded': reloaded_tools
        })
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/agents/<agent_name>/entry-component/<component_type>', methods=['GET'])
def get_workflow_agent_component(agent_name, component_type):
    """Get YAML content for a specific workflow agent component by reading from the catalog."""
    try:
        if not agent_manager:
            print("TRACE: Agent manager not available", file=sys.stderr)
            return jsonify({'error': 'Agent manager not available'}), 500
        
        if agent_name not in agent_manager.workflow_agents:
            print(f"TRACE: Agent '{agent_name}' not found in workflow_agents", file=sys.stderr)
            return jsonify({'error': f'Agent "{agent_name}" is not a known workflow agent'}), 404
        
        entry_agent = agent_manager.workflow_agents[agent_name]
        
        valid_component_types = ['workflow', 'planner', 'router', 'summarizer']
        if component_type not in valid_component_types:
            print(f"TRACE: Invalid component type '{component_type}'", file=sys.stderr)
            return jsonify({'error': f'Invalid component type: {component_type}'}), 400
        
        rel_path = None
        # Special case for 'workflow', which is stored in the top-level 'agent_config'
        if component_type == 'workflow':
            rel_path = getattr(entry_agent, 'agent_config', None)
            print(f"TRACE: Determined rel_path for workflow: '{rel_path}' from top-level agent_config", file=sys.stderr)
        # For other components, search the 'components' list
        elif hasattr(entry_agent, 'components') and entry_agent.components:
            component_entry = next((c for c in entry_agent.components if c.get('type') == component_type), None)
            if component_entry:
                rel_path = component_entry.get('agent_config')

        if not rel_path:
            print(f"TRACE: No path defined in catalog for component '{component_type}'", file=sys.stderr)
            return jsonify({'error': f'Component type "{component_type}" has no path defined in the catalog for agent "{agent_name}".'}), 404

        # Resolve the absolute path relative to the catalog file
        catalog_dir = os.path.dirname(os.path.abspath(agent_manager.catalog_path))
        component_file = os.path.normpath(os.path.join(catalog_dir, rel_path))
        
        if not os.path.exists(component_file):
            print(f"TRACE: Component file does not exist at path: {component_file}", file=sys.stderr)
            return jsonify({'error': f'Component file not found. Path resolved from catalog: {component_file}'}), 404
        
        with open(component_file, 'r', encoding='utf-8') as f:
            content = f.read()
        
        return jsonify({
            'success': True,
            'agent': agent_name,
            'component_type': component_type,
            'path': component_file,
            'content': content
        })
        
    except Exception as e:
        # Log the full exception for better debugging on the server side
        error_message = f"An unexpected error occurred in get_workflow_agent_component for agent '{agent_name}', component '{component_type}': {str(e)}"
        print(f"⚠️ {error_message}", file=sys.stderr)
        return jsonify({'error': error_message}), 500

@app.route('/api/agents/<agent_name>/entry-diagram', methods=['GET'])
def get_workflow_agent_diagram(agent_name):
    """Get Mermaid diagram content for an workflow agent by looking for the .mmd file."""
    try:
        if not agent_manager:
            return jsonify({'error': 'Agent manager not available'}), 500
        
        if agent_name not in agent_manager.workflow_agents:
            return jsonify({'error': f'Agent "{agent_name}" is not a known workflow agent'}), 404
        
        entry_agent = agent_manager.workflow_agents[agent_name]
        
        # Get the workflow file path to determine the agent folder
        workflow_rel_path = getattr(entry_agent, 'agent_config', None)
        if not workflow_rel_path:
            return jsonify({'error': f'No workflow path defined for agent "{agent_name}"'}), 404
            
        # Resolve the absolute path of the workflow file
        catalog_dir = os.path.dirname(os.path.abspath(agent_manager.catalog_path))
        workflow_file = os.path.normpath(os.path.join(catalog_dir, workflow_rel_path))
        
        # Get the folder containing the workflow file
        agent_folder = os.path.dirname(workflow_file)
        
        # Look for a diagram file with the pattern {agent_name}-diagram.mmd
        diagram_filename = f"{agent_name.lower()}-diagram.mmd"
        diagram_path = os.path.join(agent_folder, diagram_filename)
        
        if not os.path.exists(diagram_path):
            return jsonify({
                'success': False,
                'error': f'No diagram file found at {diagram_path}'
            }), 404
        
        # Read the diagram content
        with open(diagram_path, 'r', encoding='utf-8') as f:
            content = f.read()
        
        return jsonify({
            'success': True,
            'agent': agent_name,
            'path': diagram_path,
            'filename': diagram_filename,
            'content': content
        })
        
    except Exception as e:
        error_message = f"Error loading diagram for agent '{agent_name}': {str(e)}"
        print(f"⚠️ {error_message}", file=sys.stderr)
        return jsonify({'error': error_message}), 500

@app.route('/api/agents/<agent_name>/entry-component/<component_type>', methods=['PUT'])
def save_workflow_agent_component(agent_name, component_type):
    """Save YAML content for a specific workflow agent component by writing to the path defined in the catalog."""
    try:
        if not agent_manager:
            return jsonify({'error': 'Agent manager not available'}), 500
        
        if agent_name not in agent_manager.workflow_agents:
            return jsonify({'error': f'Agent "{agent_name}" is not a known workflow agent'}), 404
        
        entry_agent = agent_manager.workflow_agents[agent_name]
        
        valid_component_types = ['workflow', 'planner', 'router', 'summarizer']
        if component_type not in valid_component_types:
            return jsonify({'error': f'Invalid component type: {component_type}'}), 400
        
        data = request.get_json(force=True, silent=True) or {}
        new_content = data.get('content')
        if new_content is None:
            return jsonify({'error': 'Missing content field'}), 400
        
        # Optional YAML validation before writing
        if data.get('validate', True):
            try:
                schema_checked = False
                if config_manager:
                    try:
                        t_files = config_manager.get_template_files()
                    except Exception:
                        t_files = None

                    if component_type == 'workflow':
                        schema_rel = t_files.get('WorkflowDefinitionSchema') if t_files else None
                    else:
                        schema_rel = t_files.get('AgentDefinitionSchema') if t_files else None

                    if schema_rel:
                        candidate = Path(__file__).parent / schema_rel
                        if candidate.exists():
                            vres = validate_yaml(str(candidate), new_content)
                            schema_checked = True
                            if not vres.valid:
                                summarized = '; '.join(f"{e.path}: {e.message}" for e in vres.errors[:6])
                                if len(vres.errors) > 6:
                                    summarized += ' ...'
                                return jsonify({'error': f'Component schema validation failed: {summarized}'}), 400

                if not schema_checked:
                    yaml.safe_load(new_content)
            except yaml.YAMLError as ve:
                return jsonify({'error': f'YAML validation failed: {ve}'}), 400
            except Exception:
                try:
                    yaml.safe_load(new_content)
                except Exception:
                    pass

        # Determine the component's file path strictly from the catalog
        rel_path = None
        if component_type == 'workflow':
            rel_path = entry_agent.agent_config
        else:
            for component in entry_agent.components:
                if component.get('type') == component_type:
                    rel_path = component.get('agent_config')
                    break
        
        if not rel_path:
            return jsonify({'error': f'Component type "{component_type}" has no path defined in the catalog for agent "{agent_name}". Cannot save.'}), 404

        # Resolve the absolute path relative to the catalog file
        catalog_dir = os.path.dirname(os.path.abspath(agent_manager.catalog_path))
        component_file = os.path.normpath(os.path.join(catalog_dir, rel_path))
        
        # Ensure parent directory exists before writing
        parent_dir = os.path.dirname(component_file)
        os.makedirs(parent_dir, exist_ok=True)
        
        # Write file safely (atomic replace)
        tmp_path = component_file + '.tmp'
        with open(tmp_path, 'w', encoding='utf-8') as f:
            f.write(new_content)
        os.replace(tmp_path, component_file)
        
        return jsonify({
            'success': True,
            'agent': agent_name,
            'component_type': component_type,
            'path': component_file,
            'message': f'{component_type} component saved successfully to catalog path.'
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500


@app.route('/api/agents/convert/yaml-to-json', methods=['POST'])
def convert_yaml_to_json():
    """Convert provided YAML content to JSON and return it.

    Expects JSON body: { "yaml": "...", "filename": "optional-filename" }
    Returns: { success: True, "json": "...", "filename": "..." }
    This helper is useful for client-side download of JSON equivalent of YAML.
    """
    try:
        data = request.get_json(force=True, silent=True) or {}
        yaml_content = data.get('yaml')
        filename = data.get('filename') or 'document.json'
        if yaml_content is None:
            return jsonify({'error': 'Missing yaml field'}), 400

        try:
            parsed = yaml.safe_load(yaml_content)
        except Exception as ye:
            return jsonify({'error': f'YAML parse error: {str(ye)}'}), 400

        try:
            json_text = json.dumps(parsed, indent=2, ensure_ascii=False)
        except Exception as je:
            return jsonify({'error': f'JSON serialization error: {str(je)}'}), 500

        # Return JSON string and suggested filename
        return jsonify({'success': True, 'json': json_text, 'filename': filename})

    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/agents/<agent_name>/start-container', methods=['POST'])
def start_agent_container_endpoint(agent_name):
    """Start container for a specific agent without switching to it"""
    try:
        if not agent_manager:
            return jsonify({'error': 'Agent manager not available'}), 500
        
        if not docker_client:
            return jsonify({'error': 'Docker client not available'}), 500
        
        # Validate agent exists and files are accessible
        validation = agent_manager.validate_agent_files(agent_name)
        # For container startup, dockerfile IS required
        missing_files = [k for k, v in validation.items() if k != 'type' and not v]
        
        if missing_files:
            # If only dockerfile is missing, provide a helpful error message
            if missing_files == ['dockerfile']:
                return jsonify({
                    'error': f'Cannot start container for {agent_name}: no Dockerfile available. Please add a Dockerfile to enable container features.'
                }), 400
            else:
                return jsonify({
                    'error': f'Cannot start container for {agent_name}: missing files {missing_files}'
                }), 400
        
        # Get agent paths
        paths = agent_manager.get_agent_paths(agent_name)
        info = agent_manager.get_agent_info(agent_name)
        
        # Get or ensure the container (optimized approach)
        container_result = get_or_ensure_agent_container(agent_name, paths)
        if not container_result['success']:
            return jsonify({
                'error': f'Failed to start container for {agent_name}: {container_result["error"]}'
            }), 500
        
        container_info = container_result['container_info']
        action = 'reused existing' if container_info.get('reused') else ('restarted' if container_info.get('restarted') else 'started new')
        
        return jsonify({
            'success': True,
            'message': f'Container {action} for agent: {info.display_name}',
            'agent': {
                'name': agent_name,
                'display_name': info.display_name,
                'description': info.description
            },
            'container': container_result['container_info']
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/agents/catalog/reload', methods=['POST'])
def reload_agent_catalog():
    """Reload the agent catalog from disk"""
    try:
        if not agent_manager:
            return jsonify({'error': 'Agent manager not available'}), 500
        
        agent_manager.reload_catalog()
        agents = agent_manager.list_agents()
        
        return jsonify({
            'success': True,
            'message': 'Agent catalog reloaded successfully',
            'agents_count': len(agents),
            'agents': agents
        })
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

@app.route('/api/agents/catalog/delete/<agent_name>', methods=['DELETE'])
def delete_agent_from_catalog(agent_name):
    """Delete an agent (regular or entry) from the catalog. If an workflow agent, also delete its directory."""
    try:
        if not agent_manager:
            return jsonify({'error': 'Agent manager not available'}), 500

        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')

        # Load current catalog
        import yaml, shutil
        with open(catalog_path, 'r', encoding='utf-8') as f:
            catalog_data = yaml.safe_load(f)

        # Track what was deleted for response
        deleted_type = None
        deleted_entry = None
        deleted_agent_config_path = None  # capture path to derive directory for workflow agent deletion
        deleted_kb_config_path = None  # capture path for KB agent file deletion
        deleted_tool_config_path = None  # capture path for tool agent directory deletion
        
        # Check and remove from tool agents
        if 'agents' in catalog_data:
            original_count = len(catalog_data['agents'])
            # Find tool agent by deriving name from agent_config path
            catalog_data['agents'] = [
                agent for agent in catalog_data['agents']
                if not _is_agent_match(agent.get('agent_config', ''), agent_name)
            ]
            if len(catalog_data['agents']) < original_count:
                deleted_type = 'regular'
                deleted_entry = f"Tool agent '{agent_name}'"
        
        # Check and remove from tool agents (new structure)
        if 'tool_agents' in catalog_data and deleted_type is None:
            tool_to_remove = None
            deleted_tool_config_path = None
            for i, tool_agent in enumerate(catalog_data['tool_agents']):
                if not isinstance(tool_agent, dict):
                    continue
                tool_name = tool_agent.get('name')
                if tool_name == agent_name:
                    tool_to_remove = i
                    deleted_entry = f"Tool agent '{agent_name}'"
                    deleted_tool_config_path = tool_agent.get('agent_config', '')
                    break
            if tool_to_remove is not None:
                catalog_data['tool_agents'].pop(tool_to_remove)
                deleted_type = 'tool'
        
    # Check and remove from workflow agents (catalog no longer guaranteed to have 'name')
    # We derive a key from agent_config when legacy name absent, mirroring StaticAgentManager.
        if 'workflow_agents' in catalog_data and deleted_type is None:
            entry_to_remove = None
            for i, entry_agent in enumerate(catalog_data['workflow_agents']):
                if not isinstance(entry_agent, dict):
                    continue
                legacy_name = entry_agent.get('name')
                agent_config_path = entry_agent.get('agent_config', '')
                derived_key = None
                if agent_config_path:
                    parts = agent_config_path.replace('\\', '/').split('/')
                    for part in parts:
                        if part and part not in ('..', '.') and not part.startswith('i-') and not part.startswith('ii-') and not part.endswith('.yaml'):
                            derived_key = part
                            break
                if legacy_name == agent_name or derived_key == agent_name:
                    entry_to_remove = i
                    deleted_entry = f"Entry agent '{agent_name}'"
                    deleted_agent_config_path = agent_config_path
                    break
            if entry_to_remove is not None:
                catalog_data['workflow_agents'].pop(entry_to_remove)
                deleted_type = 'entry'
        
        # Check and remove from KB agents
        if 'kb_agents' in catalog_data and deleted_type is None:
            kb_to_remove = None
            deleted_kb_config_path = None
            for i, kb_agent in enumerate(catalog_data['kb_agents']):
                if not isinstance(kb_agent, dict):
                    continue
                kb_name = kb_agent.get('name')
                if kb_name == agent_name:
                    kb_to_remove = i
                    deleted_entry = f"KB agent '{agent_name}'"
                    deleted_kb_config_path = kb_agent.get('agent_config', '')
                    break
            if kb_to_remove is not None:
                catalog_data['kb_agents'].pop(kb_to_remove)
                deleted_type = 'kb'
        
        # Check if anything was deleted
        if deleted_type is None:
            return jsonify({
                'success': False,
                'error': f'Agent "{agent_name}" not found in catalog'
            }), 404
        
        # Save updated catalog
        with open(catalog_path, 'w', encoding='utf-8') as f:
            yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False, indent=2)

        print(f"✅ Removed {deleted_entry} from catalog")

        files_deleted = False
        file_delete_error = None
        if deleted_type == 'entry' and deleted_agent_config_path:
            try:
                catalog_dir = os.path.dirname(__file__)
                abs_agent_config_file = os.path.normpath(os.path.join(catalog_dir, deleted_agent_config_path))
                entry_dir = os.path.dirname(abs_agent_config_file)
                # Use configured workflow agents directory for allowed root
                workflow_agents_dir = get_workflow_agents_dir()
                allowed_root = os.path.normpath(os.path.join(catalog_dir, workflow_agents_dir))
                if os.path.commonpath([entry_dir, allowed_root]) == allowed_root and os.path.isdir(entry_dir):
                    shutil.rmtree(entry_dir)
                    files_deleted = True
                    print(f"🧹 Deleted workflow agent directory: {entry_dir}")
                else:
                    print(f"⚠️ Skipping directory deletion (outside allowed root or missing): {entry_dir}")
            except Exception as del_err:
                file_delete_error = str(del_err)
                print(f"⚠️ Failed to delete workflow agent directory: {del_err}")
        
        # Handle KB agent file deletion
        if deleted_type == 'kb' and deleted_kb_config_path:
            try:
                catalog_dir = os.path.dirname(__file__)
                abs_kb_config_file = os.path.normpath(os.path.join(catalog_dir, deleted_kb_config_path))
                # Use configured KB agent directory for allowed root
                kb_output_dir = get_kb_agent_output_dir()
                allowed_root = os.path.normpath(os.path.join(catalog_dir, kb_output_dir))
                    
                if os.path.commonpath([abs_kb_config_file, allowed_root]) == allowed_root and os.path.isfile(abs_kb_config_file):
                    os.remove(abs_kb_config_file)
                    files_deleted = True
                    print(f"🧹 Deleted KB agent file: {abs_kb_config_file}")
                else:
                    print(f"⚠️ Skipping KB agent file deletion (outside allowed root or missing): {abs_kb_config_file}")
            except Exception as del_err:
                file_delete_error = str(del_err)
                print(f"⚠️ Failed to delete KB agent file: {del_err}")
        
        # Handle Tool agent file deletion (delete only definition files, not entire directory)
        if deleted_type == 'tool' and deleted_tool_config_path:
            try:
                catalog_dir = os.path.dirname(__file__)
                abs_tool_config_file = os.path.normpath(os.path.join(catalog_dir, deleted_tool_config_path))
                tool_dir = os.path.dirname(abs_tool_config_file)
                
                # Use configured tool agents directory for allowed root
                tool_agents_dir = get_discovery_tool_output_dir()
                allowed_root = os.path.normpath(os.path.join(catalog_dir, tool_agents_dir))
                
                if os.path.commonpath([tool_dir, allowed_root]) == allowed_root and os.path.isdir(tool_dir):
                    # Find and delete only the agent and tool definition files
                    files_to_delete = []
                    
                    # Look for the agent config file
                    if os.path.isfile(abs_tool_config_file):
                        files_to_delete.append(abs_tool_config_file)
                    
                    # Look for corresponding tool definition file
                    # Pattern: if agent_config is "Simple-agent-definition.yaml", tool is "Simple-tool-definition.yaml"
                    agent_basename = os.path.basename(abs_tool_config_file)
                    if '-agent-definition.yaml' in agent_basename:
                        tool_basename = agent_basename.replace('-agent-definition.yaml', '-tool-definition.yaml')
                        tool_file_path = os.path.join(tool_dir, tool_basename)
                        if os.path.isfile(tool_file_path):
                            files_to_delete.append(tool_file_path)
                    
                    # Delete the identified files
                    deleted_count = 0
                    for file_path in files_to_delete:
                        try:
                            os.remove(file_path)
                            deleted_count += 1
                            print(f"🧹 Deleted: {file_path}")
                        except Exception as e:
                            print(f"⚠️ Could not delete {file_path}: {e}")
                    
                    if deleted_count > 0:
                        files_deleted = True
                        print(f"🧹 Deleted {deleted_count} tool agent definition file(s)")
                    else:
                        print(f"⚠️ No tool agent definition files found to delete")
                else:
                    print(f"⚠️ Skipping tool agent file deletion (outside allowed root or missing): {tool_dir}")
            except Exception as del_err:
                file_delete_error = str(del_err)
                print(f"⚠️ Failed to delete tool agent files: {del_err}")
        
        # Reload the agent manager to pick up the changes
        agent_manager.reload_catalog()
        
        return jsonify({
            'success': True,
            'message': f'{deleted_entry} deleted successfully from catalog',
            'deleted_type': deleted_type,
            'agent_name': agent_name,
            'files_deleted': files_deleted,
            'file_delete_error': file_delete_error
        })

    except Exception as e:
        print(f"⚠️ Error deleting agent from catalog: {e}")
        return jsonify({'error': str(e)}), 500

def _is_agent_match(agent_config_path, agent_name):
    """Helper function to check if an agent_config path matches the given agent name"""
    if not agent_config_path:
        return False
    
    # Extract agent name from path patterns like:
    # ../../MolToolkit/2-Agent/a-core/i-moltoolkitAgent.yaml -> MolToolkit
    # ../../Quantum/2-Agent/a-core/i-QuantumAgent.yaml -> Quantum
    path_parts = agent_config_path.replace('\\', '/').split('/')
    
    # Look for the directory name pattern (e.g., "MolToolkit", "Quantum")
    for part in path_parts:
        if part and not part.startswith('.') and not part.startswith('i-') and part != '2-Agent' and part != 'a-core':
            # This is likely the agent directory name
            if part.lower() == agent_name.lower():
                return True
            break
    
    return False

@app.route('/api/workflow-agents/rename', methods=['POST'])
def rename_workflow_agent():
    """Rename an Workflow Agent and all its associated components"""
    try:
        data = request.get_json()
        old_name = data.get('old_name')
        new_name = data.get('new_name')
        
        if not old_name or not new_name:
            return jsonify({'error': 'Both old_name and new_name are required'}), 400
            
        if old_name == new_name:
            return jsonify({'error': 'New name must be different from old name'}), 400
            
        # Validate new name (no special characters, spaces, etc.)
        if not re.match(r'^[a-zA-Z0-9_-]+$', new_name):
            return jsonify({'error': 'New name can only contain letters, numbers, underscores, and hyphens'}), 400
            
        print(f"🔄 Renaming Workflow Agent '{old_name}' to '{new_name}'")
        
        # Load catalog
        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        if not os.path.exists(catalog_path):
            return jsonify({'error': 'Agents catalog not found'}), 404
            
        with open(catalog_path, 'r', encoding='utf-8') as f:
            catalog_data = yaml.safe_load(f)
            
        if not catalog_data or 'workflow_agents' not in catalog_data:
            return jsonify({'error': 'No workflow agents found in catalog'}), 404
            
        # Find the workflow agent to rename
        target_entry = None
        entry_index = None
        for i, entry_agent in enumerate(catalog_data['workflow_agents']):
            if entry_agent.get('name') == old_name:
                target_entry = entry_agent
                entry_index = i
                break
                
        if target_entry is None:
            return jsonify({'error': f'Entry agent "{old_name}" not found'}), 404
            
        # Check if new name already exists
        for entry_agent in catalog_data['workflow_agents']:
            if entry_agent.get('name') == new_name:
                return jsonify({'error': f'Entry agent with name "{new_name}" already exists'}), 409
                
        # Get paths to current files
        workflow_agents_dir = get_workflow_agents_dir()
        old_dir = os.path.join(os.path.dirname(__file__), workflow_agents_dir, old_name)
        new_dir = os.path.join(os.path.dirname(__file__), workflow_agents_dir, new_name)
        
        if not os.path.exists(old_dir):
            return jsonify({'error': f'Entry agent directory not found: {old_dir}'}), 404
            
        if os.path.exists(new_dir):
            return jsonify({'error': f'Target directory already exists: {new_dir}'}), 409
            
        # Step 1: Rename the directory
        print(f"📁 Renaming directory {old_dir} -> {new_dir}")
        os.rename(old_dir, new_dir)
        
        # Step 2: Rename files and update their content
        print(f"📝 Renaming files and updating YAML content")
        yaml_files = []
        component_types = ['wfl', 'pln', 'rtr', 'sum']
        
        # Process each component file
        for comp_type in component_types:
            old_file = os.path.join(new_dir, f"{old_name.lower()}-{comp_type}.yaml")
            new_file = os.path.join(new_dir, f"{new_name.lower()}-{comp_type}.yaml")
            
            if os.path.exists(old_file):
                print(f"✏️ Renaming {old_file} -> {new_file}")
                
                # First update the YAML content
                rewrite_yaml_agent_names(old_file, old_name, new_name)
                
                # Then rename the file
                os.rename(old_file, new_file)
                yaml_files.append(new_file)
                
        # Also process any additional files in the directory (like .mmd files)
        for filename in os.listdir(new_dir):
            if filename.endswith('.yaml') and not any(filename.startswith(f"{new_name.lower()}-{ct}") for ct in component_types):
                # Handle any other YAML files that might exist
                file_path = os.path.join(new_dir, filename)
                print(f"🔄 Updating additional YAML file: {filename}")
                rewrite_yaml_agent_names(file_path, old_name, new_name)
            elif filename.lower().startswith(old_name.lower() + '-') and (filename.lower().endswith('.yaml') or filename.lower().endswith('.mmd')):
                # Rename files that follow the pattern
                old_file_path = os.path.join(new_dir, filename)
                suffix = filename[len(old_name):]  # includes the '-' and extension
                new_filename = new_name.lower() + suffix
                new_file_path = os.path.join(new_dir, new_filename)
                try:
                    os.rename(old_file_path, new_file_path)
                    print(f"  → Renamed additional file: {filename} -> {new_filename}")
                except Exception as rename_err:
                    print(f"⚠️ Failed to rename {filename} to {new_filename}: {rename_err}")
                
        # Step 3: Update catalog entries
        print(f"📋 Updating catalog entries")
        catalog_data['workflow_agents'][entry_index]['name'] = new_name
        
        # Update main agent_config path
        old_path = catalog_data['workflow_agents'][entry_index]['agent_config']
        workflow_agents_dir_config = get_workflow_agents_dir()
        # Remove leading ./ or ../../ prefix if present to get just the relative directory name
        entry_dir_name = workflow_agents_dir_config.strip('./').rstrip('/')
        new_path = old_path.replace(f'{entry_dir_name}/{old_name}/', f'{entry_dir_name}/{new_name}/')
        new_path = new_path.replace(f'{old_name.lower()}-', f'{new_name.lower()}-')
        catalog_data['workflow_agents'][entry_index]['agent_config'] = new_path
        
        # Update component paths
        if 'components' in catalog_data['workflow_agents'][entry_index]:
            for component in catalog_data['workflow_agents'][entry_index]['components']:
                # Update component name
                old_comp_name = component['name']
                if old_comp_name.startswith(old_name.lower()):
                    component['name'] = old_comp_name.replace(old_name.lower(), new_name.lower(), 1)
                    
                # Update component agent_config path
                old_comp_path = component['agent_config']
                workflow_agents_dir_config = get_workflow_agents_dir()
                # Remove leading ./ or ../../ prefix if present to get just the relative directory name
                entry_dir_name = workflow_agents_dir_config.strip('./').rstrip('/')
                new_comp_path = old_comp_path.replace(f'{entry_dir_name}/{old_name}/', f'{entry_dir_name}/{new_name}/')
                new_comp_path = new_comp_path.replace(f'{old_name.lower()}-', f'{new_name.lower()}-')
                component['agent_config'] = new_comp_path
                
        # Save updated catalog
        with open(catalog_path, 'w', encoding='utf-8') as f:
            yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False, indent=2)
            
        print(f"✅ Successfully renamed workflow agent '{old_name}' to '{new_name}'")
        
        # Reload the agent manager to pick up the changes
        if agent_manager:
            agent_manager.reload_catalog()

        # If the renamed agent was the current agent in this session, update the session
        sm = get_session_manager()
        session_current_agent = get_current_agent_name()
        if session_current_agent == old_name and sm and sm.current_session_id:
            print(f"🔄 Updating session agent from '{old_name}' to '{new_name}'")
            sm.update_session(sm.current_session_id, agent_name=new_name)
        
        return jsonify({
            'success': True,
            'message': f'Entry agent renamed from "{old_name}" to "{new_name}"',
            'old_name': old_name,
            'new_name': new_name,
            'updated_files': yaml_files
        })
        
    except Exception as e:
        print(f"⚠️ Error renaming workflow agent: {e}")
        # If we partially renamed, we should try to rollback
        # For now, just return the error
        return jsonify({'error': str(e)}), 500

@app.route('/api/tool-agents/rename', methods=['POST'])
def rename_tool_agent():
    """Rename a Tool Agent and all its associated components"""
    try:
        data = request.get_json()
        old_name = data.get('old_name')
        new_name = data.get('new_name')
        
        if not old_name or not new_name:
            return jsonify({'error': 'Both old_name and new_name are required'}), 400
            
        if old_name == new_name:
            return jsonify({'error': 'New name must be different from old name'}), 400
            
        # Validate new name (no special characters, spaces, etc.)
        if not re.match(r'^[a-zA-Z0-9_-]+$', new_name):
            return jsonify({'error': 'New name can only contain letters, numbers, underscores, and hyphens'}), 400
            
        print(f"🔄 Renaming Tool Agent '{old_name}' to '{new_name}'")
        
        # Load catalog
        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        if not os.path.exists(catalog_path):
            return jsonify({'error': 'Agents catalog not found'}), 404
            
        with open(catalog_path, 'r', encoding='utf-8') as f:
            catalog_data = yaml.safe_load(f)
            
        if not catalog_data or 'tool_agents' not in catalog_data:
            return jsonify({'error': 'No tool agents found in catalog'}), 404
            
        # Find the tool agent to rename
        target_agent = None
        agent_index = None
        for i, tool_agent in enumerate(catalog_data['tool_agents']):
            if tool_agent.get('name') == old_name:
                target_agent = tool_agent
                agent_index = i
                break
                
        if target_agent is None:
            return jsonify({'error': f'Tool agent "{old_name}" not found'}), 404
            
        # Check if new name already exists within tool agents
        for tool_agent in catalog_data['tool_agents']:
            if tool_agent.get('name') == new_name:
                return jsonify({'error': f'Tool agent with name "{new_name}" already exists'}), 409
        
        # Get the base directory path from the agent config
        agent_config_path = target_agent.get('agent_config', '')
        if not agent_config_path:
            return jsonify({'error': 'Agent config path not found'}), 404
            
        # Extract the directory path
        # Example paths: ../../Agents/ToolAgents/corePython/corePythonAgent.yaml
        #                ../../Agents/KBAgents/SomeKB/SomeKB-Agent.yaml
        config_dir = os.path.dirname(agent_config_path)
        full_config_dir = os.path.normpath(os.path.join(os.path.dirname(__file__), config_dir))
        
        if not os.path.exists(full_config_dir):
            return jsonify({'error': f'Agent directory not found: {full_config_dir}'}), 404
        
        # Determine directory path - no renaming needed, just for reference
        dir_parts = config_dir.split('/')
        
        # Step 1: Update YAML files in the existing directory (no directory rename)
        files_to_update = []
        updated_paths = {}
        
        try:
            # Step 2: Update YAML files that contain the agent name
            for root, dirs, files in os.walk(full_config_dir):
                for file in files:
                    file_path = os.path.join(root, file)
                    
                    # For YAML files, update internal name references
                    if file_path.endswith('.yaml') or file_path.endswith('.yml'):
                        try:
                            # Use ruamel.yaml to preserve formatting
                            yaml_processor = YAML()
                            yaml_processor.preserve_quotes = True
                            yaml_processor.map_indent = 2
                            yaml_processor.sequence_indent = 4
                            
                            with open(file_path, 'r', encoding='utf-8') as f:
                                yaml_content = yaml_processor.load(f)
                            
                            updated = False
                            
                            # Check for agent.name field (Agent YAML files)
                            if isinstance(yaml_content, dict) and 'agent' in yaml_content:
                                if isinstance(yaml_content['agent'], dict) and 'name' in yaml_content['agent']:
                                    if yaml_content['agent']['name'] == old_name:
                                        yaml_content['agent']['name'] = new_name
                                        updated = True
                                        print(f"📝 Updated agent.name: {old_name} → {new_name} in {file_path}")
                            
                            # Check for top-level name field (Tools definition files)
                            if isinstance(yaml_content, dict) and 'name' in yaml_content:
                                # Convert old name to expected tool name format (lowercase)
                                old_tool_name = old_name.lower()
                                new_tool_name = new_name.lower()
                                if yaml_content['name'] == old_tool_name:
                                    yaml_content['name'] = new_tool_name
                                    updated = True
                                    print(f"📝 Updated tool name: {old_tool_name} → {new_tool_name} in {file_path}")

                            # Check and update ACR image references if present anywhere in the YAML
                            def _replace_acr_images(node):
                                nonlocal updated
                                # Recursively walk dicts and lists
                                if isinstance(node, dict):
                                    for k, v in node.items():
                                        if k == 'acr' and isinstance(v, str):
                                            try:
                                                orig = v
                                                # Preserve everything around the image name: registry host and tag
                                                # e.g. myregistry.azurecr.io/hlgap:latest -> myregistry.azurecr.io/<new>:latest
                                                last_slash = v.rfind('/')
                                                if last_slash != -1:
                                                    host = v[:last_slash+1]
                                                    rest = v[last_slash+1:]
                                                    colon_idx = rest.find(':')
                                                    image = rest if colon_idx == -1 else rest[:colon_idx]
                                                    tag = '' if colon_idx == -1 else rest[colon_idx:]
                                                    # Use lowercase comparison for name segments
                                                    if old_tool_name in image:
                                                        new_image = image.replace(old_tool_name, new_tool_name)
                                                        new_acr = host + new_image + tag
                                                        node[k] = new_acr
                                                        updated = True
                                                        print(f"📝 Updated acr in {file_path}: {orig} → {new_acr}")
                                            except Exception as e:
                                                print(f"⚠️ Could not process acr field in {file_path}: {e}")
                                        else:
                                            _replace_acr_images(v)
                                elif isinstance(node, list):
                                    for item in node:
                                        _replace_acr_images(item)

                            try:
                                _replace_acr_images(yaml_content)
                            except Exception as e:
                                print(f"⚠️ Error traversing YAML for acr updates in {file_path}: {e}")
                            
                            if updated:
                                with open(file_path, 'w', encoding='utf-8') as f:
                                    yaml_processor.dump(yaml_content, f)
                                files_to_update.append({
                                    'path': file_path,
                                    'action': 'updated_yaml_name'
                                })
                                
                        except Exception as e:
                            print(f"⚠️ Warning: Could not update YAML file {file_path}: {e}")
            
            # Step 2.5: Rename files to follow consistent naming pattern
            print(f"🔄 Renaming files to follow pattern: {new_name}-Agent.yaml and {new_name}-Tool.yaml")
            
            # Track old and new file paths for catalog update
            old_agent_file = None
            old_tool_file = None
            new_agent_file = None
            new_tool_file = None
            
            # Find existing agent and tool files
            for file in os.listdir(full_config_dir):
                file_path = os.path.join(full_config_dir, file)
                if file.endswith('.yaml') or file.endswith('.yml'):
                    # Check if this is an agent file (contains agent.name)
                    try:
                        with open(file_path, 'r', encoding='utf-8') as f:
                            content = yaml.safe_load(f)
                        if isinstance(content, dict):
                            if 'agent' in content and isinstance(content['agent'], dict) and content['agent'].get('name') == new_name:
                                old_agent_file = file_path
                                new_agent_file = os.path.join(full_config_dir, f"{new_name}-Agent.yaml")
                            elif 'name' in content and content.get('name') == new_name.lower():
                                old_tool_file = file_path
                                new_tool_file = os.path.join(full_config_dir, f"{new_name}-Tool.yaml")
                    except Exception as e:
                        print(f"⚠️ Warning: Could not analyze file {file_path}: {e}")
            
            # Rename agent file if found and needed
            if old_agent_file and new_agent_file and old_agent_file != new_agent_file:
                try:
                    os.rename(old_agent_file, new_agent_file)
                    print(f"📁 Renamed agent file: {os.path.basename(old_agent_file)} → {os.path.basename(new_agent_file)}")
                    files_to_update.append({
                        'path': new_agent_file,
                        'action': 'renamed_agent_file',
                        'old_path': old_agent_file
                    })
                except Exception as e:
                    print(f"⚠️ Warning: Could not rename agent file {old_agent_file}: {e}")
            
            # Rename tool file if found and needed
            if old_tool_file and new_tool_file and old_tool_file != new_tool_file:
                try:
                    os.rename(old_tool_file, new_tool_file)
                    print(f"📁 Renamed tool file: {os.path.basename(old_tool_file)} → {os.path.basename(new_tool_file)}")
                    files_to_update.append({
                        'path': new_tool_file,
                        'action': 'renamed_tool_file',
                        'old_path': old_tool_file
                    })
                except Exception as e:
                    print(f"⚠️ Warning: Could not rename tool file {old_tool_file}: {e}")
            
            # Step 3: Update the catalog entry name and file paths
            catalog_data['tool_agents'][agent_index]['name'] = new_name
            
            # Update file paths in catalog to reflect renamed files
            if new_agent_file and old_agent_file != new_agent_file:
                # Update agent_config path
                relative_agent_path = os.path.relpath(new_agent_file, os.path.dirname(__file__)).replace('\\', '/')
                catalog_data['tool_agents'][agent_index]['agent_config'] = relative_agent_path
                print(f"📝 Updated catalog agent_config path: {relative_agent_path}")
                
            if new_tool_file and old_tool_file != new_tool_file:
                # Update tools_definition path
                relative_tool_path = os.path.relpath(new_tool_file, os.path.dirname(__file__)).replace('\\', '/')
                catalog_data['tool_agents'][agent_index]['tools_definition'] = relative_tool_path
                print(f"📝 Updated catalog tools_definition path: {relative_tool_path}")
            
            # Step 4: Save the updated catalog
            with open(catalog_path, 'w', encoding='utf-8') as f:
                yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False)
            
            print(f"✅ Successfully renamed tool agent '{old_name}' to '{new_name}'")
            
            # Reload the agent manager if available
            if agent_manager:
                try:
                    agent_manager.reload_catalog()
                    print("✅ Agent manager catalog reloaded")
                except Exception as e:
                    print(f"⚠️ Warning: Could not reload agent manager catalog: {e}")

            # If the renamed agent was the current agent in this session, update the session
            sm = get_session_manager()
            session_current_agent = get_current_agent_name()
            was_current_agent = (session_current_agent == old_name)
            if was_current_agent and sm and sm.current_session_id:
                print(f"🔄 Renamed agent was current in session, updating to '{new_name}'")
                # Get current agent type from session
                session = sm.get_session(sm.current_session_id)
                session_agent_type = session.agent_type if session else 'tool'
                sm.update_session(sm.current_session_id, agent_name=new_name)

                # Force reload of agent configuration and tools for the renamed agent
                try:
                    global system_prompt
                    system_prompt = load_agent_config(new_name, session_agent_type)
                    print(f"✅ Reloaded complete agent configuration for '{new_name}'")
                except Exception as reload_error:
                    print(f"⚠️ Warning: Could not reload agent configuration for '{new_name}': {reload_error}")
            
            return jsonify({
                'success': True,
                'message': f'Tool agent renamed from "{old_name}" to "{new_name}"',
                'old_name': old_name,
                'new_name': new_name,
                'updated_files': files_to_update
            })
            
        except Exception as e:
            print(f"⚠️ Error during file operations: {e}")
            raise e
            
    except Exception as e:
        print(f"⚠️ Error renaming tool agent: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/kb-agents/rename', methods=['POST'])
def rename_kb_agent():
    """Rename a Knowledge Base Agent and all its associated components"""
    try:
        data = request.get_json()
        old_name = data.get('old_name')
        new_name = data.get('new_name')
        
        if not old_name or not new_name:
            return jsonify({'error': 'Both old_name and new_name are required'}), 400
            
        if old_name == new_name:
            return jsonify({'error': 'New name must be different from old name'}), 400
            
        # Validate new name (no special characters, spaces, etc.)
        if not re.match(r'^[a-zA-Z0-9_-]+$', new_name):
            return jsonify({'error': 'New name can only contain letters, numbers, underscores, and hyphens'}), 400
            
        print(f"🔄 Renaming KB Agent '{old_name}' to '{new_name}'")
        
        # Load catalog
        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        if not os.path.exists(catalog_path):
            return jsonify({'error': 'Agents catalog not found'}), 404
            
        with open(catalog_path, 'r', encoding='utf-8') as f:
            catalog_data = yaml.safe_load(f)
            
        if not catalog_data or 'kb_agents' not in catalog_data:
            return jsonify({'error': 'No KB agents found in catalog'}), 404
            
        # Find the KB agent to rename
        target_agent = None
        agent_index = None
        for i, kb_agent in enumerate(catalog_data['kb_agents']):
            if kb_agent.get('name') == old_name:
                target_agent = kb_agent
                agent_index = i
                break
                
        if target_agent is None:
            return jsonify({'error': f'KB agent "{old_name}" not found'}), 404
            
        # Check if new name already exists in any agent type
        for kb_agent in catalog_data['kb_agents']:
            if kb_agent.get('name') == new_name:
                return jsonify({'error': f'KB agent with name "{new_name}" already exists'}), 409
                
        # Step 1: Update agent YAML file
        agent_config_path = target_agent.get('agent_config')
        if not agent_config_path:
            return jsonify({'error': 'Agent config path not found in catalog'}), 404

        # Resolve agent config path relative to the catalog location when necessary
        catalog_dir = os.path.dirname(catalog_path)
        if os.path.isabs(agent_config_path):
            full_agent_path = agent_config_path
        else:
            # Normalize any ../ segments and join with catalog dir
            full_agent_path = os.path.normpath(os.path.join(catalog_dir, agent_config_path))

        if not os.path.exists(full_agent_path):
            return jsonify({'error': f'Agent config file not found: {full_agent_path}'}), 404

        files_to_update = []

        # Update agent YAML file (only the name field, YAML-only approach)
        print(f"📝 Updating agent config: {full_agent_path}")
        
        # Use ruamel.yaml to preserve formatting, comments, and multiline strings
        from ruamel.yaml import YAML
        yaml_processor = YAML()
        yaml_processor.preserve_quotes = True
        yaml_processor.map_indent = 2
        yaml_processor.sequence_indent = 4
        
        # Read and update agent config
        with open(full_agent_path, 'r', encoding='utf-8') as f:
            agent_yaml = yaml_processor.load(f)
            
        if 'agent' in agent_yaml and 'name' in agent_yaml['agent']:
            old_yaml_name = agent_yaml['agent']['name']
            agent_yaml['agent']['name'] = new_name
            print(f"  📝 Updated agent.name: {old_yaml_name} -> {new_name}")
            
            # Write updated content with preserved formatting
            with open(full_agent_path, 'w', encoding='utf-8') as f:
                yaml_processor.dump(agent_yaml, f)
                
            files_to_update.append(full_agent_path)
            
            # Attempt to rename the agent config file to match the new agent name
            try:
                agent_dir = os.path.dirname(full_agent_path)
                new_agent_filename = f"{new_name}.yaml"
                new_full_agent_path = os.path.join(agent_dir, new_agent_filename)
                # Only rename if the target name differs
                if os.path.abspath(new_full_agent_path) != os.path.abspath(full_agent_path):
                    os.rename(full_agent_path, new_full_agent_path)
                    print(f"📁 Renamed KB agent config file: {os.path.basename(full_agent_path)} -> {os.path.basename(new_full_agent_path)}")
                    files_to_update.append({
                        'path': new_full_agent_path,
                        'action': 'renamed_kb_agent_file',
                        'old_path': full_agent_path
                    })

                    # Update the catalog entry to point to the new relative path
                    try:
                        relative_agent_path = os.path.relpath(new_full_agent_path, catalog_dir).replace('\\', '/')
                        catalog_data['kb_agents'][agent_index]['agent_config'] = relative_agent_path
                        print(f"📝 Updated catalog agent_config path: {relative_agent_path}")
                        # Update full_agent_path reference for any further processing
                        full_agent_path = new_full_agent_path
                    except Exception as e:
                        print(f"⚠️ Warning: Could not update catalog path for renamed KB agent file: {e}")
            except Exception as e:
                print(f"⚠️ Warning: Could not rename KB agent file {full_agent_path}: {e}")
        else:
            print(f"  ⚠️ Warning: No agent.name field found in {full_agent_path}")
            
        # Step 2: Update catalog entry
        print(f"📋 Updating catalog entry")
        catalog_data['kb_agents'][agent_index]['name'] = new_name
        
        # Step 4: Save the updated catalog
        with open(catalog_path, 'w', encoding='utf-8') as f:
            yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False)
        
        print(f"✅ Successfully renamed KB agent '{old_name}' to '{new_name}'")
        
        # Reload the agent manager if available
        if agent_manager:
            try:
                agent_manager.reload_catalog()
                print("✅ Agent manager catalog reloaded")
            except Exception as e:
                print(f"⚠️ Warning: Could not reload agent manager: {e}")
        
        return jsonify({
            'success': True,
            'message': f'KB agent renamed from "{old_name}" to "{new_name}"',
            'old_name': old_name,
            'new_name': new_name,
            'updated_files': files_to_update
        })

    except Exception as e:
        print(f"⚠️ Error renaming KB agent: {e}")
        return jsonify({'error': str(e)}), 500

