# 404 logger to show unmatched requests (helps debug why a route isn't found)
@app.errorhandler(404)
def log_404(err):
    try:
        print(f"⚠️ 404 Not Found - path={request.path} method={request.method} args={request.args}")
    except Exception:
        print('⚠️ 404 Not Found - could not inspect request')
    return err, 404

@app.route('/api/discovery-publish/get-config', methods=['POST'])
def get_discovery_config():
    """Get agent and tool configuration for Discovery publishing"""
    print("🔍 Discovery config endpoint called!")
    try:
        # Check if we can import the required modules
        try:
            from discovery_config import DiscoveryConfigParser, AgentCatalogParser
            from discovery_config_manager import DiscoveryConfigManager
            print("✅ Discovery modules imported successfully")
        except ImportError as import_error:
            print(f"❌ Import error: {import_error}")
            return jsonify({'error': f'Discovery modules not available: {str(import_error)}'}), 500
            
        data = request.get_json()
        print(f"📋 Request data: {data}")
        agent_name = data.get('agent_name')
        
        if not agent_name:
            return jsonify({'error': 'agent_name is required'}), 400
            
        # Initialize configuration parser
        parser = DiscoveryConfigParser()
        catalog_parser = AgentCatalogParser()
        
        # Load agent configuration from catalog (in same directory as web_server.py)
        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        
        if not os.path.exists(catalog_path):
            return jsonify({'error': f'Agents catalog not found at {catalog_path}'}), 404
            
        # Set the catalog path in the parser
        catalog_parser.catalog_path = catalog_path
        
        # Determine catalog section (agent_type) and get agent information
        # agent_manager knows the agent 'type' values: 'regular', 'entry', 'kb'
        # Map those to catalog sections expected by AgentCatalogParser.
        catalog_section = 'tool_agents'
        try:
            if agent_manager:
                paths = agent_manager.get_agent_paths(agent_name)
                atype = paths.get('type', 'regular')
                if atype == 'regular':
                    catalog_section = 'tool_agents'
                elif atype == 'entry':
                    catalog_section = 'workflow_agents'
                elif atype == 'kb':
                    catalog_section = 'kb_agents'
        except Exception:
            # If agent_manager isn't available or lookup fails, default to tool_agents
            catalog_section = 'tool_agents'

        agent_info = catalog_parser.get_agent_info(agent_name, catalog_section)
        
        if not agent_info:
            return jsonify({'error': f'Agent {agent_name} not found in catalog'}), 404
            
        # Extract configurations
        agent_config = agent_info['agent_config']
        
        # Parse tool definition
        tool_config = parser.parse_tool_definition(agent_info['tool_definition_path'])
        
        # Load saved Azure configuration for form pre-population
        config_manager = DiscoveryConfigManager()
        azure_config = config_manager.get_azure_config()
        preferences = config_manager.get_preferences()
        llm_config = config_manager.get_llm_config()
        
        # Resolve {name} placeholder in ACR image before returning to frontend
        tool_config = config_manager.process_tool_definition_acr(tool_config)
        
        # Generate resource names
        agent_config['resource_name'] = parser.generate_agent_resource_name(agent_config['name'])
        tool_config['resource_name'] = parser.generate_tool_resource_name(tool_config['name'])
        
        # Merge resource names into configurations
        agent_config.update({
            'resource_name': agent_config['resource_name']
        })
        tool_config.update({
            'resource_name': tool_config['resource_name']
        })
        
        return jsonify({
            'success': True,
            'agent_config': agent_config,
            'tool_config': tool_config,
            'azure_config': azure_config,
            'preferences': preferences,
            'llm_config': llm_config
        })
        
    except Exception as e:
        print(f"Error in get_discovery_config: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/azure/discovery-agents', methods=['POST'])
def list_azure_discovery_agents():
    """List Azure Discovery agents in a resource group with pagination"""
    try:
        if not DISCOVERY_AVAILABLE:
            return jsonify({'error': 'Discovery modules not available'}), 500
            
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Invalid JSON data in request'}), 400
            
        subscription_id = data.get('subscription_id')
        resource_group = data.get('resource_group')
        tenant_id = data.get('tenant_id')  # Extract tenant_id from request
        load_all = data.get('load_all', False)  # New parameter to load all agents
        
        # Legacy pagination parameters (kept for backward compatibility)
        page = data.get('page', 1)
        page_size = data.get('page_size', 50)
        
        if not all([subscription_id, resource_group]):
            return jsonify({'error': 'subscription_id and resource_group are required'}), 400
            
        # Initialize Azure Discovery client
        azure_client = AzureDiscoveryClient()
        
        print(f"DEBUG: Loading Azure Discovery agents: sub={subscription_id}, rg={resource_group}, tenant={tenant_id}, load_all={load_all}")
        
        # List all Discovery agents (no pattern filter to get all agents)
        result = azure_client.list_discovery_agents(subscription_id, resource_group, "*", tenant_id=tenant_id)
        
        if result.get('exists'):
            all_agents = result.get('all_agents', [])
            
            # Transform agents to the format expected by frontend
            formatted_agents = []
            for agent_info in all_agents:
                formatted_agent = {
                    'name': agent_info.get('name', ''),
                    'display_name': agent_info.get('name', ''),
                    'resource_id': agent_info.get('resource_id', ''),
                    'location': agent_info.get('location', ''),
                    'provisioning_state': agent_info.get('provisioning_state', 'Unknown'),
                    'description': f"Azure Discovery Agent - {agent_info.get('provisioning_state', 'Unknown')}"
                }
                formatted_agents.append(formatted_agent)
            
            if load_all:
                # Return all agents without pagination
                return jsonify({
                    'success': True,
                    'agents': formatted_agents,
                    'has_more': False,
                    'total_count': len(formatted_agents)
                })
            else:
                # Legacy pagination logic (for backward compatibility)
                start_idx = (page - 1) * page_size
                end_idx = start_idx + page_size
                paginated_agents = formatted_agents[start_idx:end_idx]
                has_more = end_idx < len(formatted_agents)
                
                return jsonify({
                    'success': True,
                    'agents': paginated_agents,
                    'has_more': has_more,
                    'total_count': len(formatted_agents),
                    'page': page,
                    'page_size': page_size
                })
        else:
            return jsonify({
                'success': True,
                'agents': [],
                'has_more': False,
                'total_count': 0,
                'message': result.get('message', 'No agents found')
            })
        
    except Exception as e:
        print(f"Error in list_azure_discovery_agents: {e}")
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500


@app.route('/api/discovery-publish/check-tools', methods=['POST'])
def check_discovery_tools():
    """Check for existing Discovery tools and agents with matching patterns"""
    try:
        if not DISCOVERY_AVAILABLE:
            return jsonify({'error': 'Discovery modules not available'}), 500
            
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Invalid JSON data in request'}), 400
            
        subscription_id = data.get('subscription_id')
        resource_group = data.get('resource_group')
        tenant_id = data.get('tenant_id')
        acr_image = data.get('acr_image')
        tool_name = data.get('tool_name')
        agent_name = data.get('agent_name')
        
        # Require subscription_id and resource_group, and at least one of acr_image or tool_name
        if not subscription_id or not resource_group or (not acr_image and not tool_name):
            return jsonify({'error': 'subscription_id and resource_group are required, and at least one of acr_image or tool_name must be provided'}), 400
            
        # Initialize Azure Discovery client
        azure_client = AzureDiscoveryClient()
        
        print(f"DEBUG: About to check for existing tools and agents with params: sub={subscription_id}, rg={resource_group}, tenant={tenant_id}, acr={acr_image}, tool_name={tool_name}, agent_name={agent_name}")


        # Check for existing tools (exact-only matching by tool_name if provided, otherwise by acr_image)
        existing_tool_result = azure_client.list_discovery_tools(subscription_id, resource_group, acr_image, tool_name=tool_name, tenant_id=tenant_id)

        # Determine agent to check. Prefer explicit agent_name from client.
        if agent_name:
            existing_agent_result = azure_client.list_discovery_agents(subscription_id, resource_group, agent_name, tenant_id=tenant_id)
        else:
            # If no agent_name provided, try to derive likely agent names from tool_name or matched tool resource
            existing_agent_result = {'exists': False, 'message': 'No agent found'}
            # derive candidates from provided tool_name first
            candidates = []
            if tool_name:
                candidates.append(tool_name)
                candidates.append(f"{tool_name}Agent")
                candidates.append(f"{tool_name}-agent")
                candidates.append(f"{tool_name}Agent")

            # if tool lookup returned a best_match, use that resource name as candidate
            try:
                best_tool = existing_tool_result.get('best_match') if isinstance(existing_tool_result, dict) else None
                if best_tool and best_tool.get('name'):
                    best_name = best_tool.get('name')
                    if best_name not in candidates:
                        candidates.append(best_name)
                        candidates.append(f"{best_name}Agent")
                        candidates.append(f"{best_name}-agent")
            except Exception:
                pass

            # Try each candidate via exact agent lookup
            for cand in candidates:
                try:
                    res = azure_client.list_discovery_agents(subscription_id, resource_group, cand, tenant_id=tenant_id)
                    if res.get('exists'):
                        existing_agent_result = res
                        break
                except Exception:
                    continue

        # Indicate which criteria were used for the tool lookup so the UI can render clearer messages
        search_criteria = 'tool_name' if tool_name else 'acr_image'

        # Debug: log the raw discovery results so we can trace unexpected matches
        try:
            print(f"DEBUG: existing_tool_result: {json.dumps(existing_tool_result)[:400]}")
        except Exception:
            print(f"DEBUG: existing_tool_result (repr): {repr(existing_tool_result)}")
        try:
            print(f"DEBUG: existing_agent_result: {json.dumps(existing_agent_result)[:400]}")
        except Exception:
            print(f"DEBUG: existing_agent_result (repr): {repr(existing_agent_result)}")

        return jsonify({
            'success': True,
            'search_criteria': search_criteria,
            'existing_tool': existing_tool_result,
            'existing_agent': existing_agent_result
        })
        
    except Exception as e:
        print(f"Error in check_discovery_tools: {e}")
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500

@app.route('/api/discovery-publish/delete-resources', methods=['POST'])
def delete_discovery_resources():
    """Delete selected Discovery tools and agents"""
    try:
        if not DISCOVERY_AVAILABLE:
            return jsonify({'error': 'Discovery modules not available'}), 500
            
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Invalid JSON data in request'}), 400
            
        subscription_id = data.get('subscription_id')
        resource_group = data.get('resource_group')
        tenant_id = data.get('tenant_id')
        resources = data.get('resources', [])

        if not all([subscription_id, resource_group]):
            return jsonify({'error': 'subscription_id and resource_group are required'}), 400
            
        if not resources:
            return jsonify({'error': 'No resources specified for deletion'}), 400
            
        # Initialize Azure Discovery client
        azure_client = AzureDiscoveryClient()
        
        deleted_count = 0
        errors = []

        # Sort resources: delete agents first (they depend on tools), then tools
        # This ensures we don't try to delete a tool that's still referenced by an agent
        def resource_sort_key(r):
            rtype = r.get('type', '').lower()
            if rtype == 'agent':
                return 0  # Agents first
            elif rtype == 'tool':
                return 1  # Tools second
            return 2  # Others last

        resources = sorted(resources, key=resource_sort_key)
        print(f"DEBUG: About to delete {len(resources)} resources (sorted: agents first, then tools)")

        for resource in resources:
            resource_type = resource.get('type')
            resource_id = resource.get('resourceId')
            resource_name = resource.get('name')
            
            if not all([resource_type, resource_id, resource_name]):
                errors.append(f"Invalid resource data: {resource}")
                continue
                
            try:
                print(f"DEBUG: Deleting {resource_type}: {resource_name}")

                # Use Azure CLI to delete the resource
                delete_result = azure_client.delete_discovery_resource(resource_id, tenant_id=tenant_id)
                
                if delete_result.get('success', False):
                    deleted_count += 1
                    print(f"DEBUG: Successfully deleted {resource_name}")
                else:
                    error_msg = delete_result.get('error', 'Unknown error')
                    errors.append(f"Failed to delete {resource_name}: {error_msg}")
                    print(f"DEBUG: Failed to delete {resource_name}: {error_msg}")
                    
            except Exception as e:
                error_msg = f"Exception deleting {resource_name}: {str(e)}"
                errors.append(error_msg)
                print(f"DEBUG: {error_msg}")
        
        if errors:
            error_summary = f"Deleted {deleted_count} resources with {len(errors)} errors: " + "; ".join(errors)
            return jsonify({
                'success': deleted_count > 0,
                'deleted_count': deleted_count,
                'error': error_summary,
                'errors': errors
            })
        else:
            return jsonify({
                'success': True,
                'deleted_count': deleted_count,
                'message': f'Successfully deleted {deleted_count} resource(s)'
            })
        
    except Exception as e:
        print(f"Error in delete_discovery_resources: {e}")
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500

@app.route('/api/discovery-publish/stream-rest', methods=['POST'])
def stream_discovery_deployment_rest():
    """Stream Microsoft Discovery deployment progress using REST API"""
    print(f"TRACE: stream_discovery_deployment_rest started")
    try:
        if not DISCOVERY_AVAILABLE:
            print(f"TRACE: Discovery not available")
            return Response('data: {"type": "error", "message": "Discovery modules not available"}\n\n', 
                          mimetype='text/plain')
            
        data = request.get_json()
        print(f"TRACE: request data received: {data}")

        # Get the current agent from session (session-scoped), with fallback to request data
        agent_name = get_current_agent_name()
        if not agent_name:
            # Fallback: use agent_name from request if session doesn't have it
            agent_name = data.get('agent_name')
        # Get local_agent_name for file lookups (folder name may differ from YAML Name field)
        local_agent_name = data.get('local_agent_name') or agent_name
        print(f"TRACE: current agent from session: {agent_name}, local_agent_name: {local_agent_name}")

        subscription_id = data.get('subscription_id')
        resource_group = data.get('resource_group')
        location = data.get('location')
        tenant_id = data.get('tenant_id', '').strip()
        print(f"TRACE: Azure config - sub:{subscription_id}, rg:{resource_group}, loc:{location}, tenant:{tenant_id}")
        
        # Check for selected resources to reuse/update
        selected_resources = data.get('selected_resources_for_reuse', [])
        reuse_mode = len(selected_resources) > 0
        
        if not all([agent_name, subscription_id, resource_group, location]):
            missing_params = []
            if not agent_name: missing_params.append('agent_name (no current agent)')
            if not subscription_id: missing_params.append('subscription_id')
            if not resource_group: missing_params.append('resource_group')
            if not location: missing_params.append('location')
            return Response(f'data: {{"type": "error", "message": "Missing required parameters: {", ".join(missing_params)}. All Azure configuration must be provided by the user."}}\n\n', 
                          mimetype='text/plain')
        
        # Validate that values are not empty strings
        if not subscription_id.strip() or not resource_group.strip() or not location.strip():
            return Response('data: {"type": "error", "message": "Azure configuration values cannot be empty. Please provide valid subscription ID, resource group, and location."}\n\n', 
                          mimetype='text/plain')
        
        def generate_deployment_stream():
            """Generator function for streaming deployment progress using REST API"""
            import json as json_mod
            try:
                # SSE trace for Discovery deployment start
                if SSE_AVAILABLE:
                    try:
                        trace_system(
                            f"🚀 Starting Discovery deployment for {agent_name}",
                            level='info',
                            metadata={'context': 'Discovery Publish', 'agent': agent_name},
                            details=json_mod.dumps({
                                'agent_name': agent_name,
                                'subscription_id': subscription_id[:8] + '...' if subscription_id else None,
                                'resource_group': resource_group,
                                'location': location
                            }, indent=2)
                        )
                    except Exception:
                        pass
                
                # Save Azure configuration for future use
                config_manager = DiscoveryConfigManager()
                config_manager.update_azure_config(
                    subscription_id=subscription_id,
                    resource_group=resource_group,
                    location=location
                )
                
                # Initialize REST API publisher with provided configuration
                print(f"TRACE: initializing DiscoveryRestPublisher with tenant {tenant_id}")
                publisher = DiscoveryRestPublisher(
                    subscription_id=subscription_id,
                    resource_group=resource_group,
                    location=location,
                    tenant_id=tenant_id
                )
                print(f"TRACE: DiscoveryRestPublisher initialized successfully")
                
                # Azure discovery client for lookups in update mode
                azure_client = None
                try:
                    print(f"TRACE: initializing AzureDiscoveryClient")
                    from discovery_publisher import AzureDiscoveryClient
                    azure_client = AzureDiscoveryClient()
                    print(f"TRACE: AzureDiscoveryClient initialized successfully")
                except Exception as e:
                    print(f"TRACE: AzureDiscoveryClient initialization failed: {e}")
                    azure_client = None
                
                # Stream progress
                yield 'data: {"type": "progress", "message": "Initializing Discovery deployment..."}\n\n'
                yield 'data: {"type": "progress", "message": "Configuration saved for future use"}\n\n'
                
                # Load configuration using agent manager
                print(f"TRACE: loading agent configuration")
                yield 'data: {"type": "progress", "message": "Loading agent configuration..."}\n\n'
                
                if not agent_manager:
                    print(f"TRACE: agent manager not available")
                    yield 'data: {"type": "error", "message": "Agent manager not available"}\n\n'
                    return
                
                if not agent_name:
                    print(f"TRACE: agent name not provided")
                    yield 'data: {"type": "error", "message": "Agent name not provided"}\n\n'
                    return
                
                # Get agent paths from agent manager using local_agent_name (folder name)
                print(f"TRACE: getting agent paths for {local_agent_name}")
                agent_paths = agent_manager.get_agent_paths(local_agent_name)
                print(f"TRACE: agent_paths = {agent_paths}")
                
                # Load tool definition (YAML)
                print(f"TRACE: loading tool definition")
                tool_def_path = agent_paths['tools_definition']
                print(f"TRACE: tool_def_path = {tool_def_path}")
                if not os.path.exists(tool_def_path):
                    print(f"TRACE: tool definition file not found: {tool_def_path}")
                    yield f'data: {{"type": "error", "message": "Tool definition not found: {tool_def_path}"}}\n\n'
                    return
                
                print(f"TRACE: reading tool definition YAML")
                import yaml
                with open(tool_def_path, 'r', encoding='utf-8') as f:
                    tool_definition = yaml.safe_load(f)
                print(f"TRACE: tool definition loaded successfully, keys: {list(tool_definition.keys()) if isinstance(tool_definition, dict) else 'not a dict'}")
                
                # Process ACR placeholders in tool definition
                print(f"TRACE: processing ACR placeholders in tool definition")
                config_manager = DiscoveryConfigManager()
                tool_definition = config_manager.process_tool_definition_acr(tool_definition)
                print(f"TRACE: ACR placeholder processing complete")
                
                # Add environment variables to tool definition if available
                env_vars_path = agent_paths.get('env_vars')
                print(f"TRACE: env_vars_path = {env_vars_path}")
                print(f"TRACE: current working directory = {os.getcwd()}")
                if env_vars_path:
                    abs_env_vars_path = os.path.abspath(env_vars_path)
                    print(f"DEBUG WEB_SERVER: absolute env_vars_path = {abs_env_vars_path}")
                    print(f"DEBUG WEB_SERVER: env_vars_path exists check: {os.path.exists(env_vars_path)}")
                    print(f"DEBUG WEB_SERVER: absolute path exists check: {os.path.exists(abs_env_vars_path)}")
                else:
                    print("DEBUG WEB_SERVER: env_vars_path is None or empty")
                
                print(f"DEBUG WEB_SERVER: Condition check - env_vars_path: {bool(env_vars_path)}, file exists: {os.path.exists(env_vars_path) if env_vars_path else False}")
                    
                if env_vars_path and os.path.exists(env_vars_path):
                    print("DEBUG WEB_SERVER: Entering environment variables loading block")
                    try:
                        import json  # Ensure json is available in local scope
                        print(f"DEBUG WEB_SERVER: Opening file: {env_vars_path}")
                        with open(env_vars_path, 'r', encoding='utf-8') as f:
                            env_vars_content = json.loads(f.read())
                        
                        print(f"DEBUG WEB_SERVER: Successfully loaded env vars: {env_vars_content}")
                        
                        # Add environment variables to the properties section
                        if 'properties' not in tool_definition:
                            tool_definition['properties'] = {}
                            print("DEBUG WEB_SERVER: Created properties section in tool definition")
                        
                        tool_definition['properties']['environmentVariables'] = env_vars_content
                        yield 'data: {"type": "progress", "message": "Environment variables loaded and included"}\n\n'
                        print(f"DEBUG WEB_SERVER: Added env vars to tool definition. Properties keys: {list(tool_definition.get('properties', {}).keys())}")
                        print(f"DEBUG WEB_SERVER: Env vars content: {env_vars_content}")
                    except Exception as e:
                        print(f"DEBUG WEB_SERVER: Exception occurred while loading env vars: {str(e)}")
                        print(f"DEBUG WEB_SERVER: Exception type: {type(e).__name__}")
                        yield f'data: {{"type": "warning", "message": "Failed to load environment variables: {str(e)}"}}\n\n'
                
                # Load agent definition (YAML)
                agent_def_path = agent_paths['agent_config']
                if not os.path.exists(agent_def_path):
                    yield f'data: {{"type": "error", "message": "Agent definition not found: {agent_def_path}"}}\n\n'
                    return
                
                with open(agent_def_path, 'r', encoding='utf-8') as f:
                    agent_definition = yaml.safe_load(f)
                
                # Initialize variables for both create and update scenarios
                tool_name_created = 'unknown'
                agent_name_created = 'unknown'
                tool_id = None
                agent_id = None
                
                # Handle tool creation or update using unified approach
                tool_name = tool_definition.get('name', 'unknown-tool')
                
                # Sanitize tool name same way as create_or_update_discovery_tool does
                sanitized_tool_name = tool_name.replace('_', '-').replace(' ', '-')
                sanitized_tool_name = ''.join(c for c in sanitized_tool_name if c.isalnum() or c == '-')
                if len(sanitized_tool_name) > 24:
                    sanitized_tool_name = sanitized_tool_name[:24]
                if len(sanitized_tool_name) < 3:
                    sanitized_tool_name = (sanitized_tool_name + "tool")[:3]
                
                # Check if tool exists to show appropriate message
                existing_tool_id = publisher.check_tool_exists(sanitized_tool_name)
                if existing_tool_id:
                    yield 'data: {"type": "progress", "message": "Updating Discovery tool..."}\n\n'
                else:
                    yield 'data: {"type": "progress", "message": "Creating Discovery tool..."}\n\n'
                
                print(f"DEBUG WEB_SERVER: About to call create_or_update_discovery_tool")
                print(f"DEBUG WEB_SERVER: Tool definition keys: {list(tool_definition.keys())}")
                if 'properties' in tool_definition:
                    print(f"DEBUG WEB_SERVER: Properties keys: {list(tool_definition['properties'].keys())}")
                    if 'environmentVariables' in tool_definition['properties']:
                        print(f"DEBUG WEB_SERVER: Environment variables: {tool_definition['properties']['environmentVariables']}")
                else:
                    print("DEBUG WEB_SERVER: No properties section in tool definition")
                
                tool_result = publisher.create_or_update_discovery_tool(
                    tool_name=tool_name,
                    tool_definition=tool_definition,
                    location=location
                )
                
                if not tool_result['success']:
                    error_msg = tool_result.get('error', 'Unknown error')
                    action = tool_result.get('action', 'create/update')
                    # SSE trace for tool failure
                    if SSE_AVAILABLE:
                        try:
                            trace_system(
                                f"❌ Failed to {action} Discovery tool: {tool_name}",
                                level='error',
                                metadata={'context': 'Discovery Publish', 'agent': agent_name},
                                details=json_mod.dumps({
                                    'tool_name': tool_name,
                                    'action': action,
                                    'error': error_msg[:500]
                                }, indent=2)
                            )
                        except Exception:
                            pass
                    # Properly escape the error message for JSON
                    import json as json_module
                    error_data = {"type": "error", "message": f"Failed to {action} Discovery tool: {error_msg}"}
                    yield f'data: {json_module.dumps(error_data)}\n\n'
                    return
                
                tool_id = tool_result.get('tool_id')
                tool_name_created = tool_result.get('tool_name', 'unknown')
                action = tool_result.get('action', 'processed')
                action_past = 'updated' if action == 'updated' else 'created'
                
                # SSE trace for tool success
                if SSE_AVAILABLE:
                    try:
                        trace_system(
                            f"✅ Discovery tool {action_past}: {tool_name_created}",
                            level='success',
                            metadata={'context': 'Discovery Publish', 'agent': agent_name},
                            details=json_mod.dumps({
                                'tool_name': tool_name_created,
                                'tool_id': tool_id[:50] + '...' if tool_id and len(tool_id) > 50 else tool_id,
                                'action': action_past,
                                'provisioning_state': tool_result.get('provisioning_state', 'Unknown')
                            }, indent=2)
                        )
                    except Exception:
                        pass
                
                yield f'data: {{"type": "success", "message": "Discovery tool {action_past} successfully: {tool_name_created}"}}\n\n'
                provisioning_state = tool_result.get('provisioning_state', 'Unknown')
                yield f'data: {{"type": "progress", "message": "Tool provisioning state: {provisioning_state}"}}\n\n'
                
                # Handle agent creation or update using unified approach
                if not tool_id:
                    yield 'data: {"type": "error", "message": "Tool ID not available for agent processing"}\n\n'
                    return
                
                agent_name_from_def = agent_definition.get('agent', {}).get('name', 'unknown-agent')
                
                # Sanitize agent name same way as create_or_update_discovery_agent does
                sanitized_agent_name = agent_name_from_def.replace('_', '-').replace(' ', '-')
                sanitized_agent_name = ''.join(c for c in sanitized_agent_name if c.isalnum() or c == '-')
                if len(sanitized_agent_name) > 24:
                    sanitized_agent_name = sanitized_agent_name[:24]
                if len(sanitized_agent_name) < 3:
                    sanitized_agent_name = (sanitized_agent_name + "agent")[:3]
                
                # Check if agent exists to show appropriate message
                existing_agent_id = publisher.check_agent_exists(sanitized_agent_name)
                if existing_agent_id:
                    yield 'data: {"type": "progress", "message": "Updating Discovery agent..."}\n\n'
                else:
                    yield 'data: {"type": "progress", "message": "Creating Discovery agent..."}\n\n'
                
                # Determine model from YAML if present
                agent_yaml_model = None
                try:
                    agent_yaml_model = (agent_definition or {}).get('agent', {}).get('model')
                except Exception:
                    agent_yaml_model = None
                chosen_agent_model = agent_yaml_model or "gpt-4o"
                
                agent_result = publisher.create_or_update_discovery_agent(
                    agent_name=agent_name_from_def,
                    agent_definition=agent_definition,
                    tool_id=tool_id,
                    location=location,
                    model_name=chosen_agent_model
                )
                
                if not agent_result['success']:
                    error_msg = agent_result.get('error', 'Unknown error')
                    action = agent_result.get('action', 'process')
                    # SSE trace for agent failure
                    if SSE_AVAILABLE:
                        try:
                            trace_system(
                                f"❌ Failed to {action} Discovery agent: {agent_name_from_def}",
                                level='error',
                                metadata={'context': 'Discovery Publish', 'agent': agent_name},
                                details=json_mod.dumps({
                                    'agent_name': agent_name_from_def,
                                    'action': action,
                                    'error': error_msg[:500]
                                }, indent=2)
                            )
                        except Exception:
                            pass
                    # Properly escape the error message for JSON
                    import json as json_module
                    error_data = {"type": "error", "message": f"Failed to {action} Discovery agent: {error_msg}"}
                    yield f'data: {json_module.dumps(error_data)}\n\n'
                    return
                
                agent_id = agent_result.get('agent_id')
                agent_name_created = agent_result.get('agent_name', 'unknown')
                action = agent_result.get('action', 'processed')
                action_past = 'updated' if action == 'updated' else 'created'
                
                # SSE trace for agent success
                if SSE_AVAILABLE:
                    try:
                        trace_system(
                            f"✅ Discovery agent {action_past}: {agent_name_created}",
                            level='success',
                            metadata={'context': 'Discovery Publish', 'agent': agent_name},
                            details=json_mod.dumps({
                                'agent_name': agent_name_created,
                                'agent_id': agent_id[:50] + '...' if agent_id and len(agent_id) > 50 else agent_id,
                                'action': action_past,
                                'provisioning_state': agent_result.get('provisioning_state', 'Unknown'),
                                'model': chosen_agent_model
                            }, indent=2)
                        )
                    except Exception:
                        pass
                
                yield f'data: {{"type": "success", "message": "Discovery agent {action_past} successfully: {agent_name_created}"}}\n\n'
                agent_provisioning_state = agent_result.get('provisioning_state', 'Unknown')
                yield f'data: {{"type": "progress", "message": "Agent provisioning state: {agent_provisioning_state}"}}\n\n'
                
                # Generate Discovery Studio URLs with proper URL encoding
                import urllib.parse
                
                # Extract resource IDs for Discovery Studio links
                tool_resource_id = tool_id
                agent_resource_id = agent_id
                
                # URL encode the full resource ID for the Discovery Studio query parameter
                tool_encoded_id = urllib.parse.quote(str(tool_resource_id or ''), safe='')
                agent_encoded_id = urllib.parse.quote(str(agent_resource_id or ''), safe='')
                
                # Generate Discovery Studio deep links
                tool_studio_url = f"https://studio.discovery.microsoft.com/tools/{tool_name_created}?id={tool_encoded_id}"
                agent_studio_url = f"https://studio.discovery.microsoft.com/agents/{agent_name_created}?id={agent_encoded_id}"
                
                # Generate Azure Portal deep links
                # Azure Portal URL format for Discovery resources with tenant specification
                tenant_url_part = f"@{tenant_id}" if tenant_id else ""
                tool_azure_url = f"https://ms.portal.azure.com/#{tenant_url_part}/resource/subscriptions/{subscription_id}/resourceGroups/{resource_group}/providers/Microsoft.Discovery/tools/{tool_name_created}/dxResourceOverviewTool"
                agent_azure_url = f"https://ms.portal.azure.com/#{tenant_url_part}/resource/subscriptions/{subscription_id}/resourceGroups/{resource_group}/providers/Microsoft.Discovery/agents/{agent_name_created}/dxResourceOverviewAgent"
                
                # Final success message with HTML table format
                success_message = """<div style="font-family: monospace;">
<table style="border-collapse: collapse; width: 100%; margin: 10px 0;">
  <thead>
    <tr>
      <th style="border: 1px solid #ddd; padding: 8px; text-align: left;">Discovery Studio Links</th>
      <th style="border: 1px solid #ddd; padding: 8px; text-align: left;">Azure Portal Links</th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td style="border: 1px solid #ddd; padding: 8px;">Tool: <a href="{tool_studio_url}" target="_blank">{tool_name}</a></td>
      <td style="border: 1px solid #ddd; padding: 8px;">Tool: <a href="{tool_azure_url}" target="_blank">{tool_name}</a></td>
    </tr>
    <tr>
      <td style="border: 1px solid #ddd; padding: 8px;">Agent: <a href="{agent_studio_url}" target="_blank">{agent_name}</a></td>
      <td style="border: 1px solid #ddd; padding: 8px;">Agent: <a href="{agent_azure_url}" target="_blank">{agent_name}</a></td>
    </tr>
  </tbody>
</table>
</div>

<p><strong>Your agent is now published to Microsoft Discovery!</strong></p>""".format(
                    tool_studio_url=tool_studio_url,
                    agent_studio_url=agent_studio_url,
                    tool_azure_url=tool_azure_url,
                    agent_azure_url=agent_azure_url,
                    tool_name=tool_name_created,
                    agent_name=agent_name_created
                )
                
                # Properly escape the message for JSON
                import json
                escaped_message = json.dumps(success_message)
                yield f'data: {{"type": "success", "message": {escaped_message}, "isHtml": true}}\n\n'
                yield 'data: {"type": "complete", "message": "Deployment completed successfully"}\n\n'
                
                # SSE trace for deployment completion
                if SSE_AVAILABLE:
                    try:
                        trace_system(
                            f"🎉 Discovery deployment completed for {agent_name}",
                            level='success',
                            metadata={'context': 'Discovery Publish', 'agent': agent_name},
                            details=json_mod.dumps({
                                'agent_name': agent_name,
                                'tool_name': tool_name_created,
                                'agent_created': agent_name_created,
                                'resource_group': resource_group,
                                'location': location,
                                'tool_studio_url': tool_studio_url,
                                'agent_studio_url': agent_studio_url
                            }, indent=2)
                        )
                    except Exception:
                        pass
                
            except Exception as e:
                error_message = f"Deployment error: {str(e)}"
                # SSE trace for deployment error
                if SSE_AVAILABLE:
                    try:
                        trace_system(
                            f"❌ Discovery deployment failed for {agent_name}",
                            level='error',
                            metadata={'context': 'Discovery Publish', 'agent': agent_name},
                            details=json_mod.dumps({
                                'agent_name': agent_name,
                                'error': str(e)[:500]
                            }, indent=2)
                        )
                    except Exception:
                        pass
                # Properly escape the error message for JSON
                import json as json_module
                error_data = {"type": "error", "message": error_message}
                yield f'data: {json_module.dumps(error_data)}\n\n'
        
        return Response(generate_deployment_stream(), mimetype='text/plain')
        
    except Exception as e:
        print(f"❌ Error in stream_discovery_deployment_rest: {e}")
        import traceback
        print(f"Full traceback: {traceback.format_exc()}")
        return Response(f'data: {{"type": "error", "message": "Stream setup failed: {str(e)}"}}\n\n', 
                      mimetype='text/plain')

# KB Agent Clone Endpoint
@app.route('/api/kb-agents/clone', methods=['POST'])
def clone_kb_agent():
    """Clone an existing KB Agent (YAML file + catalog record) to a new unique name.

    Request JSON body:
      { "source_name": "ExistingKBAgent", "new_name": "NewKBAgent" }

    Behavior:
      - Validates source exists in catalog kb_agents.
      - Validates new_name not already present.
      - Copies YAML file Agents/KBAgents/<source>.yaml -> Agents/KBAgents/<new_name>.yaml.
      - Updates 'name' field inside copied YAML if present.
      - Updates agents-catalog.yaml creating a new entry cloned from source.
      - Reloads agent_manager.
    """
    try:
        data = request.get_json(silent=True) or {}
        source_name = (data.get('source_name') or '').strip()
        new_name = (data.get('new_name') or '').strip()
        
        if not source_name or not new_name:
            return jsonify({'success': False, 'error': 'source_name and new_name are required'}), 400
        if source_name == new_name:
            return jsonify({'success': False, 'error': 'new_name must be different from source_name'}), 400

        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        if not os.path.exists(catalog_path):
            return jsonify({'success': False, 'error': 'Catalog not found'}), 404

        import yaml, shutil
        with open(catalog_path, 'r', encoding='utf-8') as f:
            catalog_data = yaml.safe_load(f) or {}
        kb_agents = catalog_data.get('kb_agents') or []

        # Locate source KB agent record
        source_record = None
        for rec in kb_agents:
            if not isinstance(rec, dict):
                continue
            if rec.get('name') == source_name:
                source_record = rec
                break
        if not source_record:
            return jsonify({'success': False, 'error': f'Source KB agent "{source_name}" not found'}), 404

        # Ensure new_name not already present
        for rec in kb_agents:
            if not isinstance(rec, dict):
                continue
            if rec.get('name') == new_name:
                return jsonify({'success': False, 'error': f'KB agent "{new_name}" already exists'}), 400

        # Source and target file paths - use configured directory
        kb_output_dir = get_kb_agent_output_dir()
        kb_agents_dir = os.path.join(os.path.dirname(__file__), kb_output_dir)
            
        source_file = os.path.join(kb_agents_dir, f"{source_name}.yaml")
        target_file = os.path.join(kb_agents_dir, f"{new_name}.yaml")
        
        if not os.path.isfile(source_file):
            return jsonify({'success': False, 'error': f'Source YAML file not found: {source_file}'}), 404
        if os.path.exists(target_file):
            return jsonify({'success': False, 'error': f'Target YAML file already exists: {target_file}'}), 400

        # Copy YAML file
        try:
            print(f"🔄 Cloning KB Agent: copying {source_file} -> {target_file}")
            shutil.copy2(source_file, target_file)
            print(f"✅ Copy successful")
            
            # Update the 'name' field inside the copied YAML if present
            with open(target_file, 'r', encoding='utf-8') as yf:
                content = yf.read()
            
            # Simple regex replacement for top-level 'name:' field
            import re
            pattern = r'^(\s*)name\s*:\s*[\'"]?' + re.escape(source_name) + r'[\'"]?\s*$'
            replacement = r'\1name: ' + new_name
            updated_content = re.sub(pattern, replacement, content, flags=re.MULTILINE)
            
            # Write back the updated content
            with open(target_file, 'w', encoding='utf-8') as yf:
                yf.write(updated_content)
            print(f"📝 Updated name field in {target_file}")
            
        except Exception as copy_err:
            print(f"❌ Error during KB agent file copy: {copy_err}")
            return jsonify({'success': False, 'error': f'Failed to copy KB agent file: {copy_err}'}), 500

        # Create new catalog entry
        new_record = source_record.copy()
        new_record['name'] = new_name
        # Update agent_config path to point to the new file - use configured directory
        kb_output_dir = get_kb_agent_output_dir()
        new_record['agent_config'] = f"{kb_output_dir}{new_name}.yaml"
        
        # Add to catalog
        catalog_data.setdefault('kb_agents', []).append(new_record)
        
        # Save updated catalog
        with open(catalog_path, 'w', encoding='utf-8') as f:
            yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False, indent=2)
        print(f"✅ Added new KB agent '{new_name}' to catalog")

        # Reload agent manager
        if agent_manager:
            agent_manager.reload_catalog()
            print(f"🔄 Agent manager reloaded")

        return jsonify({
            'success': True,
            'message': f'KB agent "{source_name}" successfully cloned to "{new_name}"',
            'source_name': source_name,
            'new_name': new_name,
            'new_agent_config': new_record['agent_config']
        })

    except Exception as e:
        print(f"⚠️ Error cloning KB agent: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/tool-agents/clone', methods=['POST'])
def clone_tool_agent():
    """Clone an existing Tool Agent (files + catalog record) to a new unique name.

    Request JSON body:
      { "source_name": "ExistingToolAgent", "new_name": "NewToolAgent" }

    Behavior:
      - Validates source exists in catalog tool_agents.
      - Validates new_name not already present.
      - Creates new directory for cloned agent.
      - Copies and renames files based on catalog definitions.
      - Updates YAML content with new agent names.
      - Updates agents-catalog.yaml creating a new entry cloned from source.
      - Reloads agent_manager.
    """
    try:
        data = request.get_json(silent=True) or {}
        source_name = (data.get('source_name') or '').strip()
        new_name = (data.get('new_name') or '').strip()
        
        if not source_name or not new_name:
            return jsonify({'success': False, 'error': 'source_name and new_name are required'}), 400
        if source_name == new_name:
            return jsonify({'success': False, 'error': 'new_name must be different from source_name'}), 400

        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        if not os.path.exists(catalog_path):
            return jsonify({'success': False, 'error': 'Catalog not found'}), 404

        import yaml, shutil
        with open(catalog_path, 'r', encoding='utf-8') as f:
            catalog_data = yaml.safe_load(f) or {}
        tool_agents = catalog_data.get('tool_agents') or []

        # Locate source tool agent record
        source_record = None
        for rec in tool_agents:
            if not isinstance(rec, dict):
                continue
            if rec.get('name') == source_name:
                source_record = rec
                break
                
        if not source_record:
            return jsonify({'success': False, 'error': f'Source tool agent "{source_name}" not found'}), 404

        # Ensure new_name not already present
        for rec in tool_agents:
            if not isinstance(rec, dict):
                continue
            if rec.get('name') == new_name:
                return jsonify({'success': False, 'error': f'Tool agent "{new_name}" already exists'}), 400

        # Determine target directory for the cloned tool agent
        tool_agents_dir = get_discovery_tool_output_dir()
        target_dir = os.path.join(tool_agents_dir, new_name)
        if os.path.exists(target_dir):
            return jsonify({'success': False, 'error': f'Target directory already exists: {target_dir}'}), 400

        # Create target directory
        try:
            print(f"🔄 Creating target directory: {target_dir}")
            os.makedirs(target_dir, exist_ok=False)
        except FileExistsError:
            return jsonify({'success': False, 'error': f'Target directory already exists: {target_dir}'}), 400
        except Exception as mkdir_err:
            return jsonify({'success': False, 'error': f'Failed to create target directory: {mkdir_err}'}), 500

        # Copy files based on catalog definitions
        try:
            print(f"🔄 Copying files based on catalog definitions")
            
            # Helper function to copy and rename a single file
            def copy_catalog_file(source_rel_path: str, target_rel_path: str, file_type: str = "file"):
                if not source_rel_path:
                    print(f"  ⚠️ Skipping empty {file_type} path")
                    return True
                    
                # Resolve source path relative to web server directory
                source_abs_path = os.path.join(os.path.dirname(__file__), source_rel_path)
                target_abs_path = os.path.join(os.path.dirname(__file__), target_rel_path)
                
                if not os.path.exists(source_abs_path):
                    print(f"  ⚠️ Source {file_type} not found: {source_abs_path}")
                    return False
                
                # Ensure target directory exists
                target_dir_path = os.path.dirname(target_abs_path)
                os.makedirs(target_dir_path, exist_ok=True)
                
                # Copy the file
                try:
                    shutil.copy2(source_abs_path, target_abs_path)
                    print(f"  ✅ Copied {file_type}: {source_rel_path} -> {target_rel_path}")
                    return True
                except Exception as copy_err:
                    print(f"  ❌ Failed to copy {file_type} {source_rel_path}: {copy_err}")
                    return False
            
            # Track all files to copy
            files_copied = []
            copy_errors = []
            
            # Determine the relative path prefix for the new tool agent
            # Convert tool_agents_dir to relative path from web server directory
            web_server_dir = os.path.dirname(__file__)
            try:
                rel_tool_dir = os.path.relpath(tool_agents_dir, web_server_dir).replace('\\', '/')
            except ValueError:
                # Fallback if relpath fails (different drives on Windows)
                rel_tool_dir = tool_agents_dir.replace('\\', '/')
            
            # 1. Copy agent_config file
            source_agent_config = source_record.get('agent_config', '')
            new_agent_config = None
            if source_agent_config:
                # Extract filename and create new filename with new agent name
                source_filename = os.path.basename(source_agent_config)
                if source_filename.lower().startswith(source_name.lower()):
                    # Replace the source name prefix with new name
                    suffix = source_filename[len(source_name):]
                    new_filename = new_name + suffix
                else:
                    # Fallback: use standard naming pattern
                    new_filename = f"{new_name}Agent.yaml"
                
                new_agent_config = f"{rel_tool_dir}/{new_name}/{new_filename}"
                
                if copy_catalog_file(source_agent_config, new_agent_config, "agent config"):
                    files_copied.append((source_agent_config, new_agent_config))
                else:
                    copy_errors.append(f"agent config: {source_agent_config}")
            
            # 2. Copy tools_definition file
            source_tools_def = source_record.get('tools_definition', '')
            new_tools_def = None
            if source_tools_def:
                # Extract filename and create new filename with new tool name
                source_filename = os.path.basename(source_tools_def)
                if source_filename.lower().startswith(source_name.lower()):
                    # Replace the source name prefix with new name
                    suffix = source_filename[len(source_name):]
                    new_filename = new_name + suffix
                else:
                    # Fallback: use standard naming pattern
                    new_filename = f"{new_name}-tool-definition.yaml"
                
                new_tools_def = f"{rel_tool_dir}/{new_name}/{new_filename}"
                
                if copy_catalog_file(source_tools_def, new_tools_def, "tools definition"):
                    files_copied.append((source_tools_def, new_tools_def))
                else:
                    copy_errors.append(f"tools definition: {source_tools_def}")
            
            # 3. Copy dockerfile
            source_dockerfile = source_record.get('dockerfile', '')
            new_dockerfile = None
            if source_dockerfile:
                # Dockerfile typically keeps the same name
                new_dockerfile = f"{rel_tool_dir}/{new_name}/Dockerfile"
                
                if copy_catalog_file(source_dockerfile, new_dockerfile, "dockerfile"):
                    files_copied.append((source_dockerfile, new_dockerfile))
                else:
                    copy_errors.append(f"dockerfile: {source_dockerfile}")
            
            # 4. Copy any additional files (requirements.txt, scripts, etc.)
            source_dir_path = os.path.dirname(os.path.join(web_server_dir, source_agent_config)) if source_agent_config else None
            if source_dir_path and os.path.isdir(source_dir_path):
                print(f"🔄 Copying additional files from source directory")
                cataloged_files = set()
                
                # Build set of files already handled by catalog
                for source_path, _ in files_copied:
                    if source_path:
                        cataloged_files.add(os.path.basename(source_path))
                
                # Copy any additional files
                for filename in os.listdir(source_dir_path):
                    source_file_path = os.path.join(source_dir_path, filename)
                    if os.path.isfile(source_file_path) and filename not in cataloged_files:
                        target_file_path = os.path.join(target_dir, filename)
                        try:
                            shutil.copy2(source_file_path, target_file_path)
                            print(f"  ✅ Copied additional file: {filename}")
                        except Exception as add_copy_err:
                            print(f"  ⚠️ Failed to copy additional file {filename}: {add_copy_err}")
            
            print(f"✅ File copying complete: {len(files_copied)} catalog files copied")
            if copy_errors:
                print(f"⚠️ Copy errors encountered: {copy_errors}")
                
        except Exception as copy_err:
            print(f"❌ Unexpected error during copy: {copy_err}")
            return jsonify({'success': False, 'error': f'Failed to copy files: {copy_err}'}), 500

        # Update YAML files in target directory (rewrite 'name' fields)
        print(f"🔄 Updating YAML name fields in copied files")
        for root, _dirs, files in os.walk(target_dir):
            for fname in files:
                if fname.lower().endswith('.yaml'):
                    rewrite_yaml_agent_names(os.path.join(root, fname), source_name, new_name)

        # Build new catalog record
        def _deep_copy_resolve_yaml_refs(obj):
            """Deep copy an object while resolving any YAML anchors/references to plain values."""
            if isinstance(obj, dict):
                result = {}
                for k, v in obj.items():
                    result[k] = _deep_copy_resolve_yaml_refs(v)
                return result
            elif isinstance(obj, list):
                return [_deep_copy_resolve_yaml_refs(item) for item in obj]
            else:
                return obj
        
        new_record = _deep_copy_resolve_yaml_refs(source_record)
        new_record['name'] = new_name
        
        # Update file paths in the new record
        if new_agent_config:
            new_record['agent_config'] = new_agent_config
        if new_tools_def:
            new_record['tools_definition'] = new_tools_def
        if new_dockerfile:
            new_record['dockerfile'] = new_dockerfile
        
        # Add new record to catalog
        if 'tool_agents' not in catalog_data:
            catalog_data['tool_agents'] = []
        catalog_data['tool_agents'].append(new_record)
        
        # Save updated catalog
        with open(catalog_path, 'w', encoding='utf-8') as f:
            yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False)
        
        print(f"✅ Added new tool agent '{new_name}' to catalog")

        # Reload agent manager
        if agent_manager:
            agent_manager.reload_catalog()
            print(f"🔄 Agent manager reloaded")

        return jsonify({
            'success': True,
            'message': f'Tool agent "{source_name}" successfully cloned to "{new_name}"',
            'source_name': source_name,
            'new_name': new_name,
            'new_agent_config': new_agent_config,
            'new_tools_definition': new_tools_def,
            'new_dockerfile': new_dockerfile
        })

    except Exception as e:
        print(f"⚠️ Error cloning tool agent: {e}")
        return jsonify({'error': str(e)}), 500

# Workflow Agent Publishing Endpoints
@app.route('/api/workflow-agents/clone', methods=['POST'])
def clone_entry_agent():
    """Clone an existing Workflow Agent (files + catalog record) to a new unique name.

    Request JSON body:
      { "source_name": "ExistingEntryAgent", "new_name": "NewEntryAgent" }

    Behavior:
      - Validates source exists in catalog entry_agents.
      - Validates new_name not already present.
      - Copies directory Workflow-Agents/<source> -> Workflow-Agents/<new_name>.
      - Renames internal YAML 'name' fields inside copied component YAMLs only if present and simple scalar.
        (Does NOT attempt deep semantic rewrite of workflow content.)
      - Updates agents-catalog.yaml creating a new entry cloned from source (adjusting agent_config path & component agent_config paths with new unique filenames if directory copied verbatim).
      - Reloads agent_manager.
    """
    try:
        data = request.get_json(silent=True) or {}
        source_name = (data.get('source_name') or '').strip()
        new_name = (data.get('new_name') or '').strip()
        # Ensure final YAML-stored Entry agent name does not exceed 24 characters.
        # If user provided a longer name, truncate and inform via logs.
        if new_name and len(new_name) > 24:
            truncated = new_name[:24]
            print(f"⚠️ Provided new_name '{new_name}' exceeds 24 chars; truncating to '{truncated}'")
            new_name = truncated
        if not source_name or not new_name:
            return jsonify({'success': False, 'error': 'source_name and new_name are required'}), 400
        if source_name == new_name:
            return jsonify({'success': False, 'error': 'new_name must be different from source_name'}), 400

        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        if not os.path.exists(catalog_path):
            return jsonify({'success': False, 'error': 'Catalog not found'}), 404

        import yaml, shutil
        with open(catalog_path, 'r', encoding='utf-8') as f:
            catalog_data = yaml.safe_load(f) or {}
        entry_agents = catalog_data.get('workflow_agents') or []

        # Locate source workflow agent record
        source_record = None
        for rec in workflow_agents:
            if not isinstance(rec, dict):
                continue
            # Match by catalog stored name (if any) OR derived key (source_name)
            if rec.get('name') == source_name:
                source_record = rec
                break
            # Derive key similar to StaticAgentManager for robustness
            agent_config_path = rec.get('agent_config', '')
            if agent_config_path:
                parts = agent_config_path.replace('\\', '/').split('/')
                derived_key = None
                for part in parts:
                    if part and part not in ('..', '.') and not part.startswith('i-') and not part.startswith('ii-') and not part.endswith('.yaml'):
                        derived_key = part
                        break
                if derived_key == source_name:
                    source_record = rec
                    break
        if not source_record:
            return jsonify({'success': False, 'error': f'Source workflow agent "{source_name}" not found'}), 404

        # Ensure new_name not already present
        for rec in workflow_agents:
            if not isinstance(rec, dict):
                continue
            if rec.get('name') == new_name:
                return jsonify({'success': False, 'error': f'Entry agent "{new_name}" already exists'}), 400
            agent_config_path = rec.get('agent_config', '')
            workflow_agents_dir_config = get_workflow_agents_dir()
            # Remove leading ./ or ../../ prefix if present to get just the relative directory name
            entry_dir_name = workflow_agents_dir_config.strip('./').rstrip('/')
            if agent_config_path and f'/{entry_dir_name}/{new_name}/' in agent_config_path.replace('\\', '/'):
                return jsonify({'success': False, 'error': f'Entry agent directory for "{new_name}" already referenced in catalog'}), 400

        # Source directory
        base_dir = os.path.join(os.path.dirname(__file__), get_workflow_agents_dir())
        target_dir = os.path.join(base_dir, new_name)
        if os.path.exists(target_dir):
            return jsonify({'success': False, 'error': f'Target directory already exists: {target_dir}'}), 400

        # Create target directory
        try:
            print(f"🔄 Creating target directory: {target_dir}")
            os.makedirs(target_dir, exist_ok=False)
        except FileExistsError:
            return jsonify({'success': False, 'error': f'Target directory already exists: {target_dir}'}), 400
        except Exception as mkdir_err:
            return jsonify({'success': False, 'error': f'Failed to create target directory: {mkdir_err}'}), 500

        # Copy files based on catalog definitions (safer than directory copying)
        try:
            print(f"🔄 Copying files based on catalog definitions")
            
            # Helper function to copy and rename a single file
            def copy_catalog_file(source_rel_path: str, target_rel_path: str, file_type: str = "file"):
                if not source_rel_path:
                    print(f"  ⚠️ Skipping empty {file_type} path")
                    return True
                    
                # Resolve source path relative to web server directory
                source_abs_path = os.path.join(os.path.dirname(__file__), source_rel_path)
                target_abs_path = os.path.join(os.path.dirname(__file__), target_rel_path)
                
                if not os.path.exists(source_abs_path):
                    print(f"  ⚠️ Source {file_type} not found: {source_abs_path}")
                    return False
                
                # Ensure target directory exists
                target_dir_path = os.path.dirname(target_abs_path)
                os.makedirs(target_dir_path, exist_ok=True)
                
                # Copy the file
                try:
                    shutil.copy2(source_abs_path, target_abs_path)
                    print(f"  ✅ Copied {file_type}: {source_rel_path} -> {target_rel_path}")
                    return True
                except Exception as copy_err:
                    print(f"  ❌ Failed to copy {file_type} {source_rel_path}: {copy_err}")
                    return False
            
            # Track all files to copy
            files_copied = []
            copy_errors = []
            
            # 1. Copy main agent_config (workflow file)
            source_main_config = source_record.get('agent_config', '')
            if source_main_config:
                # Generate target path: change directory and optionally rename file
                workflow_agents_dir_config = get_workflow_agents_dir()
                entry_dir_name = workflow_agents_dir_config.strip('./').rstrip('/')
                
                # Extract filename from source path
                source_filename = os.path.basename(source_main_config)
                
                # Create new filename with new agent name prefix if it follows pattern
                if source_filename.lower().startswith(source_name.lower() + '-'):
                    suffix = source_filename[len(source_name):]  # includes '-' and extension
                    new_filename = new_name.lower() + suffix
                else:
                    # Keep original filename if it doesn't follow the pattern
                    new_filename = source_filename
                
                target_main_config = f"{workflow_agents_dir_config}/{new_name}/{new_filename}"
                
                if copy_catalog_file(source_main_config, target_main_config, "main workflow"):
                    files_copied.append((source_main_config, target_main_config))
                else:
                    copy_errors.append(f"main workflow: {source_main_config}")
            
            # 2. Copy component files
            components = source_record.get('components', [])
            for comp in components:
                if not isinstance(comp, dict):
                    continue
                    
                comp_config = comp.get('agent_config', '')
                if comp_config:
                    # Extract filename from source path
                    source_filename = os.path.basename(comp_config)
                    
                    # Create new filename with new agent name prefix if it follows pattern
                    if source_filename.lower().startswith(source_name.lower() + '-'):
                        suffix = source_filename[len(source_name):]  # includes '-' and extension
                        new_filename = new_name.lower() + suffix
                    else:
                        # Keep original filename if it doesn't follow the pattern
                        new_filename = source_filename
                    
                    target_comp_config = f"{workflow_agents_dir_config}/{new_name}/{new_filename}"
                    
                    comp_name = comp.get('name', 'component')
                    if copy_catalog_file(comp_config, target_comp_config, f"component '{comp_name}'"):
                        files_copied.append((comp_config, target_comp_config))
                    else:
                        copy_errors.append(f"component '{comp_name}': {comp_config}")
            
            # 3. Copy any additional files in the source directory that aren't in catalog
            # (like .mmd diagram files, documentation, etc.)
            source_dir = os.path.join(base_dir, source_name)
            if os.path.isdir(source_dir):
                print(f"🔄 Copying additional files from source directory")
                cataloged_files = set()
                
                # Build set of files already handled by catalog
                for source_path, _ in files_copied:
                    if source_path:
                        cataloged_files.add(os.path.basename(source_path))
                
                # Copy any additional files
                for filename in os.listdir(source_dir):
                    source_file_path = os.path.join(source_dir, filename)
                    if os.path.isfile(source_file_path) and filename not in cataloged_files:
                        # Rename file if it follows the pattern
                        if filename.lower().startswith(source_name.lower() + '-'):
                            suffix = filename[len(source_name):]
                            new_filename = new_name.lower() + suffix
                        else:
                            new_filename = filename
                            
                        target_file_path = os.path.join(target_dir, new_filename)
                        try:
                            shutil.copy2(source_file_path, target_file_path)
                            print(f"  ✅ Copied additional file: {filename} -> {new_filename}")
                        except Exception as add_copy_err:
                            print(f"  ⚠️ Failed to copy additional file {filename}: {add_copy_err}")
            
            print(f"✅ File copying complete: {len(files_copied)} catalog files copied")
            if copy_errors:
                print(f"⚠️ Copy errors encountered: {copy_errors}")
                
        except Exception as copy_err:
            print(f"❌ Unexpected error during copy: {copy_err}")
            return jsonify({'success': False, 'error': f'Failed to copy files: {copy_err}'}), 500

        # Update YAML files in target directory (rewrite 'name' fields)
        print(f"🔄 Updating YAML name fields in copied files")
        for root, _dirs, files in os.walk(target_dir):
            for fname in files:
                if fname.lower().endswith('.yaml'):
                    rewrite_yaml_agent_names(os.path.join(root, fname), source_name, new_name)

        # Build new catalog record
        def _rewrite_agent_config_path(rel_path: str) -> str:
            if not rel_path:
                return rel_path
            # rel_path format: ../../Workflow-Agents/<SourceName>/<file>.yaml
            old_path = rel_path
            workflow_agents_dir_config = get_workflow_agents_dir()
            
            # Replace directory name from source to new name
            new_path = rel_path.replace(f'/{source_name}/', f'/{new_name}/')
            
            # Update filename if it follows the source_name pattern
            filename = os.path.basename(new_path)
            if filename.lower().startswith(source_name.lower() + '-'):
                # Extract the suffix after the source name
                suffix = filename[len(source_name):]  # includes the '-' and extension
                new_filename = new_name.lower() + suffix
                # Replace just the filename part in the path
                path_parts = new_path.split('/')
                path_parts[-1] = new_filename
                new_path = '/'.join(path_parts)
                    
            print(f"  → Rewriting path: '{old_path}' -> '{new_path}'")
            return new_path

        def _deep_copy_resolve_yaml_refs(obj):
            """Deep copy an object while resolving any YAML anchors/references to plain values."""
            if isinstance(obj, dict):
                result = {}
                for k, v in obj.items():
                    result[k] = _deep_copy_resolve_yaml_refs(v)
                return result
            elif isinstance(obj, list):
                return [_deep_copy_resolve_yaml_refs(item) for item in obj]
            else:
                return obj  # Plain values (str, int, etc.) are copied as-is

        print(f"🔄 Building new catalog record for '{new_name}' from '{source_name}'")
        new_record = {}
        for k, v in source_record.items():
            if k == 'name':
                continue  # we'll set explicitly
            elif k == 'agent_config' and isinstance(v, str):
                new_record[k] = _rewrite_agent_config_path(v)
            elif k == 'components' and isinstance(v, list):
                new_components = []
                for comp in v:
                    if isinstance(comp, dict):
                        comp_copy = {}
                        for ck, cv in comp.items():
                            if ck == 'agent_config' and isinstance(cv, str):
                                comp_copy[ck] = _rewrite_agent_config_path(cv)
                            elif ck == 'name' and isinstance(cv, str):
                                # Update component name if it follows the pattern
                                if cv.lower().startswith(source_name.lower() + '-'):
                                    suffix = cv[len(source_name):]  # includes '-' and suffix
                                    comp_copy[ck] = new_name.lower() + suffix
                                else:
                                    comp_copy[ck] = cv
                            else:
                                comp_copy[ck] = cv
                        new_components.append(comp_copy)
                new_record[k] = new_components
            else:
                # Deep copy other fields to resolve any potential YAML references
                new_record[k] = _deep_copy_resolve_yaml_refs(v)
        new_record['name'] = new_name
        print(f"✅ New catalog record: {new_record}")

        # Append and persist
        entry_agents.append(new_record)
        catalog_data['workflow_agents'] = entry_agents
        try:
            print(f"🔄 Writing updated catalog with {len(entry_agents)} workflow agents")
            with open(catalog_path, 'w', encoding='utf-8') as f:
                yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False, indent=2)
            print(f"✅ Catalog updated successfully")
        except Exception as w_err:
            print(f"❌ Failed to write catalog: {w_err}")
            return jsonify({'success': False, 'error': f'Failed to write updated catalog: {w_err}'}), 500

        # Reload manager
        if agent_manager:
            try:
                agent_manager.reload_catalog()
            except Exception as r_err:
                print(f"⚠️ Clone: reload_catalog failed: {r_err}")

        return jsonify({'success': True, 'source': source_name, 'new': new_name})
    except Exception as e:
        print(f"Error in clone_entry_agent: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

def _verify_resource_via_rest_api(resource_id: str, tenant_id: str = None) -> dict:
    """
    Verify a Discovery resource using Azure Management REST API with tenant-aware authentication.
    
    Args:
        resource_id: Full ARM resource ID
        
    Returns:
        dict with 'success', 'provisioning_state', 'error'
    """
    try:
        from azure_auth_helpers import get_token_default_credential
        import requests
        
        server_traces = []
        
        # Acquire OAuth token using explicit tenant (required for publishing flows)
        from azure_auth_helpers import get_token_for_tenant
        if not tenant_id:
            return {'success': False, 'error': 'Missing tenant_id for resource verification; explicit tenant_id required'}
        token = get_token_for_tenant(
            "https://management.azure.com/.default",
            tenant_id,
            server_traces,
            purpose='verify-resource'
        )
        
        if not token:
            return {'success': False, 'error': 'Failed to acquire authentication token'}
        
        # Build REST API URL
        url = f"https://management.azure.com{resource_id}"
        headers = {
            'Authorization': f'Bearer {token}',
        }
        params = {
            'api-version': '2025-07-01-preview'
        }
        
        response = requests.get(url, headers=headers, params=params, timeout=30)
        
        if response.status_code == 200:
            data = response.json()
            provisioning_state = data.get('properties', {}).get('provisioningState', 'Unknown')
            return {
                'success': True,
                'provisioning_state': provisioning_state,
                'resource_data': data
            }
        else:
            return {
                'success': False,
                'error': f"REST API returned {response.status_code}: {response.text}"
            }
            
    except Exception as e:
        return {
            'success': False,
            'error': str(e)
        }


def verify_agent_deployment(azure_client, subscription_id, resource_group, agent_name, tenant_id: str = None, max_wait_seconds=60):
    """
    Verify that an agent was successfully deployed with retry logic.
    Uses Azure Resource Manager API to check provisioning state.
    
    Args:
        azure_client: Azure client instance
        subscription_id: Azure subscription ID
        resource_group: Azure resource group name
        agent_name: Name of the agent to verify
        max_wait_seconds: Maximum time to wait for verification (default 60 seconds)
    
    Returns:
        dict: {'success': bool, 'message': str, 'agent_id': str}
    """
    import time
    import json
    start_time = time.time()
    retry_interval = 3  # Wait 3 seconds between retries
    
    while (time.time() - start_time) < max_wait_seconds:
        try:
            # Check if the agent exists and is properly deployed (tenant-aware)
            lookup_result = azure_client.list_discovery_agents(subscription_id, resource_group, agent_name, tenant_id=tenant_id)
            
            if isinstance(lookup_result, dict) and lookup_result.get('exists'):
                best_match = lookup_result.get('best_match')
                if isinstance(best_match, dict):
                    agent_id = best_match.get('resource_id') or best_match.get('id')
                    actual_name = best_match.get('name', agent_name)
                    
                    # Additional verification using Azure Resource Manager API
                    if agent_id:
                        try:
                            # Use REST API to get resource details and check provisioning state (primary method)
                            rest_result = _verify_resource_via_rest_api(agent_id, tenant_id)
                            
                            if rest_result['success']:
                                provisioning_state = rest_result.get('provisioning_state')
                                
                                if provisioning_state == 'Succeeded':
                                    return {
                                        'success': True,
                                        'message': f'Agent {actual_name} verified successfully (provisioningState: {provisioning_state})',
                                        'agent_id': agent_id,
                                        'agent_name': actual_name,
                                        'provisioning_state': provisioning_state
                                    }
                                elif provisioning_state in ['Creating', 'Running', 'Updating', 'Accepted']:
                                    # Still provisioning, continue waiting
                                    elapsed = time.time() - start_time
                                    remaining = max_wait_seconds - elapsed
                                    if remaining > retry_interval:
                                        time.sleep(retry_interval)
                                        continue
                                    else:
                                        return {
                                            'success': False,
                                            'message': f'Agent {actual_name} still provisioning (state: {provisioning_state}) after {elapsed:.1f} seconds',
                                            'agent_id': agent_id,
                                            'agent_name': actual_name,
                                            'provisioning_state': provisioning_state
                                        }
                                elif provisioning_state == 'Failed':
                                    return {
                                        'success': False,
                                        'message': f'Agent {actual_name} provisioning failed (state: {provisioning_state})',
                                        'agent_id': agent_id,
                                        'agent_name': actual_name,
                                        'provisioning_state': provisioning_state
                                    }
                                else:
                                    # Unknown state, treat as still provisioning for now
                                    elapsed = time.time() - start_time
                                    remaining = max_wait_seconds - elapsed
                                    if remaining > retry_interval:
                                        time.sleep(retry_interval)
                                        continue
                                    else:
                                        return {
                                            'success': False,
                                            'message': f'Agent {actual_name} unknown provisioning state: {provisioning_state} after {elapsed:.1f} seconds',
                                            'agent_id': agent_id,
                                            'agent_name': actual_name,
                                            'provisioning_state': provisioning_state
                                        }
                            else:
                                # REST API failed - return error
                                return {
                                    'success': False,
                                    'message': f'Agent {actual_name} verification failed: {rest_result.get("error", "unknown error")}',
                                    'agent_id': agent_id,
                                    'agent_name': actual_name
                                }
                        except Exception as e:
                            # If we can't get details, still consider it a success if we found the agent
                            return {
                                'success': True,
                                'message': f'Agent {actual_name} found but provisioning state verification failed: {str(e)}',
                                'agent_id': agent_id,
                                'agent_name': actual_name
                            }
                    
                    return {
                        'success': True,
                        'message': f'Agent {actual_name} found',
                        'agent_id': agent_id or 'unknown',
                        'agent_name': actual_name
                    }
            
            # Agent not found yet, wait and retry
            elapsed = time.time() - start_time
            remaining = max_wait_seconds - elapsed
            
            if remaining > retry_interval:
                time.sleep(retry_interval)
            else:
                break
                
        except Exception as e:
            # Log error but continue retrying
            elapsed = time.time() - start_time
            remaining = max_wait_seconds - elapsed
            
            if remaining > retry_interval:
                time.sleep(retry_interval)
            else:
                break
    
    # Verification failed
    elapsed = time.time() - start_time
    return {
        'success': False,
        'message': f'Agent {agent_name} verification failed after {elapsed:.1f} seconds',
        'agent_id': None,
        'agent_name': agent_name
    }

def verify_workflow_deployment(azure_client, subscription_id, resource_group, workflow_name, max_wait_seconds=60, expected_definition=None):
    """
    Verify that a workflow was successfully deployed with retry logic.
    Uses Azure Resource Manager API to check provisioning state.
    Optionally verifies that the definitionContent matches the expected definition
    (useful after update operations to confirm the new content is in place).
    
    Args:
        azure_client: Azure client instance
        subscription_id: Azure subscription ID
        resource_group: Azure resource group name
        workflow_name: Name of the workflow to verify
        max_wait_seconds: Maximum time to wait for verification (default 60 seconds)
        expected_definition: Optional dict of expected definitionContent fields to verify
                            (e.g. {'name': '...', 'startstate': '...'}) after an update
    
    Returns:
        dict: {'success': bool, 'message': str, 'workflow_id': str, 'content_verified': bool}
    """
    import time
    import json
    start_time = time.time()
    retry_interval = 3  # Wait 3 seconds between retries
    
    while (time.time() - start_time) < max_wait_seconds:
        try:
            # Check if the workflow exists and is properly deployed
            lookup_result = azure_client.list_discovery_workflows(subscription_id, resource_group, workflow_name)
            
            if isinstance(lookup_result, dict) and lookup_result.get('exists'):
                best_match = lookup_result.get('best_match')
                if isinstance(best_match, dict):
                    workflow_id = best_match.get('resource_id') or best_match.get('id')
                    actual_name = best_match.get('name', workflow_name)
                    
                    # Additional verification using Azure Resource Manager API
                    if workflow_id:
                        try:
                            # Use REST API to get resource details and check provisioning state (primary method)
                            rest_result = _verify_resource_via_rest_api(workflow_id, tenant_id)
                            
                            if rest_result['success']:
                                provisioning_state = rest_result.get('provisioning_state')
                                
                                if provisioning_state == 'Succeeded':
                                    # Optionally verify definitionContent was updated
                                    content_verified = None
                                    content_msg = ''
                                    if expected_definition and isinstance(expected_definition, dict):
                                        try:
                                            resource_data = rest_result.get('resource_data', {})
                                            actual_def = resource_data.get('properties', {}).get('definitionContent', {})
                                            mismatches = []
                                            for key, expected_val in expected_definition.items():
                                                actual_val = actual_def.get(key)
                                                if actual_val != expected_val:
                                                    mismatches.append(f"'{key}': expected '{expected_val}', got '{actual_val}'")
                                            if mismatches:
                                                content_verified = False
                                                content_msg = f' (WARNING: definitionContent mismatch: {"; ".join(mismatches[:3])})'
                                            else:
                                                content_verified = True
                                                content_msg = ' (definitionContent verified)'
                                        except Exception as cv_err:
                                            content_verified = None
                                            content_msg = f' (could not verify content: {cv_err})'
                                    return {
                                        'success': True,
                                        'message': f'Workflow {actual_name} verified successfully (provisioningState: {provisioning_state}){content_msg}',
                                        'workflow_id': workflow_id,
                                        'workflow_name': actual_name,
                                        'provisioning_state': provisioning_state,
                                        'content_verified': content_verified
                                    }
                                elif provisioning_state in ['Creating', 'Running', 'Updating', 'Accepted']:
                                    # Still provisioning, continue waiting
                                    elapsed = time.time() - start_time
                                    remaining = max_wait_seconds - elapsed
                                    if remaining > retry_interval:
                                        time.sleep(retry_interval)
                                        continue
                                    else:
                                        return {
                                            'success': False,
                                            'message': f'Workflow {actual_name} still provisioning (state: {provisioning_state}) after {elapsed:.1f} seconds',
                                            'workflow_id': workflow_id,
                                            'workflow_name': actual_name,
                                            'provisioning_state': provisioning_state
                                        }
                                elif provisioning_state == 'Failed':
                                    return {
                                        'success': False,
                                        'message': f'Workflow {actual_name} provisioning failed (state: {provisioning_state})',
                                        'workflow_id': workflow_id,
                                        'workflow_name': actual_name,
                                        'provisioning_state': provisioning_state
                                    }
                                else:
                                    # Unknown state
                                    elapsed = time.time() - start_time
                                    remaining = max_wait_seconds - elapsed
                                    if remaining > retry_interval:
                                        time.sleep(retry_interval)
                                        continue
                                    else:
                                        return {
                                            'success': False,
                                            'message': f'Workflow {actual_name} unknown provisioning state: {provisioning_state} after {elapsed:.1f} seconds',
                                            'workflow_id': workflow_id,
                                            'workflow_name': actual_name,
                                            'provisioning_state': provisioning_state
                                        }
                            else:
                                # REST API failed - return error
                                return {
                                    'success': False,
                                    'message': f'Workflow {actual_name} verification failed: {rest_result.get("error", "unknown error")}',
                                    'workflow_id': workflow_id,
                                    'workflow_name': actual_name
                                }
                        except Exception as e:
                            # If we can't get details, still consider it a success if we found the workflow
                            return {
                                'success': True,
                                'message': f'Workflow {actual_name} found but provisioning state verification failed: {str(e)}',
                                'workflow_id': workflow_id,
                                'workflow_name': actual_name
                            }
                    
                    return {
                        'success': True,
                        'message': f'Workflow {actual_name} verified successfully',
                        'workflow_id': workflow_id or 'unknown',
                        'workflow_name': actual_name
                    }
            
            # Workflow not found yet, wait and retry
            elapsed = time.time() - start_time
            remaining = max_wait_seconds - elapsed
            
            if remaining > retry_interval:
                time.sleep(retry_interval)
            else:
                break
                
        except Exception as e:
            # Log error but continue retrying
            elapsed = time.time() - start_time
            remaining = max_wait_seconds - elapsed
            
            if remaining > retry_interval:
                time.sleep(retry_interval)
            else:
                break
    
    # Verification failed
    elapsed = time.time() - start_time
    return {
        'success': False,
        'message': f'Workflow {workflow_name} verification failed after {elapsed:.1f} seconds',
        'workflow_id': None,
        'workflow_name': workflow_name
    }

@app.route('/api/workflow-agent-publish/stream-rest', methods=['POST'])
def stream_workflow_agent_deployment_rest():
    """Stream Workflow Agent deployment progress using Discovery REST API methodology"""
    try:
        if not DISCOVERY_AVAILABLE:
            return Response('data: {"type": "error", "message": "Discovery modules not available"}\n\n', 
                          mimetype='text/plain')
        
        data = request.get_json()
        workflow_agent_name = data.get('workflow_agent_name')
        subscription_id = data.get('subscription_id')
        resource_group = data.get('resource_group')
        location = data.get('location')
        # Always get tenant_id from config if not provided in request
        tenant_id = data.get('tenant_id')
        if not tenant_id:
            from discovery_config_manager import DiscoveryConfigManager
            config_manager = DiscoveryConfigManager()
            azure_config = config_manager.get_azure_config()
            tenant_id = azure_config.get('tenant_id', '').strip() or None
        # Optional override; if not provided we will derive model from YAML definitions per component
        model_name = data.get('model_name')
        # Configurable verification timeout (default 60 seconds)
        verification_timeout = data.get('verification_timeout', 60)
        
        if not all([workflow_agent_name, subscription_id, resource_group, location]):
            missing_params = []
            if not workflow_agent_name: missing_params.append('workflow_agent_name')
            if not subscription_id: missing_params.append('subscription_id')
            if not resource_group: missing_params.append('resource_group')
            if not location: missing_params.append('location')
            return Response(f'data: {{"type": "error", "message": "Missing required parameters: {", ".join(missing_params)}"}}\n\n', 
                          mimetype='text/plain')
        
        # Validate that values are not empty strings
        if not subscription_id.strip() or not resource_group.strip() or not location.strip():
            return Response('data: {"type": "error", "message": "Azure configuration values cannot be empty"}\n\n', 
                          mimetype='text/plain')
        
        def generate_entry_agent_deployment_stream():
            """Generator function for streaming Entry agent deployment progress"""
            try:
                # Initialize Azure client for verification
                azure_client = None
                try:
                    azure_client = AzureDiscoveryClient()
                except Exception as e:
                    yield f'data: {{"type": "progress", "message": "⚠️ Azure client initialization failed: {str(e)} (verification will be skipped)"}}\n\n'
                # Save Azure configuration for future use
                config_manager = DiscoveryConfigManager()
                config_manager.update_azure_config(
                    subscription_id=subscription_id,
                    resource_group=resource_group,
                    location=location
                )
                
                # Initialize REST API publisher with provided configuration
                publisher = DiscoveryRestPublisher(
                    subscription_id=subscription_id,
                    resource_group=resource_group,
                    location=location,
                    tenant_id=tenant_id
                )
                
                yield 'data: {"type": "progress", "message": "🚀 Initializing Workflow Agent deployment using Discovery REST API..."}\n\n'
                yield f'data: {{"type": "progress", "message": "📋 Workflow Agent: {workflow_agent_name}"}}\n\n'
                yield f'data: {{"type": "progress", "message": "🌍 Location: {location}"}}\n\n'
                yield f'data: {{"type": "progress", "message": "📦 Resource Group: {resource_group}"}}\n\n'

                # Determine effective base name for newly created component agents
                client_publish_mode = (data or {}).get('workflow_publish_mode')
                client_name_override = (data or {}).get('workflow_name_override')
                component_name_prefix = workflow_agent_name
                if client_name_override and (client_publish_mode != 'update'):
                    try:
                        component_name_prefix = str(client_name_override).strip() or workflow_agent_name
                    except Exception:
                        component_name_prefix = workflow_agent_name
                    yield f'data: {{"type": "progress", "message": "🧩 Using renamed base for components: {component_name_prefix}"}}\n\n'
                
                # Find Entry agent component files using catalog as source of truth
                try:
                    # Get the workflow agent directory from the catalog
                    if not (agent_manager and workflow_agent_name in agent_manager.workflow_agents):
                        yield f'data: {{"type": "error", "message": "Entry agent \'{workflow_agent_name}\' not found in agents catalog"}}\n\n'
                        return
                    
                    catalog_entry = agent_manager.workflow_agents.get(workflow_agent_name)
                    agent_config_path = getattr(catalog_entry, 'agent_config', None)
                    if not agent_config_path:
                        yield f'data: {{"type": "error", "message": "Entry agent \'{workflow_agent_name}\' has no agent_config path in catalog"}}\n\n'
                        return
                    
                    # Extract directory from the agent_config path
                    # e.g., "../../6-solutions/tools-and-models/CoderWorfklow/coderworfklow-wfl.yaml" 
                    # -> "../../6-solutions/tools-and-models/CoderWorfklow"
                    agent_config_full_path = os.path.join(os.path.dirname(__file__), agent_config_path)
                    entry_agent_path = os.path.dirname(agent_config_full_path)
                except Exception as e:
                    yield f'data: {{"type": "error", "message": "Failed to resolve workflow agent directory from catalog: {str(e)}"}}\n\n'
                    return
                
                if not os.path.exists(entry_agent_path):
                    yield f'data: {{"type": "error", "message": "Entry agent directory not found: {entry_agent_path}"}}\n\n'
                    # Provide a hint about expected structure using config-driven path
                    entry_dir_name = workflow_agents_base_dir.strip('./').rstrip('/')
                    yield f'data: {{"type": "progress", "message": "Expected path pattern: <repo>/{entry_dir_name}/<EntryAgentName>"}}\n\n'
                    return
                
                # Define component roles and deployment order (IMPORTANT: Summarizer -> Router -> Planner)
                # The Workflow resource (Microsoft.Discovery/workflows) will be created separately after these agents.
                deployment_order = ['summarizer', 'router', 'planner']
                component_files = {}
                role_yaml_names = {}
                # Top-level-only workflow policy enforcement (no legacy detection)
                workflow_yaml_path = None
                workflow_yaml_filename = None
                try:
                    catalog_entry = agent_manager.workflow_agents.get(workflow_agent_name) if (agent_manager and workflow_agent_name in agent_manager.workflow_agents) else None
                    if catalog_entry:
                        top_level_workflow = getattr(catalog_entry, 'agent_config', None)
                        if isinstance(top_level_workflow, str) and top_level_workflow.strip():
                            candidate = os.path.join(entry_agent_path, os.path.basename(top_level_workflow))
                            if os.path.exists(candidate):
                                workflow_yaml_path = candidate
                                workflow_yaml_filename = os.path.basename(candidate)
                    if workflow_yaml_path:
                        yield f'data: {{"type": "progress", "message": "📄 Workflow YAML (top-level) detected: {workflow_yaml_filename}"}}\n\n'
                    else:
                        yield f'data: {{"type": "progress", "message": "⚠️ No top-level workflow YAML found (will not create workflow resource)"}}\n\n'
                except Exception as e:
                    yield f'data: {{"type": "error", "message": "❌ Workflow YAML detection error: {str(e)}"}}\n\n'
                
                # Find all component files first - use catalog information for accurate file names
                for role in deployment_order:
                    role_title = role.title()
                    component_file = None
                    filename = None
                    
                    # Find the component file using catalog information
                    if agent_manager and workflow_agent_name in agent_manager.workflow_agents:
                        entry_agent_catalog = agent_manager.workflow_agents[workflow_agent_name]
                        for component in entry_agent_catalog.components:
                            if component.get('type') == role:
                                agent_config_path = component.get('agent_config')
                                if agent_config_path and isinstance(agent_config_path, str):
                                    filename = os.path.basename(agent_config_path)
                                    component_file = os.path.join(entry_agent_path, filename)
                                    break # Found the component for this role
                    
                    if component_file and os.path.exists(component_file):
                        component_files[role] = component_file
                        yield f'data: {{"type": "progress", "message": "✅ Found {role_title} component: {filename}"}}\n\n'
                    else:
                        # Use the unique filename from the catalog in the error message if possible
                        error_filename = filename if filename else f"for role '{role}'"
                        yield f'data: {{"type": "progress", "message": "⚠️ Warning: Component file {error_filename} not found or path is invalid."}}\n\n'
                
                if not component_files:
                    yield 'data: {"type": "error", "message": "No Entry agent component files found"}\n\n'
                    return
                
                yield f'data: {{"type": "progress", "message": "📋 Found {len(component_files)} components in deployment order: {list(component_files.keys())}"}}\n\n'
                yield 'data: {"type": "progress", "message": "🎯 Deployment order: Summarizer → Router → Planner (then create Workflow resource)"}\n\n'
                
                # Deploy each component in the specified order using Azure REST APIs
                deployed_components = []
                errors = []
                created_agent_names = {}
                effective_workflow_name = None
                
                for role in deployment_order:
                    if role not in component_files:
                        yield f'data: {{"type": "progress", "message": "⏭️ Skipping {role.title()} component (not found)"}}\n\n'
                        continue
                        
                    file_path = component_files[role]
                    try:
                        # Show preparatory message; precise action (Create vs Update) will be emitted once decision is made
                        yield f'data: {{"type": "progress", "message": "🔧 Preparing {role.title()} component... ({deployment_order.index(role) + 1}/{len(deployment_order)})"}}\n\n'
                        
                        # Load component definition
                        with open(file_path, 'r', encoding='utf-8') as f:
                            component_definition = yaml.safe_load(f)
                        # Capture YAML-declared agent name for this role (for later workflow substitution)
                        yaml_agent_name = None
                        try:
                            yaml_agent_name = (component_definition or {}).get('agent', {}).get('name')
                            if isinstance(yaml_agent_name, str) and yaml_agent_name.strip():
                                role_yaml_names[role] = yaml_agent_name.strip()
                                yaml_agent_name = yaml_agent_name.strip()
                        except Exception:
                            pass
                        
                        # Use the YAML-declared agent name to ensure consistency between YAML and Azure resource names
                        # This ensures the rule "NAMES IN THE YAMLS == NAMES OF AZURE RESOURCES" is followed
                        component_name = yaml_agent_name if yaml_agent_name else f"{component_name_prefix}{role.title()}Agent"
                        
                        # Use Azure REST API to deploy the component
                        yield f'data: {{"type": "progress", "message": "   📝 Component Name: {component_name}"}}\n\n'
                        
                        # Determine model to use: prefer YAML agent.model, else request-provided model_name
                        yaml_model = None
                        try:
                            yaml_model = (component_definition or {}).get('agent', {}).get('model')
                        except Exception:
                            yaml_model = None

                        chosen_model_name = yaml_model or model_name
                        # In update mode: try to find and PATCH the existing agent; else create
                        use_update_mode = ((data or {}).get('workflow_publish_mode') == 'update')
                        result = None
                        updated_resource_name = None
                        if use_update_mode and azure_client is not None:
                            # Build a search pattern: YAML-declared name if available, else conventional name
                            search_pattern = role_yaml_names.get(role) or f"{workflow_agent_name}{role.title()}Agent"
                            try:
                                lookup = azure_client.list_discovery_agents(subscription_id, resource_group, search_pattern)
                            except Exception as _:
                                lookup = {'exists': False}
                            if isinstance(lookup, dict) and lookup.get('exists'):
                                # Prefer best match; log if multiple
                                matches = lookup.get('all_agents') or []
                                best = lookup.get('best_match') or (matches[0] if isinstance(matches, list) and matches else None)
                                if isinstance(best, dict):
                                    best_name = best.get('name', 'unknown')
                                    best_id = best.get('resource_id') or best.get('id')
                                    total = lookup.get('total_matches') or (len(matches) if isinstance(matches, list) else 0)
                                    if total and total > 1:
                                        # List a couple of candidates for transparency
                                        try:
                                            names_preview = ', '.join([m.get('name','') for m in (matches[:3] if isinstance(matches, list) else [])])
                                        except Exception:
                                            names_preview = best_name
                                        yield f'data: {{"type": "progress", "message": "   🔍 Found {total} existing {role.title()} candidates; choosing: {best_name} (candidates: {names_preview})"}}\n\n'
                                    else:
                                        yield f'data: {{"type": "progress", "message": "   🔍 Found existing {role.title()} agent: {best_name}"}}\n\n'
                                    # Perform PATCH update
                                    if isinstance(best_id, str) and best_id.strip():
                                        # Emit explicit updating action in the stream
                                        yield f'data: {{"type": "progress", "message": "   🔁 Updating {role.title()} component: {best_name} ({deployment_order.index(role) + 1}/{len(deployment_order)})"}}\n\n'
                                        result = publisher.update_discovery_agent(
                                            resource_id=best_id,
                                            agent_definition=component_definition,
                                            tool_id="",
                                            location=location,
                                            model_name=chosen_model_name if chosen_model_name else None
                                        )
                                        updated_resource_name = best_name
                                    else:
                                        yield f'data: {{"type": "progress", "message": "   ⚠️ Could not determine resource ID for existing {role.title()} agent; creating new."}}\n\n'
                            else:
                                yield f'data: {{"type": "progress", "message": "   ❔ No existing {role.title()} agent found to update; will create new."}}\n\n'
                        if result is None:
                            # Fallback or create mode — emit explicit creating action
                            yield f'data: {{"type": "progress", "message": "   ✳️ Creating {role.title()} component: {component_name} ({deployment_order.index(role) + 1}/{len(deployment_order)})"}}\n\n'
                            result = publisher.create_discovery_agent(
                                agent_name=component_name,
                                agent_definition=component_definition,
                                tool_id="",  # Entry agents don't require tool references
                                location=location,
                                model_name=chosen_model_name if chosen_model_name else "gpt-4o",
                                generate_unique_name=False,  # Use exact YAML name as Azure Resource name
                                preserve_yaml_name=True
                            )
                        
                        if result['success']:
                            # Successful deployment
                            deployed_components.append({
                                'name': updated_resource_name or component_name,
                                'role': role,
                                'resource_name': result.get('resource_name'),
                                'agent_id': result.get('agent_id'),
                                'deployment_order': deployment_order.index(role) + 1
                            })
                            # Track Azure resource names for planner/router/summarizer
                            created_agent_names[role] = result.get('resource_name')
                            
                            yield f'data: {{"type": "progress", "message": "✅ Completed: {updated_resource_name or component_name}"}}\n\n'
                            
                            # Provide detailed Azure resource information
                            resource_name = result.get('resource_name', 'unknown')
                            agent_id = result.get('agent_id', 'unknown')
                            yield f'data: {{"type": "progress", "message": "   🏷️ Azure Resource: {resource_name}"}}\n\n'
                            yield f'data: {{"type": "progress", "message": "   🆔 Agent ID: {agent_id}"}}\n\n'
                            
                            # Note: Verification will be performed after all components are deployed for efficiency
                            
                            # Add brief pause between components for better UX
                            import time
                            time.sleep(0.5)
                        else:
                            error_msg = f"Failed to deploy {component_name}: {result.get('error', 'Unknown error')}"
                            errors.append(error_msg)
                            yield f'data: {{"type": "progress", "message": "❌ {error_msg}"}}\n\n'
                            
                            # Provide detailed Azure error information for debugging
                            if 'details' in result:
                                details = result.get('details', 'No additional details')
                                yield f'data: {{"type": "progress", "message": "   🔍 Details: {details}"}}\n\n'
                            
                            # Include Azure REST API response details if available
                            if 'stderr' in result and result['stderr']:
                                stderr_msg = str(result['stderr']).replace('"', '\\"').replace('\n', '\\n')
                                yield f'data: {{"type": "progress", "message": "   📋 Azure CLI stderr: {stderr_msg}"}}\n\n'
                            
                            # Include raw response data for troubleshooting
                            if 'data' in result and result['data']:
                                data_str = str(result['data'])[:500]  # Limit to 500 chars to avoid overwhelming output
                                data_str = data_str.replace('"', '\\"').replace('\n', '\\n')
                                yield f'data: {{"type": "progress", "message": "   🔍 Azure Response: {data_str}"}}\n\n'
                            
                    except Exception as e:
                        error_msg = f"Error processing {role} component: {str(e)}"
                        errors.append(error_msg)
                        yield f'data: {{"type": "progress", "message": "❌ {error_msg}"}}\n\n'
                
                # Verify all component agents before creating workflow
                if azure_client and deployed_components:
                    yield 'data: {"type": "progress", "message": "\n🔍 Verifying all deployed components are ready (provisioning state check)..."}\n\n'
                    
                    verification_failed = False
                    for component in deployed_components:
                        role = component['role']
                        resource_name = component['resource_name']
                        
                        if resource_name:
                            yield f'data: {{"type": "progress", "message": "   Verifying {role.title()}: {resource_name}"}}\n\n'
                            verification_result = verify_agent_deployment(
                                azure_client=azure_client,
                                subscription_id=subscription_id,
                                resource_group=resource_group,
                                agent_name=resource_name,
                                tenant_id=tenant_id,
                                max_wait_seconds=verification_timeout
                            )
                            
                            if verification_result['success']:
                                provisioning_state = verification_result.get('provisioning_state', 'verified')
                                yield f'data: {{"type": "progress", "message": "   ✅ {role.title()} verified successfully (state: {provisioning_state})"}}\n\n'
                            else:
                                yield f'data: {{"type": "warning", "message": "   ⚠️ {role.title()} verification failed: {verification_result["message"]}"}}\n\n'
                                verification_failed = True
                    
                    if verification_failed:
                        yield 'data: {"type": "warning", "message": "⚠️ Some component agents failed verification. Workflow creation will proceed but may fail if agents are not ready."}\n\n'
                    else:
                        yield 'data: {"type": "progress", "message": "✅ All component agents verified successfully. Proceeding with workflow creation."}\n\n\n'
                
                # Create or Update the Workflow resource from YAML definition
                try:
                    # Use earlier validated top-level workflow path only (legacy scanning removed)
                    if workflow_yaml_path and os.path.exists(workflow_yaml_path):
                        yield 'data: {"type": "progress", "message": "\n🧭 Preparing Workflow resource from YAML..."}\n\n'
                        with open(workflow_yaml_path, 'r', encoding='utf-8') as wf:
                            wf_yaml = yaml.safe_load(wf)

                        # Build pure workflow definition JSON (no legacy wrappers)
                        wf_def = {}
                        
                        # Initialize variables
                        states = []
                        transitions = []
                        variables = []
                        
                        # Only support new format - fail if legacy format detected
                        if 'workflow' in wf_yaml and isinstance(wf_yaml['workflow'], dict):
                            errors.append("Legacy workflow format detected with 'workflow:' section. Only the new format is supported with direct top-level keys: name, states, transitions, variables, startstate")
                            yield f'data: {{"type": "progress", "message": "❌ Legacy workflow format detected. Please update to new format."}}\n\n'
                        elif 'agent' in wf_yaml and isinstance(wf_yaml['agent'], dict):
                            errors.append("Legacy agent format detected with 'agent:' section. Only the new workflow format is supported with direct top-level keys: name, states, transitions, variables, startstate")
                            yield f'data: {{"type": "progress", "message": "❌ Legacy agent format detected. Please update to new format."}}\n\n'
                        else:
                            # Extract from new format only
                            wf_def['name'] = wf_yaml.get('name') or workflow_agent_name
                            wf_def['startstate'] = wf_yaml.get('startstate')
                            states = wf_yaml.get('states', [])
                            transitions = wf_yaml.get('transitions', [])
                            variables = wf_yaml.get('variables', [])

                        # Substitute planner/router/summarizer references with created agent resource names
                        def detect_role_for_agent_name(name: str) -> str:
                            n = (name or '').strip()
                            low = n.lower()
                            # Exact YAML-declared names take precedence
                            for r in ['planner', 'router', 'summarizer']:
                                yaml_name = (role_yaml_names.get(r) or '').strip()
                                if yaml_name and low == yaml_name.lower():
                                    return r
                            # Common conventional names: <EntryName><Role>Agent
                            for r in ['planner', 'router', 'summarizer']:
                                conv1 = f"{workflow_agent_name}{r.title()}Agent".lower()
                                conv2 = f"{component_name_prefix}{r.title()}Agent".lower()
                                if low == conv1 or low == conv2:
                                    return r
                            # Substring fallback
                            if 'planner' in low:
                                return 'planner'
                            if 'router' in low:
                                return 'router'
                            if 'summarizer' in low:
                                return 'summarizer'
                            return ''

                        def swap_agent_name(a):
                            if not isinstance(a, str):
                                return a
                            role = detect_role_for_agent_name(a)
                            if role and created_agent_names.get(role):
                                return created_agent_names[role]
                            return a

                        for st in states:
                            for act in st.get('actors', []):
                                if 'agent' in act:
                                    act['agent'] = swap_agent_name(act['agent'])

                        wf_def['states'] = states
                        wf_def['transitions'] = transitions
                        wf_def['variables'] = variables

                        # Allow client to override name or request update
                        client_publish_mode = (data or {}).get('workflow_publish_mode')
                        client_name_override = (data or {}).get('workflow_name_override')
                        workflow_name = (client_name_override or wf_def['name']).strip()
                        if client_name_override and client_publish_mode != 'update':
                            # Align definitionContent name with override for create
                            wf_def['name'] = workflow_name
                        # Track effective workflow name for summary output
                        try:
                            effective_workflow_name = workflow_name
                        except Exception:
                            effective_workflow_name = workflow_name
                        if client_publish_mode == 'update':
                            action_label = 'Updating'
                        elif client_publish_mode == 'create':
                            action_label = 'Creating'
                        else:
                            action_label = 'Publishing (create or update)'
                        yield f'data: {{"type": "progress", "message": "🚀 {action_label} Workflow resource (requested): {workflow_name}"}}\n\n'

                        if client_publish_mode == 'update':
                            wf_result = publisher.update_discovery_workflow(
                                workflow_name=workflow_name,
                                workflow_definition=wf_def,
                                version="2025-05-15-preview"
                            )
                        elif client_publish_mode == 'create':
                            wf_result = publisher.create_discovery_workflow(
                                workflow_name=workflow_name,
                                workflow_definition=wf_def,
                                location=location,
                                version="2025-05-15-preview"
                            )
                        else:
                            # Default: auto-detect create or update
                            wf_result = publisher.create_or_update_discovery_workflow(
                                workflow_name=workflow_name,
                                workflow_definition=wf_def,
                                location=location,
                                version="2025-05-15-preview"
                            )
                        if wf_result.get('success'):
                            wf_action = wf_result.get('action', '')
                            verb = wf_action if wf_action else ('updated' if client_publish_mode == 'update' else 'created')
                            workflow_resource_name = wf_result.get('resource_name')
                            yield f'data: {{"type": "progress", "message": "✅ Workflow {verb}: {workflow_resource_name}"}}\n\n'
                            
                            # Verify workflow deployment (include content verification for updates)
                            if azure_client and workflow_resource_name:
                                yield f'data: {{"type": "progress", "message": "🔍 Verifying workflow deployment..."}}\n\n'
                                # For updates, pass key fields from wf_def to verify content was applied
                                expected_def = None
                                if verb == 'updated':
                                    expected_def = {}
                                    if wf_def.get('startstate'):
                                        expected_def['startstate'] = wf_def['startstate']
                                    if wf_def.get('name'):
                                        expected_def['name'] = wf_def['name']
                                workflow_verification = verify_workflow_deployment(
                                    azure_client=azure_client,
                                    subscription_id=subscription_id,
                                    resource_group=resource_group,
                                    workflow_name=workflow_resource_name,
                                    max_wait_seconds=verification_timeout,
                                    expected_definition=expected_def
                                )
                                
                                if workflow_verification['success']:
                                    yield f'data: {{"type": "progress", "message": "✅ {workflow_verification["message"]}"}}\n\n'
                                    if workflow_verification.get('content_verified') is False:
                                        yield f'data: {{"type": "warning", "message": "⚠️ Workflow content may not have been updated. Check the definitionContent in Azure Portal."}}\n\n'
                                else:
                                    yield f'data: {{"type": "warning", "message": "⚠️ {workflow_verification["message"]}"}}\n\n'
                            else:
                                yield f'data: {{"type": "progress", "message": "⚠️ Skipping workflow verification (Azure client not available or no resource name)"}}\n\n'
                        else:
                            err = wf_result.get('error', 'Unknown error')
                            if client_publish_mode == 'update':
                                errors.append(f"Workflow update failed: {err}")
                                yield f'data: {{"type": "progress", "message": "❌ Workflow update failed: {err}"}}\n\n'
                            else:
                                errors.append(f"Workflow creation failed: {err}")
                                yield f'data: {{"type": "progress", "message": "❌ Workflow creation failed: {err}"}}\n\n'
                                
                            # Provide detailed Azure workflow error information for debugging
                            if 'details' in wf_result:
                                details = wf_result.get('details', 'No additional details')
                                yield f'data: {{"type": "progress", "message": "   🔍 Workflow Details: {details}"}}\n\n'
                            
                            # Include Azure REST API response details if available
                            if 'stderr' in wf_result and wf_result['stderr']:
                                stderr_msg = str(wf_result['stderr']).replace('"', '\\"').replace('\n', '\\n')
                                yield f'data: {{"type": "progress", "message": "   📋 Azure CLI stderr: {stderr_msg}"}}\n\n'
                            
                            # Include raw response data for troubleshooting
                            if 'data' in wf_result and wf_result['data']:
                                data_str = str(wf_result['data'])[:500]  # Limit to 500 chars
                                data_str = data_str.replace('"', '\\"').replace('\n', '\\n')
                                yield f'data: {{"type": "progress", "message": "   🔍 Azure Response: {data_str}"}}\n\n'
                            # Capture successful workflow deployment for unified summary
                            if wf_result.get('success'):
                                deployed_components.append({
                                    'role': 'workflow',
                                    'name': effective_workflow_name,
                                    'resource_name': wf_result.get('resource_name'),
                                    'deployment_order': len(deployment_order) + 1
                                })
                    else:
                        yield f'data: {{"type": "progress", "message": "⚠️ Skipping workflow creation: no top-level workflow YAML."}}\n\n'
                except Exception as e:
                    errors.append(f"Workflow processing error: {str(e)}")
                    yield f'data: {{"type": "progress", "message": "❌ Workflow processing error: {str(e)}"}}\n\n'

                # Enhanced Summary with deployment order information
                overall_success = len(errors) == 0
                yield f'data: {{"type": "progress", "message": "\\n{"=" * 60}"}}\n\n'
                yield 'data: {"type": "progress", "message": "ENTRY AGENT DEPLOYMENT SUMMARY"}\n\n'
                yield f'data: {{"type": "progress", "message": "{"=" * 60}"}}\n\n'
                summary_entry_name = effective_workflow_name or workflow_agent_name
                yield f'data: {{"type": "progress", "message": "Workflow Agent: {summary_entry_name}"}}\n\n'
                yield f'data: {{"type": "progress", "message": "Location: {location}"}}\n\n'
                yield f'data: {{"type": "progress", "message": "Resource Group: {resource_group}"}}\n\n'
                if effective_workflow_name:
                    yield f'data: {{"type": "progress", "message": "Workflow: {effective_workflow_name}"}}\n\n'
                yield f'data: {{"type": "progress", "message": "Deployment Order: Summarizer → Router → Planner → (Workflow resource)"}}\n\n'
                yield f'data: {{"type": "progress", "message": "Overall Success: {overall_success}"}}\n\n'
                
                if deployed_components:
                    # Sort components by deployment order for display
                    sorted_components = sorted(deployed_components, key=lambda x: x.get('deployment_order', 0))
                    yield f'data: {{"type": "progress", "message": "\\n✅ Successfully Deployed Components ({len(deployed_components)}):"}}\n\n'
                    for component in sorted_components:
                        comp_name = component['name']
                        comp_role = component['role'].title()
                        comp_resource = component['resource_name']
                        comp_order = component.get('deployment_order', '?')
                        yield f'data: {{"type": "progress", "message": "  {comp_order}. {comp_name} ({comp_role})"}}\n\n'
                        yield f'data: {{"type": "progress", "message": "     🏷️ Azure Resource: {comp_resource}"}}\n\n'
                
                if errors:
                    yield f'data: {{"type": "progress", "message": "\\n❌ Errors ({len(errors)}):"}}\n\n'
                    for error in errors:
                        yield f'data: {{"type": "progress", "message": "  - {error}"}}\n\n'
                
                if overall_success:
                    yield 'data: {"type": "success", "message": "🎉 Entry agent deployment completed successfully!"}\n\n'
                    
                    # Build Discovery Studio URL for the workflow
                    if effective_workflow_name:
                        # URL encode the resource ID components
                        import urllib.parse
                        resource_id = f"/subscriptions/{subscription_id}/resourceGroups/{resource_group}/providers/Microsoft.Discovery/workflows/{effective_workflow_name}"
                        encoded_id = urllib.parse.quote(resource_id, safe='')
                        studio_url = f"https://studio.discovery.microsoft.com/agents/{effective_workflow_name}?id={encoded_id}"
                        yield f'data: {{"type": "progress", "message": "\\n🔗 View in Discovery Studio: {studio_url}"}}\n\n'
                    
                    yield 'data: {"type": "progress", "message": "ℹ️ Next: In Discovery Studio, add agents to your Project and select the newly created Workflow as the Workflow Agent."}\n\n'
                else:
                    yield 'data: {"type": "error", "message": "⚠️ Entry agent deployment completed with errors"}\n\n'
                    
                    # Provide detailed error summary for troubleshooting
                    yield f'data: {{"type": "progress", "message": "🔍 Error Summary ({len(errors)} errors):"}}\n\n'
                    for i, error in enumerate(errors, 1):
                        # Escape quotes in error messages for JSON compatibility
                        escaped_error = error.replace('"', '\\"').replace('\n', '\\n')
                        yield f'data: {{"type": "progress", "message": "   {i}. {escaped_error}"}}\n\n'
                    
                    yield f'data: {{"type": "progress", "message": "💡 Check the error details above for troubleshooting guidance."}}\n\n'
                
                # Final result data
                result_data = {
                    'success': overall_success,
                    'workflow_agent_name': workflow_agent_name,
                    'deployed_components': deployed_components,
                    'errors': errors,
                    'resource_group': resource_group,
                    'location': location
                }
                
                yield f'data: {{"type": "result", "data": {json.dumps(result_data)}}}\n\n'
                
            except Exception as e:
                yield f'data: {{"type": "error", "message": "Entry agent deployment error: {str(e)}"}}\n\n'
        
        return Response(generate_entry_agent_deployment_stream(), mimetype='text/plain')
        
    except Exception as e:
        print(f"Error in stream_workflow_agent_deployment_rest: {e}")
        return Response(f'data: {{"type": "error", "message": "Internal server error: {str(e)}"}}\n\n', 
                      mimetype='text/plain')

@app.route('/api/workflow-agent-publish/check-config', methods=['POST'])
def check_entry_agent_publish_config():
    """Check Azure configuration for Entry agent publishing"""
    try:
        if not DISCOVERY_AVAILABLE:
            return jsonify({'error': 'Discovery modules not available'}), 500
            
        data = request.get_json()
        workflow_agent_name = data.get('workflow_agent_name')
        
        if not workflow_agent_name:
            return jsonify({'error': 'Entry agent name is required'}), 400
        
        # Check if Entry agent exists using config-driven path
        try:
            workflow_agents_base_dir = get_workflow_agents_dir()
            workflow_agents_dir = os.path.join(os.path.dirname(__file__), workflow_agents_base_dir)
            entry_agent_path = os.path.join(workflow_agents_dir, workflow_agent_name)
        except Exception as e:
            return jsonify({'error': f'Failed to resolve workflow agents directory: {str(e)}'}), 500
        
        if not os.path.exists(entry_agent_path):
            return jsonify({
                'error': f'Entry agent "{workflow_agent_name}" not found',
                'path': entry_agent_path
            }), 404
        
        # Find component files
        component_roles = ['Planner', 'Router', 'Summarizer', 'Workflow']
        found_components = []
        missing_components = []
        
        for role in component_roles:
            filename = f"{workflow_agent_name}{role}Agent.yaml"
            file_path = os.path.join(entry_agent_path, filename)
            
            if os.path.exists(file_path):
                found_components.append({
                    'role': role.lower(),
                    'filename': filename,
                    'path': file_path
                })
            else:
                missing_components.append({
                    'role': role.lower(),
                    'filename': filename,
                    'path': file_path
                })
        
        # Load saved Azure configuration
        config_manager = DiscoveryConfigManager()
        saved_config = config_manager.get_azure_config()
        
        return jsonify({
            'success': True,
            'workflow_agent_name': workflow_agent_name,
            'entry_agent_path': entry_agent_path,
            'found_components': found_components,
            'missing_components': missing_components,
            'total_components': len(found_components),
            'can_deploy': len(found_components) > 0,
            'azure_config': saved_config
        })
        
    except Exception as e:
        print(f"Error in check_entry_agent_publish_config: {e}")
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500

@app.route('/api/workflow-agent-publish/get-config', methods=['POST', 'GET'])
def get_entry_agent_publish_config():
    """Get Entry agent publishing configuration and available agents.

    Improvements:
    - Accepts both POST (with optional JSON body) and GET (no body) for idempotent retrieval.
    - Tolerant JSON parsing (empty or invalid JSON no longer triggers 400/500).
    - Returns full component metadata (name, agent_config, type) instead of only names.
    - Provides consistent shape even when catalog stores entry_agents as dict keyed by name.
    - Safeguards against partially formed entries by normalizing missing lists/fields.
    """
    try:
        if not DISCOVERY_AVAILABLE:
            return jsonify({'error': 'Discovery modules not available'}), 500

        # Tolerant parse: do not raise on empty body or invalid JSON
        data = request.get_json(silent=True) or {}
        workflow_agent_name = data.get('workflow_agent_name') or request.args.get('workflow_agent_name')

        # Collect workflow agents from manager; handle dict-of-dict or list forms
        raw_workflow_agents = []
        # Safely obtain workflow agents collection (manager may initialize these differently)
        manager_workflow_agents = getattr(agent_manager, 'workflow_agents', None)
        if manager_workflow_agents:
            if isinstance(manager_workflow_agents, dict):
                raw_workflow_agents = list(manager_workflow_agents.values())
            else:
                raw_workflow_agents = manager_workflow_agents

        available_entry_agents = []
        for entry in raw_workflow_agents:
            # Handle both dataclass instances (from agent_manager) and raw dicts
            if hasattr(entry, 'name'):
                ea_name = entry.name
                ea_desc = getattr(entry, 'description', '')
                ea_config = getattr(entry, 'agent_config', '')
                ea_components_raw = getattr(entry, 'components', []) or []
            elif isinstance(entry, dict):
                ea_name = entry.get('name', '')
                ea_desc = entry.get('description', '')
                ea_config = entry.get('agent_config', '')
                ea_components_raw = entry.get('components', []) or []
            else:
                available_entry_agents.append({
                    'name': str(entry),
                    'description': 'Workflow agent',
                    'agent_config': '',
                    'coordinated_agents': [],
                    'components': []
                })
                continue

            components = []
            for comp in ea_components_raw:
                if isinstance(comp, dict):
                    components.append({
                        'name': comp.get('name', ''),
                        'agent_config': comp.get('agent_config', ''),
                        'type': comp.get('type', '')
                    })
                else:
                    components.append({'name': str(comp), 'agent_config': '', 'type': ''})
            available_entry_agents.append({
                'name': ea_name,
                'description': ea_desc,
                'agent_config': ea_config,
                'coordinated_agents': agent_manager.get_coordinated_agents(ea_name) if agent_manager else [],
                'components': components,
            })

        # Lookup specific workflow agent config if requested
        workflow_agent_config = None
        if workflow_agent_name:
            for ea in available_entry_agents:
                if ea.get('name') == workflow_agent_name:
                    workflow_agent_config = ea
                    break

        # Load saved configuration data
        config_manager = DiscoveryConfigManager()
        saved_config = config_manager.get_azure_config()
        llm_config = config_manager.get_llm_config()

        response = {
            'success': True,
            'available_entry_agents': available_entry_agents,
            'total_entry_agents': len(available_entry_agents),
            'azure_config': saved_config,
            'llm_config': llm_config
        }
        if workflow_agent_config:
            response['workflow_agent_config'] = workflow_agent_config

        return jsonify(response)

    except Exception as e:
        print(f"Error in get_entry_agent_publish_config: {e}")
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500

