@app.route('/api/workflow-agent-publish/enumerate-agents', methods=['POST'])
def enumerate_entry_agent_agents():
    """Enumerate an Workflow Agent's full structure: workflow agent, components,
    coordinated agents, presence/size of YAML files.

    Returns (on success):
      {
        success: true,
        entry_agent: {
           name, description,
           workflow: { name, agent_config_path, exists, size_bytes },
           coordinated_agents: [...],
           components: [ { name, type, agent_config_path, exists, size_bytes } ]
        },
        referenced_agents: [...],
        total_referenced: N
      }

    On failure (any missing required file): success: false with error list.
    Enumeration failure MUST abort validation upstream per product requirement.
    """
    try:
        if not DISCOVERY_AVAILABLE:
            return jsonify({'success': False, 'error': 'Discovery modules not available'}), 500

        data = request.get_json(silent=True) or {}
        workflow_agent_name = data.get('workflow_agent_name')
        if not workflow_agent_name:
            return jsonify({'success': False, 'error': 'workflow_agent_name is required'}), 400

        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        if not os.path.exists(catalog_path):
            return jsonify({'success': False, 'error': f'Agents catalog not found at {catalog_path}'}), 404

        import yaml
        try:
            with open(catalog_path, 'r', encoding='utf-8') as f:
                catalog_data = yaml.safe_load(f) or {}
        except Exception as e:
            return jsonify({'success': False, 'error': f'Failed to parse agents catalog: {e}'}), 500

        entry_agents_list = catalog_data.get('workflow_agents') or []
        target = None
        for ea in entry_agents_list:
            if isinstance(ea, dict) and ea.get('name') == workflow_agent_name:
                target = ea
                break

        if not target:
            return jsonify({'success': False, 'error': f'Entry agent "{workflow_agent_name}" not found in catalog'}), 404

        def _abs_path(rel_path):
            if not rel_path or not isinstance(rel_path, str):
                return None
            return os.path.normpath(os.path.join(os.path.dirname(catalog_path), rel_path))

        def _file_info(rel_path):
            original = rel_path if isinstance(rel_path, str) else ''
            ap = _abs_path(original)
            if not ap:
                return {'agent_config_path': original, 'exists': False, 'size_bytes': 0}
            if os.path.exists(ap) and os.path.isfile(ap):
                try:
                    size = os.path.getsize(ap)
                except OSError:
                    size = 0
                return {'agent_config_path': original, 'exists': True, 'size_bytes': size}
            return {'agent_config_path': original, 'exists': False, 'size_bytes': 0}

        workflow_info = _file_info(target.get('agent_config'))
        workflow_info['name'] = workflow_agent_name

        components = []
        for comp in target.get('components', []) or []:
            if isinstance(comp, dict):
                ci = _file_info(comp.get('agent_config'))
                ci.update({'name': comp.get('name'), 'type': comp.get('type')})
                components.append(ci)
            else:
                ci = _file_info('')
                ci.update({'name': str(comp), 'type': ''})
                components.append(ci)

        coordinated_agents = agent_manager.get_coordinated_agents(workflow_agent_name) if agent_manager else []
        referenced_agents = set(coordinated_agents)
        for c in components:
            if c.get('name'):
                referenced_agents.add(c['name'])

        missing_items = []
        if not workflow_info.get('exists'):
            missing_items.append(f'Workflow agent config missing: {workflow_info.get("agent_config_path")}')
        for c in components:
            if c.get('agent_config_path') and not c.get('exists'):
                missing_items.append(f'Component {c.get("type") or "unknown"} missing: {c.get("agent_config_path")}')

        if missing_items:
            return jsonify({'success': False, 'error': 'One or more required files are missing', 'missing': missing_items}), 200

        return jsonify({
            'success': True,
            'workflow_agent': {
                'name': workflow_agent_name,
                'description': target.get('description', ''),
                'workflow': workflow_info,
                'coordinated_agents': coordinated_agents,
                'components': components
            },
            'referenced_agents': sorted(list(referenced_agents)),
            'total_referenced': len(referenced_agents)
        })
    except Exception as e:
        print(f"Error in enumerate_entry_agent_agents: {e}")
        return jsonify({'success': False, 'error': f'Internal server error: {e}'}), 500


@app.route('/api/workflow-agent-publish/validate-agent', methods=['POST'])
def validate_single_entry_agent():
    """Validate a single referenced agent against Discovery (fast, single-agent check).
    This endpoint is intended for per-agent progress updates from the client. It mirrors
    the agent-matching logic used by validate-workflow-agent-dependencies but only for one agent.
    """
    try:
        if not DISCOVERY_AVAILABLE:
            return jsonify({'error': 'Discovery modules not available'}), 500

        data = request.get_json()
        if not data:
            return jsonify({'error': 'Invalid JSON data in request'}), 400

        workflow_agent_name = data.get('workflow_agent_name')
        agent_name = data.get('agent_name')
        subscription_id = data.get('subscription_id')
        resource_group = data.get('resource_group')

        if not all([workflow_agent_name, agent_name, subscription_id, resource_group]):
            return jsonify({'error': 'workflow_agent_name, agent_name, subscription_id, and resource_group are required'}), 400

        azure_client = get_azure_discovery_client()
        if not azure_client:
            return jsonify({'error': 'AzureDiscoveryClient not available'}), 500

        # Get tenant_id from config for correct Azure authentication
        from discovery_config_manager import DiscoveryConfigManager
        config_manager = DiscoveryConfigManager()
        azure_config = config_manager.get_azure_config()
        tenant_id = azure_config.get('tenant_id', '').strip() or None

        # Call discovery to list agents in the specified scope (use short-term server-side cache)
        all_agents_result = cached_list_discovery_agents(subscription_id, resource_group, azure_client, tenant_id=tenant_id)

        agent_result = {
            'agent_name': agent_name,
            'exact_match': False,
            'similar_agents': [],
            'status': 'not_found'
        }

        if all_agents_result.get('exists') or (all_agents_result.get('all_agents') and len(all_agents_result['all_agents']) > 0):
            # Normalize response
            agents = []
            if all_agents_result.get('agents'):
                agents = all_agents_result['agents']
            elif all_agents_result.get('all_agents'):
                agents = all_agents_result['all_agents']
            elif all_agents_result.get('best_match'):
                agents = [all_agents_result['best_match']]

            # Exact match first (case-insensitive)
            exact_matches = [ag for ag in agents if ag.get('name', '').lower() == agent_name.lower()]
            if exact_matches:
                agent_result['exact_match'] = True
                agent_result['status'] = 'found'
                agent_result['matched_agent'] = exact_matches[0]
            # If no exact match, status remains 'not_found' (similar matching removed)

        return jsonify({'success': True, 'result': agent_result})

    except Exception as e:
        print(f"Error in validate_single_entry_agent: {e}")
        return jsonify({'success': False, 'error': f'Internal server error: {e}'}), 500

@app.route('/api/workflow-agent-publish/validate-agents', methods=['POST'])
def validate_workflow_agent_dependencies():
    """Validate that all agents referenced in the Workflow Agent Workflow are published"""
    try:
        if not DISCOVERY_AVAILABLE:
            return jsonify({'error': 'Discovery modules not available'}), 500

        data = request.get_json()
        if not data:
            return jsonify({'error': 'Invalid JSON data in request'}), 400

        workflow_agent_name = data.get('workflow_agent_name')
        subscription_id = data.get('subscription_id')
        resource_group = data.get('resource_group')
        inline_workflow_yaml = data.get('inline_workflow_yaml')

        if not all([workflow_agent_name, subscription_id, resource_group]):
            return jsonify({'error': 'workflow_agent_name, subscription_id, and resource_group are required'}), 400

        # Use the dedicated Workflow Agent workflow loader
        workflow_result = load_workflow_agent_workflow_config(workflow_agent_name, inline_workflow_yaml)
        
        if not workflow_result['success']:
            return jsonify({'error': workflow_result['error']}), 404 if 'not found' in workflow_result['error'].lower() else 400
        
        workflow_config = workflow_result['workflow_config']
        referenced_agents = workflow_result['referenced_agents']
        workflow_source = workflow_result['workflow_source']

        print(f"DEBUG: validate_workflow_agent_dependencies - Found {len(referenced_agents)} referenced agents: {referenced_agents}")
        print(f"DEBUG: validate_workflow_agent_dependencies - Workflow source: {workflow_source}")

        # VALIDATION CHECK 1: Ensure specialized agents are detected
        if not referenced_agents or len(referenced_agents) == 0:
            print(f"WARNING: No specialized agents detected for Workflow Agent '{workflow_agent_name}' - cannot publish")
            return jsonify({
                'success': False,
                'error': 'No specialized agents detected in workflow. Workflow Agent must reference at least one external agent to be publishable.',
                'can_deploy': False,
                'overall_status': 'failure',
                'referenced_agents': [],
                'validation_results': [],
                'workflow_name': workflow_config.get('name', workflow_agent_name),
                'workflow_source': workflow_source,
                'summary': {
                    'total_agents': 0,
                    'found_agents': 0,
                    'missing_agents': 0,
                    'agent_details': 'No specialized agents found - cannot publish'
                }
            }), 400

        print(f"DEBUG: validate_workflow_agent_dependencies - Validation passed: {len(referenced_agents)} specialized agents found")

        # Initialize Azure Discovery client
        azure_client = get_azure_discovery_client()
        if not azure_client:
            return jsonify({'error': 'AzureDiscoveryClient not available'}), 500

        # Get tenant_id from config for correct Azure authentication
        from discovery_config_manager import DiscoveryConfigManager
        config_manager = DiscoveryConfigManager()
        azure_config = config_manager.get_azure_config()
        tenant_id = azure_config.get('tenant_id', '').strip() or None

        # Build a mapping of workflow-agent component name -> component type (planner/router/summarizer/agent)
        comp_type_map = {}
        try:
            catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
            if os.path.exists(catalog_path):
                try:
                    with open(catalog_path, 'r', encoding='utf-8') as _cf:
                        _catalog = yaml.safe_load(_cf) or {}
                    for ea in _catalog.get('workflow_agents') or []:
                        if isinstance(ea, dict) and ea.get('name') == workflow_agent_name:
                            for comp in ea.get('components') or []:
                                if isinstance(comp, dict):
                                    c_name = comp.get('name')
                                    c_type = (comp.get('type') or 'agent').lower()
                                    if c_name:
                                        comp_type_map[c_name] = c_type
                            break
                except Exception as _cat_err:
                    print(f"DEBUG: Failed to parse agents-catalog for component types: {_cat_err}")
        except Exception:
            pass

        validation_results = []
        # Use short-term cached listing to avoid repeating the same expensive call for each agent
        for agent_name in referenced_agents:
            # Get ALL agents first, then apply our own matching logic
            all_agents_result = cached_list_discovery_agents(subscription_id, resource_group, azure_client, tenant_id=tenant_id)

            agent_result = {
                'agent_name': agent_name,
                'exact_match': False,
                'similar_agents': [],
                'status': 'not_found'
            }

            if all_agents_result.get('exists') or (all_agents_result.get('all_agents') and len(all_agents_result['all_agents']) > 0):
                # Normalize response
                agents = []
                if all_agents_result.get('agents'):
                    agents = all_agents_result['agents']
                elif all_agents_result.get('all_agents'):
                    agents = all_agents_result['all_agents']
                elif all_agents_result.get('best_match'):
                    agents = [all_agents_result['best_match']]

                # Exact match first
                exact_matches = [ag for ag in agents if ag.get('name', '').lower() == agent_name.lower()]
                if exact_matches:
                    agent_result['exact_match'] = True
                    agent_result['status'] = 'found'
                    agent_result['matched_agent'] = exact_matches[0]
                # If no exact match, status remains 'not_found' (similar matching removed)

            # Attach discovered component type if available
            agent_result['component_type'] = comp_type_map.get(agent_name)

            # Downgrade missing specialized workflow-agent components (planner/router/summarizer) to warnings
            if agent_result.get('status') == 'not_found' and agent_result.get('component_type') in ('planner', 'router', 'summarizer'):
                agent_result['status'] = 'warning'
                agent_result['warning'] = f"Component '{agent_name}' of type '{agent_result['component_type']}' is not published to Discovery; treated as a warning."

            validation_results.append(agent_result)

        # Determine overall validation status
        # Consider planner/router/summarizer missing components (status=='warning') as acceptable for deployment
        # A result is acceptable if it's found or a warning for allowed component types
        def _is_acceptable(r):
            if r['status'] == 'found':
                return True
            if r['status'] == 'warning' and r.get('component_type') in ('planner', 'router', 'summarizer'):
                return True
            return False

        all_good = all(_is_acceptable(r) for r in validation_results)
        overall_status = 'valid' if all_good else 'invalid'

        # Preflight check for duplicate Workflow name to avoid NonUniqueResourceName
        try:
            workflow_name_requested = (
                workflow_config.get('name')
                or workflow_config.get('workflow', {}).get('name')
                or workflow_config.get('agent', {}).get('name')
                or workflow_agent_name
            )
        except Exception:
            workflow_name_requested = workflow_agent_name

        workflow_duplicate_info = None
        try:
            wf_list = azure_client.list_discovery_workflows(subscription_id, resource_group, workflow_name_requested, tenant_id=tenant_id)
            duplicate_found = False
            existing = []
            if wf_list.get('exists'):
                items = wf_list.get('all_workflows') or []
                best = wf_list.get('best_match')
                if best and isinstance(best, dict) and best.get('name', '').lower() == (workflow_name_requested or '').lower():
                    duplicate_found = True
                    existing.append({'name': best.get('name'), 'resource_id': best.get('resource_id')})
                for it in items:
                    try:
                        n = (it.get('name') or it.get('workflow_name') or '').lower()
                        if n == (workflow_name_requested or '').lower():
                            duplicate_found = True
                            existing.append({'name': it.get('name') or it.get('workflow_name'), 'resource_id': it.get('resource_id')})
                    except Exception:
                        continue
            if duplicate_found:
                workflow_duplicate_info = {
                    'name': workflow_name_requested,
                    'existing': existing,
                    'message': f'Workflow name "{workflow_name_requested}" already exists. Choose Update or provide a new name before publishing.'
                }
        except Exception as wf_err:
            workflow_duplicate_info = workflow_duplicate_info or {'check_error': str(wf_err)}

        # ---------------------------------------------------------------
        # Event Validation (workflow transitions vs router agent actions)
        # ---------------------------------------------------------------
        # Build the agents_data list expected by validators.events_validation:
        # Each element: { 'type': 'workflow'|'agent', 'name': str, 'yaml_content': YAML string }
        # Currently we include the workflow itself and (if found) the router component.
        # TODO: Load coordinated agent YAML contents for event validation (future improvement)
        events_validation_result_serialized = None
        try:
            try:
                # Local import to avoid circular imports at module load time
                from validators import events_validation  # type: ignore
            except ImportError as _ev_imp_err:
                print(f"DEBUG: events_validation import failed: {_ev_imp_err}")
                events_validation = None  # type: ignore

            if 'yaml' not in globals():  # ensure yaml is available
                import yaml as _yaml_tmp  # noqa: F401

            agents_data_for_events = []
            # Serialize workflow_config back to YAML for validator
            try:
                import yaml as _yaml_ev
                workflow_yaml_content = _yaml_ev.safe_dump(workflow_config, sort_keys=False)
            except Exception as _wy_err:
                print(f"DEBUG: Failed to dump workflow YAML for events validation: {_wy_err}")
                workflow_yaml_content = ''
            agents_data_for_events.append({
                'type': 'workflow',
                'name': workflow_config.get('name', workflow_agent_name),
                'yaml_content': workflow_yaml_content
            })

            # Attempt to locate router component YAML via agents-catalog (mirrors enumeration logic)
            router_agent_name = None
            router_yaml_content = None
            try:
                catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
                if os.path.exists(catalog_path):
                    import yaml as _yaml_cat
                    with open(catalog_path, 'r', encoding='utf-8') as _cf:
                        _catalog = _yaml_cat.safe_load(_cf) or {}
                    for ea in _catalog.get('workflow_agents') or []:
                        if isinstance(ea, dict) and ea.get('name') == workflow_agent_name:
                            for comp in ea.get('components') or []:
                                if isinstance(comp, dict) and comp.get('type') == 'router':
                                    router_agent_name = comp.get('name')
                                    rel_path = comp.get('agent_config')
                                    if rel_path:
                                        router_path = os.path.normpath(os.path.join(os.path.dirname(catalog_path), rel_path))
                                        if os.path.exists(router_path):
                                            try:
                                                with open(router_path, 'r', encoding='utf-8') as _rf:
                                                    router_yaml_content = _rf.read()
                                                    print(f"DEBUG: Loaded router YAML '{router_agent_name}' from {router_path} (bytes={len(router_yaml_content)})")
                                                    # Print a small safe prefix to help diagnose encoding/parsing issues
                                                    preview = router_yaml_content[:120].replace('\n', ' ') if router_yaml_content else ''
                                                    print(f"DEBUG: Router YAML prefix: {preview}")
                                            except Exception as _rf_err:
                                                print(f"DEBUG: Failed reading router YAML for events validation: {_rf_err}")
                            break
            except Exception as _router_exc:
                print(f"DEBUG: Event validation router component discovery failed: {_router_exc}")

            if router_agent_name and router_yaml_content:
                # Mark the router component explicitly with type 'router' so
                # downstream validation does not rely on name-based heuristics.
                agents_data_for_events.append({
                    'type': 'router',
                    'name': router_agent_name,
                    'yaml_content': router_yaml_content
                })
            else:
                print("DEBUG: Router component YAML not available for events validation (will still validate workflow presence)")

            # === Added: Load all workflow agent components (planner, router, summarizer, etc.) for events validation ===
            try:
                # Reuse catalog_path if defined; otherwise compute relative path
                try:
                    catalog_path_multi = catalog_path  # type: ignore  # may already exist
                except Exception:
                    catalog_path_multi = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
                if os.path.exists(catalog_path_multi):
                    with open(catalog_path_multi, 'r', encoding='utf-8') as _cf_all:
                        _catalog_all = yaml.safe_load(_cf_all) or {}
                    for _ea in _catalog_all.get('workflow_agents') or []:
                        if isinstance(_ea, dict) and _ea.get('name') == workflow_agent_name:
                            existing_names = {a.get('name') for a in agents_data_for_events}
                            components_iter = _ea.get('components') or []
                            if not components_iter:
                                print(f"DEBUG: Entry agent '{workflow_agent_name}' has no components to append for events validation")
                            for _comp in components_iter:
                                if not isinstance(_comp, dict):
                                    continue
                                _c_name = _comp.get('name')
                                if not _c_name or _c_name in existing_names:
                                    continue  # skip duplicates or unnamed
                                _c_type = _comp.get('type') or 'agent'
                                _rel = _comp.get('agent_config')
                                if not _rel:
                                    print(f"DEBUG: Component '{_c_name}' missing agent_config path (skipping)")
                                    continue
                                _abs = os.path.normpath(os.path.join(os.path.dirname(catalog_path_multi), _rel))
                                if not os.path.exists(_abs):
                                    print(f"DEBUG: Component YAML path does not exist (multi-load): {_abs}")
                                    continue
                                try:
                                    with open(_abs, 'r', encoding='utf-8') as _cf_c:
                                        _yaml_txt = _cf_c.read()
                                    agents_data_for_events.append({'name': _c_name, 'type': _c_type, 'yaml_content': _yaml_txt})
                                    existing_names.add(_c_name)
                                    print(f"DEBUG: Added component '{_c_name}' type={_c_type} to agents_data_for_events (size={len(_yaml_txt)})")
                                except Exception as _comp_err:
                                    print(f"DEBUG: Failed reading component YAML '{_c_name}' for events validation: {_comp_err}")
                            break  # processed matching workflow agent
                else:
                    print(f"DEBUG: Catalog not found when attempting to load all components: {catalog_path_multi}")
            except Exception as _all_comp_err:
                print(f"DEBUG: Error while loading all components for events validation: {_all_comp_err}")
            # === End Added ===

            if callable(locals().get('events_validation')):
                ev_result = events_validation(agents_data_for_events)  # type: ignore
                # Serialize ValidationResult to plain dict
                errors_serialized = []
                try:
                    for e in getattr(ev_result, 'errors', []) or []:
                        errors_serialized.append({
                            'path': getattr(e, 'path', ''),
                            'message': getattr(e, 'message', '')
                        })
                except Exception as _es_err:
                    print(f"DEBUG: Failed to serialize events validation errors: {_es_err}")
                events_validation_result_serialized = {
                    'valid': getattr(ev_result, 'valid', False),
                    'errors': errors_serialized,
                    'data': getattr(ev_result, 'data', None)
                }
            else:
                events_validation_result_serialized = {
                    'valid': False,
                    'errors': [{'path': '<events_validation>', 'message': 'events_validation function unavailable'}],
                    'data': None
                }
        except Exception as _ev_unexpected:
            print(f"DEBUG: Unexpected error during events_validation: {_ev_unexpected}")
            events_validation_result_serialized = {
                'valid': False,
                'errors': [{'path': '<events_validation>', 'message': f'Exception: {_ev_unexpected}'}],
                'data': None
            }

        return jsonify({
            'success': True,
            'overall_status': overall_status,
            'can_deploy': all_good,
            'referenced_agents': referenced_agents,
            'validation_results': validation_results,
            'workflow_name': workflow_name_requested,
            'workflow_duplicate': workflow_duplicate_info,
            'events_validation': events_validation_result_serialized,
            'summary': {
                'total_agents': len(referenced_agents),
                'found_exact': len([r for r in validation_results if r['status'] == 'found']),
                'found_similar': len([r for r in validation_results if r['status'] == 'similar_found']),
                'not_found': len([r for r in validation_results if r['status'] == 'not_found']),
                'warnings': len([r for r in validation_results if r['status'] == 'warning'])
            }
        })

    except Exception as e:
        print(f"Error in validate_workflow_agent_dependencies: {e}")
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500

@app.route('/api/workflow-agent-publish/get-workflow-agents', methods=['POST'])
def get_workflow_agents():
    """Get the list of agents referenced in an Workflow Agent's workflow"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Invalid JSON data in request'}), 400
            
        workflow_agent_name = data.get('workflow_agent_name')
        if not workflow_agent_name:
            return jsonify({'error': 'workflow_agent_name is required'}), 400
            
        # Use the dedicated Workflow Agent workflow loader
        workflow_result = load_workflow_agent_workflow_config(workflow_agent_name)
        
        if not workflow_result['success']:
            if 'not found' in workflow_result['error'].lower():
                return jsonify({'error': workflow_result['error']}), 404
            else:
                return jsonify({'error': workflow_result['error']}), 400
        
        workflow_agents = workflow_result['referenced_agents']
        
        print(f"DEBUG: Found workflow agents for {workflow_agent_name}: {workflow_agents}")
        
        return jsonify({
            'success': True,
            'workflow_agents': workflow_agents,
            'total_agents': len(workflow_agents),
            'workflow_agent_name': workflow_agent_name
        })
        
    except Exception as e:
        print(f"Error in get_workflow_agents: {e}")
        return jsonify({'error': f'Internal server error: {str(e)}'}), 500

    # ---------------------------------------------------------------------------
    # Workflow Agent Draft Endpoints (save-temp, promote, delete-if-temp)
    # ---------------------------------------------------------------------------

@app.route('/api/workflow-agent-drafts/save-temp', methods=['POST'])
def save_temp_workflow_agent():
    """Persist (or update) a temporary draft Workflow Agent and its component YAML files.

    Expected JSON payload:
      {
        "agent_name": str,
        "description": str,
        "selected_agents": [str],          # coordinated agents
        "components": {                     # optional component yaml strings
            "workflow": "yaml...",
            "router": "yaml...",
            "planner": "yaml...",
            "summarizer": "yaml..."
        },
        "auto_expire_minutes": 1440        # optional (default 1440 = 1 day)
      }
    """
    try:
        data = request.get_json(silent=True) or {}
        agent_name = data.get('agent_name')
        description = data.get('description', 'Draft Workflow Agent')
        selected_agents = data.get('selected_agents') or []
        components_payload = data.get('components') or {}
        unique_component_names = data.get('unique_component_names') or {}
        auto_expire_minutes = int(data.get('auto_expire_minutes') or 1440)

        if not agent_name:
            return jsonify({'success': False, 'error': 'agent_name is required'}), 400

        # Base directories
        workflow_agents_base_dir = os.path.join(os.path.dirname(__file__), get_workflow_agents_dir())
        agent_specific_dir = os.path.join(workflow_agents_base_dir, agent_name)
        os.makedirs(agent_specific_dir, exist_ok=True)

        # Helper to write a component file if yaml provided
        def _write_component_file(component_key: str, yaml_text: str):
            if not yaml_text or not isinstance(yaml_text, str):
                return None
            
            # Use unique name for filename if available, fallback to generic pattern
            unique_name = unique_component_names.get(component_key)
            if not unique_name:
                # If no unique name is provided for a component, we cannot proceed with a predictable name.
                # This indicates an issue with the client-side request.
                print(f"⚠️  Draft save for '{agent_name}' missing unique name for component '{component_key}'. Skipping file write.")
                return None

            filename = f"{unique_name}.yaml"
            component_display_name = unique_name
            
            abs_path = os.path.join(agent_specific_dir, filename)
            try:
                with open(abs_path, 'w', encoding='utf-8') as f:
                    f.write(yaml_text)
                rel_catalog_path = f"{get_workflow_agents_dir()}{agent_name}/{filename}"
                return {'name': component_display_name, 'type': component_key, 'agent_config': rel_catalog_path}
            except Exception as w_err:
                print(f"⚠️ Failed writing component {component_key} for draft {agent_name}: {w_err}")
                return None

        # Write provided components
        component_records = []
        for ck in ['planner', 'router', 'summarizer', 'workflow']:
            comp_yaml = components_payload.get(ck)
            rec = _write_component_file(ck, comp_yaml) if comp_yaml else None
            if rec and ck != 'workflow':  # workflow tracked separately via agent_config
                component_records.append(rec)

        # Set workflow agent_config path using unique name if available
        unique_workflow_name = unique_component_names.get('workflow')
        if unique_workflow_name:
            workflow_rel = f"{get_workflow_agents_dir()}{agent_name}/{unique_workflow_name}.yaml"
        else:
            # This is a failure condition. The client MUST provide a unique name for the workflow.
            print(f"❌ Draft save for '{agent_name}' missing unique name for 'workflow' component. Aborting.")
            return jsonify({'success': False, 'error': "Missing unique name for 'workflow' component."}), 400

        # Load / update catalog
        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        import yaml
        catalog_data = {}
        if os.path.exists(catalog_path):
            try:
                with open(catalog_path, 'r', encoding='utf-8') as f:
                    loaded = yaml.safe_load(f)
                    if isinstance(loaded, dict):
                        catalog_data = loaded
            except Exception as c_err:
                print(f"⚠️ Draft save: failed to read existing catalog: {c_err}")
        if 'workflow_agents' not in catalog_data or not isinstance(catalog_data.get('workflow_agents'), list):
            catalog_data['workflow_agents'] = []

        # Build new/updated workflow agent draft record
    # datetime is already imported at the top
        created_ts = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')
        temp_meta = {'created_ts': created_ts, 'auto_expire_minutes': auto_expire_minutes}
        new_entry = {
            'name': agent_name,
            'description': description,
            'agent_config': workflow_rel,
            'components': component_records,
            'temp': temp_meta
        }

        # Replace existing draft (match by name) or append
        replaced = False
        for i, ea in enumerate(catalog_data['workflow_agents']):
            if isinstance(ea, dict) and ea.get('name') == agent_name:
                catalog_data['workflow_agents'][i] = new_entry
                replaced = True
                break
        if not replaced:
            catalog_data['workflow_agents'].append(new_entry)

        # Persist catalog
        try:
            with open(catalog_path, 'w', encoding='utf-8') as f:
                yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False, indent=2)
        except Exception as w_cat_err:
            return jsonify({'success': False, 'error': f'Failed to write catalog: {w_cat_err}'}), 500

        # Reload manager if available (triggers prune logic too)
        if agent_manager:
            try:
                agent_manager.reload_catalog()
            except Exception as r_err:
                print(f"⚠️ Draft save: reload_catalog failed: {r_err}")

        return jsonify({'success': True, 'draft': new_entry, 'replaced': replaced})
    except Exception as e:
        print(f"Error in save_temp_workflow_agent: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/workflow-agent-drafts/promote', methods=['POST'])
def promote_workflow_agent_draft():
    """Promote a draft Workflow Agent to a finalized one (remove temp metadata)."""
    try:
        data = request.get_json(silent=True) or {}
        agent_name = data.get('agent_name')
        if not agent_name:
            return jsonify({'success': False, 'error': 'agent_name is required'}), 400

        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        import yaml
        if not os.path.exists(catalog_path):
            return jsonify({'success': False, 'error': 'Catalog not found'}), 404
        with open(catalog_path, 'r', encoding='utf-8') as f:
            catalog_data = yaml.safe_load(f) or {}
        changed = False
        for ea in catalog_data.get('workflow_agents', []) or []:
            if isinstance(ea, dict) and ea.get('name') == agent_name:
                if 'temp' in ea:
                    ea.pop('temp', None)
                    changed = True
                break
        if changed:
            try:
                with open(catalog_path, 'w', encoding='utf-8') as f:
                    yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False, indent=2)
            except Exception as w_err:
                return jsonify({'success': False, 'error': f'Failed to persist catalog: {w_err}'}), 500
            if agent_manager:
                try:
                    agent_manager.reload_catalog()
                except Exception as r_err:
                    print(f"⚠️ promote reload failed: {r_err}")
        return jsonify({'success': True, 'promoted': changed})
    except Exception as e:
        print(f"Error in promote_workflow_agent_draft: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/workflow-agent-drafts/delete-if-temp', methods=['POST'])
def delete_workflow_agent_draft():
    """Delete a draft Workflow Agent only if it is still marked as temp.
    Removes catalog entry and any component files under Workflow-Agents/<agent_name>/."""
    try:
        data = request.get_json(silent=True) or {}
        agent_name = data.get('agent_name')
        if not agent_name:
            return jsonify({'success': False, 'error': 'agent_name is required'}), 400

        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        import yaml, shutil
        if not os.path.exists(catalog_path):
            return jsonify({'success': False, 'error': 'Catalog not found'}), 404
        with open(catalog_path, 'r', encoding='utf-8') as f:
            catalog_data = yaml.safe_load(f) or {}
        workflow_agents = catalog_data.get('workflow_agents') or []
        new_list = []
        removed = False
        for ea in workflow_agents:
            if isinstance(ea, dict) and ea.get('name') == agent_name and ea.get('temp'):
                removed = True
                continue
            new_list.append(ea)
        if removed:
            catalog_data['workflow_agents'] = new_list
            try:
                with open(catalog_path, 'w', encoding='utf-8') as f:
                    yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False, indent=2)
            except Exception as w_err:
                return jsonify({'success': False, 'error': f'Failed to persist updated catalog: {w_err}'}), 500
            # Delete directory
            draft_dir = os.path.join(os.path.dirname(__file__), get_workflow_agents_dir(), agent_name)
            if os.path.isdir(draft_dir):
                try:
                    shutil.rmtree(draft_dir)
                except Exception as del_err:
                    print(f"⚠️ Failed removing draft directory {draft_dir}: {del_err}")
            if agent_manager:
                try:
                    agent_manager.reload_catalog()
                except Exception as r_err:
                    print(f"⚠️ delete draft reload failed: {r_err}")
        return jsonify({'success': True, 'deleted': removed})
    except Exception as e:
        print(f"Error in delete_workflow_agent_draft: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

