def auto_start_default_container():
    """Start the default agent container if marked for auto-start"""
    global auto_start_agent, auto_start_paths
    
    if auto_start_agent and auto_start_paths and docker_client:
        print(f"\n🐳 Auto-starting container for: {auto_start_agent}")
        try:
            result = get_existing_agent_container(auto_start_agent)
            if result['success']:
                container_info = result.get('container_info', {})
                action = 'reused' if container_info.get('reused') else ('restarted' if container_info.get('restarted') else 'started')
                print(f"✅ Container {action} successfully: {container_info.get('name', 'unknown')}")
            else:
                print(f"⚠️  Warning: Could not start container: {result.get('error', 'Unknown error')}")
                print(f"💡 You can manually start it via: POST /api/agents/{auto_start_agent}/start-container")
        except Exception as e:
            print(f"⚠️  Warning: Error starting container: {e}")
            print(f"💡 You can manually start it via: POST /api/agents/{auto_start_agent}/start-container")
        finally:
            # Clear auto-start variables
            auto_start_agent = None
            auto_start_paths = None

@app.route('/api/config/llm', methods=['GET', 'POST'])
def manage_llm_config():
    """Get or update LLM configuration"""
    try:
        config_manager = DiscoveryConfigManager()
        
        if request.method == 'GET':
            # Return current LLM configuration
            llm_config = config_manager.get_llm_config()
            return jsonify({
                'success': True,
                'llm_config': llm_config
            })
        
        elif request.method == 'POST':
            # Update LLM configuration
            data = request.get_json()
            if not data:
                return jsonify({'error': 'Invalid JSON data in request'}), 400
            
            endpoint = data.get('endpoint')
            if not endpoint:
                return jsonify({'error': 'endpoint is required'}), 400
            
            # Update the configuration
            success = config_manager.update_llm_config(endpoint)
            
            if success:
                return jsonify({
                    'success': True,
                    'message': 'LLM configuration updated successfully',
                    'llm_config': config_manager.get_llm_config()
                })
            else:
                return jsonify({'error': 'Failed to update LLM configuration'}), 500
                
    except Exception as e:
        print(f"Error in manage_llm_config: {e}")
        return jsonify({'error': str(e)}), 500

@app.route('/api/test/yaml-validation', methods=['POST'])
def test_yaml_validation():
    """Test endpoint to verify YAML validation with retry logic"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Invalid JSON data in request'}), 400
        
        test_yaml = data.get('yaml_content', '')
        component_name = data.get('component', 'test')
        
        if not test_yaml:
            return jsonify({'error': 'yaml_content is required'}), 400
        
        # Test YAML validation
        try:
            # Replace template variables temporarily for validation
            test_content = test_yaml
            template_vars = ['{{userGoal}}', '{{nodePoolContext}}', '{{dataHandlingContext}}']
            for var in template_vars:
                test_content = test_content.replace(var, f'"{var}"')
            
            parsed = yaml.safe_load(test_content)
            
            return jsonify({
                'success': True,
                'message': f'YAML validation successful for {component_name}',
                'parsed_structure': str(type(parsed))
            })
            
        except yaml.YAMLError as e:
            return jsonify({
                'success': False,
                'error': f'YAML validation failed for {component_name}: {str(e)}',
                'error_type': 'yaml_error'
            }), 400
            
    except Exception as e:
        return jsonify({
            'success': False,
            'error': f'Test validation error: {str(e)}',
            'error_type': 'general_error'
        }), 500

def analyze_scripts_with_llm(scripts_path, conversation_manager, dockerfile_content="", use_parallel=True):
    """
    Analyze script files using LLM to extract API definitions and documentation
    Returns comprehensive API documentation suitable for agent generation
    
    Args:
        scripts_path: Path to scripts directory
        conversation_manager: ConversationManager instance for LLM calls
        dockerfile_content: Optional Dockerfile content for context
        use_parallel: If True, use parallel processing when available (default: True)
    """
    # Try parallel processing first if enabled and available
    if use_parallel:
        try:
            from parallel_integration import analyze_scripts_parallel_integration, get_parallel_config
            
            # Get LLM configuration from conversation manager or config
            config_manager = get_global_config_manager()
            llm_config = config_manager.get_llm_config()
            api_url = llm_config.get('api_url')
            api_key = llm_config.get('subscription_key')
            
            if api_url and api_key:
                parallel_config = get_parallel_config()
                max_concurrent = parallel_config.get('max_concurrent_requests', 5)
                
                print(f"🚀 Using PARALLEL script analysis ({max_concurrent} concurrent requests)")
                return analyze_scripts_parallel_integration(
                    scripts_path, api_url, api_key, dockerfile_content, max_concurrent
                )
        except ImportError:
            print("⚠️ Parallel processing not available, using sequential analysis")
        except Exception as e:
            print(f"⚠️ Parallel processing failed ({e}), falling back to sequential analysis")
    
    # Sequential fallback (original implementation)
    print("Using sequential script analysis")
    script_docs = []
    folder_structure = {}
    
    if os.path.isdir(scripts_path):
        # First, build the complete folder structure
        folder_structure = build_folder_structure(scripts_path)
        
        # Process each script file with folder context
        for root, dirs, files in os.walk(scripts_path):
            for file in files:
                if file.endswith(('.py', '.sh', '.ps1', '.bat', '.js', '.ts')):
                    file_path = os.path.join(root, file)
                    rel_path = os.path.relpath(file_path, scripts_path)
                    folder_context = os.path.dirname(rel_path) if os.path.dirname(rel_path) != '.' else 'root'
                    
                    # Read script content
                    try:
                        with open(file_path, 'r', encoding='utf-8') as f:
                            script_content = f.read()
                        
                        # Generate script documentation using LLM with folder context
                            script_doc = extract_script_api_documentation(
                                rel_path, script_content, folder_context, conversation_manager, dockerfile_content
                            )
                        if script_doc:
                            script_docs.append(script_doc)
                    except Exception as e:
                        print(f"Warning: Could not analyze {rel_path}: {e}")
    
    # Combine all script docs into comprehensive API documentation with structure awareness
    if script_docs:
        combined_api_doc = combine_script_docs_into_api_doc(
            script_docs, folder_structure, conversation_manager, dockerfile_content
        )
        
        # Final organizational pass with complete project context
        final_organized_doc = organize_final_documentation(
            combined_api_doc, folder_structure, scripts_path, conversation_manager, dockerfile_content
        )
        return final_organized_doc
    
    return "No script documentation available"

# get_llm_completion - now imported from llm_client module

def build_folder_structure(scripts_path):
    """Build a comprehensive folder structure representation"""
    structure = {
        'root_path': scripts_path,
        'folders': {},
        'files_by_folder': {},
        'total_files': 0,
        'folder_summary': []
    }
    
    for root, dirs, files in os.walk(scripts_path):
        rel_root = os.path.relpath(root, scripts_path)
        if rel_root == '.':
            rel_root = 'root'
        
        # Track folders
        structure['folders'][rel_root] = {
            'path': root,
            'subdirs': dirs,
            'script_files': [],
            'other_files': []
        }
        
        # Categorize files
        script_files = []
        other_files = []
        for file in files:
            if file.endswith(('.py', '.sh', '.ps1', '.bat', '.js', '.ts')):
                script_files.append(file)
                structure['total_files'] += 1
            elif file.endswith(('.md', '.txt', '.json', '.yaml', '.yml', '.cfg', '.ini', '.toml')):
                other_files.append(file)
        
        structure['folders'][rel_root]['script_files'] = script_files
        structure['folders'][rel_root]['other_files'] = other_files
        structure['files_by_folder'][rel_root] = script_files
        
        # Create folder summary
        if script_files or other_files:
            folder_desc = f"{rel_root}: {len(script_files)} scripts"
            if other_files:
                folder_desc += f", {len(other_files)} config/docs"
            structure['folder_summary'].append(folder_desc)
    
    return structure

def extract_script_api_documentation(script_path, script_content, folder_context, conversation_manager, dockerfile_content=""):
    """Extract API definition and documentation from a single script with folder context; dockerfile_content may be provided to help determine WORKDIR and runtime layout."""
    from script_chunker import chunk_script_by_structure, merge_chunk_analyses, estimate_tokens
    
    # Load the system prompt from prompts/tool-creation/extract_script_api_documentation.md
    prompts_dir = os.path.join(os.path.dirname(__file__), 'prompts', 'tool-creation')
    prompt_file = os.path.join(prompts_dir, 'extract_script_api_documentation.md')
    if not os.path.exists(prompt_file):
        # Fail loudly as requested
        raise FileNotFoundError(f"Required prompt file not found: {prompt_file}")

    with open(prompt_file, 'r', encoding='utf-8') as pf:
        system_prompt = pf.read()
    
    # Get encoder from conversation_manager for accurate token estimation
    encoder = None
    try:
        if conversation_manager and hasattr(conversation_manager, 'encoder'):
            encoder = conversation_manager.encoder
    except Exception:
        pass
    
    # Determine maximum chunk size based on conversation_manager settings
    max_chunk_tokens = 15000  # Conservative fallback
    try:
        if conversation_manager and hasattr(conversation_manager, 'max_tokens'):
            # Calculate available tokens: total - output budget - system prompt overhead
            available = int(conversation_manager.max_tokens)
            if hasattr(conversation_manager, 'max_output_tokens'):
                available -= int(conversation_manager.max_output_tokens)
            
            # Apply safety fraction (default 0.85 from config)
            safety_fraction = 0.85
            if hasattr(conversation_manager, 'safety_fraction'):
                safety_fraction = float(conversation_manager.safety_fraction)
            
            # Reserve tokens for system prompt, dockerfile, and other overhead (~5000 tokens)
            overhead_reserve = 5000
            max_chunk_tokens = int((available - overhead_reserve) * safety_fraction)
            
            # Clamp to reasonable range: min 10k (ensure we chunk if needed), max 40k (avoid too large chunks)
            max_chunk_tokens = max(10000, min(max_chunk_tokens, 40000))
            
            print(f"[chunking-config] max_tokens={conversation_manager.max_tokens}, available_after_output={available}, safety={safety_fraction}, chunk_limit={max_chunk_tokens}")
    except Exception as e:
        print(f"[chunking-config] Failed to read config, using default: {e}")
        pass
    
    # Chunk the script if needed
    chunks = chunk_script_by_structure(script_content, max_chunk_tokens, encoder)
    
    total_chars = len(script_content)
    total_tokens = estimate_tokens(script_content, encoder)
    
    if len(chunks) == 1:
        # Single chunk - use original logic
        user_prompt = f"""Analyze this script and extract its API definition and documentation:

**Script: {script_path}**
**Folder Context: {folder_context}**

Dockerfile (if provided):
```
{dockerfile_content}
```

```
{script_content}
```

Extract:
1. **Main Functions**: All public functions with parameters and descriptions
2. **Command Line Interface**: Arguments, flags, options
3. **Input/Output**: File formats, paths, data structures
4. **Configuration**: Required settings, environment variables
5. **Usage Patterns**: Common workflows and examples
6. **Error Handling**: Expected error cases and responses
7. **Module Role**: How this script fits within the {folder_context} folder structure

When writing example imports and usage examples, prefer module paths that reflect the runtime layout derived from the Dockerfile (e.g., omit a top-level package prefix if the Dockerfile's WORKDIR makes that folder the root). Format as structured documentation that an AI agent could use to understand how to call and use this script effectively within its project context."""

        start_time = time.time()
        response = get_llm_completion(system_prompt, user_prompt, session_id="script_analysis")
        duration = time.time() - start_time
        
        print(f"[script-analysis] path={script_path} size={total_chars} chars est_tokens={total_tokens} chunks=1 duration={duration:.2f}s mode=single")
        
        return {
            'script_path': script_path,
            'folder_context': folder_context,
            'documentation': response,
            'size': total_chars,
            'generation_stats': {
                'estimated_tokens': total_tokens,
                'chunks': 1,
                'duration_seconds': round(duration, 3),
                'response_chars': len(response) if response else 0
            }
        }
    
    # Multiple chunks - analyze each and merge
    print(f"📄 Large script detected: {script_path} ({total_chars} chars, ~{total_tokens} tokens)")
    print(f"   Splitting into {len(chunks)} chunks for complete analysis")
    
    chunk_results = []
    total_duration = 0
    
    for i, chunk in enumerate(chunks, 1):
        chunk_prompt = f"""Analyze this section of {script_path} and extract its API definitions:

**Script: {script_path}** (Chunk {i}/{len(chunks)}: {chunk['description']})
**Folder Context: {folder_context}**

Dockerfile (if provided):
```
{dockerfile_content}
```

```
{chunk['content']}
```

Extract ALL functions, classes, and APIs from this section. Include:
1. Function signatures and parameters
2. Return types and values
3. Purpose and usage
4. Dependencies and imports

Be comprehensive - this is part {i} of {len(chunks)} of the complete script."""

        try:
            start_time = time.time()
            chunk_response = get_llm_completion(system_prompt, chunk_prompt, session_id=f"script_analysis_chunk_{i}")
            chunk_duration = time.time() - start_time
            total_duration += chunk_duration
            
            chunk_results.append(chunk_response)
            print(f"   ✓ Chunk {i}/{len(chunks)} analyzed ({chunk['tokens']} tokens, {chunk_duration:.2f}s)")
        except Exception as e:
            print(f"   ✗ Chunk {i}/{len(chunks)} failed: {e}")
            chunk_results.append(f"# Chunk {i} Analysis Failed\n\nError: {e}\n\n```\n{chunk['content'][:500]}...\n```")
    
    # Merge chunk results
    merged_documentation = merge_chunk_analyses(chunk_results, script_path)
    
    print(f"[script-analysis] path={script_path} size={total_chars} chars est_tokens={total_tokens} chunks={len(chunks)} duration={total_duration:.2f}s mode=chunked")
    
    return {
        'script_path': script_path,
        'folder_context': folder_context,
        'documentation': merged_documentation,
        'size': total_chars,
        'generation_stats': {
            'estimated_tokens': total_tokens,
            'chunks': len(chunks),
            'duration_seconds': round(total_duration, 3),
            'response_chars': len(merged_documentation) if merged_documentation else 0
        }
    }


def combine_script_docs_into_api_doc(script_docs, folder_structure, conversation_manager, dockerfile_content=""):
    try:
        from combiner import combine_script_docs_shared
        return combine_script_docs_shared(script_docs, folder_structure, conversation_manager, dockerfile_content)
    except Exception as e:
        print(f"Falling back: combiner.shared failed: {e}")
        return "Error generating comprehensive API documentation"

def organize_final_documentation(combined_api_doc, folder_structure, scripts_path, conversation_manager, dockerfile_content=""):
    """Final organizational pass to create the most logical and comprehensive documentation"""
    # Load system prompt from prompts/tool-creation/organize_final_documentation.md
    prompts_dir = os.path.join(os.path.dirname(__file__), 'prompts', 'tool-creation')
    organize_prompt_file = os.path.join(prompts_dir, 'organize_final_documentation.md')
    if not os.path.exists(organize_prompt_file):
        raise FileNotFoundError(f"Required prompt file not found: {organize_prompt_file}")
    with open(organize_prompt_file, 'r', encoding='utf-8') as opf:
        system_prompt = opf.read()

    # Create enhanced context about the project
    project_context = f"""
**Project Path**: {scripts_path}
**Total Folders**: {len(folder_structure['folders'])}
**Total Script Files**: {folder_structure['total_files']}

**Folder Structure**:
{chr(10).join(folder_structure['folder_summary'])}

**Folder Details**:
"""
    
    for folder_name, folder_info in folder_structure['folders'].items():
        if folder_info['script_files']:
            project_context += f"- **{folder_name}**: {', '.join(folder_info['script_files'])}"
            if folder_info['other_files']:
                project_context += f" (+ {len(folder_info['other_files'])} config/doc files)"
            project_context += "\n"

    user_prompt = f"""Take this comprehensive API documentation and organize it into the most logical, actionable format:

{project_context}

**Current Documentation**:
{combined_api_doc}

Create the FINAL, DEFINITIVE documentation that includes:

1. **Executive Summary**: What this tool/project does and its main value proposition
2. **Quick Start Guide**: Essential steps to get started
3. **Core Workflows**: The main use cases and execution patterns
4. **API Reference**: Detailed function/script documentation organized logically
5. **Integration Patterns**: How different components work together
6. **File Handling**: Input/output patterns, formats, and conventions
7. **Configuration & Environment**: Setup requirements and parameters
8. **Error Handling**: Common issues and troubleshooting
9. **AI Agent Guidelines**: Specific guidance for automated usage

This should be the COMPLETE reference that an AI agent needs to effectively use this entire project. Organize information by logical workflows rather than just folder structure."""

    # Include Dockerfile context explicitly if provided so the final organization step can account for runtime layout and installed tools
    if dockerfile_content:
        user_prompt = """Dockerfile (if provided):
```
# Include full Dockerfile content in prompt to ensure accurate import/layout derivation.
if len(dockerfile_content) > 200000:
    try:
        print(f"DEBUG: Embedding large Dockerfile content ({len(dockerfile_content)} chars) into LLM prompt")
    except Exception:
        pass

""" + dockerfile_content + """

""" + user_prompt

    try:
        # Determine runtime output token budget to use for final organization step.
        # Prefer conversation_manager.max_output_tokens when available; otherwise fall back to discovery config.
        runtime_max_output = None
        try:
            if conversation_manager is not None and getattr(conversation_manager, 'max_output_tokens', None):
                runtime_max_output = int(getattr(conversation_manager, 'max_output_tokens'))
        except Exception:
            runtime_max_output = None

        if not runtime_max_output:
            try:
                conv_cfg = DiscoveryConfigManager().get_conversation_config() or {}
                runtime_max_output = int(conv_cfg.get('max_output_tokens', 0) or 0) or None
            except Exception:
                runtime_max_output = None

        if runtime_max_output:
            # Use the configured output budget (not the model context size) for max generation length
            print(f"🔢 Using max_output_tokens={runtime_max_output} for final_doc_organization")
            response = get_llm_completion(
                system_prompt, user_prompt, session_id="final_doc_organization", max_tokens=runtime_max_output
            )
        else:
            print("🔢 No configured max_output_tokens found; using get_llm_completion default for final_doc_organization")
            response = get_llm_completion(
                system_prompt, user_prompt, session_id="final_doc_organization"
            )

        return response
    except Exception as e:
        print(f"Error in final documentation organization: {e}")
        return combined_api_doc  # Return the combined doc as fallback

@app.route('/api/generate-tool-agent-definitions', methods=['POST'])
def generate_tool_agent_definitions():
    """Generate both tool definition and agent definition YAMLs for a tool agent"""
    try:
        print("🔄 Starting tool agent definitions generation")
        data = request.json
                
        if not data:
            return jsonify({'error': 'Invalid JSON data in request'}), 400
        
        # Initialize configuration manager to get ACR settings
        from discovery_config_manager import DiscoveryConfigManager
        config_manager = DiscoveryConfigManager()
        azure_config = config_manager.get_azure_config()
        acr_name = azure_config.get('acr_name', 'contoso.azurecr.io')  # Default fallback
        
        # Initialize errors list to collect any issues
        errors = []
        
        # Check if parallel processing is available in this function context
        parallel_available = False
        try:
            from parallel_integration import analyze_uploaded_scripts_parallel, get_parallel_config
            parallel_available = True
        except ImportError:
            parallel_available = False
        
        # Extract form data
        tool_name = data.get('toolName', '').strip()
        tool_description = data.get('toolDescription', '').strip()
        docker_image = data.get('dockerImage', '').strip()
        dockerfile_path = data.get('dockerfilePath', '').strip()
        api_specs = data.get('apiSpecs', '').strip()
        apis_path = data.get('apisPath', '').strip()
        scripts_path = data.get('scriptsPath', '').strip()
        working_directory = data.get('workingDirectory', '').strip()
        
        # Extract SKU data
        recommended_skus = data.get('recommended_skus', [])
        min_resources = data.get('min_resources', {})
        max_resources = data.get('max_resources', {})
        sku_details = data.get('sku_details', [])

        # Generate SKU resource information for prompt template
        sku_resource_info = ""
        if recommended_skus or min_resources or max_resources:
            sku_resource_info = "\n\n**MANDATORY SKU AND RESOURCE CONSTRAINTS:**"
            
            if recommended_skus:
                sku_resource_info += f"\n- REQUIRED recommended_sku field: {recommended_skus}"
                sku_resource_info += f"\n- You MUST use exactly these SKUs: {', '.join(recommended_skus)}"
                
                if min_resources and max_resources:
                    min_cpu = min_resources.get('cpu', 'N/A')
                    min_mem = min_resources.get('memory_gb', 'N/A')
                    max_cpu = max_resources.get('cpu', 'N/A')
                    max_mem = max_resources.get('memory_gb', 'N/A')
                    
                    sku_resource_info += f"\n- REQUIRED min_resources: cpu: {min_cpu}, ram: {min_mem}Gi"
                    sku_resource_info += f"\n- REQUIRED max_resources: cpu: {max_cpu}, ram: {max_mem}Gi"
                    sku_resource_info += f"\n- DO NOT exceed these limits or use different values"
                    sku_resource_info += f"\n- DO NOT substitute other SKUs or resource values"
            else:
                sku_resource_info += "\n- No specific SKU constraints provided - use appropriate defaults"

        # Build categorized internal list from per-session upload folder. sessionId is required.
        script_dir = os.path.dirname(os.path.abspath(__file__))
        session_id = data.get('sessionId') or data.get('sessionid') or None
        if not session_id:
            return jsonify({'error': 'sessionId is required for tool-agent generation and uploads must be provided in user-session/<sessionId>/uploads'}), 400

        shared_input_dir = os.path.join(script_dir, 'user-session', session_id, 'uploads')
        # Fail if session upload directory is not present or inaccessible
        if not os.path.exists(shared_input_dir) or not os.path.isdir(shared_input_dir):
            return jsonify({'error': f'Session uploads not found or inaccessible for sessionId {session_id} (expected path: {shared_input_dir})'}), 400

        try:
            # Walk the shared_input_dir recursively and record relative paths so folder structure is preserved
            inputs_summary = {'dockerfiles': [], 'docs': [], 'scripts': [], 'other': [], 'all_files': []}
            if os.path.exists(shared_input_dir):
                for root, dirs, files in os.walk(shared_input_dir):
                    for fname in files:
                        fpath = os.path.join(root, fname)
                        # relative path from the uploads base
                        rel = os.path.relpath(fpath, shared_input_dir).replace('\\', '/')
                        inputs_summary['all_files'].append(rel)
                        ln = fname.lower()
                        if ln == 'dockerfile' or ln.endswith('dockerfile') or ln.endswith('.dockerfile'):
                            inputs_summary['dockerfiles'].append(rel)
                        elif ln.endswith(('.yaml', '.yml', '.json', '.md', '.txt')):
                            inputs_summary['docs'].append(rel)
                        elif ln.endswith(('.py', '.js', '.ts', '.go', '.java', '.sh', '.ps1', '.bat', '.c', 'cpp', '.rs', '.jl', '.R')):
                            # Exclude entrypoint.sh files as they confuse AI agents
                            if ln == 'entrypoint.sh':
                                inputs_summary['other'].append(rel)  # Categorize as 'other' instead of 'scripts'
                                print(f"🚫 Excluded entrypoint.sh from script analysis: {rel}")
                            else:
                                inputs_summary['scripts'].append(rel)
                        else:
                            inputs_summary['other'].append(rel)

            # Debug trace: show all uploaded files with their relative paths
            try:
                print(f"📥 Uploaded files in session {session_id}: {len(inputs_summary.get('all_files', []))} files")
                for f in inputs_summary.get('all_files', [])[:200]:
                    print(f"  - {f}")
            except Exception:
                pass
        except Exception as e:
            inputs_summary = {'dockerfiles': [], 'docs': [], 'scripts': [], 'other': []}
            print(f"Warning: could not scan shared input dir: {e}")

        print(f"[TRACE] generate_tool_agent_definitions - Tool Agent Generation Request: Generating tool agent for '{tool_name}' (session: {session_id})")

        if not tool_name:
            return jsonify({'error': 'toolName is required'}), 400
        # If no description provided, let the LLM generate a short description from uploaded files
        if not tool_description:
            tool_description = ''

        # Helper function to resolve paths with working directory context
        def resolve_path_with_context(path_input, path_type="file"):
            """Resolve a path with working directory context"""
            if not path_input:
                return None, []
            
            resolved_path = None
            attempted_paths = []
            
            # Try absolute path first
            if os.path.isabs(path_input):
                attempted_paths.append(path_input)
                if os.path.exists(path_input):
                    resolved_path = path_input
            else:
                # Try relative paths with multiple base directories
                base_dirs = []
                
                # Add working directory first if provided
                if working_directory and os.path.exists(working_directory):
                    base_dirs.append(working_directory)
                
                # Add standard fallback directories
                # Prefer the ephemeral uploaded inputs directory so uploaded filenames resolve
                try:
                    # shared_input_dir is defined earlier in the outer scope for this request
                    if 'shared_input_dir' in locals() and os.path.exists(shared_input_dir):
                        base_dirs.append(shared_input_dir)
                except Exception:
                    pass

                base_dirs.extend([
                    os.getcwd(),  # Current working directory
                    os.path.dirname(os.path.abspath(__file__)),  # Directory of this script
                    os.path.join(os.path.dirname(os.path.abspath(__file__)), '..', '..'),  # Repository root
                    'C:\\Code\\MicrosoftDiscoveryTemplates'  # Hardcoded fallback
                ])
                
                for base_dir in base_dirs:
                    if os.path.exists(base_dir):
                        candidate_path = os.path.normpath(os.path.join(base_dir, path_input))
                        attempted_paths.append(candidate_path)
                        if os.path.exists(candidate_path):
                            resolved_path = candidate_path
                            break
            
            return resolved_path, attempted_paths

        # Read additional context files if provided
        dockerfile_content = ""
        api_documentation = ""
        scripts_info = ""
        
        print("Reading additional context files")

        # Read Dockerfile content
        if dockerfile_path:
            resolved_dockerfile_path, attempted_dockerfile_paths = resolve_path_with_context(dockerfile_path)
            if resolved_dockerfile_path:
                try:
                    with open(resolved_dockerfile_path, 'r', encoding='utf-8') as f:
                        dockerfile_content = f.read()
                    print(f"  ✅ Dockerfile read: {len(dockerfile_content)} chars from {resolved_dockerfile_path}")
                except Exception as e:
                    error_msg = f"Could not read Dockerfile: {str(e)}"
                    errors.append(error_msg)
                    print(f"  ❌ {error_msg}")
            else:
                print(f"  ⚠️ Dockerfile not found. Original: {dockerfile_path}")
                print(f"      Attempted paths: {attempted_dockerfile_paths}")
        else:
            # Try to find a Dockerfile in the uploaded ephemeral inputs
            if inputs_summary.get('dockerfiles'):
                candidate = inputs_summary['dockerfiles'][0]
                candidate_path = os.path.join(shared_input_dir, candidate)
                try:
                    with open(candidate_path, 'r', encoding='utf-8') as f:
                        dockerfile_content = f.read()
                    dockerfile_path = candidate_path
                    print(f"  ✅ Dockerfile loaded from uploads: {candidate}")
                except Exception as e:
                    error_msg = f"Could not read uploaded Dockerfile {candidate}: {str(e)}"
                    errors.append(error_msg)
                    print(f"  ❌ {error_msg}")
            else:
                print(f"  ⚠️ Dockerfile path not provided and no uploaded Dockerfile found")
        
        # Read API documentation
        if apis_path:
            resolved_apis_path, attempted_apis_paths = resolve_path_with_context(apis_path)
            if resolved_apis_path:
                try:
                    with open(resolved_apis_path, 'r', encoding='utf-8') as f:
                        api_documentation = f.read()
                        print(f"  ✅ API documentation read: {len(api_documentation)} chars from {resolved_apis_path}")
                except Exception as e:
                    error_msg = f"Could not read API documentation: {str(e)}"
                    errors.append(error_msg)
                    print(f"  ❌ {error_msg}")
            else:
                print(f"  ⚠️ API documentation file not found. Original: {apis_path}")
                print(f"      Attempted paths: {attempted_apis_paths}")
        elif api_specs:
            api_documentation = api_specs
            print(f"  ✅ API specs from form: {len(api_documentation)} chars")
        else:
            # Check uploaded docs in ephemeral storage
            if inputs_summary.get('docs'):
                combined = []
                for doc in inputs_summary['docs']:
                    p = os.path.join(shared_input_dir, doc)
                    try:
                        with open(p, 'r', encoding='utf-8') as f:
                            combined.append(f"\n--- {doc} ---\n" + f.read())
                    except Exception as e:
                        errors.append(f"Could not read uploaded doc {doc}: {str(e)}")
                api_documentation = "\n".join(combined)
                print(f"  ✅ API documentation aggregated from uploads: {len(api_documentation)} chars")
            else:
                print(f"  ⚠️ No API documentation provided and none found in uploads")
        
        # Read and analyze scripts information
        if scripts_path:
            resolved_scripts_path, attempted_paths = resolve_path_with_context(scripts_path)
            
            print("Scripts path resolution")
            print(f"      Original path: {scripts_path}")
            print(f"      Attempted paths: {attempted_paths}")
            
            if resolved_scripts_path:
                print(f"      ✅ Resolved to: {resolved_scripts_path}")
                
                if os.path.isdir(resolved_scripts_path):
                    # Analyze script directory with LLM-generated documentation
                    try:
                        print("Analyzing scripts directory with enhanced LLM analysis")
                        print("  • Building folder structure and relationships")
                        print("  • Analyzing individual scripts with context")
                        print("  • Combining into comprehensive API documentation")
                        print("  • Final organizational pass for optimal structure")
                        if llm_available():
                            scripts_info = analyze_scripts_with_llm(resolved_scripts_path, conversation_manager)
                            print(f"  ✅ Scripts analyzed with enhanced 3-stage LLM process: {len(scripts_info)} chars")
                        else:
                            # Provide diagnostic info so it's clear why the enhanced LLM path was not taken
                            try:
                                print("  ⚠️ Skipping enhanced LLM analysis due to missing LLM configuration or credentials:")
                                print(f"     - conversation_manager set: {bool(conversation_manager)}")
                                print(f"     - api_url set: {bool(api_url)}; preview: {str(api_url)[:120] if api_url else 'N/A'}")
                                print(f"     - subscription_key set: {bool(subscription_key)}")
                            except Exception:
                                pass
                    except Exception as e:
                        error_msg = f"Could not analyze scripts directory: {str(e)}"
                        errors.append(error_msg)
                        print(f"  ❌ {error_msg}")
                elif os.path.isfile(resolved_scripts_path):
                    # Analyze single script file
                    try:
                        with open(resolved_scripts_path, 'r', encoding='utf-8') as f:
                            script_content = f.read()
                        
                        if llm_available():
                            print(f"  🔍 Analyzing single script file with LLM: {resolved_scripts_path}")
                            script_doc = extract_script_api_documentation(
                                os.path.basename(resolved_scripts_path), script_content, "single_file", conversation_manager
                            )
                            scripts_info = script_doc['documentation'] if script_doc else f"Script analysis failed for {os.path.basename(resolved_scripts_path)}"
                            print(f"  ✅ Script file analyzed with LLM: {len(scripts_info)} chars")
                        else:
                            scripts_info = f"Script content from {os.path.basename(resolved_scripts_path)} (raw content - LLM analysis not available):\n{script_content}"
                            print(f"  ⚠️ Script file read (basic mode): {len(scripts_info)} chars from {resolved_scripts_path}")
                    except Exception as e:
                        error_msg = f"Could not read script file: {str(e)}"
                        errors.append(error_msg)
                        print(f"  ❌ {error_msg}")
            else:
                error_msg = f"Scripts path could not be resolved. Attempted paths: {attempted_paths}"
                errors.append(error_msg)
                print(f"  ❌ {error_msg}")
        else:
            # Try to gather uploaded scripts from ephemeral storage with PARALLEL processing
            if inputs_summary.get('scripts'):
                try:
                    print(f"Starting analysis of {len(inputs_summary['scripts'])} uploaded scripts")
                    
                    # SSE: Script analysis started
                    if SSE_AVAILABLE:
                        try:
                            event_bus.publish(
                                EventChannel.VALIDATION,
                                f"Analyzing {len(inputs_summary['scripts'])} script files...",
                                level=EventLevel.PROGRESS,
                                context={'generation_id': generation_id, 'tool_name': tool_name}
                            )
                        except Exception:
                            pass

                    # Attempt parallel analysis if available and LLM configuration present
                    used_parallel = False
                    if parallel_available and llm_available():
                        try:
                            parallel_config = get_parallel_config()
                            max_concurrent = parallel_config.get('max_concurrent_requests', 4)

                            script_docs, scripts_info = analyze_uploaded_scripts_parallel(
                                shared_input_dir, api_url, subscription_key, dockerfile_content, max_concurrent, conversation_manager
                            )
                            print(f"  ✅ PARALLEL analysis completed: {len(script_docs)} scripts processed")
                            
                            # SSE: Script analysis completed
                            if SSE_AVAILABLE:
                                try:
                                    event_bus.publish(
                                        EventChannel.VALIDATION,
                                        f"✅ Script analysis complete ({len(script_docs)} files)",
                                        level=EventLevel.SUCCESS,
                                        context={'generation_id': generation_id, 'tool_name': tool_name}
                                    )
                                except Exception:
                                    pass
                            
                            used_parallel = True
                        except Exception as parallel_error:
                            print(f"  ⚠️ Parallel processing failed: {parallel_error}, falling back to sequential")
                            used_parallel = False

                    # If we didn't run parallel processing, do sequential processing
                    if not (parallel_available and used_parallel and script_docs):
                        if not parallel_available:
                            print(f"  ⚠️ Parallel processing not available, using sequential analysis")
                        elif not llm_available():
                            print(f"  ⚠️ LLM not available, using basic processing")

                        script_docs = []
                        script_files_count = 0
                        for s in inputs_summary['scripts']:
                            # s is a relative path (e.g., 'subdir/io_utils.py') relative to shared_input_dir
                            p = os.path.join(shared_input_dir, *s.split('/'))
                            try:
                                with open(p, 'r', encoding='utf-8') as f:
                                    content = f.read()
                                script_files_count += 1

                                # Debug trace: show the exact uploaded path being processed
                                try:
                                    print(f"Processing uploaded script -> session: {session_id}; uploaded_name: '{s}'; full_path: '{p}'; size: {len(content)}")
                                except Exception:
                                    pass

                                # If conversation_manager and LLM are available, analyze each script individually
                                folder_ctx = os.path.dirname(s) or '.'
                                if llm_available():
                                    try:
                                        print(f"  🎯 Sending script to LLM analysis: '{s}'")
                                        doc = extract_script_api_documentation(s, content, folder_ctx, conversation_manager, dockerfile_content)
                                        if doc:
                                            script_docs.append(doc)
                                    except Exception as e:
                                        # Fallback to raw inclusion if analysis fails for a file
                                        errors.append(f"LLM analysis failed for {s}: {e}")
                                        script_docs.append({'script_path': s, 'folder_context': folder_ctx, 'documentation': f"# {s}\n" + content, 'size': len(content)})
                                else:
                                    # No LLM available: include raw content with header
                                    script_docs.append({'script_path': s, 'folder_context': folder_ctx, 'documentation': f"# {s}\n" + content, 'size': len(content)})

                            except Exception as e:
                                errors.append(f"Could not read uploaded script {s}: {str(e)}")

                        # Combine per-file docs into a single organized API document when possible
                        if script_docs:
                            try:
                                # Build an actual folder structure from the uploads directory so the combiner gets accurate context
                                folder_structure = build_folder_structure(shared_input_dir)
                                folder_structure['total_files'] = len(script_docs)
                                # Debug trace: show folder_structure summary before combining
                                try:
                                    print(f"🔗 Combining {len(script_docs)} script docs; folder_summary: {folder_structure.get('folder_summary')} ; root_path: {folder_structure.get('root_path')}")
                                    # Also print a short tree of folders
                                    for k, v in folder_structure.get('folders', {}).items():
                                        print(f"   - folder: '{k}' scripts: {len(v.get('script_files', []))} other: {len(v.get('other_files', []))}")
                                except Exception:
                                    pass

                                combined = combine_script_docs_into_api_doc(script_docs, folder_structure, conversation_manager, dockerfile_content)
                                scripts_info = combined
                                print(f"  ✅ Scripts analyzed and combined from uploads: {len(script_docs)} files")
                            except Exception as e:
                                # Fallback: concatenate raw docs
                                scripts_info = "\n\n".join([d.get('documentation','') for d in script_docs])
                                errors.append(f"Could not combine script docs: {e}")
                                print(f"  ⚠️ Could not combine script docs into organized doc: {e}")
                        else:
                            scripts_info = ''
                            print(f"  ⚠️ No uploaded scripts could be read for analysis")

                except Exception as e:
                    errors.append(f"Could not analyze uploaded scripts: {str(e)}")
                    print(f"  ❌ Could not analyze uploaded scripts: {str(e)}")
            else:
                print(f"  ⚠️ No scripts path provided and none found in uploads")

        # Load sample templates using DiscoveryConfigManager
        if not config_manager:
            return jsonify({'error': 'Configuration manager not available'}), 500
        
        # SSE: Loading templates
        if SSE_AVAILABLE:
            try:
                event_bus.publish(
                    EventChannel.VALIDATION,
                    "Loading templates...",
                    level=EventLevel.INFO,
                    context={'generation_id': generation_id, 'tool_name': tool_name}
                )
            except Exception:
                pass
            
        template_files = config_manager.get_template_files()
        # Get the configured ToolAgent template path
        agent_sample_relative_path = template_files.get('ToolAgent')
        agent_sample_path = os.path.join(os.path.dirname(__file__), agent_sample_relative_path)
        # Get the configured ToolDefinition template path
        tool_sample_relative_path = template_files.get('ToolDefinition')
        if not tool_sample_relative_path:
            return jsonify({'error': 'ToolDefinition template not configured in discovery_config.json'}), 500
        tool_sample_path = os.path.join(os.path.dirname(__file__), tool_sample_relative_path)
        
        print(f"\n📋 Loading sample templates:")
        print(f"  - Agent sample: {agent_sample_path}")
        print(f"  - Tool sample: {tool_sample_path}")
        
        if not os.path.exists(agent_sample_path):
            return jsonify({'error': f'Agent sample template not found: {agent_sample_path}'}), 500
        if not os.path.exists(tool_sample_path):
            return jsonify({'error': f'Tool sample template not found: {tool_sample_path}'}), 500
        
        # Read sample templates
        with open(agent_sample_path, 'r', encoding='utf-8') as f:
            agent_sample_content = f.read()
        with open(tool_sample_path, 'r', encoding='utf-8') as f:
            tool_sample_content = f.read()
            
        print(f"  ✅ Agent sample loaded: {len(agent_sample_content)} chars")
        print(f"  ✅ Tool sample loaded: {len(tool_sample_content)} chars")
        
        # ===============================
        # INPUT SUMMARY
        # ===============================
        print(f"\nGeneration inputs: Dockerfile({len(dockerfile_content) if dockerfile_content else 0} chars), Scripts({len(scripts_info) if scripts_info else 0} chars), API Docs({len(api_documentation) if api_documentation else 0} chars)")
        
        # Generate a unique generation_id for SSE context filtering
        import uuid
        generation_id = session_id or str(uuid.uuid4())[:8]
        
        # Generate tool definition
        tool_definition = ""
        agent_definition = ""
        errors = []

        # If LLM is available via discovery config and conversation manager, run generation flow
        if llm_available():
            try:
                # Load tool definition prompts
                tool_system_path = os.path.join(os.path.dirname(__file__), 'prompts', 'tool-agent', 'tool_system.txt')
                tool_user_path = os.path.join(os.path.dirname(__file__), 'prompts', 'tool-agent', 'tool_user.txt')

                if not os.path.exists(tool_system_path) or not os.path.exists(tool_user_path):
                    return jsonify({'error': 'Tool generation prompts not found'}), 500

                with open(tool_system_path, 'r', encoding='utf-8') as f:
                    tool_system_prompt = f.read()
                with open(tool_user_path, 'r', encoding='utf-8') as f:
                    tool_user_template = f.read()

                # Prepare variables for tool definition generation
                domain = _extract_domain_from_description(tool_description)

                # Use specific SKU constraints if provided, otherwise fall back to domain-based hints
                if recommended_skus or min_resources or max_resources:
                    resource_hints = "User has selected specific SKU constraints (see below)"
                else:
                    resource_hints = _get_resource_hints_for_domain(domain)

                tool_prompt_variables = {
                    'tool_name': tool_name.lower().replace(' ', ''),
                    'tool_description': tool_description,
                    'domain': domain,
                    'docker_image': docker_image or f"{acr_name}/{tool_name.lower().replace(' ', '')}-image:latest",
                    'api_specs': api_documentation or api_specs or "Tool-specific APIs",
                    'dockerfile_content': dockerfile_content,
                    'api_documentation': api_documentation,
                    'scripts_info': scripts_info,
                    'sku_resource_info': sku_resource_info,
                    'resource_hints': resource_hints,
                    'sample_content': tool_sample_content
                }

                # Generate tool definition
                print(f"\n🤖 Generating tool definition...")
                
                # SSE: Tool definition generation started
                if SSE_AVAILABLE:
                    try:
                        print(f"[SSE] Publishing tool definition event for generation_id={generation_id}")
                        event_bus.publish(
                            EventChannel.VALIDATION,
                            "Generating tool definition...",
                            level=EventLevel.PROGRESS,
                            context={'generation_id': generation_id, 'tool_name': tool_name}
                        )
                        print(f"[SSE] Tool definition event published")
                    except Exception as e:
                        print(f"[SSE] Failed to publish tool definition event: {e}")
                
                tool_user_prompt = substitute_prompt_variables(tool_user_template, tool_prompt_variables)

                # Generate tool definition with schema validation
                tool_definition, tool_success, tool_error = validate_and_retry_tool_agent_generation(
                    'tool', tool_system_prompt, tool_user_prompt, conversation_manager, max_retries=2
                )

                print(f"  {'✅' if tool_success else '❌'} Tool: {len(tool_definition) if tool_success else 'Failed'} chars")
                if not tool_success:
                    print(f"    Error: {tool_error}")
                    errors.append(f"Tool definition generation failed: {tool_error}")

                # Load agent definition prompts
                agent_system_path = os.path.join(os.path.dirname(__file__), 'prompts', 'tool-agent', 'agent_system.txt')
                agent_user_path = os.path.join(os.path.dirname(__file__), 'prompts', 'tool-agent', 'agent_user.txt')

                if not os.path.exists(agent_system_path) or not os.path.exists(agent_user_path):
                    return jsonify({'error': 'Agent generation prompts not found'}), 500

                with open(agent_system_path, 'r', encoding='utf-8') as f:
                    agent_system_prompt = f.read()
                with open(agent_user_path, 'r', encoding='utf-8') as f:
                    agent_user_template = f.read()

                # Attempt to extract a canonical tool description from the generated tool YAML
                tool_description_canonical = ''
                try:
                    if tool_definition and isinstance(tool_definition, str) and tool_definition.strip():
                        parsed = yaml.safe_load(tool_definition)
                        if isinstance(parsed, dict):
                            if parsed.get('description'):
                                tool_description_canonical = str(parsed.get('description'))
                            else:
                                tool_block = parsed.get('tool')
                                if isinstance(tool_block, dict) and tool_block.get('description'):
                                    tool_description_canonical = str(tool_block.get('description'))
                except Exception as _e:
                    print(f"Warning: could not parse tool_definition YAML to extract description: {_e}")

                if not tool_description_canonical:
                    tool_description_canonical = tool_description or ''

                print(f"  🔎 tool_description_canonical: '{tool_description_canonical[:200]}'")

                agent_prompt_variables = {
                    'agent_name': tool_name.replace(' ', ''),
                    'agent_description': tool_description_canonical or tool_description,
                    'tool_description_canonical': tool_description_canonical,
                    'domain': domain,
                    'tool_focus': tool_name,
                    'model_endpoint': config_manager.get_llm_endpoint() if config_manager else "http://localhost:1234/v1/models/gpt-4o",
                    'dockerfile_content': dockerfile_content,
                    'api_documentation': api_documentation,
                    'scripts_info': scripts_info,
                    'resource_hints': resource_hints,
                    'sku_resource_info': sku_resource_info,
                    'sample_content': agent_sample_content
                }

                # Generate agent definition
                print(f"\nGenerating agent definition...")
                
                # SSE: Agent definition generation started
                if SSE_AVAILABLE:
                    try:
                        event_bus.publish(
                            EventChannel.VALIDATION,
                            "Generating agent definition...",
                            level=EventLevel.PROGRESS,
                            context={'generation_id': generation_id, 'tool_name': tool_name}
                        )
                    except Exception:
                        pass
                
                agent_user_prompt = substitute_prompt_variables(agent_user_template, agent_prompt_variables)

                agent_definition, agent_success, agent_error = validate_and_retry_tool_agent_generation(
                    'agent', agent_system_prompt, agent_user_prompt, conversation_manager, max_retries=2
                )

                print(f"  {'✅' if agent_success else '❌'} Agent: {len(agent_definition) if agent_success else 'Failed'} chars")
                if not agent_success:
                    print(f"    Error: {agent_error}")
                    errors.append(f"Agent definition generation failed: {agent_error}")
                
                # SSE: Validation step
                if SSE_AVAILABLE:
                    try:
                        if tool_success and agent_success:
                            event_bus.publish(
                                EventChannel.VALIDATION,
                                "Validating definitions...",
                                level=EventLevel.SUCCESS,
                                context={'generation_id': generation_id, 'tool_name': tool_name}
                            )
                        else:
                            event_bus.publish(
                                EventChannel.VALIDATION,
                                "❌ Generation completed with errors",
                                level=EventLevel.ERROR,
                                context={'generation_id': generation_id, 'tool_name': tool_name}
                            )
                    except Exception:
                        pass

                # Summary
                print(f"\nGeneration complete: Tool({'✅' if tool_definition else '❌'}), Agent({'✅' if agent_definition else '❌'})")
                if errors:
                    print(f"  ⚠️ Errors encountered: {len(errors)}")
                    for error in errors:
                        print(f"    - {error}")
                else:
                    print(f"  ✅ No errors encountered")

            except Exception as e:
                errors.append(f"LLM generation failed: {str(e)}")
                print(f"❌ TRACE: LLM generation exception: {str(e)}")
        else:
            errors.append("LLM generation not available - missing Azure OpenAI configuration")
            print(f"⚠️ TRACE: LLM generation skipped - missing Azure OpenAI configuration")
        
        # Return results
        if tool_definition or agent_definition:
            # Persist LLM outputs into the user-session generated folder for traceability
            try:
                import json, datetime
                session_root = os.path.join(script_dir, 'user-session', session_id)
                generated_dir = os.path.join(session_root, 'generated')
                os.makedirs(generated_dir, exist_ok=True)

                saved_files = []

                # Save per-script docs if available (script_docs variable may exist in locals)
                try:
                    if 'script_docs' in locals() and script_docs:
                        scripts_out_dir = os.path.join(generated_dir, 'script_summaries')
                        os.makedirs(scripts_out_dir, exist_ok=True)
                        for sd in script_docs:
                            spath = sd.get('script_path', 'script')
                            safe_name = spath.replace('/', '__').replace('..', '')
                            out_path = os.path.join(scripts_out_dir, f"{safe_name}.md")
                            with open(out_path, 'w', encoding='utf-8') as of:
                                of.write(sd.get('documentation', '') or '')
                            saved_files.append(out_path)
                        print(f"💾 Saved {len(script_docs)} per-script summaries to: {scripts_out_dir}")
                except Exception as _e:
                    print(f"⚠️ Could not save per-script summaries: {_e}")

                # Save combined API documentation (scripts_info)
                try:
                    if scripts_info:
                        api_out = os.path.join(generated_dir, 'api_documentation.md')
                        with open(api_out, 'w', encoding='utf-8') as af:
                            af.write(scripts_info)
                        saved_files.append(api_out)
                        print(f"💾 Saved combined API documentation: {api_out}")
                except Exception as _e:
                    print(f"⚠️ Could not save combined API documentation: {_e}")

                # Save generated tool and agent definitions
                try:
                    if tool_definition:
                        tool_out = os.path.join(generated_dir, 'tool_definition.yaml')
                        with open(tool_out, 'w', encoding='utf-8') as tf:
                            tf.write(tool_definition)
                        saved_files.append(tool_out)
                        print(f"💾 Saved tool definition YAML: {tool_out}")
                except Exception as _e:
                    print(f"⚠️ Could not save tool definition: {_e}")

                try:
                    if agent_definition:
                        agent_out = os.path.join(generated_dir, 'agent_definition.yaml')
                        with open(agent_out, 'w', encoding='utf-8') as af:
                            af.write(agent_definition)
                        saved_files.append(agent_out)
                        print(f"💾 Saved agent definition YAML: {agent_out}")
                except Exception as _e:
                    print(f"⚠️ Could not save agent definition: {_e}")

                # Save inputs summary for debugging
                try:
                    inputs_out = os.path.join(generated_dir, 'inputs_summary.json')
                    with open(inputs_out, 'w', encoding='utf-8') as jf:
                        json.dump(inputs_summary if 'inputs_summary' in locals() else {}, jf, indent=2)
                    saved_files.append(inputs_out)
                    print(f"💾 Saved inputs summary JSON: {inputs_out}")
                except Exception as _e:
                    print(f"⚠️ Could not save inputs summary: {_e}")

                # Record a generation manifest
                try:
                    manifest = {
                        'tool_name': tool_name,
                        'session_id': session_id,
                        # use timezone-aware UTC datetime to avoid deprecation warnings
                        'generated_at': datetime.now(timezone.utc).isoformat(),
                        'files': [os.path.relpath(p, session_root).replace('\\','/') for p in saved_files]
                    }
                    manifest_out = os.path.join(generated_dir, 'generation_manifest.json')
                    with open(manifest_out, 'w', encoding='utf-8') as mf:
                        json.dump(manifest, mf, indent=2)
                    print(f"💾 Saved generation manifest: {manifest_out}")
                except Exception as _e:
                    print(f"⚠️ Could not save generation manifest: {_e}")
            except Exception as _e:
                print(f"⚠️ Could not persist LLM outputs for session {session_id}: {_e}")

            # Run centralized schema validation to collect structured validation errors for UI
            validation_errors = {'tool': [], 'agent': []}
            try:
                if tool_definition:
                    tool_schema_path = os.path.join(os.path.dirname(__file__), template_files.get('ToolDefinitionSchema'))
                    v_tool = validate_yaml(str(tool_schema_path), tool_definition)
                    # Debug: surface validator result to server logs for troubleshooting
                    try:
                        vtool_valid = getattr(v_tool, 'valid', False)
                        vtool_errs = getattr(v_tool, 'errors', []) or []
                        print(f"🔍 Tool validation: valid={vtool_valid}, errors_count={len(vtool_errs)}")
                        for i, e in enumerate(vtool_errs[:5]):
                            print(f"   - tool_error[{i}]: {e.path}: {e.message}")
                    except Exception as _e:
                        print(f"⚠️ Could not introspect tool validation result: {_e}")
                    if v_tool and not getattr(v_tool, 'valid', False) and getattr(v_tool, 'errors', None):
                        validation_errors['tool'] = [{ 'path': e.path, 'message': e.message } for e in v_tool.errors]
            except Exception as e:
                validation_errors['tool'].append({ 'path': 'tool', 'message': f'Validator error: {e}' })

            try:
                if agent_definition:
                    agent_schema_path = os.path.join(os.path.dirname(__file__), template_files.get('AgentDefinitionSchema'))
                    v_agent = validate_yaml(str(agent_schema_path), agent_definition)
                    # Debug: surface validator result to server logs for troubleshooting
                    try:
                        vagent_valid = getattr(v_agent, 'valid', False)
                        vagent_errs = getattr(v_agent, 'errors', []) or []
                        print(f"🔍 Agent validation: valid={vagent_valid}, errors_count={len(vagent_errs)}")
                        for i, e in enumerate(vagent_errs[:10]):
                            print(f"   - agent_error[{i}]: {e.path}: {e.message}")
                    except Exception as _e:
                        print(f"⚠️ Could not introspect agent validation result: {_e}")
                    if v_agent and not getattr(v_agent, 'valid', False) and getattr(v_agent, 'errors', None):
                        validation_errors['agent'] = [{ 'path': e.path, 'message': e.message } for e in v_agent.errors]
            except Exception as e:
                validation_errors['agent'].append({ 'path': 'agent', 'message': f'Validator error: {e}' })

            # Note: Only save to session temp folder during generation
            # Permanent files will be saved only when create-tool-agent-files endpoint is called
            final_api_documentation = scripts_info if scripts_info and scripts_info != "No script documentation available" else (api_documentation or '')
            
            # Extract Dockerfile relative path from session for intelligent discovery during finalization
            dockerfile_rel_path = None
            if inputs_summary and inputs_summary.get('dockerfiles'):
                dockerfile_rel_path = inputs_summary['dockerfiles'][0]  # First Dockerfile found
            
            return jsonify({
                'success': True,
                'toolDefinition': tool_definition,
                'agentDefinition': agent_definition,
                'apiDocumentation': final_api_documentation,
                'inputsSummary': inputs_summary if 'inputs_summary' in locals() else {},
                'dockerfileRelPath': dockerfile_rel_path,  # Pass to client for finalization
                'errors': errors,
                'validationErrors': validation_errors,
                'aiGenerated': bool(tool_definition and agent_definition)
            })
        else:
            return jsonify({
                'success': False,
                'error': 'Failed to generate definitions. ' + '; '.join(errors),
                'toolDefinition': '',
                'agentDefinition': '',
                'apiDocumentation': ''
            }), 500
            
    except Exception as e:
        return jsonify({
            'success': False,
            'error': f'Tool agent generation error: {str(e)}'
        }), 500

def add_tool_agent_to_catalog(tool_name, tool_file_path, agent_file_path, user_dockerfile_path=None, working_directory=None, session_id=None, dockerfile_rel_path=None):
    """Add a new tool agent to the agents catalog with intelligent Dockerfile discovery
    
    Args:
        dockerfile_rel_path: Relative path of Dockerfile within session uploads (e.g., "simple/Dockerfile")
                            This is captured during generation and passed through for discovery
    """
    import yaml
    import glob
    
    catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
    
    # Load current catalog (initialize empty structure if missing/empty)
    catalog_data = {}
    if os.path.exists(catalog_path):
        with open(catalog_path, 'r', encoding='utf-8') as f:
            loaded = yaml.safe_load(f)
            if isinstance(loaded, dict):
                catalog_data = loaded
    
    # Ensure tool_agents section exists (updated from 'agents' to 'tool_agents')
    if 'tool_agents' not in catalog_data or not isinstance(catalog_data['tool_agents'], list):
        catalog_data['tool_agents'] = []
    
    # Convert absolute paths to relative paths from the catalog location
    # The catalog is in Utils/agent-workbench/, so we need to calculate relative paths properly
    catalog_dir = os.path.dirname(catalog_path)
    tool_rel_path = os.path.relpath(tool_file_path, catalog_dir).replace('\\', '/')
    agent_rel_path = os.path.relpath(agent_file_path, catalog_dir).replace('\\', '/')
    
    # Load tool_agents_dir from config for intelligent search
    tool_agents_dir = "../../"  # Default
    try:
        from discovery_config_manager import DiscoveryConfigManager
        config_mgr = DiscoveryConfigManager()
        config = config_mgr.load_config()
        if config and 'directories' in config and 'tool_agents_dir' in config['directories']:
            tool_agents_dir = config['directories']['tool_agents_dir']
            print(f"🔍 Using tool_agents_dir from config: {tool_agents_dir}")
    except Exception as e:
        print(f"⚠️ Could not load tool_agents_dir from config, using default: {e}")
    
    # Intelligent Dockerfile discovery
    dockerfile_path = None
    
    # Strategy 1: Use dockerfile_rel_path from generation (passed through from client)
    if dockerfile_rel_path and not user_dockerfile_path:
        print(f"🔍 Attempting intelligent Dockerfile discovery using captured path: {dockerfile_rel_path}")
        
        # Extract folder pattern (e.g., "simple" from "simple/Dockerfile")
        if dockerfile_rel_path != 'Dockerfile':
            folder_pattern = os.path.dirname(dockerfile_rel_path)
            folder_name = os.path.basename(folder_pattern) if folder_pattern else None
            
            print(f"   🔎 Folder pattern: {folder_pattern}")
            print(f"   🔎 Folder name: {folder_name}")
            
            # Search base directory (resolve tool_agents_dir relative to catalog)
            search_base = os.path.normpath(os.path.join(catalog_dir, tool_agents_dir))
            print(f"   🔎 Search base: {search_base}")
            
            # Try multiple search patterns in order of specificity
            search_patterns = []
            if folder_pattern:
                search_patterns.extend([
                    # Exact match (most specific)
                    os.path.join(search_base, folder_pattern, 'Dockerfile'),
                    # Recursive search for exact pattern
                    os.path.join(search_base, '**', folder_pattern, 'Dockerfile'),
                ])
            if folder_name:
                # Search by folder name only (less specific)
                search_patterns.append(os.path.join(search_base, '**', folder_name, 'Dockerfile'))
            
            for pattern in search_patterns:
                print(f"   🔍 Trying: {pattern}")
                matches = glob.glob(pattern, recursive=True)
                
                if matches:
                    if len(matches) == 1:
                        # Unambiguous match
                        dockerfile_path = os.path.relpath(matches[0], catalog_dir).replace('\\', '/')
                        print(f"   ✅ Found unique match: {dockerfile_path}")
                        break
                    else:
                        # Multiple matches - pick the most likely
                        best_match = None
                        for match in matches:
                            match_rel = os.path.relpath(match, catalog_dir).replace('\\', '/')
                            if folder_pattern and folder_pattern in match_rel:
                                best_match = match
                                break
                        
                        if not best_match:
                            best_match = matches[0]
                        
                        dockerfile_path = os.path.relpath(best_match, catalog_dir).replace('\\', '/')
                        print(f"   ⚠️ Multiple matches found, using: {dockerfile_path}")
                        print(f"      Other matches: {[os.path.relpath(m, catalog_dir) for m in matches[1:3]]}")
                        break
    
    # Strategy 2: User-provided path resolution
    if not dockerfile_path and user_dockerfile_path:
        print(f"🔍 Using user-provided Dockerfile path: {user_dockerfile_path}")
        resolved_dockerfile = None
        
        if os.path.isabs(user_dockerfile_path):
            # Absolute path
            resolved_dockerfile = user_dockerfile_path
        else:
            # Relative path - use working directory if provided, otherwise try multiple base directories
            potential_base_dirs = []
            
            # If working directory is provided, try it first
            if working_directory:
                potential_base_dirs.append(working_directory)
            
            # Add other potential base directories
            potential_base_dirs.extend([
                os.getcwd(),
                catalog_dir,
                os.path.dirname(catalog_dir),
                os.path.dirname(os.path.dirname(catalog_dir)),
            ])
            
            for base_dir in potential_base_dirs:
                test_path = os.path.join(base_dir, user_dockerfile_path)
                if os.path.exists(test_path):
                    resolved_dockerfile = test_path
                    break
        
        if resolved_dockerfile and os.path.exists(resolved_dockerfile):
            dockerfile_path = os.path.relpath(resolved_dockerfile, catalog_dir).replace('\\', '/')
            print(f"   ✅ Resolved to: {dockerfile_path}")
        else:
            print(f"   ⚠️ Could not resolve user-provided path, Dockerfile will be missing from catalog")
    
    # Strategy 3: Copy from session to generated folder (fallback)
    if not dockerfile_path and session_id:
        print(f"🔄 Fallback: Copying Dockerfile from session to generated folder...")
        session_uploads_dir = os.path.join(os.path.dirname(__file__), 'user-session', session_id, 'uploads')
        
        if os.path.exists(session_uploads_dir):
            for root, dirs, files in os.walk(session_uploads_dir):
                if 'Dockerfile' in files:
                    session_dockerfile = os.path.join(root, 'Dockerfile')
                    target_dir = os.path.dirname(tool_file_path)
                    target_dockerfile = os.path.join(target_dir, 'Dockerfile')
                    
                    try:
                        import shutil
                        os.makedirs(target_dir, exist_ok=True)
                        shutil.copy2(session_dockerfile, target_dockerfile)
                        dockerfile_path = os.path.relpath(target_dockerfile, catalog_dir).replace('\\', '/')
                        print(f"   ✅ Copied Dockerfile to: {dockerfile_path}")
                    except Exception as copy_err:
                        print(f"   ❌ Failed to copy Dockerfile: {copy_err}")
                    break
    
    # Build new tool agent record (updated to include name field)
    new_agent = {
        'name': tool_name,
        'agent_config': agent_rel_path,
        'tools_definition': tool_rel_path
    }
    
    # Only add dockerfile if it exists and was found
    if dockerfile_path:
        new_agent['dockerfile'] = dockerfile_path
    
    # Check if agent already exists (by name or agent_config path) and replace it
    replaced = False
    for i, agent in enumerate(catalog_data['tool_agents']):
        if isinstance(agent, dict) and (agent.get('name') == tool_name or agent.get('agent_config') == agent_rel_path):
            catalog_data['tool_agents'][i] = new_agent
            replaced = True
            break
    
    if not replaced:
        catalog_data['tool_agents'].append(new_agent)
    
    # Save updated catalog
    with open(catalog_path, 'w', encoding='utf-8') as f:
        yaml.dump(catalog_data, f, default_flow_style=False, sort_keys=False, indent=2)
    
    print(f"✅ {'Updated' if replaced else 'Added'} tool agent '{tool_name}' in catalog")
    print(f"   📁 Agent config: {agent_rel_path}")
    print(f"   🔧 Tool definition: {tool_rel_path}")
    if dockerfile_path:
        print(f"   🐳 Dockerfile: {dockerfile_path}")
    
    # Reload the agent manager (if available) to pick up the changes
    global agent_manager
    if agent_manager:
        try:
            agent_manager.reload_catalog()
            print(f"🔄 Agent manager catalog reloaded successfully")
        except Exception as reload_error:
            print(f"⚠️ Warning: Failed to reload agent manager catalog: {reload_error}")
    else:
        print(f"⚠️ Warning: Agent manager is not available for catalog reload")

