# Tool Agent Settings (output directory config)
############################

TOOL_AGENT_SETTINGS_FILE = os.path.join(os.path.dirname(__file__), 'tool-agent-settings.json')

def load_tool_agent_settings():
    """Load tool agent directory setting.
    Precedence:
      1. ENV DISCOVERY_TOOL_OUTPUT_DIR
      2. Persisted tool-agent-settings.json
      3. discovery_config.json preferences.tool_agents_output_dir
      4. Hard default ./generated-tool-agents
    """
    # 1. Environment override handled by callers
    # 2. Persisted settings
    persisted = None
    if os.path.exists(TOOL_AGENT_SETTINGS_FILE):
        try:
            with open(TOOL_AGENT_SETTINGS_FILE, 'r', encoding='utf-8') as f:
                data = json.load(f)
                if isinstance(data, dict) and data.get('outputDir'):
                    persisted = data['outputDir']
        except Exception as e:
            print(f"⚠️ Failed reading tool-agent settings file: {e}")
    # 3. discovery_config.json via global config_manager if available
    pref_dir = None
    try:
        cfg = config_manager.load_config() if 'config_manager' in globals() and config_manager else None
        if cfg and isinstance(cfg, dict):
            prefs = cfg.get('preferences', {})
            cand = prefs.get('tool_agents_output_dir') or prefs.get('toolAgentsOutputDir')
            if cand:
                if not os.path.isabs(cand):
                    cand = os.path.abspath(os.path.join(os.path.dirname(__file__), cand))
                pref_dir = cand
    except Exception as e:
        print(f"⚠️ Could not read discovery_config preferences for tool_agents_output_dir: {e}")
    # 4. Fallback default
    default_dir = os.path.join(os.path.dirname(__file__), 'generated-tool-agents')
    chosen = persisted or pref_dir or default_dir
    return { 'outputDir': chosen }

def save_tool_agent_settings(output_dir):
    os.makedirs(os.path.dirname(TOOL_AGENT_SETTINGS_FILE), exist_ok=True)
    with open(TOOL_AGENT_SETTINGS_FILE, 'w', encoding='utf-8') as f:
        json.dump({ 'outputDir': output_dir }, f, indent=2)
    print(f"🗂 Saved tool-agent output directory setting: {output_dir}")

@app.route('/api/tool-agent-settings', methods=['GET'])
def api_get_tool_agent_settings():
    try:
        settings = load_tool_agent_settings()
        # Configuration can override persisted setting
        config_override = get_discovery_tool_output_dir()
        if config_override != os.path.join(os.path.dirname(__file__), 'generated-tool-agents'):
            settings['outputDir'] = config_override
            settings['configOverride'] = True
        return jsonify({ 'success': True, 'settings': settings })
    except Exception as e:
        return jsonify({ 'success': False, 'error': str(e) }), 500

@app.route('/api/tool-agent-settings', methods=['POST'])
def api_set_tool_agent_settings():
    try:
        data = request.get_json() or {}
        output_dir = (data.get('outputDir') or '').strip()
        if not output_dir:
            return jsonify({ 'success': False, 'error': 'outputDir is required' }), 400
        # Normalize to absolute path relative to server file if not absolute
        if not os.path.isabs(output_dir):
            base = os.path.dirname(__file__)
            output_dir = os.path.abspath(os.path.join(base, output_dir))
        os.makedirs(output_dir, exist_ok=True)
        save_tool_agent_settings(output_dir)
        # Update configuration for immediate effect
        if DISCOVERY_AVAILABLE and config_manager:
            config_manager.update_directories_config(discovery_tool_output_dir=output_dir)
        return jsonify({ 'success': True, 'settings': { 'outputDir': output_dir, 'configOverride': True } })
    except Exception as e:
        return jsonify({ 'success': False, 'error': str(e) }), 500

@app.route('/api/create-tool-agent-files', methods=['POST'])
def create_tool_agent_files():
    """Create tool & agent definition files in a configurable server-relative location.
    Requirements (updated):
      - Do NOT copy any uploaded session source files (they remain on user disk)
      - Only create the new YAML definition files
      - Location is configurable via env DISCOVERY_TOOL_OUTPUT_DIR (default: ./generated-tool-agents)
      - Do NOT infer toolName (must be supplied by client)
      - workingDirectory is now optional; a client may instead supply targetRelativeDir
    """
    try:
        data = request.get_json() or {}
        tool_name = (data.get('toolName') or '').strip()
        tool_definition = (data.get('toolDefinition') or '').strip()
        agent_definition = (data.get('agentDefinition') or '').strip()
        api_documentation = (data.get('apiDocumentation') or '').strip()
        working_directory = (data.get('workingDirectory') or '').strip()
        dockerfile_path = (data.get('dockerfilePath') or '').strip()
        docker_image = (data.get('dockerImage') or '').strip()
        target_relative_dir = (data.get('targetRelativeDir') or '').strip().strip('/\\')

        settings_loaded = load_tool_agent_settings()
        base_dir = get_discovery_tool_output_dir() or settings_loaded.get('outputDir') or os.path.join(os.path.dirname(__file__), 'generated-tool-agents')
        if not base_dir:
            base_dir = os.path.join(os.path.dirname(__file__), 'generated-tool-agents')
        os.makedirs(base_dir, exist_ok=True)

        print("🔍 Received tool agent creation request (new mode):")
        print(f"   📛 Tool name: {tool_name}")
        print(f"   🧩 Provided workingDirectory (legacy): '{working_directory}'")
        print(f"   📂 targetRelativeDir: '{target_relative_dir}'")
        print(f"   🐳 Dockerfile path: '{dockerfile_path}' (empty: {not dockerfile_path})")
        print(f"   📦 Docker image: '{docker_image}' (empty: {not docker_image})")
        print(f"   📁 Base output dir: {base_dir}")

        if not tool_name or not tool_definition or not agent_definition:
            return jsonify({'success': False, 'error': 'Missing required fields: toolName, toolDefinition, agentDefinition'}), 400

        # Run intelligent Dockerfile discovery FIRST to determine placement
        dockerfile_rel_path_from_client = data.get('dockerfileRelPath') or None
        discovered_dockerfile_path = None
        
        if dockerfile_rel_path_from_client:
            print(f"   🔍 Running intelligent Dockerfile discovery using: '{dockerfile_rel_path_from_client}'")
            import glob
            
            # Load tool_agents_dir from config
            tool_agents_dir = "../../"  # Default
            try:
                from discovery_config_manager import DiscoveryConfigManager
                config_mgr = DiscoveryConfigManager()
                config = config_mgr.load_config()
                if config and 'directories' in config and 'tool_agents_dir' in config['directories']:
                    tool_agents_dir = config['directories']['tool_agents_dir']
            except Exception as e:
                print(f"      ⚠️ Could not load tool_agents_dir, using default")
            
            # Extract folder pattern
            if dockerfile_rel_path_from_client != 'Dockerfile':
                folder_pattern = os.path.dirname(dockerfile_rel_path_from_client)
                folder_name = os.path.basename(folder_pattern) if folder_pattern else None
                
                # Search from agent-workbench directory
                catalog_dir = os.path.dirname(__file__)
                search_base = os.path.normpath(os.path.join(catalog_dir, tool_agents_dir))
                
                # Try search patterns
                search_patterns = []
                if folder_pattern:
                    search_patterns.extend([
                        os.path.join(search_base, folder_pattern, 'Dockerfile'),
                        os.path.join(search_base, '**', folder_pattern, 'Dockerfile'),
                    ])
                if folder_name:
                    search_patterns.append(os.path.join(search_base, '**', folder_name, 'Dockerfile'))
                
                for pattern in search_patterns:
                    matches = glob.glob(pattern, recursive=True)
                    if matches:
                        # Use first match (or best match logic)
                        discovered_dockerfile_path = matches[0]
                        print(f"      ✅ Discovered Dockerfile at: {discovered_dockerfile_path}")
                        break
        
        # Resolve target directory with intelligent placement
        # Priority: 1. Discovered Dockerfile directory 2. targetRelativeDir 3. workingDirectory 4. tool_name
        if discovered_dockerfile_path:
            # Place definition files in same directory as discovered Dockerfile
            target_directory = os.path.dirname(discovered_dockerfile_path)
            print(f"   📁 Using discovered Dockerfile directory: {target_directory}")
        elif target_relative_dir:
            target_directory = os.path.join(base_dir, target_relative_dir)
        elif working_directory and os.path.isabs(working_directory):
            try:
                inside = os.path.commonpath([os.path.abspath(working_directory), os.path.abspath(base_dir)]) == os.path.abspath(base_dir)
            except Exception:
                inside = False
            target_directory = working_directory if inside else os.path.join(base_dir, tool_name)
        elif working_directory and not os.path.isabs(working_directory):
            target_directory = os.path.join(base_dir, working_directory)
        else:
            target_directory = os.path.join(base_dir, tool_name)

        os.makedirs(target_directory, exist_ok=True)
        print(f"   ✅ Using target directory: {target_directory}")

        tool_filename = f"{tool_name}-tool-definition.yaml"
        agent_filename = f"{tool_name}-agent-definition.yaml"
        api_doc_filename = f"{tool_name}-api-documentation.md"
        tool_file_path = os.path.join(target_directory, tool_filename)
        agent_file_path = os.path.join(target_directory, agent_filename)
        api_doc_file_path = os.path.join(target_directory, api_doc_filename)
        
        # Save YAML files
        with open(tool_file_path, 'w', encoding='utf-8') as f:
            f.write(tool_definition)
        with open(agent_file_path, 'w', encoding='utf-8') as f:
            f.write(agent_definition)
        
        # Save API documentation if provided
        files_created = [tool_filename, agent_filename]
        files_dict = {
            'toolDefinition': tool_file_path,
            'agentDefinition': agent_file_path
        }
        
        if api_documentation:
            with open(api_doc_file_path, 'w', encoding='utf-8') as f:
                f.write(api_documentation)
            files_created.append(api_doc_filename)
            files_dict['apiDocumentation'] = api_doc_file_path
            print(f"📚 Saved API documentation: {api_doc_file_path}")

        print(f"📝 Created tool agent definition files for '{tool_name}'")
        if dockerfile_path:
            print(f"   🐳 Dockerfile (user path reference only): {dockerfile_path}")
        if docker_image:
            print(f"   📦 Docker image ref: {docker_image}")
        
        # Extract session_id and dockerfileRelPath for intelligent Dockerfile discovery
        session_id_for_catalog = data.get('sessionId') or data.get('sessionid') or None
        dockerfile_rel_path_for_catalog = data.get('dockerfileRelPath') or None
        
        try:
            add_tool_agent_to_catalog(
                tool_name=tool_name,
                tool_file_path=tool_file_path,
                agent_file_path=agent_file_path,
                user_dockerfile_path=dockerfile_path if dockerfile_path else None,
                working_directory=target_directory,
                session_id=session_id_for_catalog,
                dockerfile_rel_path=dockerfile_rel_path_for_catalog
            )
        except Exception as cataprint:
            print(f"⚠️ Warning: Failed to update catalog: {cataprint}")

        rel_dir_from_server_root = os.path.relpath(target_directory, os.path.dirname(__file__)).replace('\\', '/')
        return jsonify({
            'success': True,
            'message': f"Tool agent definition files created in {target_directory}",
            'files': files_dict,
            'targetDirectory': target_directory,
            'relativeDirectory': rel_dir_from_server_root,
            'filesCreated': files_created
        })
    except Exception as e:
        return jsonify({'success': False, 'error': f"File creation error: {str(e)}"}), 500

def _extract_domain_from_description(description):
    """Extract domain/category from tool description"""
    description_lower = description.lower()
    
    # Domain mapping based on keywords
    domain_keywords = {
        'molecular': 'Molecular Science',
        'chemistry': 'Chemistry',
        'physics': 'Physics',
        'simulation': 'Physics-Based Simulations',
        'dynamics': 'Physics-Based Simulations',
        'bioinformatics': 'Bioinformatics',
        'genomics': 'Bioinformatics',
        'protein': 'Molecular Science',
        'drug': 'Drug Discovery',
        'machine learning': 'Machine Learning',
        'ai': 'Machine Learning',
        'data': 'Data Science',
        'visualization': 'Data Visualization',
        'analysis': 'Data Analysis'
    }
    
    for keyword, domain in domain_keywords.items():
        if keyword in description_lower:
            return domain
    
    return 'Scientific Computing'

def _get_resource_hints_for_domain(domain):
    """Get resource sizing hints based on domain"""
    resource_map = {
        'Molecular Science': 'High CPU/Memory (8-16 cores, 64-128GB RAM)',
        'Physics-Based Simulations': 'High CPU/Memory (12-24 cores, 128-256GB RAM)',
        'Machine Learning': 'GPU-enabled (4-8 cores, 32-64GB RAM, GPU)',
        'Data Science': 'Medium CPU/Memory (4-8 cores, 32-64GB RAM)',
        'Bioinformatics': 'High Memory (8-16 cores, 64-128GB RAM)',
        'Drug Discovery': 'High CPU/Memory (8-16 cores, 64-128GB RAM)'
    }
    
    return resource_map.get(domain, 'Standard (4-8 cores, 16-32GB RAM)')

@app.route('/api/preview-scripts-folder', methods=['POST'])
def preview_scripts_folder():
    """Preview files in a scripts folder to help with debugging and validation"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'error': 'Invalid JSON data in request'}), 400
        
        scripts_path = data.get('scriptsPath', '').strip()
        if not scripts_path:
            return jsonify({'error': 'scriptsPath is required'}), 400
        
        print(f"🔍 PREVIEW: Scripts folder preview request for: {scripts_path}")
        
        # Try to resolve the path - handle both absolute and relative paths
        resolved_path = None
        
        if os.path.isabs(scripts_path):
            # Absolute path
            resolved_path = scripts_path
            print(f"  📁 Using absolute path: {resolved_path}")
        else:
            # Relative path - try multiple base directories
            possible_bases = [
                os.getcwd(),  # Current working directory
                os.path.dirname(__file__),  # Script directory
                os.path.join(os.path.dirname(__file__), '..', '..'),  # Repository root
            ]
            
            for base in possible_bases:
                candidate = os.path.abspath(os.path.join(base, scripts_path))
                print(f"  🔍 Checking candidate path: {candidate}")
                if os.path.exists(candidate):
                    resolved_path = candidate
                    print(f"  ✅ Found valid path: {resolved_path}")
                    break
        
        if not resolved_path or not os.path.exists(resolved_path):
            # Return 200 with success:false so the browser doesn't surface an HTTP error in the console.
            return jsonify({
                'success': False,
                'error': f'Scripts path not found: {scripts_path}',
                'attempted_paths': [
                    scripts_path,
                    os.path.abspath(os.path.join(os.getcwd(), scripts_path)),
                    os.path.abspath(os.path.join(os.path.dirname(__file__), scripts_path)),
                    os.path.abspath(os.path.join(os.path.dirname(__file__), '..', '..', scripts_path))
                ]
            }), 200
        
        if not os.path.isdir(resolved_path):
            # Return 200 with success:false to keep client-side behavior consistent and avoid HTTP errors
            return jsonify({
                'success': False,
                'error': f'Path is not a directory: {resolved_path}'
            }), 200
        
        # Scan the directory structure
        structure = {
            'path': resolved_path,
            'folders': [],
            'script_files': [],
            'other_files': [],
            'total_files': 0,
            'total_script_files': 0
        }
        
        script_extensions = {'.py', '.sh', '.ps1', '.bat', '.js', '.ts'}
        doc_extensions = {'.md', '.txt', '.json', '.yaml', '.yml', '.cfg', '.ini', '.toml', '.rst'}
        
        for root, dirs, files in os.walk(resolved_path):
            rel_root = os.path.relpath(root, resolved_path)
            if rel_root == '.':
                rel_root = 'root'
            
            folder_info = {
                'name': rel_root,
                'full_path': root,
                'script_files': [],
                'other_files': [],
                'subdirs': dirs
            }
            
            for file in files:
                file_path = os.path.join(root, file)
                rel_file_path = os.path.relpath(file_path, resolved_path)
                file_ext = os.path.splitext(file)[1].lower()
                file_size = os.path.getsize(file_path) if os.path.exists(file_path) else 0
                
                file_info = {
                    'name': file,
                    'path': rel_file_path,
                    'size': file_size,
                    'extension': file_ext
                }
                
                structure['total_files'] += 1
                
                if file_ext in script_extensions:
                    folder_info['script_files'].append(file_info)
                    structure['script_files'].append(file_info)
                    structure['total_script_files'] += 1
                elif file_ext in doc_extensions:
                    folder_info['other_files'].append(file_info)
                    structure['other_files'].append(file_info)
                else:
                    folder_info['other_files'].append(file_info)
                    structure['other_files'].append(file_info)
            
            if folder_info['script_files'] or folder_info['other_files'] or folder_info['subdirs']:
                structure['folders'].append(folder_info)
        
        print(f"  ✅ Scripts folder scanned successfully:")
        print(f"     📁 Path: {resolved_path}")
        print(f"     📊 Total files: {structure['total_files']}")
        print(f"     🔧 Script files: {structure['total_script_files']}")
        print(f"     📁 Folders: {len(structure['folders'])}")
        
        return jsonify({
            'success': True,
            'structure': structure
        })
        
    except Exception as e:
        print(f"❌ Error in preview_scripts_folder: {e}")
        return jsonify({
            'success': False,
            'error': f'Error previewing scripts folder: {str(e)}'
        }), 500

@app.route('/api/generate-knowledge-base-agent', methods=['POST'])
def generate_knowledge_base_agent():
    """Generate a Knowledge Base Agent definition using the template"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'success': False, 'error': 'No data provided'}), 400
            
        name = data.get('name', 'KnowledgeBaseAgent').strip()
        domains = data.get('domains', '').strip()
        
        if not name:
            return jsonify({'success': False, 'error': 'Agent name is required'}), 400
            
        # Load the KnowledgeBaseAgent template
        config_path = os.path.join(os.path.dirname(__file__), 'discovery_config.json')
        with open(config_path, 'r') as f:
            config = json.load(f)
            
        template_path = config.get('template_files', {}).get('KnowledgeBaseAgent')
        if not template_path:
            return jsonify({'success': False, 'error': 'KnowledgeBaseAgent template not found in config'}), 500
            
        full_template_path = os.path.join(os.path.dirname(__file__), template_path)
        if not os.path.exists(full_template_path):
            return jsonify({'success': False, 'error': f'Template file not found: {template_path}'}), 500
            
        # Read the template
        with open(full_template_path, 'r') as f:
            template_content = f.read()
            
        # Simple text-based customization to preserve YAML formatting
        customized_yaml = template_content
        
        # Replace the agent name
        customized_yaml = customized_yaml.replace('name: KnowledgeBaseAgent', f'name: {name}')
        
        # Update description if domains provided
        if domains:
            domain_text = f" specializing in {domains}"
            current_desc_line = 'description: Specialized agent for retrieving information from domain-specific knowledge bases'
            new_desc_line = f'description: Specialized agent for retrieving information from domain-specific knowledge bases{domain_text}'
            customized_yaml = customized_yaml.replace(current_desc_line, new_desc_line)
        
        # Debug: log the actual YAML content
        print(f"📝 Generated YAML preview (first 300 chars):")
        print(repr(customized_yaml[:300]))
        
        return jsonify({
            'success': True,
            'agent_definition': customized_yaml
        })
        
    except Exception as e:
        print(f"❌ Error generating knowledge base agent: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/create-knowledge-base-agent', methods=['POST'])
def create_knowledge_base_agent():
    """Create a Knowledge Base Agent file and add to catalog"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'success': False, 'error': 'No data provided'}), 400
            
        print(f"📝 Received KB agent creation request: {data}")
        
        name = data.get('name', '').strip()
        agent_definition = data.get('agent_definition', '').strip()
        overwrite = data.get('overwrite', False)
        
        print(f"📝 Parsed: name='{name}', agent_definition length={len(agent_definition)}, overwrite={overwrite}")
        
        if not name or not agent_definition:
            return jsonify({'success': False, 'error': 'Name and agent definition are required'}), 400
            
        # Get output directory for Knowledge Base agents
        base_dir = get_kb_agent_output_dir()
        
        print(f"📁 KB_AGENT_OUTPUT_DIR config: {base_dir}")
        print(f"📁 Absolute base_dir: {os.path.abspath(base_dir)}")
        
        # Create the base directory if it doesn't exist
        os.makedirs(base_dir, exist_ok=True)
        
        # Create agent file
        agent_filename = f"{name}.yaml"
        agent_path = os.path.join(base_dir, agent_filename)
        
        # Check if file already exists
        if os.path.exists(agent_path) and not overwrite:
            return jsonify({'success': False, 'error': f'Knowledge Base Agent "{name}" already exists'}), 400
            
        # Write the agent file
        with open(agent_path, 'w') as f:
            f.write(agent_definition)
            
        print(f"📝 Created knowledge base agent file: {agent_path}")
        
        # Update agents-catalog.yaml to add this agent under kb_agents section
        catalog_path = os.path.join(os.path.dirname(__file__), 'agents-catalog.yaml')
        
        try:
            # Load existing catalog
            if os.path.exists(catalog_path):
                with open(catalog_path, 'r') as f:
                    catalog = yaml.safe_load(f) or {}
            else:
                catalog = {}
                
            # Initialize kb_agents section if it doesn't exist
            if 'kb_agents' not in catalog:
                catalog['kb_agents'] = []
                
            # Add the new agent
            relative_path = os.path.relpath(agent_path, os.path.dirname(catalog_path))
            # Convert backslashes to forward slashes for consistency across platforms
            relative_path = relative_path.replace('\\', '/')
            print(f"📁 Agent path: {agent_path}")
            print(f"📁 Catalog path: {catalog_path}")
            print(f"📁 Catalog dir: {os.path.dirname(catalog_path)}")
            print(f"📁 Calculated relative path: {relative_path}")
            
            new_kb_agent = {
                'name': name,
                'agent_config': relative_path
            }
            
            # Check if agent already exists in catalog
            existing_agent = next((agent for agent in catalog['kb_agents'] if agent.get('name') == name), None)
            if existing_agent:
                # Update existing entry
                existing_agent['agent_config'] = relative_path
            else:
                # Add new entry
                catalog['kb_agents'].append(new_kb_agent)
                
            # Write updated catalog
            with open(catalog_path, 'w') as f:
                yaml.dump(catalog, f, default_flow_style=False, sort_keys=False)
                
            print(f"📝 Updated agents catalog with knowledge base agent: {name}")
            
            # Reload the agent manager catalog to pick up the new agent
            try:
                agent_manager.reload_catalog()
                print(f"🔄 Reloaded agent catalog after KB agent creation")
            except Exception as reload_error:
                print(f"⚠️ Warning: Could not reload agents catalog: {reload_error}")
            
        except Exception as cataprint:
            print(f"⚠️ Warning: Could not update agents catalog: {cataprint}")
            # Don't fail the creation if catalog update fails
            
        return jsonify({
            'success': True,
            'message': f'Knowledge Base Agent "{name}" created successfully',
            'agentName': name,
            'agent_file': agent_filename,
            'agent_path': agent_path
        })
        
    except Exception as e:
        print(f"❌ Error creating knowledge base agent: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/validate-kb-agent', methods=['POST'])
def validate_kb_agent():
    """Validate a Knowledge Base Agent YAML definition against the schema"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'success': False, 'error': 'No data provided'}), 400
            
        agent_name = data.get('agent_name', '').strip()
        agent_config_yaml = data.get('agent_config', '').strip()
        
        if not agent_name:
            return jsonify({'success': False, 'error': 'Agent name is required'}), 400
            
        if not agent_config_yaml:
            # If no YAML provided, try to load from file
            if not agent_manager or agent_name not in agent_manager.kb_agents:
                return jsonify({
                    'success': False, 
                    'error': f'Knowledge Base Agent "{agent_name}" not found in catalog'
                }), 404
                
            kb_agent = agent_manager.kb_agents[agent_name]
            agent_config_path = os.path.join(os.path.dirname(agent_manager.catalog_path), kb_agent.agent_config)
            
            if not os.path.exists(agent_config_path):
                return jsonify({
                    'success': False, 
                    'error': f'Agent configuration file not found: {agent_config_path}'
                }), 404
                
            try:
                with open(agent_config_path, 'r', encoding='utf-8') as f:
                    agent_config_yaml = f.read()
            except Exception as e:
                return jsonify({
                    'success': False, 
                    'error': f'Failed to read agent configuration: {str(e)}'
                }), 500
        
        print(f"🔍 Validating Knowledge Base Agent: {agent_name}")
        
        # Get template files for schema path
        try:
            config_manager = DiscoveryConfigManager()
            template_files = config_manager.get_template_files()
        except Exception as e:
            print(f"⚠️ Could not load template files: {e}")
            template_files = {}
        
        # Perform YAML schema validation
        validation_errors = []
        try:
            if validate_yaml is not None:
                agent_schema_file = template_files.get('AgentDefinitionSchema')
                if agent_schema_file:
                    agent_schema_path = os.path.join(os.path.dirname(__file__), agent_schema_file)
                    if os.path.exists(agent_schema_path):
                        print(f"📋 Using schema file: {agent_schema_path}")
                        v_result = validate_yaml(str(agent_schema_path), agent_config_yaml)
                        if v_result and not getattr(v_result, 'valid', False):
                            errors = getattr(v_result, 'errors', [])
                            validation_errors = [{'path': e.path, 'message': e.message} for e in errors]
                            print(f"❌ YAML validation failed: {len(validation_errors)} errors")
                            for i, error in enumerate(validation_errors[:5]):
                                print(f"   - error[{i}]: {error['path']}: {error['message']}")
                        else:
                            print(f"✅ YAML validation passed for agent: {agent_name}")
                    else:
                        return jsonify({
                            'success': False,
                            'error': f'Agent schema file not found: {agent_schema_path}'
                        }), 500
                else:
                    return jsonify({
                        'success': False,
                        'error': 'AgentDefinitionSchema not configured in template_files'
                    }), 500
            else:
                return jsonify({
                    'success': False,
                    'error': 'YAML validator not available'
                }), 500
        except Exception as e:
            validation_errors.append({'path': 'schema_validation', 'message': f'Validation error: {str(e)}'})
            
        if validation_errors:
            return jsonify({
                'success': False,
                'valid': False,
                'error': 'Agent configuration validation failed',
                'validation_errors': validation_errors
            }), 200  # Return 200 with validation errors in body
        
        # Additional validation: Check for reserved keywords in agent name
        try:
            import yaml
            agent_data = yaml.safe_load(agent_config_yaml)
            agent_def_name = agent_data.get('agent', {}).get('name', '').lower()

            # Additional validation: reserved extension input names
            forbidden = _find_forbidden_extension_input_names(agent_data)
            if forbidden:
                forbidden_list = ', '.join(sorted(forbidden))
                validation_errors.append({
                    'path': 'extension.inputs',
                    'message': (
                        'Reserved inputs are not allowed in agent definition extension.inputs: '
                        f'{forbidden_list}. Remove them from extension.inputs.'
                    )
                })
            
            # List of reserved keywords that Azure Discovery blocks
            reserved_keywords = ['filewriter']
            
            for keyword in reserved_keywords:
                if keyword in agent_def_name:
                    validation_errors.append({
                        'path': 'agent.name',
                        'message': f'Agent name contains reserved keyword "{keyword}". This name is blocked by Azure Discovery. Please use an alternative like "file-writer", "document-writer", or "content-saver".'
                    })
                    print(f"⚠️ Agent name '{agent_def_name}' contains reserved keyword: {keyword}")
            
            if validation_errors:
                return jsonify({
                    'success': False,
                    'valid': False,
                    'error': 'Agent name contains reserved keyword',
                    'validation_errors': validation_errors
                }), 200
        except Exception as e:
            print(f"⚠️ Could not check reserved keywords: {e}")
        
        return jsonify({
            'success': True,
            'valid': True,
            'message': f'Agent "{agent_name}" configuration is valid'
        })
            
    except Exception as e:
        print(f"❌ Error validating KB agent: {e}")
        import traceback
        traceback.print_exc()
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/publish-kb-agent', methods=['POST'])
def publish_kb_agent():
    """Publish a Knowledge Base Agent with validation and duplicate checking"""
    try:
        data = request.get_json()
        if not data:
            return jsonify({'success': False, 'error': 'No data provided'}), 400
            
        agent_name = data.get('agent_name', '').strip()
        force_update = data.get('force_update', False)
        knowledge_bases = data.get('knowledge_bases', [])
        tenant_id = data.get('tenant_id', '').strip()
        
        print(f"📚 Received {len(knowledge_bases)} knowledge base(s) from frontend:")
        for kb in knowledge_bases:
            print(f"   - {kb.get('name', 'unnamed')}: {kb.get('knowledgeBaseId', 'no-id')}")
        
        # Get Azure configuration from DiscoveryConfigManager
        try:
            config_manager = DiscoveryConfigManager()
            azure_config = config_manager.get_azure_config()
            template_files = config_manager.get_template_files()
            subscription_id = azure_config.get('subscription_id', '').strip()
            resource_group = azure_config.get('resource_group', '').strip()
            location = azure_config.get('location', '').strip()
            # Use tenant_id from request if provided, otherwise from config
            if not tenant_id:
                tenant_id = azure_config.get('tenant_id', '').strip()
        except Exception as e:
            print(f"⚠️ Could not load Azure configuration: {e}")
            subscription_id = resource_group = location = ''
            template_files = {}
        # At this point: tenant_id must come either from request or from the discovery config
        if not tenant_id:
            err = ('tenant_id not provided in request and not configured in discovery_config.json. '
                   'Set tenant_id in discovery_config.json or include tenant_id in the request body.')
            print(f"⚠️ {err}")
            return jsonify({'success': False, 'error': err}), 400
        
        if not agent_name:
            return jsonify({'success': False, 'error': 'Agent name is required'}), 400
            
        print(f"📤 Publishing Knowledge Base Agent: {agent_name}")
        print(f"   - Force update: {force_update}")
        
        # Step 1: Validate that the agent exists in our KB agents catalog
        if not agent_manager or agent_name not in agent_manager.kb_agents:
            return jsonify({
                'success': False, 
                'error': f'Knowledge Base Agent "{agent_name}" not found in catalog'
            }), 404
            
        # Get the agent configuration path
        kb_agent = agent_manager.kb_agents[agent_name]
        agent_config_path = os.path.join(os.path.dirname(agent_manager.catalog_path), kb_agent.agent_config)
        
        if not os.path.exists(agent_config_path):
            return jsonify({
                'success': False, 
                'error': f'Agent configuration file not found: {agent_config_path}'
            }), 404
            
        # Step 2: Load and validate the YAML configuration
        # Use provided agent_config if available, otherwise load from file
        agent_config_from_request = data.get('agent_config', '').strip()
        
        try:
            if agent_config_from_request:
                print("📝 Using agent configuration from request (includes selected knowledge bases)")
                agent_yaml = agent_config_from_request
            else:
                print("📝 Loading agent configuration from file")
                with open(agent_config_path, 'r', encoding='utf-8') as f:
                    agent_yaml = f.read()
        except Exception as e:
            return jsonify({
                'success': False, 
                'error': f'Failed to read agent configuration: {str(e)}'
            }), 500
            
        # Step 3: Perform YAML schema validation
        validation_errors = []
        try:
            if validate_yaml is not None:
                agent_schema_file = template_files.get('AgentDefinitionSchema')
                if agent_schema_file:
                    agent_schema_path = os.path.join(os.path.dirname(__file__), agent_schema_file)
                    if os.path.exists(agent_schema_path):
                        v_result = validate_yaml(str(agent_schema_path), agent_yaml)
                        if v_result and not getattr(v_result, 'valid', False):
                            errors = getattr(v_result, 'errors', [])
                            validation_errors = [{'path': e.path, 'message': e.message} for e in errors]
                            print(f"🔍 YAML validation failed: {len(validation_errors)} errors")
                            for i, error in enumerate(validation_errors[:5]):
                                print(f"   - error[{i}]: {error['path']}: {error['message']}")
                    else:
                        print(f"⚠️ Agent schema file not found: {agent_schema_path}")
                else:
                    print("⚠️ AgentDefinitionSchema not configured in template_files")
        except Exception as e:
            validation_errors.append({'path': 'schema_validation', 'message': f'Validation error: {str(e)}'})
            
        if validation_errors:
            return jsonify({
                'success': False,
                'error': 'Agent configuration validation failed',
                'validation_errors': validation_errors
            }), 400

        # Additional semantic validation: reserved extension input names
        try:
            parsed_for_inputs = yaml.safe_load(agent_yaml)
            forbidden = _find_forbidden_extension_input_names(parsed_for_inputs)
            if forbidden:
                forbidden_list = ', '.join(sorted(forbidden))
                return jsonify({
                    'success': False,
                    'error': 'Agent configuration validation failed',
                    'validation_errors': [{
                        'path': 'extension.inputs',
                        'message': (
                            'Reserved inputs are not allowed in agent definition extension.inputs: '
                            f'{forbidden_list}. Remove them from extension.inputs.'
                        )
                    }]
                }), 400
        except Exception:
            # If YAML can't be parsed, schema validation above would have caught it.
            pass
            
        print(f"✅ YAML validation passed for agent: {agent_name}")
        
        # Step 4: Check for existing agents in Azure (if Azure configuration provided)
        if subscription_id and resource_group and not force_update:
            try:
                if not DISCOVERY_AVAILABLE:
                    print("⚠️ Discovery modules not available - skipping duplicate check")
                else:
                    # Initialize Azure Discovery client  
                    azure_client = AzureDiscoveryClient()
                    
                    # List existing agents
                    agents_result = azure_client.list_discovery_agents(subscription_id, resource_group, agent_name)
                    existing_agents = agents_result.get('agents', [])
                    
                    # Check if agent with same name exists
                    matching_agents = [a for a in existing_agents if a.get('name', '').lower() == agent_name.lower()]
                    
                    if matching_agents:
                        print(f"🔍 Found {len(matching_agents)} existing agent(s) with name '{agent_name}'")
                        return jsonify({
                            'success': False,
                            'error': 'duplicate_agent',
                            'message': f'Knowledge Base Agent "{agent_name}" already exists in Azure Discovery. Choose "Update" to overwrite or provide a new name.',
                            'existing_agent': matching_agents[0],
                            'agent_name': agent_name
                        }), 409  # Conflict status code
                        
            except Exception as e:
                print(f"⚠️ Could not check for existing agents: {str(e)}")
                # Continue with publishing - don't fail on duplicate check errors
                
        # Step 5: Proceed with publishing
        try:
            azure_client = AzureDiscoveryClient()
            
            # Parse the agent YAML to extract configuration
            import yaml
            agent_config = yaml.safe_load(agent_yaml)
            agent_display_name = agent_config.get('agent', {}).get('name', agent_name)
            
            # Create the agent resource in Azure Discovery
            config_manager = DiscoveryConfigManager()
            
            # Use the REST publisher to deploy the agent
            publisher = DiscoveryRestPublisher(
                subscription_id=subscription_id,
                resource_group=resource_group,
                location=location,
                tenant_id=tenant_id
            )
            
            # Publish the KB agent (no tools needed)
            # Pass the YAML config and knowledge bases separately
            deployment_result = publisher.deploy_kb_agent(
                agent_name=agent_name,
                agent_definition=agent_config,  # Pass the YAML config directly
                knowledge_bases=knowledge_bases,  # Pass knowledge bases separately
                force_update=force_update
            )
            
            print(f"📤 Publishing Knowledge Base Agent: {agent_name}"
                  f" - Deployment result: {deployment_result}"
                  )
            print(f"   - Subscription ID: {subscription_id}")
            print(f"   - Resource Group: {resource_group}")
            print(f"   - Location: {location}")
            print(f"   - Tenant ID: {tenant_id}")

            if deployment_result.get('success'):
                # Verify the deployment was actually successful with proper provisioning state
                print(f"🔍 Verifying KB agent deployment: {agent_name}")
                verification_result = verify_agent_deployment(
                    azure_client,
                    subscription_id,
                    resource_group,
                    deployment_result.get('resource_name', agent_name),
                    tenant_id=tenant_id,
                    max_wait_seconds=180  # Allow more time for KB agents
                )
                
                if verification_result.get('success'):
                    print(f"✅ Successfully verified KB agent: {agent_name}")
                    return jsonify({
                        'success': True,
                        'message': f'Knowledge Base Agent "{agent_name}" published and verified successfully',
                        'deployment_info': {
                            'agent_name': agent_name,
                            'type': 'knowledge_base',
                            'status': 'published',
                            'resource_id': deployment_result.get('resource_id'),
                            'location': location,
                            'provisioning_state': verification_result.get('provisioning_state')
                        }
                    })
                else:
                    # Deployment succeeded but verification failed
                    verification_msg = verification_result.get('message', 'Verification failed')
                    print(f"⚠️ KB agent deployed but verification failed: {verification_msg}")
                    return jsonify({
                        'success': False,
                        'error': f'Agent deployed but verification failed: {verification_msg}',
                        'deployment_info': {
                            'agent_name': agent_name,
                            'type': 'knowledge_base',
                            'status': 'deployed_unverified',
                            'resource_id': deployment_result.get('resource_id'),
                            'location': location
                        }
                    }), 500
            elif deployment_result.get('duplicate'):
                # Handle duplicate agent case
                print(f"🔍 Duplicate KB agent detected: {agent_name}")
                return jsonify({
                    'success': False,
                    'error': 'duplicate_agent',
                    'message': f'Knowledge Base Agent "{agent_name}" already exists in {location}. Choose "Update" to overwrite or provide a new name.',
                    'duplicate': True,
                    'agent_name': agent_name
                }), 409  # Conflict status code
            else:
                error_msg = deployment_result.get('error', 'Unknown deployment error')
                print(f"❌ Failed to publish KB agent: {error_msg}")
                return jsonify({
                    'success': False,
                    'error': f'Failed to publish agent: {error_msg}'
                }), 500
                    
        except Exception as e:
            print(f"❌ Error during agent publishing: {e}")
            return jsonify({
                'success': False,
                'error': f'Publishing failed: {str(e)}'
            }), 500
        
    except Exception as e:
        print(f"❌ Error publishing knowledge base agent: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/test-auth', methods=['POST'])
def test_auth():
    """Test Azure OpenAI authentication (both API key and Azure AD)"""
    try:
        # Simple test message
        test_messages = [
            {
                "role": "system", 
                "content": "You are a helpful assistant."
            },
            {
                "role": "user", 
                "content": "Reply with just 'Authentication successful!' and nothing else."
            }
        ]
        
        print("🔄 Testing Azure OpenAI authentication...")
        response_data = call_azure_openai_direct(test_messages, max_output_tokens=50, temperature=0.1)
        content = parse_llm_response_direct(response_data)
        
        if content:
            print("✅ Authentication test successful!")
            return jsonify({
                'success': True, 
                'message': 'Authentication successful!',
                'response': content.strip()
            })
        else:
            print("❌ Authentication test failed - no response content")
            return jsonify({
                'success': False, 
                'error': 'No response content received'
            }), 500
            
    except Exception as e:
        print(f"❌ Authentication test failed: {str(e)}")
        return jsonify({
            'success': False, 
            'error': f'Authentication failed: {str(e)}'
        }), 500

@app.route('/api/azure/knowledge-bases-v2', methods=['GET'])
def get_azure_knowledge_bases_v2():
    """Get list of all knowledge bases using the direct bookshelf data plane API.
    
    This endpoint uses the Microsoft.Bookshelf service data plane API to directly
    query knowledge bases from each bookshelf, following the swagger specification.
    This is much simpler and more reliable than the previous approach.
    """
    try:
        # Get Azure configuration
        config_manager = DiscoveryConfigManager()
        azure_config = config_manager.get_azure_config()
        subscription_id = azure_config.get('subscription_id', '').strip()
        resource_group = azure_config.get('resource_group', '').strip()
        
        if not subscription_id or not resource_group:
            return jsonify({
                'success': False,
                'error': 'Azure subscription_id and resource_group must be configured'
            }), 400
        
        # Require tenant_id from configuration and obtain tenant-scoped tokens
        tenant_id = azure_config.get('tenant_id', '').strip()
        if not tenant_id:
            return jsonify({
                'success': False,
                'error': 'Azure tenant_id must be configured in Settings and will be used for authentication. No fallbacks allowed.'
            }), 400

        # Strict policy: do NOT accept client-supplied tokens or use DefaultAzureCredential fallbacks.
        # Use tenant-scoped helper to obtain tokens for both management and bookshelf data plane.
        from azure_auth_helpers import get_token_for_tenant

        server_traces = []
        mgmt_token = get_token_for_tenant('https://management.azure.com/.default', tenant_id, server_traces, purpose='bookshelf-mgmt')
        if not mgmt_token:
            short = server_traces[-1] if server_traces else 'Failed to obtain management token'
            print(f"❌ Failed to obtain management token for tenant {tenant_id}: {short}")
            return jsonify({'success': False, 'error': 'Failed to obtain management token for tenant', 'traces': server_traces}), 401

        # Acquire discovery/data-plane token scoped to the tenant. No fallback to management token.
        dp_traces = []
        discovery_token = get_token_for_tenant('https://discovery.azure.com/.default', tenant_id, dp_traces, purpose='bookshelf-discovery')
        if not discovery_token:
            short = dp_traces[-1] if dp_traces else 'Failed to obtain discovery data plane token'
            print(f"❌ Failed to obtain discovery data plane token for tenant {tenant_id}: {short}")
            return jsonify({'success': False, 'error': 'Failed to obtain discovery data plane token for tenant', 'traces': dp_traces}), 401

        print(f"🔑 Obtained tenant-scoped tokens for tenant {tenant_id} (management + discovery)")
        
        # Call Azure REST API to list bookshelves (management plane)
        url = f"https://management.azure.com/subscriptions/{subscription_id}/resourceGroups/{resource_group}/providers/Microsoft.Discovery/bookshelves"
        headers = {
            'Authorization': f'Bearer {mgmt_token}',
        }
        params = {
            'api-version': '2025-07-01-preview'
        }
        
        print(f"📚 Fetching bookshelves from: {url}")
        response = requests.get(url, headers=headers, params=params, timeout=30)
        
        if response.status_code == 200:
            data = response.json()
            bookshelves = data.get('value', [])
            print(f"📚 Found {len(bookshelves)} bookshelf(es)")
            
            # Get all knowledge bases from all bookshelves using direct data plane API
            all_knowledge_bases = []
            processed_bookshelves = 0
            
            for bookshelf in bookshelves:
                bookshelf_name = bookshelf.get('name', '')
                bookshelf_id = bookshelf.get('id', '')
                bookshelf_location = bookshelf.get('location', '')
                bookshelf_state = bookshelf.get('properties', {}).get('provisioningState', '')
                bookshelf_properties = bookshelf.get('properties', {})
                
                print(f"   📖 Processing bookshelf: {bookshelf_name} (state: {bookshelf_state})")
                
                # Skip bookshelves that are not successfully provisioned
                if bookshelf_state != 'Succeeded':
                    print(f"   ⚠️ Skipping bookshelf {bookshelf_name} - not in Succeeded state")
                    continue
                
                processed_bookshelves += 1
                
                try:
                    # Test multiple URL patterns to find the correct one
                    # The swagger shows the pattern but DNS resolution is failing
                    
                    # Potential URL patterns based on common Azure service patterns
                    url_patterns = [
                        # Pattern 5: Original incorrect pattern (for comparison)
                        f"https://{bookshelf_name}.bookshelf.discovery.azure.com/knowledgeBases"
                    ]
                    
                    # Use tenant-scoped discovery token for data plane calls and mgmt token for management calls
                    auth_token = discovery_token
                    token_type = "discovery"
                    
                    kb_headers = {
                        'Authorization': f'Bearer {auth_token}',
                    }
                    kb_params = {
                        'api-version': '2025-07-01-preview'
                    }
                    
                    successful_response = None
                    working_url = None
                    
                    for i, kb_url in enumerate(url_patterns, 1):
                        try:
                            kb_response = requests.get(kb_url, headers=kb_headers, params=kb_params, timeout=10)
                            print(f"      📡 HTTP {kb_response.status_code}")
                            
                            if kb_response.status_code == 200:
                                successful_response = kb_response
                                working_url = kb_url
                                print(f"      🎉 SUCCESS! Found working URL pattern")
                                break
                            elif kb_response.status_code in [401, 403]:
                                print(f"      � Authentication issue - but URL exists")
                            elif kb_response.status_code == 404:
                                print(f"      📭 Not found - URL doesn't exist")
                            else:
                                print(f"      ⚠️ Other error: {kb_response.status_code}")
                                
                        except Exception as e:
                            print(f"      ❌ Error: {str(e)[:100]}...")
                    
                    if successful_response:
                        print(f"   \n   ✅ Using working URL: {working_url}")
                        kb_response = successful_response
                        kb_url = working_url                        
                    else:
                        print(f"   \n   ❌ No working URL pattern found for {bookshelf_name}")
                        print(f"   💡 This suggests the bookshelf data plane may not be available yet")
                        print(f"   📋 Tested patterns:")
                        for i, pattern in enumerate(url_patterns, 1):
                            print(f"      {i}. {pattern}")
                        continue
                    
                    if kb_response.status_code == 200:
                        kb_data = kb_response.json()
                        knowledge_bases = kb_data.get('value', [])
                        print(f"   📚 Found {len(knowledge_bases)} knowledge base(s) in {bookshelf_name}")
                        
                        # Status analysis counters
                        status_counts = {}
                        successful_kbs = []
                        failed_kbs = []
                        running_kbs = []
                        other_status_kbs = []
                        
                        # Process each knowledge base with detailed status analysis
                        for kb in knowledge_bases:
                            kb_name = kb.get('name', '')
                            kb_id = kb.get('id', '')
                            # Ensure knowledgeBaseId follows the expected bookshelf-qualified format.
                            # Some APIs or older systems may return '/knowledgeBases/{name}/versions/{v}'.
                            # Normalize by prepending the bookshelf segment when missing.
                            if kb_id and '/bookshelves/' not in kb_id:
                                # If id starts with '/knowledgeBases/', convert to '/bookshelves/{bookshelfName}/knowledgeBases/...'
                                if kb_id.startswith('/knowledgeBases/'):
                                    kb_id = f"/bookshelves/{bookshelf_name}{kb_id}"
                                else:
                                    # If it's a plain name, construct the full id
                                    # Prefer explicit version if provided, otherwise default to '1'
                                    kb_name_from_id = kb.get('name', kb.get('knowledgeBaseName', ''))
                                    kb_version = kb.get('version', '1') or '1'
                                    kb_id = f"/bookshelves/{bookshelf_name}/knowledgeBases/{kb_name_from_id}/versions/{kb_version}"
                            kb_version = kb.get('version', '')
                            kb_status = kb.get('status', '')
                            kb_description = kb.get('description', '')
                            kb_url_prop = kb.get('knowledgeBaseUrl', '')
                            created_at = kb.get('createdAt', '')
                            last_modified = kb.get('lastModifiedAt', '')
                            
                            # Extract additional properties that might indicate accessibility
                            kb_properties = kb.get('properties', {})
                            provisioning_state = kb_properties.get('provisioningState', '')
                            enabled = kb_properties.get('enabled', '')
                            ready = kb_properties.get('ready', '')
                            endpoint_state = kb_properties.get('endpointState', '')
                            deployment_state = kb_properties.get('deploymentState', '')
                            
                            # Count status occurrences
                            status_counts[kb_status] = status_counts.get(kb_status, 0) + 1
                            
                            # Determine accessibility status
                            accessibility_indicators = []
                            
                            # Primary status check - Failed status means inaccessible
                            if kb_status.lower() == 'failed':
                                accessibility_indicators.append("STATUS_FAILED")
                            elif kb_status.lower() == 'running':
                                accessibility_indicators.append("STATUS_RUNNING")
                            elif kb_status.lower() != 'succeeded':
                                accessibility_indicators.append(f"STATUS_{kb_status.upper()}")
                            
                            # Secondary property checks
                            if enabled == False or enabled == 'false':
                                accessibility_indicators.append("DISABLED")
                            if ready == False or ready == 'false':
                                accessibility_indicators.append("NOT_READY")
                            if endpoint_state and endpoint_state.lower() in ['failed', 'stopped', 'disabled']:
                                accessibility_indicators.append(f"ENDPOINT_{endpoint_state.upper()}")
                            if deployment_state and deployment_state.lower() in ['failed', 'stopped']:
                                accessibility_indicators.append(f"DEPLOYMENT_{deployment_state.upper()}")
                            if provisioning_state and provisioning_state.lower() != 'succeeded':
                                accessibility_indicators.append(f"PROVISIONING_{provisioning_state.upper()}")
                            
                            # Only mark as AVAILABLE if status is 'succeeded' and no other issues
                            if kb_status.lower() == 'succeeded' and not accessibility_indicators:
                                accessibility_status = "AVAILABLE"
                            else:
                                accessibility_status = " | ".join(accessibility_indicators) if accessibility_indicators else "UNKNOWN"
                            
                            # Status-based emoji and categorization
                            if kb_status.lower() == 'succeeded':
                                status_emoji = "✅"
                                successful_kbs.append(kb_name)
                            elif kb_status.lower() == 'failed':
                                status_emoji = "❌"
                                failed_kbs.append(kb_name)
                            elif kb_status.lower() == 'running':
                                status_emoji = "🔄"
                                running_kbs.append(kb_name)
                            else:
                                status_emoji = "❓"
                                other_status_kbs.append((kb_name, kb_status))
                            
                            print(f"     📚 Knowledge Base: {kb_name} (version: {kb_version})")
                            print(f"        {status_emoji} Status: {kb_status}")
                            print(f"        🚦 Accessibility: {accessibility_status}")
                            print(f"        🆔 ID: {kb_id}")
                            print(f"        📝 Description: {kb_description}")
                            print(f"        🌐 KB URL: {kb_url_prop}")
                            print(f"        📅 Created: {created_at}")
                            print(f"        🔄 Modified: {last_modified}")
                            
                            # Show detailed properties if they exist
                            if provisioning_state:
                                print(f"        🔧 Provisioning State: {provisioning_state}")
                            if enabled != '':
                                print(f"        🔘 Enabled: {enabled}")
                            if ready != '':
                                print(f"        ✅ Ready: {ready}")
                            if endpoint_state:
                                print(f"        🌐 Endpoint State: {endpoint_state}")
                            if deployment_state:
                                print(f"        🚀 Deployment State: {deployment_state}")
                            
                            all_knowledge_bases.append({
                                'name': kb_name,
                                'version': kb_version,
                                'knowledgeBaseId': kb_id,
                                'bookshelfName': bookshelf_name,
                                'bookshelfId': bookshelf_id,
                                'location': bookshelf_location,
                                'status': kb_status,
                                'description': kb_description,
                                'knowledgeBaseUrl': kb_url_prop,
                                'createdAt': created_at,
                                'lastModifiedAt': last_modified,
                                'discoveryMethod': 'bookshelf-data-plane-api',
                                'dataPlaneEndpoint': f"https://{bookshelf_name}.discovery.azure.com",
                                'authenticationUsed': token_type,
                                'accessibilityStatus': accessibility_status,
                                'provisioningState': provisioning_state,
                                'enabled': enabled,
                                'ready': ready,
                                'endpointState': endpoint_state,
                                'deploymentState': deployment_state,
                                'properties': kb_properties
                            })
                        
                        if successful_kbs:
                            print(f"   ✅ Succeeded KBs: {', '.join(successful_kbs)}")
                        if failed_kbs:
                            print(f"   ❌ Failed KBs: {', '.join(failed_kbs)}")
                        if running_kbs:
                            print(f"   🔄 Running KBs: {', '.join(running_kbs)}")
                        if other_status_kbs:
                            print(f"   ❓ Other Status KBs: {', '.join([f'{name}({status})' for name, status in other_status_kbs])}")
                            
                    elif kb_response.status_code == 404:
                        print(f"   📁 Bookshelf data plane endpoint not found (404) for {bookshelf_name}")
                        print(f"   💡 This could mean:")
                        print(f"      - The bookshelf data plane is not yet available")
                        print(f"      - The endpoint URL pattern is different")
                        print(f"      - The bookshelf is not fully provisioned")
                    elif kb_response.status_code == 401 or kb_response.status_code == 403:
                        print(f"   🔒 Access denied to bookshelf data plane (HTTP {kb_response.status_code}) for {bookshelf_name}")
                        print(f"   💡 Check if you have the required permissions for bookshelf data plane access")
                        print(f"   🌐 Full GET request URL: {kb_url}")
                        print(f"   📋 Query parameters: {kb_params}")
                        print(f"   🔑 Authorization header: Bearer {auth_token[:20]}...{auth_token[-10:] if len(auth_token) > 30 else ''}")
                        print(f"   🎫 Token type used: {token_type}")
                        print(f"   � Error response: {kb_response.text[:200]}...")
                    else:
                        print(f"   ❌ Failed to get knowledge bases from {bookshelf_name}: HTTP {kb_response.status_code}")
                        print(f"   📄 Error response: {kb_response.text[:200]}...")
                        print(f"   🌐 Full GET request URL: {kb_url}")
                        print(f"   📋 Query parameters: {kb_params}")
                        print(f"   🔑 Authorization header: Bearer {auth_token[:20]}...{auth_token[-10:] if len(auth_token) > 30 else ''}")
                        
                        # Try to parse error response for more details
                        try:
                            error_data = kb_response.json()
                            if 'error' in error_data:
                                error_info = error_data['error']
                                print(f"   🔍 Error code: {error_info.get('code', 'unknown')}")
                                print(f"   📝 Error message: {error_info.get('message', 'unknown')}")
                        except:
                            print(f"   📄 Raw error response: {kb_response.text}")
                
                except Exception as e:
                    print(f"   ❌ Error processing bookshelf {bookshelf_name}: {str(e)}")
                    print(f"   🔍 Exception type: {type(e).__name__}")
            
            print(f"📚 Total knowledge bases found across all bookshelves: {len(all_knowledge_bases)}")
            print(f"📊 Successfully processed {processed_bookshelves} bookshelf(es)")
            
            # Calculate overall status statistics
            overall_status_counts = {}
            overall_accessibility_counts = {}
            accessible_kbs = []
            inaccessible_kbs = []
            
            for kb in all_knowledge_bases:
                status = kb.get('status', 'unknown')
                accessibility = kb.get('accessibilityStatus', 'UNKNOWN')
                
                overall_status_counts[status] = overall_status_counts.get(status, 0) + 1
                overall_accessibility_counts[accessibility] = overall_accessibility_counts.get(accessibility, 0) + 1
                
                if accessibility == 'AVAILABLE':
                    accessible_kbs.append(f"{kb['name']} ({kb['bookshelfName']})")
                else:
                    inaccessible_kbs.append(f"{kb['name']} ({kb['bookshelfName']}) - {accessibility}")
            
            return jsonify({
                'success': True,
                'knowledgeBases': all_knowledge_bases,
                'count': len(all_knowledge_bases),
                'resourceGroup': resource_group,
                'bookshelvesCount': len(bookshelves),
                'processedBookshelvesCount': processed_bookshelves,
                'discoveryMethod': 'bookshelf-data-plane-api',
                'version': 'v2-simplified',
                'statusAnalysis': {
                    'overallStatusCounts': overall_status_counts,
                    'accessibilityCounts': overall_accessibility_counts,
                    'accessibleCount': len(accessible_kbs),
                    'inaccessibleCount': len(inaccessible_kbs),
                    'accessibleKBs': accessible_kbs,
                    'inaccessibleKBs': inaccessible_kbs
                }
            })
        
        else:
            error_msg = f"Azure API returned {response.status_code}: {response.text}"
            print(f"❌ {error_msg}")
            return jsonify({
                'success': False,
                'error': error_msg
            }), response.status_code
            
    except Exception as e:
        print(f"❌ Error fetching knowledge bases: {str(e)}")
        return jsonify({
            'success': False,
            'error': f'Failed to fetch knowledge bases: {str(e)}'
        }), 500

@app.route('/api/azure/bookshelf/<bookshelf_name>/knowledge-bases', methods=['GET'])
def get_bookshelf_knowledge_bases(bookshelf_name):
    """Get knowledge bases for a specific bookshelf using the corrected data plane API.
    
    This endpoint demonstrates the correct URL format based on the swagger specification:
    https://{bookshelfName}.discovery.azure.com/Bookshelves/{bookshelfName}/knowledgeBases
    """
    try:
        print(f"📚 Fetching knowledge bases for bookshelf: {bookshelf_name}")
        
        # Require tenant_id from configured settings and obtain tenant-scoped discovery token
        cfg = None
        try:
            cfg = DiscoveryConfigManager().get_azure_config()
        except Exception:
            cfg = None

        tenant_id = (cfg.get('tenant_id') if isinstance(cfg, dict) else '') or ''
        tenant_id = tenant_id.strip()
        if not tenant_id:
            return jsonify({'success': False, 'error': 'Azure tenant_id must be configured in Settings. No fallbacks allowed.'}), 400

        from azure_auth_helpers import get_token_for_tenant
        server_traces = []
        discovery_token = get_token_for_tenant('https://discovery.azure.com/.default', tenant_id, server_traces, purpose='bookshelf-discovery')
        if not discovery_token:
            return jsonify({'success': False, 'error': 'Failed to obtain discovery data plane token for tenant', 'traces': server_traces}), 401

        auth_token = discovery_token
        token_type = 'discovery'
        
        # Construct the correct URL according to swagger specification
        kb_url = f"https://{bookshelf_name}.discovery.azure.com/Bookshelves/{bookshelf_name}/knowledgeBases"
        
        kb_headers = {
            'Authorization': f'Bearer {auth_token}',
        }
        kb_params = {
            'api-version': '2025-07-01-preview'
        }
        
        print(f"🌐 Knowledge Base URL: {kb_url}")
        print(f"🔑 Using {token_type} token")
        print(f"📋 Request headers: {dict(kb_headers)}")
        print(f"⚙️ Request parameters: {kb_params}")
        
        # Make the API call
        kb_response = requests.get(kb_url, headers=kb_headers, params=kb_params, timeout=30)
        
        print(f"📡 Response status: {kb_response.status_code}")
        
        if kb_response.status_code == 200:
            kb_data = kb_response.json()
            knowledge_bases = kb_data.get('value', [])
            
            print(f"✅ Successfully retrieved {len(knowledge_bases)} knowledge base(s)")
            
            # Process each knowledge base
            processed_kbs = []
            for kb in knowledge_bases:
                processed_kb = {
                    'name': kb.get('name', ''),
                    'id': kb.get('id', ''),
                    'version': kb.get('version', ''),
                    'status': kb.get('status', ''),
                    'description': kb.get('description', ''),
                    'knowledgeBaseUrl': kb.get('knowledgeBaseUrl', ''),
                    'createdAt': kb.get('createdAt', ''),
                    'lastModifiedAt': kb.get('lastModifiedAt', ''),
                    'bookshelfName': bookshelf_name,
                    'dataPlaneEndpoint': f"https://{bookshelf_name}.discovery.azure.com",
                    'authenticationUsed': token_type
                }
                processed_kbs.append(processed_kb)
                
                print(f"  📚 {kb.get('name', 'Unnamed')} (status: {kb.get('status', 'unknown')})")
            
            return jsonify({
                'success': True,
                'bookshelfName': bookshelf_name,
                'knowledgeBases': processed_kbs,
                'count': len(processed_kbs),
                'authenticationUsed': token_type,
                'dataPlaneEndpoint': f"https://{bookshelf_name}.discovery.azure.com",
                'correctUrlFormat': True
            })
        
        else:
            error_info = {
                'status_code': kb_response.status_code,
                'response_text': kb_response.text,
                'headers': dict(kb_response.headers)
            }
            
            # Try to parse structured error
            try:
                error_data = kb_response.json()
                if 'error' in error_data:
                    error_info['structured_error'] = error_data['error']
            except:
                pass
            
            print(f"❌ API call failed with status {kb_response.status_code}")
            
            return jsonify({
                'success': False,
                'error': f'Knowledge base API returned {kb_response.status_code}',
                'bookshelfName': bookshelf_name,
                'error_details': error_info,
                'authenticationUsed': token_type,
                'url_used': kb_url
            }), kb_response.status_code
            
    except Exception as e:
        print(f"❌ Error fetching knowledge bases for bookshelf {bookshelf_name}: {str(e)}")
        return jsonify({
            'success': False,
            'error': f'Failed to fetch knowledge bases for bookshelf {bookshelf_name}: {str(e)}',
            'bookshelfName': bookshelf_name
        }), 500

